-- Poems batch 324
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b3e5fb33-00af-4378-bb2e-b2c00c808fb1','遊李少師園十題 和張二十五遊白龍谿甘水谷郊居雜咏七首 其七','范祖禹','宋','宋诗','song-poetry','','[]','青山跬步去無由，唯有登臨可散憂。',32,'全唐诗/poet.song.50000.json','["青山跬步去無由，唯有登臨可散憂。", "浮世只知軒冕樂，幾人能得少時休。"]'),
('bb1ca049-0c47-4d1f-b583-ad84a529a708','西街','范祖禹','宋','宋诗','song-poetry','','[]','西街春日永，輦道與天通。',48,'全唐诗/poet.song.50000.json','["西街春日永，輦道與天通。", "御水横銀漢，仙橋掛綵虹。", "草荒平樂館，花發上陽宫。", "擾擾都門路，輪蹄日向東。"]'),
('46deb382-9a5e-4421-af68-cb92e680143c','和子進六言二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','夜静碧天如水，山空明月隨人。',28,'全唐诗/poet.song.50000.json','["夜静碧天如水，山空明月隨人。", "此興庾公非淺，遠遊王子何頻。"]'),
('348ae1e4-93c2-49fb-a7ad-ef7a6e6aa7a8','和子進六言二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','蕭散獨遊何處，寂寥四顧無人。',28,'全唐诗/poet.song.50000.json','["蕭散獨遊何處，寂寥四顧無人。", "月露霑衣覺久，水風吹面宜頻。"]'),
('cd53e44d-debb-4a28-94fe-37889f18ef42','和子進千春院觀桃花二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','西度天津水見沙，輕風飛蓋緑楊斜。',64,'全唐诗/poet.song.50000.json','["西度天津水見沙，輕風飛蓋緑楊斜。", "相逢喜到千春寺，最後方開第一花。", "富媪英華當間出，東君照育想非賖。", "神仙高格黄裳色，安得深根植帝家。"]'),
('0edb81f4-e33d-4387-8632-72fd094f63ac','和子進千春院觀桃花二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','鳯刹花光照碧霄，龍樓柳色暗朱橋。',64,'全唐诗/poet.song.50000.json','["鳯刹花光照碧霄，龍樓柳色暗朱橋。", "夸娥素月人疑近，姑射仙山路豈遥。", "琮玉温姿輕拂拂，鞠衣嘉色宛飄飄。", "都人莫怪芳華晚，如隔煙霞在泬寥。"]'),
('06ce41b8-0c45-4437-9aad-f405a546bdc2','三月十八日雨後訪張二十五以詩見寄次其韻','范祖禹','宋','宋诗','song-poetry','','[]','池上魚相樂，林間鳥不驚。',48,'全唐诗/poet.song.50000.json','["池上魚相樂，林間鳥不驚。", "雨餘荷氣濕，風動水紋生。", "俗客心猶爽，高人興自清。", "何時作鄰里，卜宅剪榛荆。"]'),
('05def714-3770-41d7-8b20-a5790c059a8f','又和再寄二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','青春忽已過，白髪不須驚。',48,'全唐诗/poet.song.50000.json','["青春忽已過，白髪不須驚。", "招隠尋居士，論文訪友生。", "到来塵慮息，歸去夢魂清。", "尚想穿幽徑，楸花間紫荆。"]'),
('82972f76-b61d-47b3-bad2-ad744832f3a5','又和再寄二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','花落春臺静，鸎啼曉枕驚。',48,'全唐诗/poet.song.50000.json','["花落春臺静，鸎啼曉枕驚。", "竹間流水過，窗外白雲生。", "襟抱懷冰爽，詩篇叩玉清。", "荒唐漆園吏，環堵但披荆。"]'),
('1d56c465-d638-4ee2-a544-5fb0c63bca45','張三十病愈久不相見以詩寄問','范祖禹','宋','宋诗','song-poetry','','[]','公幹清漳卧，維摩浄室居。',48,'全唐诗/poet.song.50000.json','["公幹清漳卧，維摩浄室居。", "作詩心在否，問法意何如。", "臺榭花飛盡，池塘雨洗初。", "劇談能强起，便欲駕柴車。"]'),
('59879bcc-ffee-48c3-95e5-42be51c87a13','和張二十五春日見寄五首  其一','范祖禹','宋','宋诗','song-poetry','','[]','綽約花無語，間關鳥自吟。',24,'全唐诗/poet.song.50000.json','["綽約花無語，間關鳥自吟。", "及時須賞翫，風雨不能禁。"]'),
('ab11de02-252c-4902-b574-54e57428e978','和張二十五春日見寄五首  其二','范祖禹','宋','宋诗','song-poetry','','[]','莫恨生華髪，唯須不負春。',24,'全唐诗/poet.song.50000.json','["莫恨生華髪，唯須不負春。", "風光無老少，祗屬有情人。"]'),
('0dbc553f-92f3-4437-a340-cf4f08d6087d','和張二十五春日見寄五首  其三','范祖禹','宋','宋诗','song-poetry','','[]','瀟灑幽棲地，山嵐日夕昏。',24,'全唐诗/poet.song.50000.json','["瀟灑幽棲地，山嵐日夕昏。", "松風吹緑綺，溪月湛清樽。"]'),
('18f51af5-84fe-4560-8a7f-40110b956240','和張二十五春日見寄五首  其四','范祖禹','宋','宋诗','song-poetry','','[]','白日春臺上，歡娛莫訴盃。',24,'全唐诗/poet.song.50000.json','["白日春臺上，歡娛莫訴盃。", "飛花留客醉，啼鳥近人来。"]'),
('0f4de5ab-9e69-4c82-a6b6-823c172de587','和張二十五春日見寄五首  其五','范祖禹','宋','宋诗','song-poetry','','[]','流水家家入，脩篁處處同。',24,'全唐诗/poet.song.50000.json','["流水家家入，脩篁處處同。", "城南履道宅，白傅有遺風。"]'),
('d389662f-23fd-4248-a3ce-d3fdee20a564','和子進夏日憶寶上人','范祖禹','宋','宋诗','song-poetry','','[]','徑蘚鋪蒼錦，林花落絳趺。',48,'全唐诗/poet.song.50000.json','["徑蘚鋪蒼錦，林花落絳趺。", "山光入戸牖，雲氣起瓶盂。", "宴坐期三月，迷行有萬途。", "寥寥方丈室，一物更應無。"]'),
('f091ecec-621e-4803-94d6-e069076b904c','秋夜','范祖禹','宋','宋诗','song-poetry','','[]','月上霜威重，煙消霽景分。',48,'全唐诗/poet.song.50000.json','["月上霜威重，煙消霽景分。", "嶺猿寒嘯侣，澗鹿夜呼羣。", "天静纎毫見，山空落葉聞。", "此時真吏隠，高卧看浮雲。"]'),
('e8b1b8e9-9dff-4fce-a2a8-1159cbd48e31','送廷珍殿丞兄通判閬州','范祖禹','宋','宋诗','song-poetry','','[]','十年京洛弄殘書，喜見西歸别駕車。',64,'全唐诗/poet.song.50000.json','["十年京洛弄殘書，喜見西歸别駕車。", "錦里追遊貧莫厭，綵衣榮侍樂何如。", "詔條安遠民爲本，才刃如君地有餘。", "不日還趨宣室召，伊川重訪野人廬。"]'),
('8d9894da-3617-40b8-b43f-9aa69aa0964d','寄題傅欽之濟源草堂','范祖禹','宋','宋诗','song-poetry','','[]','傅公有幽居，近在盤山下。',120,'全唐诗/poet.song.50000.json','["傅公有幽居，近在盤山下。", "清濟出其間，白石明可把。", "盈科赴溟渤，習坎日傾瀉。", "竹色洗娟嬋，松姿照蕭灑。", "室有古詩書，門無俗車馬。", "公居雖畎畝，寤寐惟朝社。", "雲山聊嘯遨，魚鳥同游冶。", "在我本無心，羣生繫用捨。", "終當入帝夢，肖象求巖野。", "題詩寄林坰，俚調慚非雅。"]'),
('c46faa67-ae62-4282-8877-97adf31570eb','和蜀公紫薇花再發寄中書舍人','范祖禹','宋','宋诗','song-poetry','','[]','幾年幽獨飽風霜，一日榮觀似堵牆。',64,'全唐诗/poet.song.50000.json','["幾年幽獨飽風霜，一日榮觀似堵牆。", "地養深根成異産，天迴淑氣發新陽。", "賓朋須醉千鍾酒，蜂蝶争偷百和香。", "留得青氊真舊物，于今鳯閣有名郎。"]'),
('2d502c1b-553b-4a93-9c70-2cf0d74ad71d','和五十四翁登恩第後贈楊君章','范祖禹','宋','宋诗','song-poetry','','[]','力穡良農晚歲收，英名初喜動凝旒。',64,'全唐诗/poet.song.50000.json','["力穡良農晚歲收，英名初喜動凝旒。", "光如劍氣斗間沒，文似河源天上流。", "莫嘆黄金纔易箒，安知布被不封侯。", "暮年烈士心方壯，雙鶻摶風向九秋。"]'),
('4b1cce81-47e1-41cb-a253-d12c2b6557cf','孫秀才下第蹔還京口留别起居邀余和以贈行','范祖禹','宋','宋诗','song-poetry','','[]','翔鸞戢翼下層空，南浦歸帆逐曉風。',64,'全唐诗/poet.song.50000.json','["翔鸞戢翼下層空，南浦歸帆逐曉風。", "夢寐蘭陔清露白，嘯歌江國火雲紅。", "王畿結綬来無久，天漢乘槎去可通。", "莫爲淹回銷壯節，力行須與古人同。"]'),
('afaf66b6-e9f3-4c5b-aa5c-933cd5a57be6','和蜀公八十歲自咏','范祖禹','宋','宋诗','song-poetry','','[]','衛武年将百，僖公壽有千。',120,'全唐诗/poet.song.50000.json','["衛武年将百，僖公壽有千。", "形方通帝夢，兆始見王田。", "白髪高山雪，新詩清水蓮。", "福綏真樂只，燕處自超然。", "濁酒中徐聖，泠風御列仙。", "勁松臨絕壁，獨鶴在青天。", "出處邦之望，清虚性所便。", "老謀方眷用，微物正思憐。", "漢室求園綺，周家重夭顛。", "雖懐箕潁志，應未許終焉。"]'),
('7b4000fa-fba5-419b-b2a0-2017a90dcc46','答孫莘老病中寄謝諸同舍','范祖禹','宋','宋诗','song-poetry','','[]','言有逆耳忠，藥有苦口利。',144,'全唐诗/poet.song.50000.json','["言有逆耳忠，藥有苦口利。", "康强本危慮，憂患生逸意。", "先生蹈周孔，陋巷樂仁義。", "新命登諫垣，四方想平治。", "舞雩逐清爽，伏枕送炎熾。", "作詩存警戒，教告在同志。", "蒼生繫正人，丹扆渴高議。", "矧當敷經訓，勸講日嚴侍。", "桓榮大師尊，鄭公三鑑備。", "天衢進方亨，王路坦無陂。", "告猷補衮職，正色伏蒲地。", "陽城可以起，醇酒毋數醉。"]'),
('b26a9796-51d1-45bf-bf9e-9e5347488608','春日有懷僕射相公洛陽園','范祖禹','宋','宋诗','song-poetry','','[]','闕塞當門外，伊流遶舍西。',48,'全唐诗/poet.song.50000.json','["闕塞當門外，伊流遶舍西。", "松筠不改色，桃李自成蹊。", "穉笋穿堦迸，珍禽拂面棲。", "公歸卧林壑，好作釣璜溪。"]'),
('088c216b-1582-472c-a0a7-5a0624aa7f6b','和吕龍圗賀僕射相公','范祖禹','宋','宋诗','song-poetry','','[]','鼎鉉承家有慶基，蒼生翹首聖神知。',64,'全唐诗/poet.song.50000.json','["鼎鉉承家有慶基，蒼生翹首聖神知。", "韋賢世德傳經遠，衛武年華入相遲。", "霖雨八方隨說命，带河千古誓蕭規。", "行看鳳沼原鴒集，莫爲旌麾滯朔陲。"]'),
('bd19ebb2-1ea1-4d5d-812b-472a7f0acc1e','蜀公懇辭經席改領嵩宫賦詩以代獻壽','范祖禹','宋','宋诗','song-poetry','','[]','累詔褒優免造庭，兩宫虚竚想儀形。',64,'全唐诗/poet.song.50000.json','["累詔褒優免造庭，兩宫虚竚想儀形。", "千年遼鶴高華表，萬里雲鴻獨杳冥。", "綺皓採芝終佐漢，桓榮稽古舊傳經。", "真宫岑寂煙霞外，南極光中作壽星。"]'),
('30c65e60-0cef-4e7e-8821-52579a14cb6d','和門下侍郎東省夜直寄左丞光禄','范祖禹','宋','宋诗','song-poetry','','[]','黄閤訏謨作帝龍，文昌綱轄振邦風。',64,'全唐诗/poet.song.50000.json','["黄閤訏謨作帝龍，文昌綱轄振邦風。", "羣才藻鑒歸能哲，萬事鈞衡仰至公。", "連璧輝光時共美，斷金情契昔相同。", "折衝千里精神壯，正似山河繞漢宫。"]'),
('5976d7c6-e39f-4bbd-83b2-921351cfbca6','和子開從駕朝謁景靈宫二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','雨師汎灑霽光勻，華蓋香風不起塵。',64,'全唐诗/poet.song.50000.json','["雨師汎灑霽光勻，華蓋香風不起塵。", "億兆歡呼真帝啓，謀猷左右盡君陳。", "雲隨仙馭三山遠，日出咸池六合新。", "一别都門變桑海，来瞻原廟祗悲辛。"]'),
('210bb899-fc52-42cd-a3c4-3e38ffdf5b4f','和子開從駕朝謁景靈宫二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','瑶池真氣降東萊，營室新臨渭北開。',64,'全唐诗/poet.song.50000.json','["瑶池真氣降東萊，營室新臨渭北開。", "載見辟王遐邇至，思齊任姒肅雝来。", "龍胡尚泣遺弓劍，燧火俄驚變柳槐。", "誰識九重宵旰意，中天雲漢望昭回。"]'),
('cd1bc1d2-a5c3-4b34-a768-f0943891d7ec','四月三十日慈孝寺山亭席上次韻經父舍人送子敦都運待制赴河北','范祖禹','宋','宋诗','song-poetry','','[]','去年使河東，飲餞天始秋。',96,'全唐诗/poet.song.50000.json','["去年使河東，飲餞天始秋。", "今年使河北，復作蕭寺遊。", "愧我燕居息，送公頻按州。", "雍容鵷鷺列，環珮鳴琅球。", "豈知勤徒御，與國揚王休。", "譬如果適口，安問梨與榴。", "此行功名會，肯使歲月流。", "載酒都門餞，行當迓歸輈。"]'),
('21a77026-03a4-4329-8ee9-cace92304a6e','同子瞻送子敦赴河北都運次韻','范祖禹','宋','宋诗','song-poetry','','[]','顧公涉滄海，宇宙觀奇偉。',120,'全唐诗/poet.song.50000.json','["顧公涉滄海，宇宙觀奇偉。", "十年守沈冥，應笑柱下史。", "動静雖有殊，要之蓋棺已。", "邇來拜東臺，巖穴彈冠喜。", "昂藏出風塵，壯志在千里。", "忽持膚使節，急病仁爲美。", "翰林出新詩，風霆奔落紙。", "朝廷日清明，君子慎所履。", "行當繼禹功，灑災澹洪水。", "過我伊洛間，松風醒俗耳。"]'),
('e438f2e4-c362-475b-bb0d-9d493ba1b2a8','和張給事喜雨','范祖禹','宋','宋诗','song-poetry','','[]','玉座焦勞側席居，侍臣憂國盡應徐。',64,'全唐诗/poet.song.50000.json','["玉座焦勞側席居，侍臣憂國盡應徐。", "宸心有感先離畢，星使分祈未下輿。", "觸石寸雲寰宇徧，稽天巨浸百川趨。", "不才太史那能頌，唯待豐年以喜書。"]'),
('4e8bd4c1-8579-4a36-bd68-7323912ca79c','又和張給事喜雨','范祖禹','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','瞻望昭回毎夜分，崇朝忽起泰山雲。',64,'全唐诗/poet.song.50000.json','["瞻望昭回毎夜分，崇朝忽起泰山雲。", "乾坤蕩暑如醒醉，江海生波想織紋。", "禁漏深迷天闕曉，朝衣凉带御爐熏。", "時清封奏何妨簡，獻納賡歌見愛君。"]'),
('3af653dc-db60-4973-8c16-24d658aad93b','席上分韻送天覺使河東以登山臨水送将歸爲韻分得臨字','范祖禹','宋','宋诗','song-poetry','','[]','唐堯茹藜藿，民俗猶憂深。',108,'全唐诗/poet.song.50000.json','["唐堯茹藜藿，民俗猶憂深。", "晉國壯山川，羌虜皆外禽。", "宸心敬折獄，使節慎所臨。", "夫君臺閣舊，空老翰墨林。", "松柏飽歲寒，鵰鶚候秋陰。", "攬轡上太行，北風爽煩襟。", "當令桑棗地，愁嘆爲謳吟。", "二江带雙流，三峨聳危岑。", "何時早歸耕，杖屨日相尋。"]'),
('2eed74a5-df59-46f6-a235-55b62ca2aa03','謝賜御書詩五言十韻','范祖禹','宋','宋诗','song-poetry','','[]','聖志探淵學，皇慈示至仁。',120,'全唐诗/poet.song.50000.json','["聖志探淵學，皇慈示至仁。", "論經窮古訓，錫燕比嘉賓。", "天醴堯觴舉，簫韶舜樂陳。", "隆恩均近輔，賜札下嚴宸。", "灑墨星辰爛，飛毫日月新。", "聰明欽作后，氣志儼如神。", "龍馬觀犧迹，延陵識聖真。", "受藏輝蔀屋，榮遇極儒紳。", "方講三王治，思還四海淳。", "顧慚愚陋識，何所補涓塵。"]'),
('32dff87f-620c-4247-90e9-2fb1de44c33c','殿試覆考和子由侍郎','范祖禹','宋','宋诗','song-poetry','','[]','十五年前宿殿廬，伊川一紀卧巖居。',64,'全唐诗/poet.song.50000.json','["十五年前宿殿廬，伊川一紀卧巖居。", "雕蟲尚憶長楊賦，汗簡猶殘太史書。", "日月當天瞻法座，煙霞落紙看華裾。", "品題幸預諸公末，更許追隨侍玉除。"]'),
('802bcb40-57e8-47fd-9a87-7ead46220922','和子瞻禁林鎖院詔賜燭酒','范祖禹','宋','宋诗','song-poetry','','[]','晨入金華暮浴堂，聲容不動筆奔忙。',64,'全唐诗/poet.song.50000.json','["晨入金華暮浴堂，聲容不動筆奔忙。", "星間忽降龍銜耀，天上重分玉醴香。", "欲炧寒宵宫漏永，半酣歸夢蜀山長。", "起看絳闕銀河曉，山立千官拱未央。"]'),
('de9a9fc3-83a0-49e4-8a48-a3633890aa00','送周思道再知漢州三首  其一','范祖禹','宋','宋诗','song-poetry','','[]','千山行盡見平川，雞犬相聞俗晏然。',32,'全唐诗/poet.song.50000.json','["千山行盡見平川，雞犬相聞俗晏然。", "父老共知仁聖意，十年重借使君賢。"]'),
('e0981127-8e41-4d55-8475-26bcca47d540','送周思道再知漢州三首  其二','范祖禹','宋','宋诗','song-poetry','','[]','使君昔日撫疲羸，曾奏囊封有直詞。',32,'全唐诗/poet.song.50000.json','["使君昔日撫疲羸，曾奏囊封有直詞。", "一卧家山今白首，重來猶擁舊旌旗。"]'),
('30ba9aab-105c-4ce6-a6e2-b8464b40b043','送周思道再知漢州三首  其三','范祖禹','宋','宋诗','song-poetry','','[]','兩川相望各繁華，二牧蕃宣出一家。',32,'全唐诗/poet.song.50000.json','["兩川相望各繁華，二牧蕃宣出一家。", "衣繡聊爲鄉社寵，行看召節向天涯。"]'),
('d28dd6cf-8152-4a91-a3e2-5f75d34b8151','送周正孺知梓州','范祖禹','宋','宋诗','song-poetry','','[]','先朝直節貫秋霜，殿壁於今有諫囊。',64,'全唐诗/poet.song.50000.json','["先朝直節貫秋霜，殿壁於今有諫囊。", "汲黯猶煩卧居郡，馮唐何事老爲郎。", "山川壯麗開戎幕，草木榮華過故鄉。", "青蓋從来宜白髪，行看高步入明光。"]'),
('1e56a6ba-9fdc-432c-a3b9-4faa1f473ae0','寄題蒲氏清風閣','范祖禹','宋','宋诗','song-poetry','','[]','閬山錦屏秀，閬水碧玉寒。',144,'全唐诗/poet.song.50000.json','["閬山錦屏秀，閬水碧玉寒。", "高閣俯城邑，飛甍出雲端。", "惟昔隠君子，卜築兹考槃。", "圗書侔藏室，一一手自刋。", "山園養松桂，庭砌被芝蘭。", "霧深豹文蔚，風壯鵬翼摶。", "来爲廊廟重，歸爲里閭歡。", "乃知哲人訓，基構自艱難。", "我昔侍先君，借書嘗縱觀。", "題詩尚可記，手澤想未乾。", "爾来三十載，感事一汍瀾。", "側身西南望，安得陵風翰。"]'),
('b9693764-ff0c-4509-80bf-3941723e5d94','又雨中廚屋壞','范祖禹','宋','宋诗','song-poetry','','[]','我從山中來，安宅豈敢卜。',168,'全唐诗/poet.song.50000.json','["我從山中來，安宅豈敢卜。", "窮秋積霖潦，陋巷沒車轂。", "環堵不蔽風，下床毎塗足。", "竈鼃日已長，釜魚時可漉。", "瓦解豈一朝，糞土扶朽木。", "中夜若崩山，微軀憂壓覆。", "晨炊無尺椽，慨嘆食重肉。", "益思反蓬茅，終老依松竹。", "雲居蔭薜蘿，野性狎麋鹿。", "澗溪可濯飲，薇蕨餘肴蔌。", "寧惟此寓館，薄宦同旅宿。", "吾食敢求飽，民生猶歉腹。", "囊空庶無寇，囷竭尚有粟。", "墨突不暇黔，誰能憂破屋。"]'),
('cc99241b-67c6-4d8f-99f3-55de49881f1f','寄題潁昌王氏巽亭二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','危檻跨層城，憑高俗慮醒。',48,'全唐诗/poet.song.50000.json','["危檻跨層城，憑高俗慮醒。", "鵬飛適莽蒼，鴻去上青冥。", "隠地臨箕嶺，賢遊會德星。", "躋攀何日共，遠目寄郊坰。"]'),
('728b3235-a097-48a0-b70b-aa68e0bdb378','寄題潁昌王氏巽亭二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','舊館懐賢躅，先朝翊帝圗。',48,'全唐诗/poet.song.50000.json','["舊館懐賢躅，先朝翊帝圗。", "虹梁引層構，血汗出奇駒。", "几杖延鄉老，詩書問魯儒。", "南天望雲氣，應泣舜蒼梧。"]'),
('5bd96241-fe7e-4091-93d6-376875d888bc','送道純歸南康  其一','范祖禹','宋','宋诗','song-poetry','','[]','平生聞廬嶽，夢想入松門。',180,'全唐诗/poet.song.50000.json','["平生聞廬嶽，夢想入松門。", "京華走塵土，歲月空崩奔。", "緲思放巖壑，枕石清心魂。", "羡君歸舊隠，山水當高軒。", "雲林對寝食，煙靄變朝昏。", "晴空天池溢，瀑布銀河翻。", "奇觀窮宇宙，夢澤可以吞。", "少年負志氣，海運期鵬鯤。", "晚登桂堂籍，燕石笑璵璠。", "飄飄考城吏，放浪彭澤園。", "迴首出都邑，仙禽謝籠樊。", "顧我老文史，望天方戴盆。", "俛仰半世間，同僚念金昆。", "存亡已永隔，風義古所敦。", "寄語謝嵇紹，終慚山巨源。"]'),
('8d46ad74-eeaf-43a5-be0f-6c324abc63e6','送道純歸南康  其二','范祖禹','宋','宋诗','song-poetry','','[]','珍臺閒館切昭回，笙鶴應無俗駕陪。',64,'全唐诗/poet.song.50000.json','["珍臺閒館切昭回，笙鶴應無俗駕陪。", "天浸祥池三島向，春迷神囿百花開。", "沙鷗汎汎人相近，風燕飛飛隼莫猜。", "清洛故園荒徑在，與君何日賦歸来。"]'),
('dd5f4a06-4f65-4a51-9cf0-6fd85e46e68b','同安誕日賦小詩祝延','范祖禹','宋','宋诗','song-poetry','','[]','海上蟠桃方結子，月中仙桂欲生枝。',32,'全唐诗/poet.song.50000.json','["海上蟠桃方結子，月中仙桂欲生枝。", "須知陰德多餘慶，仁者從来與壽宜。"]'),
('d6414f6a-6fa3-4cc4-ad44-bb5bc75fffa7','又','范祖禹','宋','宋诗','song-poetry','','[]','奕世登公衮，羣生入化鈞。',48,'全唐诗/poet.song.50000.json','["奕世登公衮，羣生入化鈞。", "須知盛德後，宜有正家人。", "令日垂門帨，清風采澗蘋。", "兒孫環坐側，歲歲祝千春。"]'),
('8f5ee080-2018-4ee5-917e-9af37e905dc4','送吕通直致仕南遊歸壽州','范祖禹','宋','宋诗','song-poetry','','[]','掞天疇昔阻雄飛，未及耆年早拂衣。',64,'全唐诗/poet.song.50000.json','["掞天疇昔阻雄飛，未及耆年早拂衣。", "白日浮丘仙袂遠，清秋范蠡片帆歸。", "京華歲月雙奔轂，淝上滄浪一釣磯。", "况有孟光爲道侣，散花諸國叩巖扉。"]'),
('b10c38fc-48dc-4b18-beac-e944ca72afb9','答劉中叟','范祖禹','宋','宋诗','song-poetry','','[]','十年卧伊洛，半世老鉛槧。',144,'全唐诗/poet.song.50000.json','["十年卧伊洛，半世老鉛槧。", "君恩還故棲，蠧簡幸窺覘。", "濫陪英雄遊，自覺山野僭。", "有美劉夫子，相逢樂無厭。", "騰騫入霜臺，便若阻城塹。", "朝言渴蹇諤，民瘼待鍼砭。", "清詩叩哀玉，孤秀出羣艶。", "伐木激頺風，佩蘭起幽念。", "顧我久羈寓，来如水鳬泛。", "晨興想三川，夕夢越雙劍。", "終當出都門，瘦馬揺破韂。", "事業付公等，斯言免爲玷。"]'),
('f65e03c9-aea4-43f1-84cd-cbfdfe31a4d6','和劉莘老贈王聖美三子姪補試太學聨中高等','范祖禹','宋','宋诗','song-poetry','','[]','風流江左並淮原，王氏衣冠不乏賢。',64,'全唐诗/poet.song.50000.json','["風流江左並淮原，王氏衣冠不乏賢。", "文似三珠才競爽，名如羣玉氣相連。", "九秋鴻雁方遵陸，萬里驊騮始下鞭。", "白髪星郎推雅量，似聞折屐喜成顛。"]'),
('7f4d9619-11d8-447b-b579-6e9da1faf25f','黄魯直示千葉黄梅余因憶蜀中冬月山行江上聞香而不見花此真梅也魯直然余言曰不得此樂久矣感而賦小詩','范祖禹','宋','宋诗','song-poetry','','[]','江上清香隔水聞，林間不見雪紛紛。',32,'全唐诗/poet.song.50000.json','["江上清香隔水聞，林間不見雪紛紛。", "春寒忽憶登山屐，歸夢猶尋谷口雲。"]'),
('6f7df47c-37bd-4686-913b-e1d2ed6ac134','水紋扇','范祖禹','宋','宋诗','song-poetry','','[]','翦出瀟湘一片秋，動揺君手向空流。',32,'全唐诗/poet.song.50000.json','["翦出瀟湘一片秋，動揺君手向空流。", "微風自有雲濤氣，夢入江天一釣舟。"]'),
('057a762e-8fdf-49de-910c-d55a5827f911','寄蜀州吳廷珍太守','范祖禹','宋','宋诗','song-poetry','','[]','紅旆前驅一舍間，里閭相望俗安閒。',64,'全唐诗/poet.song.50000.json','["紅旆前驅一舍間，里閭相望俗安閒。", "春風城郭千家柳，落日樓臺四面山。", "南畝勸耕丹詔遠，北堂侍膳綵衣斑。", "梁園倦客思歸久，五馬何時命駕還。"]'),
('ee5dab60-1df7-40cb-b874-f165be000265','臘後一日雪晴西郊','范祖禹','宋','宋诗','song-poetry','','[]','臘後寒威壯，春回歲律窮。',48,'全唐诗/poet.song.50000.json','["臘後寒威壯，春回歲律窮。", "薄雲霏小雪，愛日解嚴風。", "銀闕千門迥，瑶林萬里同。", "誰能拂毫素，移入畫屏中。"]'),
('d410f791-44e0-41ad-b019-e4dd4636685a','寄華州提舉崇福李侍郎','范祖禹','宋','宋诗','song-poetry','','["\u534e\u5c71"]','洛社曾陪祭酒閒，承明復接侍臣班。',64,'全唐诗/poet.song.50000.json','["洛社曾陪祭酒閒，承明復接侍臣班。", "論交晚見松筠操，駐景長思冰雪顔。", "華嶽閉門窮簡冊，邵堂隠几看河山。", "相逢一笑知何日，心逐飛雲出故關。"]'),
('c3bb0998-516e-4737-8f0e-db21656f79ef','李方叔饋潭笋','范祖禹','宋','宋诗','song-poetry','','[]','穿雲劚石遠林空，来涉烟波幾萬重。',64,'全唐诗/poet.song.50000.json','["穿雲劚石遠林空，来涉烟波幾萬重。", "實比梧桐堪食鳳，籜翻風雨便成龍。", "一枝未許塵鞍掛，千畝終留渭水封。", "陋巷菜羮知不稱，君王玉食願時供。"]'),
('134421a3-47ac-43a8-b2a4-52fc5c723b57','和李方叔惠嵩山术煎松黄二首 术煎','范祖禹','宋','宋诗','song-poetry','','[]','八公淮水留丹竈，四皓商山餘紫芝。',64,'全唐诗/poet.song.50000.json','["八公淮水留丹竈，四皓商山餘紫芝。", "嵩嶺今成花鍊术，周原空詠堇如飴。", "容顔冰雪端能變，心肺塵埃信可治。", "多病直疑生羽翼，更紆仙客上清詞。"]'),
('7a236939-78a5-43cb-982e-b81d3d46c1d1','和李方叔惠嵩山术煎松黄二首 松黄','范祖禹','宋','宋诗','song-poetry','','[]','直幹千年老雪霜，不隨羣木四時芳。',64,'全唐诗/poet.song.50000.json','["直幹千年老雪霜，不隨羣木四時芳。", "冥冥黛色凝寒碧，冉冉雲英末嫰黄。", "仙桂一枝聊比德，幽蘭九畹幸同香。", "移文應怪歸来晚，安石東山興未忘。"]'),
('e88ad779-2858-4bae-9c7f-1165d94aaabc','石耳','范祖禹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山五老峰，下臨大江水。',120,'全唐诗/poet.song.50000.json','["廬山五老峰，下臨大江水。", "絕壁千餘仞，青冥洞無底。", "烝雲自太古，流雨灑千里。", "白日照層巔，陽崖生石耳。", "採之懸繩梯，磴蘚滑屐齒。", "朱門登華筵，味敵蓴絲美。", "小人勇趨利，所得僅刀匕。", "鴻毛輕軀命，一墜即已矣。", "吾思窒羣欲，豈獨艮其趾。", "高深有前戒，来者慎所履。"]'),
('628f447f-bd69-469c-95e1-628866841aa3','和張芸叟左司被賜資治通鑑','范祖禹','宋','宋诗','song-poetry','','[]','六世承平有史臣，紬書東洛布成均。',64,'全唐诗/poet.song.50000.json','["六世承平有史臣，紬書東洛布成均。", "網羅遺佚三千載，採擷精華十九春。", "天作冠篇墳典大，上思稽古憲章新。", "烏臺御史辭讐校，頭白空餘汗簡人。"]'),
('b161d2a6-903f-4412-88ea-029b88e4b1d5','送鄭閎中待制提舉洞霄宫','范祖禹','宋','宋诗','song-poetry','','[]','成均祭酒出儲胥，嘆息東門祖二疏。',64,'全唐诗/poet.song.50000.json','["成均祭酒出儲胥，嘆息東門祖二疏。", "顧我言非韓吏部，多公節似孔尚書。", "諸生共惜陽城去，三徑重開蒋詡居。", "琳館遥瞻霄漢外，秋風一鶴上空虗。"]'),
('f55b0c5d-2bee-4f86-86cf-75ddb226c8bc','和吕原明上清宫落成','范祖禹','宋','宋诗','song-poetry','','[]','炎曆儲祥億萬年，宫成四海共熙然。',64,'全唐诗/poet.song.50000.json','["炎曆儲祥億萬年，宫成四海共熙然。", "玉虚真境朝羣帝，金闕泠風下列仙。", "初日翠華来照耀，半天碧瓦欲飛騫。", "已瞻聖孝勤三殿，更寫歡聲入五絃。"]'),
('6ea2a6d3-8bc5-4dc5-acc9-4c9de2a790d1','送李邠州','范祖禹','宋','宋诗','song-poetry','','[]','文昌冠劍輟名卿，書殿丹青得老成。',64,'全唐诗/poet.song.50000.json','["文昌冠劍輟名卿，書殿丹青得老成。", "曉日旌旗熊虎動，秋郊組練雪霜明。", "邠郊風教農桑國，秦帝山河屏翰城。", "竹馬兒童應借問，使君攬轡舊澄清。"]'),
('c436b929-0064-4a0b-95b3-9bb5fe10a889','和門下相公從駕視學','范祖禹','宋','宋诗','song-poetry','','[]','堯天雲漢炳文章，親學嚴師款上庠。',64,'全唐诗/poet.song.50000.json','["堯天雲漢炳文章，親學嚴師款上庠。", "萬乘及門先降輦，諸生望日儼成行。", "三雍盛典遵前訓，千古元龜鍳逸王。", "儒服觀光真幸會，爲容深愧魯高堂。"]'),
('61e446af-7870-4680-ba8c-b1230692203f','興龍節傳法院譯經御筵','范祖禹','宋','宋诗','song-poetry','','[]','誕聖千年日，祈祥億刼尊。',48,'全唐诗/poet.song.50000.json','["誕聖千年日，祈祥億刼尊。", "祕言翻貝葉，勝事集祗園。", "寶蓋天香住，銀璫詔語温。", "曾無了義學，空愧酌堯樽。"]'),
('d4ef3db2-5955-42d9-872e-20881912fdb5','送文周翰出守陜郊','范祖禹','宋','宋诗','song-poetry','','[]','維師謝公衮，稷契仰高躅。',240,'全唐诗/poet.song.50000.json','["維師謝公衮，稷契仰高躅。", "公子睠庭闈，西郊作侯牧。", "飄颻丹穴鳳，燦爛文昌宿。", "雅望冠朝端，妙年分陜服。", "綵衣照洛水，紅旆驅崤谷。", "荆山連太華，翠氣堆羣玉。", "長河從天来，迴斡卷坤軸。", "東奔觸砥柱，北向摧平陸。", "壯哉山河固，屏翰神明隩。", "秦人亦勞止，生氣日已蹙。", "兵戈困瘡痍，賦斂苦敲朴。", "使君得召父，庶可飽饘粥。", "耕桑徧南畝，禮義興比屋。", "門前長安道，日夕撃征轂。", "念昔西徂東，經過厭結束。", "爾来卧巖谷，十載歸天禄。", "猶如閉樊籠，恨未隨鴻鵠。", "隠几思故山，側身望喬木。", "何時拂塵衣，假道西走蜀。", "駐馬問甘棠，歌謡聽淳俗。"]'),
('7f75545d-a3fb-4c4f-92e0-e75ece72093b','守歲','范祖禹','宋','宋诗','song-poetry','','[]','歲逐更籌盡，春隨斗柄廻。',48,'全唐诗/poet.song.50000.json','["歲逐更籌盡，春隨斗柄廻。", "和風先傍柳，薄雪暗驚梅。", "坐對燈花結，歡吹酒蟻開。", "莫嗟華髪短，且喜一年来。"]'),
('765b8bdb-af16-4936-b5c7-243ca62f25f0','和吕子進元夕','范祖禹','宋','宋诗','song-poetry','','[]','何處元宵好，天街第一坊。',48,'全唐诗/poet.song.50000.json','["何處元宵好，天街第一坊。", "九重金闕外，萬壽綵山旁。", "扈蹕凝祥島，迎鑾資善堂。", "帝城燈火滿，歸坐若禪房。"]'),
('6579a1f3-8b65-4928-b1b9-9b4f0547eb69','原明官閒以余兼職良苦作詩見勞次韻二首 原明','范祖禹','宋','宋诗','song-poetry','','[]','忘言象外已無求，應物環中自不憂。',32,'全唐诗/poet.song.50000.json','["忘言象外已無求，應物環中自不憂。", "匠石旁觀傷手斲，尚應皮裏有陽秋。"]'),
('b04edcfa-2dd8-46fd-91a2-23835824d15c','原明官閒以余兼職良苦作詩見勞次韻二首 言志','范祖禹','宋','宋诗','song-poetry','','[]','野性從来麋鹿遊，强加冠服秪爲憂。',32,'全唐诗/poet.song.50000.json','["野性從来麋鹿遊，强加冠服秪爲憂。", "何時放出樊籠去，定似飛鴻上九秋。"]'),
('f3bee6a3-5c87-428d-ad28-01bad758a5a1','送秦主簿赴仁和','范祖禹','宋','宋诗','song-poetry','','[]','我思適吳越，懐古意如何。',168,'全唐诗/poet.song.50000.json','["我思適吳越，懐古意如何。", "太伯振高風，仲雍揚清波。", "緒餘有季子，饑食玉山禾。", "山水發奇秀，古来英俊多。", "秦君淮海彦，文鋒雄太阿。", "早依蘓揚州，匠手爲礲磨。", "光芒侵星斗，氣象奔江河。", "青衫拾科第，試邑佐絃歌。", "春水生南國，扁舟浮緑羅。", "方将剖蚌璞，焜燿隨與和。", "我病久廢詩，緬思眄庭柯。", "徬徨戀紫闥，歲月屢蹉跎。", "看君登朝廷，奏頌助猗那。", "爲我謝蘇公，先歸待江沱。"]'),
('8b694541-ea3e-47cb-a7f0-47c95ce496e1','和錢穆父尚書蒋潁叔侍郎從駕景靈宫二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','紫嵩清洛映重闉，舊隠荒蕪白髪新。',64,'全唐诗/poet.song.50000.json','["紫嵩清洛映重闉，舊隠荒蕪白髪新。", "麋鹿未能馴野性，鸞凰何敢望前塵。", "分班拜舞趨文陛，扈蹕賡歌紀慶辰。", "共助成王朝太室，慚非史佚奉明禋。"]'),
('53727cb4-1f2a-486b-963f-c642fbb9d0fd','和錢穆父尚書蒋潁叔侍郎從駕景靈宫二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','寝廟威神挾正元，初晨天仗下端門。',64,'全唐诗/poet.song.50000.json','["寝廟威神挾正元，初晨天仗下端門。", "寒生碧瓦氣葱鬱，日麗琱輿景晏温。", "霜露感時知世遠，星辰拱極見君尊。", "自憐多病思歸客，唯有山川役夢魂。"]'),
('f3200bee-64a0-499f-916d-3d2d5a5add05','子瞻尚書惠涵星硯月石風林屏作歌以送之賦十二韻以謝','范祖禹','宋','宋诗','song-poetry','','[]','端溪千仞涵明星，虢山木古藏陰靈。',180,'全唐诗/poet.song.50000.json','["端溪千仞涵明星，虢山木古藏陰靈。", "蘇公贈我此二寶，使我坐卧瞻雲屏。", "我觀天地間，有物皆流形。", "或從清空入幽谷，中夜隕石翻堦蓂。", "齊諧志怪不能狀，欲說但恐同優伶。", "公遊浙江探禹穴，長嘯宇宙臨滄溟。", "手攀天河弄星月，醉落大筆還微醒。", "故分星月入我室，光照窗户風生庭。", "長林偃絕壁，晚色寒青冥。", "似聞洪濤卷萬木，直榦不折當風霆。", "玄雲欲落雪，夜久孤燈熒。", "報贈愧無青玉案，苦吟徒使鬼神聽。"]'),
('369cec55-436b-4b35-9196-7992435209de','送蒋潁叔赴熙州','范祖禹','宋','宋诗','song-poetry','','[]','詩書謀帥得豪英，去擁洮河十萬兵。',64,'全唐诗/poet.song.50000.json','["詩書謀帥得豪英，去擁洮河十萬兵。", "舒卷風雲爲號令，笑談樽爼是功名。", "胡塵不近彈筝峽，漢月長懸細柳營。", "莫謂安邉無上策，農桑千里見昇平。"]'),
('d8b64e4e-7889-4cad-acb3-95dcef0e415c','和王都尉押高麗人燕射北園','范祖禹','宋','宋诗','song-poetry','','[]','天上星弧日射狼，副車衣袂得餘香。',64,'全唐诗/poet.song.50000.json','["天上星弧日射狼，副車衣袂得餘香。", "朔雲曾落雙鵰羽，遼海将歸萬里航。", "酒灔堯觴賓已醉，春廻漢苑漏初長。", "何郎拜舞恩波渥，花簇金鞍道路光。"]'),
('d6e6a009-07ea-4922-906f-dad069cdffe2','謝子瞻尚書惠墨端溪硯二首 墨','范祖禹','宋','宋诗','song-poetry','','[]','禹平洪流錫玄圭，班于羣神朝會稽。',192,'全唐诗/poet.song.50000.json','["禹平洪流錫玄圭，班于羣神朝會稽。", "遼東飛煙過滄海，徂徠古氣臨天齊。", "丹砂化出黄金鼎，雄麝焚身何噬臍。", "魚膠清堅豈易致，燕支山北隨佩觿。", "雙龍蛇蟠戲缺月，吳軍破甲光水犀。", "黑雲如輪起端溪，揮灑倐忽奔鯨鯢。", "先生海內文章伯，窮年蒿目憂黔黎。", "玉堂新製自心巧，想見星象躔寶奎。", "落毫無脛走珠玉，雨雹霽止垂虹蜺。", "陋儒窮經脣欲腐，石室汗簡空沈迷。", "眼昏畫紙僅成字，何異月闇投玻瓈。", "唯當藏作篋中寶，併荷蓑笠歸鋤犂。"]'),
('99d23fed-0443-414c-8fee-45cade2d8002','謝子瞻尚書惠墨端溪硯二首 端溪硯','范祖禹','宋','宋诗','song-poetry','','[]','端溪清冥幾千尺，玄潭噴雲嘘紫石。',192,'全唐诗/poet.song.50000.json','["端溪清冥幾千尺，玄潭噴雲嘘紫石。", "層空飛溜瀉珠璣，大古陰崖摧霹靂。", "翦裁巖屏作風字，琢磨水鏡成月魄。", "似聞松上颼颼聲，一洗塵埃傾七澤。", "先生毎思窮禹穴，東叱天吳掛帆席。", "山祗水若獻幽寶，贈我不啻千金璧。", "玉堂金井汲寒泉，坐視青天浸虚碧。", "豈知来從海嶠外，鳥道穿雲下絕壁。", "嗟我本是山中人，慚無詞藻對卿客。", "鄉人子雲思奇苦，終老漢庭長執戟。", "至今舊宅有墨池，何怪著書玄尚白。", "行當提攜返敝廬，更廣牢愁弔遺迹。"]'),
('4aef5dba-183c-4031-b8a6-7103ec082822','初到玉堂','范祖禹','宋','宋诗','song-poetry','','[]','舊廬風雨暗柴荆，丘壑元無紱冕情。',64,'全唐诗/poet.song.50000.json','["舊廬風雨暗柴荆，丘壑元無紱冕情。", "一紀周南陪太史，八年書殿厠桓榮。", "陳編豈待傷麟止，藻思那能倚馬成。", "空愧朱衣華髪吏，玉堂三世見題名。"]'),
('c14aec74-b17b-40dc-9984-0d07fa644ed0','翰林寓直','范祖禹','宋','宋诗','song-poetry','','[]','雨冷絺衣初覺單，清秋寓直玉堂寒。',64,'全唐诗/poet.song.50000.json','["雨冷絺衣初覺單，清秋寓直玉堂寒。", "濛濛宿霧昏鳷鵲，獵獵光風轉蕙蘭。", "蘚積書筠塵不落，雲生硯水墨無乾。", "十年曾向伊川卧，長憶閒中夢寐安。"]'),
('995a4cd7-c394-4b24-b6fc-c30ce1a94521','夜直聞御溝聲','范祖禹','宋','宋诗','song-poetry','','[]','銀河秋瀉月明中，雲卷風吹下碧空。',32,'全唐诗/poet.song.50000.json','["銀河秋瀉月明中，雲卷風吹下碧空。", "終夕玉堂魂夢冷，蜀江聲繞水晶宫。"]'),
('0cb9214c-9d8f-41b5-b17f-3c31b912562d','送陳元輿侍御赴廬江','范祖禹','宋','宋诗','song-poetry','','[]','憶昔仁皇憑玉几，延和春晝神龍起。',160,'全唐诗/poet.song.50000.json','["憶昔仁皇憑玉几，延和春晝神龍起。", "赭袍黄傘放諸生，却下紅簾半天裏。", "君爲第二驚衆人，愧我非才居後塵。", "題名桂籍皆年少，有似鶴鴻毛羽新。", "爾来四朝三十載，相逢何怪容顔改。", "昭陵拱木鬱參天，麟閣名臣幾人在。", "侍從同登白玉除，毎思夙昔夢華胥。", "君今出作八州牧，千里旌旗引舳艫。", "淮陽卧治豈當久，宣室夜召終非踈。", "下車先表崔節婦，助我汗簡成新書。"]'),
('8ac09bd9-a743-4c40-9680-a1e4e20cafa8','八月十一日夜玉堂對月','范祖禹','宋','宋诗','song-poetry','','[]','銀雲櫛櫛王堂明，奩鏡初開六合驚。',64,'全唐诗/poet.song.50000.json','["銀雲櫛櫛王堂明，奩鏡初開六合驚。", "天卷纎毫光不隔，風收萬籟夜無聲。", "蓬萊想像皆雲氣，宫殿虚無盡水精。", "一夕夢飛雙劍外，已疑身到雪山清。"]'),
('2f04cbf7-3a79-4260-936b-f2ead9249306','送七主簿赴龍水','范祖禹','宋','宋诗','song-poetry','','[]','山行水逶迤，鬱屈如盤龍。',144,'全唐诗/poet.song.50000.json','["山行水逶迤，鬱屈如盤龍。", "緣谿夾修竹，被嶺多長松。", "懸門倚巖石，終日對青峰。", "初仕昔爲宰，讀書過三冬。", "忘機狎鷗鳥，勸稼親老農。", "訟庭可羅雀，銅印蒼蘚封。", "爾来三十年，夢想幽人蹤。", "風塵京洛間，邑子或相逢。", "晚歲上玉堂，天門深九重。", "緬思寒潭碧，一洗我心胸。", "送子西南歸，恨無羽翼從。", "爲我謝邦人，今愧白髪容。"]'),
('3f18feb2-655d-4c78-80a8-1889c002722b','和子瞻尚書儀曹北軒種栝','范祖禹','宋','宋诗','song-poetry','','[]','蘇公滄洲趣，日夕懐山陰。',192,'全唐诗/poet.song.50000.json','["蘇公滄洲趣，日夕懐山陰。", "公堂植珍木，寄夢天姥岑。", "亭亭碧玉榦，氣象俯喬林。", "雷霆已難拔，霜雪何敢侵。", "蒼皮卷鱗甲，細葉抽鋒鍼。", "稍出珊瑚枝，中含笙磬音。", "鸞鳯待棲息，詎肯容凡禽。", "西風蕩積雨，畏日方流金。", "潭潭宗伯府，窈窕巖谷深。", "北窗卧羲皇，笑語合朋簮。", "蒼生望安石，出處本無心。", "萬象入毫端，四溟納胸襟。", "文房爼豆列，武庫矛戟森。", "甘棠愛召伯，勿使螻蟻尋。", "世俗多貴遠，豈知古猶今。", "他年老東山，應記梁父吟。"]'),
('4b9e713c-d5f7-4587-96be-8781643832dd','吏部彭侍郎召會馮少師園亭即席賦詩','范祖禹','宋','宋诗','song-poetry','','[]','門生猶記鑿龍登，載酒東堂命友朋。',32,'全唐诗/poet.song.50000.json','["門生猶記鑿龍登，載酒東堂命友朋。", "終日清談陪几杖，赤松况是坐禪僧。"]'),
('cecd44fa-9533-47a1-ab1d-58d58f266ffd','多病','范祖禹','宋','宋诗','song-poetry','','[]','多病心牢落，驚秋髩颯然。',48,'全唐诗/poet.song.50000.json','["多病心牢落，驚秋髩颯然。", "風乾桐葉地，雨冷菊花天。", "舊隠荒江漢，新居俯澗瀍。", "西都長夢想，何日賦歸田。"]'),
('d59b5a4e-6ed5-42be-ae79-1b75263120b8','九日寄諸弟','范祖禹','宋','宋诗','song-poetry','','[]','白髪宜新酒，黄花似去年。',48,'全唐诗/poet.song.50000.json','["白髪宜新酒，黄花似去年。", "懐歸雙劍路，極望九秋天。", "喬木西山外，觚稜北斗邉。", "遥知行樂處，藥市隠真仙。"]'),
('98157f89-1aca-4b45-8064-6171aa23eb0d','挽歌詞','范祖禹','宋','宋诗','song-poetry','','[]','綵旆藍輿訪隠扃，雲松雪竹想儀形。',64,'全唐诗/poet.song.50000.json','["綵旆藍輿訪隠扃，雲松雪竹想儀形。", "函關應望真人氣，傅野今無處士星。", "猶憶九臯聞鶴唳，徒勞雙目送鴻冥。", "将迴俗駕頻搔首，深愧山文舊勒銘。"]'),
('2432e3ba-abe0-4758-aae7-ef9cce78a126','永州作','范祖禹','宋','宋诗','song-poetry','','[]','京華驛候遠，楚越山川分。',72,'全唐诗/poet.song.50000.json','["京華驛候遠，楚越山川分。", "心馳桂江水，夢繞蒼梧雲。", "夕與木石居，朝遊麋鹿羣。", "聖治踰繩契，皇明軼華勲。", "炎陬暨海表，休氣塞無垠。", "羈臣此幽縶，何以答恩勤。"]'),
('6f92cc39-c586-4e4e-96db-cc5a78a68904','御製太皇太后挽詞四首  其一','范祖禹','宋','宋诗','song-poetry','','[]','任姒基王迹，塗莘首化風。',48,'全唐诗/poet.song.50000.json','["任姒基王迹，塗莘首化風。", "德超千古上，治定九年中。", "日月無私照，乾坤不宰功。", "寧神登太室，永佑宋無窮。"]'),
('6b4be46d-5299-4d64-a69f-93bf33aa4070','御製太皇太后挽詞四首  其二','范祖禹','宋','宋诗','song-poetry','','[]','定策元豐末，勞謙聖烈光。',48,'全唐诗/poet.song.50000.json','["定策元豐末，勞謙聖烈光。", "外家深自抑，俊德盡明揚。", "恭儉隆三世，寛仁覆萬方。", "功成身不處，仙駕白雲鄉。"]'),
('221a2ef3-9827-4927-8b42-7f5dcf8e5508','御製太皇太后挽詞四首  其三','范祖禹','宋','宋诗','song-poetry','','[]','天祐周邦世世仁，篤生文母濟斯民。',64,'全唐诗/poet.song.50000.json','["天祐周邦世世仁，篤生文母濟斯民。", "嗣徽慈后光宗祖，配極英皇育聖神。", "崇慶垂衣寧寶座，延和負扆翊沖人。", "長言永慕遵遺訓，要在齊家與正身。"]'),
('beadbb14-c19e-4c8d-8097-b276ed4db9cc','御製太皇太后挽詞四首  其四','范祖禹','宋','宋诗','song-poetry','','[]','八荒同軌壽原成，雨露俄悲歲律更。',64,'全唐诗/poet.song.50000.json','["八荒同軌壽原成，雨露俄悲歲律更。", "曉日曈曨開鳳翣，春風縹緲轉龍旌。", "晨朝尚想趨金殿，颷馭難留返玉京。", "寶冊形容雖四字，誰知盛德莫能名。"]'),
('2b7fcdd6-afd5-41d6-b6f4-4874ea91e944','太皇太后挽詞二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','誕保天基命，光開帝永圗。',48,'全唐诗/poet.song.50000.json','["誕保天基命，光開帝永圗。", "軒星臨斗極，堯日上雲衢。", "美化形風雅，成功入典謨。", "羣生何以報，損壽濟寰區。"]'),
('0cc25899-d656-4b86-9028-ccdf32128d8a','太皇太后挽詞二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','授几咨元老，垂帷攬衆賢。',48,'全唐诗/poet.song.50000.json','["授几咨元老，垂帷攬衆賢。", "舜功成二十，周士得三千。", "德澤流終古，規摹遺億年。", "寧唯照彤史，石室爛青編。"]'),
('35f0f069-772a-403e-bd51-529756999f53','又三首  其一','范祖禹','宋','宋诗','song-poetry','','[]','九載扶皇業，三朝賴母儀。',48,'全唐诗/poet.song.50000.json','["九載扶皇業，三朝賴母儀。", "成乾功不有，並日照無私。", "天上軒星暗，人間薤露悲。", "君王自仁孝，舊典奉元龜。"]'),
('18bb3624-524f-4539-9968-eefaa67c08be','又三首  其二','范祖禹','宋','宋诗','song-poetry','','[]','治道初無事，齊家與正身。',48,'全唐诗/poet.song.50000.json','["治道初無事，齊家與正身。", "練繒躬至儉，行葦被深仁。", "受册辭隆禮，爲霖屬老臣。", "太平遺德在，白首泣堯民。"]'),
('97428621-d9b1-4791-8537-692475c3c7e3','又三首  其三','范祖禹','宋','宋诗','song-poetry','','[]','能助君成聖，惟知諫必從。',48,'全唐诗/poet.song.50000.json','["能助君成聖，惟知諫必從。", "徽音推二后，盛治見三宗。", "虚扆翔丹鳳，仙輴駕玉龍。", "凄凉厚陵路，墓木拱高峰。"]'),
('46da5ceb-1818-4d63-956d-6311435dfb04','王岐公挽詞三首  其一','范祖禹','宋','宋诗','song-poetry','','[]','景運光華際，洪鈞十六年。',48,'全唐诗/poet.song.50000.json','["景運光華際，洪鈞十六年。", "文明憲前古，禮樂被敷天。", "有美經邦業，無成載物權。", "君臣時契會，俯仰逐流川。"]'),
('3ed7e7b6-2cae-4349-93bc-9c84050ce0d5','王岐公挽詞三首  其二','范祖禹','宋','宋诗','song-poetry','','[]','乘雲仙馭遠，出震帝圗新。',48,'全唐诗/poet.song.50000.json','["乘雲仙馭遠，出震帝圗新。", "百辟瞻元宰，繁機仗老臣。", "中天扶日月，拱極失星辰。", "終始先朝遇，勤勞至沒身。"]'),
('39f717c4-3ac6-4630-98ed-88c9972137a0','王岐公挽詞三首  其三','范祖禹','宋','宋诗','song-poetry','','[]','王儉風流相，岐公博贍資。',48,'全唐诗/poet.song.50000.json','["王儉風流相，岐公博贍資。", "敷文成國典，亮采作官師。", "劍佩空黄閤，音容想赤墀。", "元臣葬禮盛，簫吹朔風悲。"]'),
('2ecb6aa9-0635-4ac8-b6e8-9872528bb86c','王開府挽詞三首  其一','范祖禹','宋','宋诗','song-poetry','','[]','聖曆當千運，天庭第一人。',48,'全唐诗/poet.song.50000.json','["聖曆當千運，天庭第一人。", "榮光親日月，優寵極臣鄰。", "賈馬推先進，夔龍接後塵。", "藩垣賴耆德，宣力至終身。"]'),
('63aa3f10-ce48-44e4-b57a-243e9e0569b9','王開府挽詞三首  其二','范祖禹','宋','宋诗','song-poetry','','[]','康寧五福備，出入四朝安。',48,'全唐诗/poet.song.50000.json','["康寧五福備，出入四朝安。", "劍佩逼台室，旌旄登将壇。", "天池将浴鳳，雲漢擬驂鸞。", "縹緲凌霞意，今成逝水嘆。"]'),
('c05878e5-ca01-4c30-8bf4-c6037ae86afd','王開府挽詞三首  其三','范祖禹','宋','宋诗','song-poetry','','[]','連帥諸侯長，維師列爵隆。',48,'全唐诗/poet.song.50000.json','["連帥諸侯長，維師列爵隆。", "儀刑憲萬國，眷禮視三公。", "白日年華盡，浮雲世事空。", "九原伊洛上，松柏自悲風。"]'),
('54ab1fc5-b984-4b43-b3ed-50d460471204','司馬温公挽詞五首  其一','范祖禹','宋','宋诗','song-poetry','','[]','伊吕爲時耦，夷齊得聖清。',48,'全唐诗/poet.song.50000.json','["伊吕爲時耦，夷齊得聖清。", "精忠貫日月，至行格神明。", "微物霑仁澤，窮荒服德名。", "須知千載後，瞻仰重嵩衡。"]'),
('c826a8cb-cbdd-49ac-a687-2adb098e1d26','司馬温公挽詞五首  其二','范祖禹','宋','宋诗','song-poetry','','[]','文母扶皇運，成王紹慶基。',48,'全唐诗/poet.song.50000.json','["文母扶皇運，成王紹慶基。", "蕭公翼左右，裴相繫安危。", "共恨登庸晚，俄成殄瘁悲。", "旂常紀勲業，長與日星垂。"]'),
('b533fdb0-9a26-46bc-b6a9-89546ecc5323','司馬温公挽詞五首  其三','范祖禹','宋','宋诗','song-poetry','','[]','上相經綸日，羣生化育中。',48,'全唐诗/poet.song.50000.json','["上相經綸日，羣生化育中。", "初開仁壽域，重立太平功。", "海宇還淳俗，朝廷復古風。", "英靈在王室，應佑宋無窮。"]'),
('86e725a5-bacf-4a1a-8acc-6afa5b16eec3','司馬温公挽詞五首  其四','范祖禹','宋','宋诗','song-poetry','','[]','盡瘁憂民瘼，孤忠簡聖心。',48,'全唐诗/poet.song.50000.json','["盡瘁憂民瘼，孤忠簡聖心。", "忘身甘首疾，報國競分陰。", "天奪楊公速，人思召伯深。", "秋風咽笳鼓，行路泣成霖。"]'),
('91e35185-fd26-490a-a2c8-e1f7d2573687','司馬温公挽詞五首  其五','范祖禹','宋','宋诗','song-poetry','','[]','自昔龍門峻，叨蒙國士知。',48,'全唐诗/poet.song.50000.json','["自昔龍門峻，叨蒙國士知。", "紬書陪太史，問學仰宗師。", "一紀依林壑，千秋隔履綦。", "餘生愧簮紱，無路送靈輀。"]'),
('62b09249-d7f2-4253-80e7-28ebedeb6357','韓獻肅公挽詞三首  其一','范祖禹','宋','宋诗','song-poetry','','[]','孝友天生德，公忠世象賢。',48,'全唐诗/poet.song.50000.json','["孝友天生德，公忠世象賢。", "八元推亮采，四海入陶甄。", "枌社棠陰老，槐庭棣萼聨。", "諮詢賴黄髪，零落已重泉。"]'),
('6da4a20a-655c-4fb0-b787-b005b36e546a','韓獻肅公挽詞三首  其二','范祖禹','宋','宋诗','song-poetry','','[]','舜禹勤勞治，臯夔翊贊功。',48,'全唐诗/poet.song.50000.json','["舜禹勤勞治，臯夔翊贊功。", "秉鈞瞻上宰，憲老佚三公。", "壽考登耆耋，哀榮備始終。", "凄凉潁川路，簫鼓愬南風。"]'),
('4bd61588-73c7-43e5-88fb-4b16b01a72bd','韓獻肅公挽詞三首  其三','范祖禹','宋','宋诗','song-poetry','','[]','東閣開無倦，西園宴不疲。',48,'全唐诗/poet.song.50000.json','["東閣開無倦，西園宴不疲。", "蒼生望安石，多士美當時。", "功業歸青史，音容閟繐帷。", "烏衣門巷在，過客有餘悲。"]'),
('bf7d7763-cb7d-4130-ab84-0754035b0614','李朝議挽詞二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','美行商山老，高年渭水翁。',48,'全唐诗/poet.song.50000.json','["美行商山老，高年渭水翁。", "政留循吏跡，家有古人風。", "操几門庭在，安車里巷空。", "子孫皆孝養，餘慶自無窮。"]'),
('257cb19b-441d-44b4-9899-266081ef41de','李朝議挽詞二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','解組紅塵外，忘機白日遲。',48,'全唐诗/poet.song.50000.json','["解組紅塵外，忘機白日遲。", "煙霞隨步武，松竹想風姿。", "沇水流清範，盤山厚福基。", "鄉人應配社，猶恨不期頤。"]'),
('c4a90e44-11c7-4f92-bc08-bd7144024ce1','鮮于諌議挽詞二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','西蜀文章老，中朝侍從臣。',48,'全唐诗/poet.song.50000.json','["西蜀文章老，中朝侍從臣。", "諫垣風烈在，書殿寵光新。", "宣室虚前席，清漳嘆病身。", "致君才未展，青史迹空陳。"]'),
('ca718811-8b90-4534-a322-86ea41e45050','鮮于諌議挽詞二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','白首方登用，忠規溢皂囊。',48,'全唐诗/poet.song.50000.json','["白首方登用，忠規溢皂囊。", "仲山違衮職，汲黯卧淮陽。", "墓劍知誰掛，人琴竟兩亡。", "猶思挺直操，松柏凛秋霜。"]'),
('0c3d150b-e8ac-4c49-859c-ea3fbeb7ccd6','哭司馬公休','范祖禹','宋','宋诗','song-poetry','','[]','昔在西都日，趨庭見伯魚。',48,'全唐诗/poet.song.50000.json','["昔在西都日，趨庭見伯魚。", "金華同勸講，石室共紬書。", "鮑叔深知我，顔淵實喪予。", "衰年哭心友，忍復望靈車。"]'),
('7a83fa64-f5ea-40f5-91ce-94d1eccf6f0e','中書侍郎傅公挽詞  其一','范祖禹','宋','宋诗','song-poetry','','[]','巖野爲霖後，千年復有人。',48,'全唐诗/poet.song.50000.json','["巖野爲霖後，千年復有人。", "累朝推鯁直，二聖倚經綸。", "盡瘁憂民色，孤忠許國身。", "徐公德不變，可使俗還淳。"]'),
('e2a38b6e-925e-4118-918d-dc29657b05e4','中書侍郎傅公挽詞  其二','范祖禹','宋','宋诗','song-poetry','','[]','洛社瞻賢躅，書筵繼老成。',48,'全唐诗/poet.song.50000.json','["洛社瞻賢躅，書筵繼老成。", "聲容陪夙昔，論議想平生。", "節與盤山峻，名隨沇水清。", "草堂空舊隠，松月爲誰明。"]'),
('c045a5a5-e9ec-49a5-919c-537f12f983ed','常大夫挽詞','范祖禹','宋','宋诗','song-poetry','','[]','禮樂追先哲，文名動搢紳。',48,'全唐诗/poet.song.50000.json','["禮樂追先哲，文名動搢紳。", "忠勤白首節，惠愛遠州民。", "石室詩書在，天衢日月深。", "九原何所憾，有子嗣芳塵。"]'),
('59b07bc1-aaa8-4051-a511-e309e4f48cf8','王承事挽詞','范祖禹','宋','宋诗','song-poetry','','[]','井絡西南奥，今無處士星。',48,'全唐诗/poet.song.50000.json','["井絡西南奥，今無處士星。", "天真養恬漠，世累絕塵冥。", "松菊陶公徑，詩書孔氏庭。", "傳家清訓在，潛德繼先銘。"]'),
('c7326f1e-67b3-4a54-86fb-cb9abe78bce8','坤成節教坊致語口號','范祖禹','宋','宋诗','song-poetry','','[]','綵仗含風縹緲間，神孫當寧燕千官。',65,'全唐诗/poet.song.50000.json','["綵仗含風縹緲間，神孫當寧燕千官。", "太陰入夢祥初發，中嶽聞呼老更難。", "諸夏豐年聯係詔令，兩儀和氣入吹彈。", "下臣拜獻坤成樂，長奉千秋萬歲歡。"]'),
('8fa033be-e9ff-4203-9409-9f6d7a562cf9','句  其一','范祖禹','宋','宋诗','song-poetry','','[]','蘚色通行徑，松陰叩隱關。',12,'全唐诗/poet.song.50000.json','["蘚色通行徑，松陰叩隱關。"]'),
('bc011fc3-c688-448c-b873-122104d99e81','句  其二','范祖禹','宋','宋诗','song-poetry','','[]','上秩乾門下奠坤，玄都境界妙難論。',16,'全唐诗/poet.song.50000.json','["上秩乾門下奠坤，玄都境界妙難論。"]'),
('59c11bda-98cc-4090-87e5-d38f18be7fe8','句  其三','范祖禹','宋','宋诗','song-poetry','','[]','會老名堂清穎上，禮賢開館大河濱。',16,'全唐诗/poet.song.50000.json','["會老名堂清穎上，禮賢開館大河濱。"]'),
('d1622e45-ddae-4e09-97df-d8d969b801c6','和馬粹老脩廣德湖','舒亶','宋','宋诗','song-poetry','','[]','古作重慮始，功利故能永。',180,'全唐诗/poet.song.50000.json','["古作重慮始，功利故能永。", "末俗分錐刀，往往附光影。", "此幾百歲餘，興廢屢動靜。", "七鄉十萬家，利害寄俄頃。", "譸張好惡曹，聒亂劇池黽。", "使君武陵孫，明潔水中荇。", "坐嘯黄堂春，獨得意外景。", "登臨莽蕪没，歎息民不幸。", "一日山水光，蕩漾出荒梗。", "黍禾雜菰魚，狼籍被他境。", "人指白鶴祠，慇懃竊有請。", "衣冠儼郡公，一一畫真鯁。", "斯人豈可作，庶用薦遺秉。", "公乎且勿去，何以慰鄉井。", "願屬丹青手，千載共觀省。"]'),
('6dd3723b-ce23-46a2-9afe-74cf8bafd032','題它山善政侯兼簡鄞令','舒亶','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嗚呼王封君，心事鬼出沒。',168,'全唐诗/poet.song.50000.json','["嗚呼王封君，心事鬼出沒。", "驅山截長江，化作雲水窟。", "旱火六月天，萬棟掛龍骨。", "蕭條一祠宇，像設何髣髴。", "破屋夜見星，漏雨濕衫笏。", "杯酒謝車篝，兹事恐亦忽。", "我聞古先王，報施必稱物。", "矧今崇佛宮，民力殆欲屈。", "豈無制作手，一爲起荒茀。", "李侯仁賢資，撫字良矻矻。", "可但清似冰，方看健如鶻。", "沉跡千載後，行且見披拂。", "陰功世易忘，遠慮俗多咈。", "勉哉君毋遲，斯民久已欝。"]'),
('047594d4-7307-4058-b01f-c52e81347932','題放生池','舒亶','宋','宋诗','song-poetry','','[]','南州幾萬家，舟楫江湖上。',72,'全唐诗/poet.song.50000.json','["南州幾萬家，舟楫江湖上。", "罾羅竭魚鼈，旁饜口腹養。", "可憐長者子，於此事脫放。", "藻荇被清流，春風不驚浪。", "直鈎亦何心，明珠豈所望。", "落日倚朱欄，無言獨惆悵。"]'),
('a5b63cbf-f209-4733-ac00-1b0069e428e8','題水月橋','舒亶','宋','宋诗','song-poetry','','[]','長空瑩如磨，平湖淨無滓。',60,'全唐诗/poet.song.50000.json','["長空瑩如磨，平湖淨無滓。", "萬里夜寥寥，清光墮寒水。", "松風吹更圓，沙鳥睡不起。", "徒勞野猿捕，漫作玄珠比。", "相對倚朱欄，時有逍遥子。"]'),
('22f31eaf-9a6e-4633-9b1f-537531f3e670','遊翠岩六首  其一','舒亶','宋','宋诗','song-poetry','','[]','繆悠此投閒，邂逅如得請。',60,'全唐诗/poet.song.50000.json','["繆悠此投閒，邂逅如得請。", "終日對林僧，是樂非世境。", "千秋紙上塵，萬事空中影。", "既往悔可追，無能味何永。", "仍幸甘露音，時時灌吾頂。"]'),
('d17b1e8b-5fb7-4981-91c7-f12cdb091c3e','遊翠岩六首  其二','舒亶','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','翠岩老禪和，欲退未容請。',60,'全唐诗/poet.song.50000.json','["翠岩老禪和，欲退未容請。", "聊許隱堂人，先占廣軒境。", "高松有寒青，孤雲無定影。", "草煖幽澗香，鳥啼清晝永。", "一笑碧雲旁，未羡匡廬頂。"]'),
('15a5c274-3ba9-4359-bb81-1ea7ad146766','遊翠岩六首  其三','舒亶','宋','宋诗','song-poetry','','[]','聊謝都城遊，來赴道人請。',60,'全唐诗/poet.song.50000.json','["聊謝都城遊，來赴道人請。", "冥懐麋鹿羣，回首冠蓋境。", "潨瀉泉石聲，蕭森松檜影。", "風帽何妨頽，藜徑敢辤永。", "還聞鐘磬音，爲我下雲頂。"]'),
('60beefc0-ff49-4788-a4d8-1496119bc3df','遊翠岩六首  其四','舒亶','宋','宋诗','song-poetry','','[]','先生盍言歸，小子願有請。',60,'全唐诗/poet.song.50000.json','["先生盍言歸，小子願有請。", "由來陶淵明，結廬在人境。", "閒抱無絃琴，靜弄南窗影。", "勝事幾人知，高風千載永。", "何當理籃輿，步月下孤頂。"]'),
('c40e135c-2653-4ccc-a4b9-29ea42d774d8','遊翠岩六首  其五','舒亶','宋','宋诗','song-poetry','','[]','願聞海潮音，幾煩檀越請。',60,'全唐诗/poet.song.50000.json','["願聞海潮音，幾煩檀越請。", "有物還有機，無心即無境。", "何當雪衲身，重現水月影。", "高卧與世疏，孤坐共夜永。", "時時挂西窗，溪光照霜頂。"]'),
('e24c2b86-2290-4a66-8723-bf72f799032c','遊翠岩六首  其六','舒亶','宋','宋诗','song-poetry','','[]','欣聞厭冥煩，頗亦謝造請。',60,'全唐诗/poet.song.50000.json','["欣聞厭冥煩，頗亦謝造請。", "孤鶱出塵埃，勝踐得真境。", "萬籟發靜音，千巖度空影。", "無味道終憐，有役慮真永。", "會當立茆茨，望子蒼岑頂。"]'),
('0ee33ea5-1973-4a7f-a8bd-014249e3ae19','再遊天童山回吳與權諸友夜集','舒亶','宋','宋诗','song-poetry','','[]','太白嶄岩幾百尺，仙人一去無消息。',128,'全唐诗/poet.song.50000.json','["太白嶄岩幾百尺，仙人一去無消息。", "臨雲時復倚欄干，獨看千峰萬峰碧。", "昨夜長鬚城裏回，報道湖上秋風來。", "醉園雨過月臺冷，籬根白菊看看開。", "却杖青藜趁流水，目送征鴻下山觜。", "蓬船荅浪遶叢蘆，咫尺烟汀幾萬里。", "忽見江頭江月白，紛紛笑語城東陌。", "一尊此酒一枰棋，未到懶堂猶是客。"]'),
('d33667a6-5378-4023-8faa-8e5a34c8ada4','遊承天望廣德湖','舒亶','宋','宋诗','song-poetry','','[]','桃源二月春風起，是處穠華有桃李。',64,'全唐诗/poet.song.50000.json','["桃源二月春風起，是處穠華有桃李。", "調笑聞聲不見人，遊人只在華山裏。", "華山逋客來何遲，隱隱茶林隔煙水。", "滿眼相思寄碧雲，獨立城南望山觜。"]'),
('635a5126-0a1a-4762-9e8e-cfaaf6fb1ef0','送韋太守','舒亶','宋','宋诗','song-poetry','','[]','四明山水東南表，海鼇背上三仙島。',128,'全唐诗/poet.song.50000.json','["四明山水東南表，海鼇背上三仙島。", "麗譙高逼斗牛寒，一曲梅花萬家曉。", "太守文章建安骨，爽氣冷侵寒月窟。", "黄堂水洗火符空，明光却擁荷囊笏。", "有客醉園雙鬢老，宦情文思如秋草。", "紫雲夢斷玉龍飛，年年送客西城道。", "曾是野亭同問柳，綺裘紗帽金船酒。", "長安宫闕九天邊，肯爲江蘺回首否。"]'),
('a6b8769e-2eb8-435d-8910-cd1b6e0b7904','粹老使君前被召約往它山謁善政侯祠既不果以書見抵謂可歎惜并示廣德湖新記因成長句奉寄','舒亶','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u897f\u6e56"]','長江衮衮西南流，秋水時至狂不收。',384,'全唐诗/poet.song.50000.json','["長江衮衮西南流，秋水時至狂不收。", "大浪似屋山欲浮，王侯神智禹所啾。", "萬鬼琢玉它山幽，梅梁贔屭卧龍虯。", "咄嗟湍駭就斂揫，巨靈縮手愚公羞。", "障成十里沙中洲，支分股引聽所求。", "赤旱稽浸民不憂，那得蟲蝗隨督郵。", "汙邪甌窶滿車篝，斯民飽煖何以酬。", "廟貌突兀寒溪頭，歲歲雞黍祠春秋。", "老農擊鼓稚子謳，當時人物紛雁鷗。", "豈無鼎食腰金儔，朽骨往往空蒿丘。", "姓名幾復人間留，唯侯施惠膏如油。", "江聲浩浩風飂飂，千古不見使人愁。", "拔俗萬丈山標崷，使君不減裴商州。", "下車百蠧隨鋤耰，一笑四境無瘡疣。", "天閑老步須驊騮，已聞歸作金華遊。", "欽賢訪古意未休，畫船載酒岸鳴騶。", "約我與往置脯饈，冠盖紛紛暇莫偷。", "搔首悵望情綢繆，我問使君亦何尤。", "西湖萬頃蛟龍湫，幾年荒茀今則脩。", "鼛鼓弗勝財不掊，長堤岌嶫高岑樓。", "寫有澮兮蕩有溝，餘波北注引漕舟。", "桑麻被野禾連疇，鶴鶴白鳥雜游鯈。", "菰蒲菱芡厭採搜，柳楊成幄蔭道周。", "耕漁呼歌羸病瘳，使君之賜侯可侔。"]'),
('edc76789-4976-4299-abb7-dc3819fdad57','和馬粹老四明雜詩聊紀里俗耳十首  其一','舒亶','宋','宋诗','song-poetry','','[]','百粤喧譁外，三江指顧中。',48,'全唐诗/poet.song.50000.json','["百粤喧譁外，三江指顧中。", "耕桑遺俗在，草木故城空。", "近澤知田美，多魚驗海豐。", "由來形勢地，越絕控遼東。"]'),
('c83b9697-1dd4-4318-8a57-41f71ba4114a','和馬粹老四明雜詩聊紀里俗耳十首  其二','舒亶','宋','宋诗','song-poetry','','[]','澄水鋪千練，平山伏萬犀。',48,'全唐诗/poet.song.50000.json','["澄水鋪千練，平山伏萬犀。", "月橋蓮棹小，春圃酒旗低。", "蓬島雲長在，桃源客不迷。", "風流未寂寞，遊屐半香泥。"]'),
('752cf10c-b083-410b-a966-c37ffdb2662c','和馬粹老四明雜詩聊紀里俗耳十首  其三','舒亶','宋','宋诗','song-poetry','','[]','御史平囚日，郎中渡母年。',48,'全唐诗/poet.song.50000.json','["御史平囚日，郎中渡母年。", "豐碑推筆妙，孤冢枕城偏。", "白鶴空寥泬，黄蒿尚蔓延。", "九原如可作，執馭故忻然。"]'),
('0aa2816d-70fc-4b86-9e44-012b0b0b3da8','和馬粹老四明雜詩聊紀里俗耳十首  其四','舒亶','宋','宋诗','song-poetry','','[]','箔蠶迎豆熟，江雪伴梅消。',48,'全唐诗/poet.song.50000.json','["箔蠶迎豆熟，江雪伴梅消。", "抵虎螯經夏，跳沙蛤趁潮。", "酒甖雙印貴，藥肆萬金饒。", "未覺西風遠，三溪好採樵。"]'),
('7e3e2942-dfb2-4650-8f8c-3943805d23aa','和馬粹老四明雜詩聊紀里俗耳十首  其五','舒亶','宋','宋诗','song-poetry','','[]','巷陌隨橋曲，閭閻占水窮。',48,'全唐诗/poet.song.50000.json','["巷陌隨橋曲，閭閻占水窮。", "郡樓孤嶺對，市港兩潮通。", "春暖雞鳴嶴，秋寒鴨信風。", "家家人富足，擊壤與吾同。"]'),
('9b71a52f-6ec8-47c7-adb2-4d40414f8705','和馬粹老四明雜詩聊紀里俗耳十首  其六','舒亶','宋','宋诗','song-poetry','','[]','歲熟禾論{禾/朿}，人歸夜擊鐘。',52,'全唐诗/poet.song.50000.json','["歲熟禾論{禾/朿}，人歸夜擊鐘。", "金澄沙底水，龍卧井邊峰。", "香火常存社，漁鹽每奪農。", "年来縑帛賤，砧杵萬家舂。"]'),
('f769731f-41bf-48bb-a5db-78c7e5f999d6','和馬粹老四明雜詩聊紀里俗耳十首  其七','舒亶','宋','宋诗','song-poetry','','[]','稻飯雪飜白，魚羮金鬬黄。',48,'全唐诗/poet.song.50000.json','["稻飯雪飜白，魚羮金鬬黄。", "鮚埼千蚌熟，花嶼一村香。", "海近春蒸濕，湖靈夜放光。", "北窗休寄傲，大隱即吾鄉。"]'),
('191faba1-c34e-44a7-afa5-764100b1f0ac','和馬粹老四明雜詩聊紀里俗耳十首  其八','舒亶','宋','宋诗','song-poetry','','[]','禽孝傳居俗，風癡動浹旬。',48,'全唐诗/poet.song.50000.json','["禽孝傳居俗，風癡動浹旬。", "靈鰻旱天雨，聖米歉年蓴。", "江漲長如海，冬温恰似春。", "雞豚追伏臘，行路亦情親。"]'),
('3c69c2fa-0fb1-413b-8df5-003ffa3ae5b8','和馬粹老四明雜詩聊紀里俗耳十首  其九','舒亶','宋','宋诗','song-poetry','','[]','佛磬雲中寺，樵歌郭裏湖。',48,'全唐诗/poet.song.50000.json','["佛磬雲中寺，樵歌郭裏湖。", "城居蔭楊柳，野冦息萑蒲。", "巫語傳盃珓，漁蓑入畫圖。", "幽香滿花谷，不趁雪霜枯。"]'),
('25e26a3c-333b-45df-8092-a46031658778','和馬粹老四明雜詩聊紀里俗耳十首  其一○','舒亶','宋','宋诗','song-poetry','','[]','蓮閣紅堪掣，蘭池靜不流。',48,'全唐诗/poet.song.50000.json','["蓮閣紅堪掣，蘭池靜不流。", "梯航紛絕徼，冠蓋錯中州。", "草市朝朝合，沙城歲歲脩。", "兩前茶更好，半属賈船收。"]'),
('298e7e89-e75e-48a6-ad89-911a02b36a1d','題福源院','舒亶','宋','宋诗','song-poetry','','[]','地占靈龜背，山横小嶼頭。',48,'全唐诗/poet.song.50000.json','["地占靈龜背，山横小嶼頭。", "一橋雲借路，雙沼月分秋。", "竹影摇虚室，松烟著曉樓。", "殘鐘誰共聽，空籟更颼颼。"]'),
('321317bf-7146-4cca-b8d5-38bd3af3b3da','題尊教院','舒亶','宋','宋诗','song-poetry','','[]','竹砌緣寒渚，松蹊藉緑苔。',48,'全唐诗/poet.song.50000.json','["竹砌緣寒渚，松蹊藉緑苔。", "樓臺隔林見，花木带雲開。", "溪旱常流水，峰青自隱雷。", "月華？萬頃，誰掉酒船來。"]'),
('612f0365-ab0b-4077-86bc-7546dd5d7e9e','香山野步二首  其一','舒亶','宋','宋诗','song-poetry','','[]','龍護空堂鉢，雲籠古殿燈。',48,'全唐诗/poet.song.50000.json','["龍護空堂鉢，雲籠古殿燈。", "經窗僧待月，茶井客敲冰。", "驚雁回峰影，疏星亞塔層。", "心清更無睡，未羡杜郎能。"]'),
('2a917d8c-488f-4e96-9947-bc2bc82f08aa','香山野步二首  其二','舒亶','宋','宋诗','song-poetry','','[]','空澗寒探月，高齋客聚星。',48,'全唐诗/poet.song.50000.json','["空澗寒探月，高齋客聚星。", "霜分破窗白，山獻隔簾青。", "窺水知僧定，占雲識地靈。", "時時驚鶴夢，木葉下危亭。"]'),
('31a9c238-d775-4236-812d-7e45b4ea411a','和遊棲真寺見寄','舒亶','宋','宋诗','song-poetry','','[]','曾是談經一草堂，千年金碧欲飛颺。',64,'全唐诗/poet.song.50000.json','["曾是談經一草堂，千年金碧欲飛颺。", "頂峰有路青天近，絕壑無塵赤日涼。", "月底露驚猿鶴夢，雲中風動薜蘿香。", "芝𥰭茶竈平生念，遥謝仙人白羽觴。"]'),
('b7323490-2c4b-4faf-b459-1f8025de1a6f','和西湖即席二首  其一','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','金碧樓臺閣暮烟，彩虹雙影卧漪漣。',63,'全唐诗/poet.song.50000.json','["金碧樓臺閣暮烟，彩虹雙影卧漪漣。", "雲鋪物外無塵地，月滿人間不夜天。", "細柳千門維畫舸，華燈兩岸度鳴？清狂亦有黄冠客，不負仙人載酒船。"]'),
('5d2d6c45-85d7-4d49-93e0-4b806127ff0e','和西湖即席二首  其二','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十洲風籟韻笙簫，疑有仙人燕碧桃。',64,'全唐诗/poet.song.50000.json','["十洲風籟韻笙簫，疑有仙人燕碧桃。", "影逼銀河星半墮，氣吞月窟兎爭豪。", "九秋波浪沙鷗狎，萬古聲名釣艇高。", "却恨何須明似鏡，空令志士泣霜毛。"]'),
('61cc3b19-b412-4f05-af66-400e7531eeba','雨中遊仗錫','舒亶','宋','宋诗','song-poetry','','[]','何人仗錫過千峰，雨裏風烟轉不窮。',64,'全唐诗/poet.song.50000.json','["何人仗錫過千峰，雨裏風烟轉不窮。", "暗壑水聲清決決，深巖花氣濕濛濛。", "遥知雪嶺開亭近，舊說雲鄉有路通。", "自恨青鞋踏城郭，仙遊長在夢魂中。"]'),
('5fb3f3c2-d228-4871-8600-e3119e06224c','遊雲湖過香山偶成二首  其一','舒亶','宋','宋诗','song-poetry','','[]','去路鶱騰逼紫霄，何年鳬舄墮王喬。',64,'全唐诗/poet.song.50000.json','["去路鶱騰逼紫霄，何年鳬舄墮王喬。", "暗峰藏雨皆龍窟，靈草含霜半藥苗。", "已覺山衣雲撲撲，還疑風鬢雪瀟瀟。", "捫蘿更上岧嶤頂，下視滄溟百水潮。"]'),
('d6cd8921-d769-44da-b88e-9b2e142e931d','遊雲湖過香山偶成二首  其二','舒亶','宋','宋诗','song-poetry','','[]','塵境回頭隔聖凡，參差疊嶂巧如鑱。',64,'全唐诗/poet.song.50000.json','["塵境回頭隔聖凡，參差疊嶂巧如鑱。", "歸雲墮碧粘僧屐，落葉飄紅上客衫。", "果熟遥看猿渡澗，風號定想虎離岩。", "長天自有無窮景，未信西岡日半銜。"]'),
('51a6bbe3-2583-4671-8f61-00689cf05d28','和劉誼翁留題惠安二首  其一','舒亶','宋','宋诗','song-poetry','','[]','塢雲過雨翠成堆，天淡平湖一鑑開。',64,'全唐诗/poet.song.50000.json','["塢雲過雨翠成堆，天淡平湖一鑑開。", "萬木號風韻絲竹，千峰带月上池臺。", "靜無俗駕金鋪地，閒有高人玉滿盃。", "聞道碧桃看欲發，劉郎何事不歸來。"]'),
('58792bb3-b4c4-4f87-b5fc-820d65fba93b','和劉誼翁留題惠安二首  其二','舒亶','宋','宋诗','song-poetry','','[]','十里松行翠插天，暗溪嫩草尚芊綿。',64,'全唐诗/poet.song.50000.json','["十里松行翠插天，暗溪嫩草尚芊綿。", "笙歌自滿蕭郎宅，琴鶴空隨賀老船。", "未分舊遊雲寂寞，遥知歸夢蝶聮翩。", "故山幸好宜回首，還見人間換一年。"]'),
('54f91309-5f1a-48e4-b968-d7598fd3f32f','和新開西湖十洲之什','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','洗出烟華紫翠匀，再将絕景付重闉。',64,'全唐诗/poet.song.50000.json','["洗出烟華紫翠匀，再将絕景付重闉。", "千山有影螺垂地，一水無塵鏡照人。", "香濺釣筒萍雨夜，緑摇花塢柳風春。", "杖藜盡日滄浪興，時有幽人岸白綸。"]'),
('e87cd99c-003b-4cca-b0e9-529003989ca6','秋宴十洲閣','舒亶','宋','宋诗','song-poetry','','[]','緑玉手持尋五嶽，正應未識海邊洲。',64,'全唐诗/poet.song.50000.json','["緑玉手持尋五嶽，正應未識海邊洲。", "倚欄花木參差見，對岸笙歌次第遊。", "烟霽多疑九峰曉，波平全勝六鼇浮。", "仙風坐隔紅塵路，消得丹青詫此州。"]'),
('d81bc20d-6631-4bca-a8aa-3038705b9b9c','和樓試可遊育王','舒亶','宋','宋诗','song-poetry','','[]','參天松柏緑陰陰，古佛巖前一路深。',64,'全唐诗/poet.song.50000.json','["參天松柏緑陰陰，古佛巖前一路深。", "猿鳥不驚如有舊，雲山相對自無心。", "數泓寒水雲藏雨，十里輕沙地布金。", "杖屨更知非世境，上方日日海潮音。"]'),
('78b14e70-7dde-48ce-92e0-a4ef71da82be','題鄞江','舒亶','宋','宋诗','song-poetry','','[]','地吞越絕海分深，渺渺平流萬馬駸。',64,'全唐诗/poet.song.50000.json','["地吞越絕海分深，渺渺平流萬馬駸。", "早晚渡江潮有信，往來鷗鳥客無心。", "寒空倒影千山動，暖日澄波萬籟沉。", "安用魚龍閒養鬛，平時春雨自成霖。"]'),
('51668b46-aaa5-4bbd-a8b1-3b515c3d5689','題西山雙乳泉','舒亶','宋','宋诗','song-poetry','','[]','石眼雙開白欲漫，潺湲更傍碧琅玕。',64,'全唐诗/poet.song.50000.json','["石眼雙開白欲漫，潺湲更傍碧琅玕。", "地饒爽氣全無滓，天借靈源兩不乾。", "曉月自分雲外潤，午茶誰鬬雪中寒。", "孝先多睡相如渇，始把清甘乞取看。"]'),
('534efbd9-b9a6-4f98-93ec-053575574507','題靈鰻廟三首  其一','舒亶','宋','宋诗','song-poetry','','[]','繞塔想曾隨白馬，蟠泥故復傍金沙。',64,'全唐诗/poet.song.50000.json','["繞塔想曾隨白馬，蟠泥故復傍金沙。", "旱天霹靂長平地，樂歲汚邪每滿車。", "受賜由來千里境，論封消得萬人家。", "朱門便是金塗榜，未負風雲在一涯。"]'),
('c89a51dd-ef50-4c23-bd74-59f6acf8c8c4','題靈鰻廟三首  其二','舒亶','宋','宋诗','song-poetry','','[]','絕境朱丹新棟宇，深山靈響雜蚖蛇。',64,'全唐诗/poet.song.50000.json','["絕境朱丹新棟宇，深山靈響雜蚖蛇。", "黄金地底應千歲，甘雨人間幾萬家。", "西域不勞方士咒，南州重識使君車。", "老農争賽豐年社，古木蕭蕭自曉鴉。"]'),
('4bb2b5a3-16cb-4061-89c9-c6562f800982','題靈鰻廟三首  其三','舒亶','宋','宋诗','song-poetry','','[]','亘古人間蒙潤澤，數泓雲底貯清泠。',64,'全唐诗/poet.song.50000.json','["亘古人間蒙潤澤，數泓雲底貯清泠。", "功将名並山無泐，道與人尊地轉靈。", "曉殿千家供香火，旱天萬里入風霆。", "誰知别有醍醐味，行路憧憧半未醒。"]'),
('7b7a2be1-c81f-467c-9d85-bcd01df01d83','題香山湯禪師','舒亶','宋','宋诗','song-poetry','','[]','千古神僧舊石扃，清風如在地還靈。',64,'全唐诗/poet.song.50000.json','["千古神僧舊石扃，清風如在地還靈。", "溪形偃月無窮碧，山氣當雲不改青。", "葉熟猿猱時嘯聚，錫飛岩穴尚芳馨。", "西來祖意誰人問，老柏森森翠滿庭。"]'),
('f736161b-a31e-4148-9612-66decc58b410','題蒙堂','舒亶','宋','宋诗','song-poetry','','[]','由來去住不相關，贏得隨緣到處閒。',64,'全唐诗/poet.song.50000.json','["由來去住不相關，贏得隨緣到處閒。", "笑出海雲飛一錫，行分江月過千山。", "微言定許誰人叩，勝事偏於俗士慳。", "咫尺蒙堂隔霄壤，城東搔首只空還。"]'),
('06931def-2b23-42b3-9538-ffe96288723e','題翠巖丈室','舒亶','宋','宋诗','song-poetry','','[]','别移寶所出埃塵，無限金光欲照人。',64,'全唐诗/poet.song.50000.json','["别移寶所出埃塵，無限金光欲照人。", "斤斧不驚龍象伏，棟梁特地水雲新。", "千峰坐斷人間路，一榻分來月裏身。", "更看須彌師子座，未饒摩詰妙通神。"]'),
('672650ed-61bb-480f-bd00-59b6ad097055','題明月堂','舒亶','宋','宋诗','song-poetry','','[]','郢匠猶來巧運斤，清光那復隔纎塵。',64,'全唐诗/poet.song.50000.json','["郢匠猶來巧運斤，清光那復隔纎塵。", "九秋萬里雲頭路，半夜千峰頂上人。", "坐見乾坤入肝膽，陡驚草木亦精神。", "應憐赤水尋珠客，白日茫茫尚問津。"]'),
('22dec89d-3d20-463b-836e-caddc56d9bee','題五峰兼簡英禪師','舒亶','宋','宋诗','song-poetry','','[]','何人縮地海東偏，靈嶽分來不計年。',64,'全唐诗/poet.song.50000.json','["何人縮地海東偏，靈嶽分來不計年。", "幾見彩雲争照日，真疑仙掌欲擎天。", "依稀故國松千尺，迤邐前山石一拳。", "四面開軒看不足，老僧時立碧溪前。"]'),
('3a9ba8c5-374e-4b40-825f-a89b5d244242','題天童','舒亶','宋','宋诗','song-poetry','','[]','日日青鞋踏白沙，未應泛艇即靈槎。',64,'全唐诗/poet.song.50000.json','["日日青鞋踏白沙，未應泛艇即靈槎。", "雨溪清越鳴哀玉，風蔓蜿蜒動暗蛇。", "曉潤芝𥰭挑秀茁，午香茶竈煑蒼芽。", "玲瓏仙客知何在，千古烟霞自一家。"]'),
('9d0b1d84-4857-4a93-b521-0d9bb9c7ad1f','題布袋和尚','舒亶','宋','宋诗','song-poetry','','[]','休話人間我獨尊，何妨廛肆且隨羣。',64,'全唐诗/poet.song.50000.json','["休話人間我獨尊，何妨廛肆且隨羣。", "乞錢往往多空手，問路時時向白雲。", "壁上形容圖尚在，囊中氣味許誰分。", "分明提起無人問，欲會應須眼裏聞。"]'),
('e0c964e5-ec19-41ea-b607-d5655c381f79','題靈橋門','舒亶','宋','宋诗','song-poetry','','[]','危樓清迥立江風，紫邏紅旗落日中。',64,'全唐诗/poet.song.50000.json','["危樓清迥立江風，紫邏紅旗落日中。", "暑雨澗溪來浩蕩，暮烟洲渚隔朦朧。", "歡聲不厭重城近，霽色遥知秀野豐。", "滄海一時傳麗句，天才真是杜陵翁。"]'),
('d6876796-c6f5-4173-8651-60d0de0cb20b','和劉珵西湖十洲 花嶼','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','暖吹紅紫上青枝，掠水風煙巧自持。',32,'全唐诗/poet.song.50000.json','["暖吹紅紫上青枝，掠水風煙巧自持。", "蜂蝶鸕鷀各芳意，錦囊消得探春詩。"]'),
('7049871e-0190-4382-901a-f33d8ddbb4af','和劉珵西湖十洲 芳草洲','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小雨如酥露乍晞，嶼花汀柳自相依。',32,'全唐诗/poet.song.50000.json','["小雨如酥露乍晞，嶼花汀柳自相依。", "畫橋不礙尋春屐，誰傍煙波拾翠歸。"]'),
('b8d1a43f-e63f-461a-a40f-2f03426b5778','和劉珵西湖十洲 柳汀','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','困倚滄波綠卻搖，冷煙疏雨共蕭條。',32,'全唐诗/poet.song.50000.json','["困倚滄波綠卻搖，冷煙疏雨共蕭條。", "誰將輕薄嬌春態，強拂人頭向市橋。"]'),
('3522ed0d-c12c-4470-96e6-029353e9aa63','和劉珵西湖十洲 竹嶼','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲問葛陂安在哉，端疑波底化龍來。',32,'全唐诗/poet.song.50000.json','["欲問葛陂安在哉，端疑波底化龍來。", "子猷此興君知否，小徑何妨卷竹開。"]'),
('c5f602d2-a435-4243-a21e-af359923573c','和劉珵西湖十洲 煙嶼','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','著漠寒蘆不見花，暗藏鷗鷺啄晴沙。',32,'全唐诗/poet.song.50000.json','["著漠寒蘆不見花，暗藏鷗鷺啄晴沙。", "暖風吹起渾無定，半落僧窗半落槎。"]'),
('28478b1b-16c3-4736-af2a-8f6b248d56e6','和劉珵西湖十洲 芙蓉洲','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','照水橫橫蜀錦囊，年年澤國爲誰芳。',32,'全唐诗/poet.song.50000.json','["照水橫橫蜀錦囊，年年澤國爲誰芳。", "朱顔自得西風意，不管清秋昨夜霜。"]'),
('2f4ea723-9d3c-4677-8fd1-4ac944ce848f','和劉珵西湖十洲 菊花洲','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','懶對陶家酒甕開，東籬寂寞久風埃。',32,'全唐诗/poet.song.50000.json','["懶對陶家酒甕開，東籬寂寞久風埃。", "會須結取登高客，折上龍山醉帽來。"]'),
('667dd885-5679-42e4-a5ce-a2f54efafdc3','和劉珵西湖十洲 月島','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','何人騎鶴上瀛洲，清影明波正九秋。',32,'全唐诗/poet.song.50000.json','["何人騎鶴上瀛洲，清影明波正九秋。", "吹罷玉笙端不見，滿空桂子有誰收。"]'),
('a09d501c-6180-4438-8ed6-555bc2e9cd3c','和劉珵西湖十洲 雪汀','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','點柳妝梅不暇裁，平波直擬湧瑤臺。',32,'全唐诗/poet.song.50000.json','["點柳妝梅不暇裁，平波直擬湧瑤臺。", "釣磯葦岸知何許，幾誤漁舟夜半來。"]'),
('f024a86a-786c-475c-81b7-18c04767ec85','和劉珵西湖十洲 松島','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','亭亭古幹對滄浪，雨洗風飄老吹香。',32,'全唐诗/poet.song.50000.json','["亭亭古幹對滄浪，雨洗風飄老吹香。", "晚歲何人同寂寞，水西我有讀書堂。"]'),
('c596a310-1241-4f61-9fa0-2dfb6a0d5c8c','遊翠巖山','舒亶','宋','宋诗','song-poetry','','[]','桃源深處一招提，門對寒雲路繞溪。',32,'全唐诗/poet.song.50000.json','["桃源深處一招提，門對寒雲路繞溪。", "長使千峰光景動，未應洞裏老金雞。"]'),
('b8d33388-c87a-451e-8942-5e2d384ddf7d','遊大梅護聖四首  其一','舒亶','宋','宋诗','song-poetry','','[]','萬壑聲中柏子煙，高僧日日看雲眠。',32,'全唐诗/poet.song.50000.json','["萬壑聲中柏子煙，高僧日日看雲眠。", "當年象虎今何在，千古寒堂一鐵鞭。"]'),
('26d9d8ee-a192-4c7d-b593-b3092cd942fc','遊大梅護聖四首  其二','舒亶','宋','宋诗','song-poetry','','[]','仙去人閒地轉靈，蛟龍合處谷風生。',32,'全唐诗/poet.song.50000.json','["仙去人閒地轉靈，蛟龍合處谷風生。", "誰知雲霧千峰頂，長作青天霹靂聲。"]'),
('e6e0df59-879a-4eb2-941c-456b2ae55182','遊大梅護聖四首  其三','舒亶','宋','宋诗','song-poetry','','[]','流水山閒無盡時，登臨到處與心期。',32,'全唐诗/poet.song.50000.json','["流水山閒無盡時，登臨到處與心期。", "世人只愛桃源好，梅熟山閒怎得知。"]'),
('01bd59a3-41a2-418b-a5c0-20ca18b5aa9a','遊大梅護聖四首  其四','舒亶','宋','宋诗','song-poetry','','[]','雞犬同時亦上昇，赤雲今日幾人行。',32,'全唐诗/poet.song.50000.json','["雞犬同時亦上昇，赤雲今日幾人行。", "我來正唱昇平曲，不用山閒變姓名。"]'),
('8db3fa8b-11a5-4e79-934c-66d7ab79f6f7','遊灌頂三首  其一','舒亶','宋','宋诗','song-poetry','','[]','十里曾聞一嘯聲，當年猿鶴想猶驚。',32,'全唐诗/poet.song.50000.json','["十里曾聞一嘯聲，當年猿鶴想猶驚。", "白雲不礙青天路，贏得重來攞手行。"]'),
('4c0f9c3e-22fe-422f-a0e8-6f1b69f65471','遊灌頂三首  其二','舒亶','宋','宋诗','song-poetry','','[]','萬松偃蹇插雲根，四面諸峰盡子孫。',32,'全唐诗/poet.song.50000.json','["萬松偃蹇插雲根，四面諸峰盡子孫。", "日日飛煙雲霧斂，不妨掌上看乾坤。"]'),
('8a92fbf6-2fdd-440b-8d48-c2f7e00837a8','遊灌頂三首  其三','舒亶','宋','宋诗','song-poetry','','[]','雪頂胡僧眼戲天，只應風月是生緣。',32,'全唐诗/poet.song.50000.json','["雪頂胡僧眼戲天，只應風月是生緣。", "那知坐作人間雨，千丈巖頭一道泉。"]'),
('371def21-9642-447d-b4df-723d0784e561','歸郡書金峨二首  其一','舒亶','宋','宋诗','song-poetry','','[]','叱咤滄溟雪浪空，鯨鯢騎去杳亡蹤。',32,'全唐诗/poet.song.50000.json','["叱咤滄溟雪浪空，鯨鯢騎去杳亡蹤。", "鍊丹井畔春蕭索，知在蓬萊第幾重。"]'),
('78c87d8e-0165-48f4-b070-2089211144f6','歸郡書金峨二首  其二','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','又入西湖醉過春，嶺頭猿鶴幾時聞。',32,'全唐诗/poet.song.50000.json','["又入西湖醉過春，嶺頭猿鶴幾時聞。", "無端雨意隨人去，直恐衣巾盡是雲。"]'),
('809d3b12-8634-449d-a960-3799e154e29f','含珠林','舒亶','宋','宋诗','song-poetry','','[]','萬箇松杉一顆珠，老僧心手最工夫。',32,'全唐诗/poet.song.50000.json','["萬箇松杉一顆珠，老僧心手最工夫。", "冷光長在千峰頂，誰道人間夜月孤。"]'),
('6dfee925-c6b4-4557-919c-f4f5faabdaad','題天王院內鑑堂','舒亶','宋','宋诗','song-poetry','','[]','等是人間出世人，數他珍寶信非珍。',32,'全唐诗/poet.song.50000.json','["等是人間出世人，數他珍寶信非珍。", "茫茫白日誰回首，此處元無一點塵。"]'),
('6f45c918-ee59-492f-ae71-d455a45b1419','題福勝院','舒亶','宋','宋诗','song-poetry','','[]','蒼巖赤壁聳崎嶔，長者何年爲布金。',32,'全唐诗/poet.song.50000.json','["蒼巖赤壁聳崎嶔，長者何年爲布金。", "卻憶樵風生乳竇，萬松回合兩龍吟。"]'),
('67e52548-f90d-47f4-9e44-b5e5433b5464','湖心寺偶書','舒亶','宋','宋诗','song-poetry','','[]','吹落清香縹緲風，樓臺彷彿水邊紅。',32,'全唐诗/poet.song.50000.json','["吹落清香縹緲風，樓臺彷彿水邊紅。", "人間誰是丹青手，畫取春湖細雨中。"]'),
('cc8745fb-b1ec-4820-bdba-cdb5d0cc24d9','題寶林院瓊闍黎房','舒亶','宋','宋诗','song-poetry','','[]','山農未用踏溝車，一穴靈泉蔭萬家。',32,'全唐诗/poet.song.50000.json','["山農未用踏溝車，一穴靈泉蔭萬家。", "香積從今飽檀施，會看講夜落天花。"]'),
('7b626f61-65fd-4122-b9ab-746ac1d08ee0','題法喜院是院一瓦一木皆自能師手而師丈室惟布衾木枕無復長物即之坐龐眉皓頂泊然似不能言者無乃真有道者耶  其一','舒亶','宋','宋诗','song-poetry','','[]','抱山重屋兩迴廊，杉檜如雲百尺長。',32,'全唐诗/poet.song.50000.json','["抱山重屋兩迴廊，杉檜如雲百尺長。", "香火它年誰第一，老師辛苦頂如霜。"]'),
('74d6fb75-3f76-4bad-a11c-9275195a58a9','題法喜院是院一瓦一木皆自能師手而師丈室惟布衾木枕無復長物即之坐龐眉皓頂泊然似不能言者無乃真有道者耶  其二','舒亶','宋','宋诗','song-poetry','','[]','了無情解作攀緣，一鉢三衣只兀然。',32,'全唐诗/poet.song.50000.json','["了無情解作攀緣，一鉢三衣只兀然。", "坐對青山不知老，學人休問祖師禪。"]'),
('8e867057-ad98-49ac-9608-bf821afe81da','太白峰','舒亶','宋','宋诗','song-poetry','','[]','千峰下視盡兒孫，仙事寥寥不可聞。',32,'全唐诗/poet.song.50000.json','["千峰下視盡兒孫，仙事寥寥不可聞。", "長作人閒三月雨，請看膚寸嶺頭雲。"]'),
('ed91b1bd-1a42-4051-8460-783245e20a00','太白庵','舒亶','宋','宋诗','song-poetry','','[]','何年杖錫此徘徊，天上真官爲我來。',32,'全唐诗/poet.song.50000.json','["何年杖錫此徘徊，天上真官爲我來。", "芝圃鶴歸香火冷，石基空鏁舊莓苔。"]'),
('73720d0f-d279-4591-9a2a-a8d106a8dc2a','玲瓏巖','舒亶','宋','宋诗','song-poetry','','[]','詭形迥與萬山殊，空洞由來一物無。',32,'全唐诗/poet.song.50000.json','["詭形迥與萬山殊，空洞由來一物無。", "直恐虛心自天意，人間穿鑿枉工夫。"]'),
('6cf52bc7-b134-4fe0-a11c-4ef9f19c9d06','響石','舒亶','宋','宋诗','song-poetry','','[]','淵明休弄沒弦琴，混沌中含太古音。',32,'全唐诗/poet.song.50000.json','["淵明休弄沒弦琴，混沌中含太古音。", "聞說幾回風雨夜，四山渾作老龍吟。"]'),
('0dc1d9c5-0e6c-4e0e-aff5-f4ce8d844998','龍池','舒亶','宋','宋诗','song-poetry','','[]','靈蹤聊寄數峰雲，雨意含雲白晝昏。',32,'全唐诗/poet.song.50000.json','["靈蹤聊寄數峰雲，雨意含雲白晝昏。", "不用高僧時咒鉢，一泓長貯萬家村。"]'),
('02ef0846-c3b7-47c1-b043-a78392b3efd5','虎跑泉','舒亶','宋','宋诗','song-poetry','','[]','一嘯風從空谷生，直教平地作滄溟。',32,'全唐诗/poet.song.50000.json','["一嘯風從空谷生，直教平地作滄溟。", "靈山不與江心比，誰會茶仙補水經。"]'),
('50cfde11-292d-43be-871d-cc4ed7de3388','佛迹','舒亶','宋','宋诗','song-poetry','','[]','蒼崖絕壁印苔痕，陳迹千年尚似新。',32,'全唐诗/poet.song.50000.json','["蒼崖絕壁印苔痕，陳迹千年尚似新。", "杖履紛紛走南北，幾人不是刻舟人。"]'),
('de336152-3693-4b9b-ab7c-c8ae9bf993b6','臨雲閣','舒亶','宋','宋诗','song-poetry','','[]','高僧終是笑憑欄，亦似無心懶出山。',32,'全唐诗/poet.song.50000.json','["高僧終是笑憑欄，亦似無心懶出山。", "幾度海風吹散雨，坐看彩翠落人間。"]'),
('1f39af0f-7e30-4320-869f-b9bba65a97d6','春樂軒','舒亶','宋','宋诗','song-poetry','','[]','隔水巖花紅淺深，花邊相對語幽禽。',32,'全唐诗/poet.song.50000.json','["隔水巖花紅淺深，花邊相對語幽禽。", "管弦不到山閒耳，誰會憑欄此日心。"]'),
('6d921bb9-09a0-4e66-a765-09d25d7da416','宿鷺亭','舒亶','宋','宋诗','song-poetry','','[]','雲過千溪月上時，雪蘆霜葦冷相依。',32,'全唐诗/poet.song.50000.json','["雲過千溪月上時，雪蘆霜葦冷相依。", "正緣野性如僧癖，肯爲游魚下釣磯。"]'),
('824023df-5fa1-48f6-a717-705cad3b5fd3','村居','舒亶','宋','宋诗','song-poetry','','["\u4e61\u6751", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u666f"]','水繞陂田竹繞籬，榆錢落盡槿花稀。',32,'全唐诗/poet.song.50000.json','["水繞陂田竹繞籬，榆錢落盡槿花稀。", "夕陽牛背無人臥，带得寒鴉兩兩歸。"]'),
('15915998-0863-417f-8ea9-4829c0032b1a','寄台州使君五首  其一','舒亶','宋','宋诗','song-poetry','','[]','聞說天台太守家，全家日日在煙霞。',65,'全唐诗/poet.song.50000.json','["聞說天台太守家，全家日日在煙霞。", "壺中夜釀夢雲分潤，洞裏秋香玉弄花。", "四郭青山連市合，一江寒水抱城斜。", "紫芝黄鶴應相識，梅福年來鬢欲華。"]'),
('66c86b98-b4d6-4be8-9cfe-db6b7163c731','寄台州使君五首  其二','舒亶','宋','宋诗','song-poetry','','[]','使君家是八仙家，不負黄菁與紫霞。',64,'全唐诗/poet.song.50000.json','["使君家是八仙家，不負黄菁與紫霞。", "麥隴兒童行竹馬，月樓鼓角度梅花。", "彩箋吟就雲初合，玉局棋殘月半斜。", "聞說握蘭消息近，星郎昨夜倍光華。"]'),
('4b579af7-fbdd-4b5b-9b11-6c290d9bb3ea','寄台州使君五首  其三','舒亶','宋','宋诗','song-poetry','','[]','赤城山下萬人家，隱隱煙霄隔海霞。',64,'全唐诗/poet.song.50000.json','["赤城山下萬人家，隱隱煙霄隔海霞。", "石上仙書留鳥跡，碗中佛供落天花。", "參雲臺樹寒陰直，照日旌旗暖影斜。", "遙想鈴齋無別事，只緣風景費才華。"]'),
('b54e42fb-12fc-43d3-be5d-f459e2562685','寄台州使君五首  其四','舒亶','宋','宋诗','song-poetry','','[]','幾夜驪珠落蔀家，直疑光燄映朝霞。',64,'全唐诗/poet.song.50000.json','["幾夜驪珠落蔀家，直疑光燄映朝霞。", "彩毫寫就千篇賦，紅燭才燒一寸花。", "卓犖高情欲飛動，淋浪醉墨半欹斜。", "陽春白雪知難繼，捧對空驚衮繡華。"]'),
('9015a1d0-81e9-4d58-9c77-6f7ae938bde8','送道士歸桐柏觀','舒亶','宋','宋诗','song-poetry','','[]','年來遊盡海邊山，獨愛青青桐柏壇。',64,'全唐诗/poet.song.50000.json','["年來遊盡海邊山，獨愛青青桐柏壇。", "光射斗牛腰下劍，氣吞龍虎鼎中丹。", "白雲千疊赤城曉，黄鶴一聲華頂寒。", "玉簡姓名仙約在，洞天莫放酒杯乾。"]'),
('800c9878-397d-4151-91d4-762fde0f230e','羅漢閣煎茶供應','舒亶','宋','宋诗','song-poetry','','[]','薦盡春園曉焙寒，靈蹤留待使君看。',32,'全唐诗/poet.song.50000.json','["薦盡春園曉焙寒，靈蹤留待使君看。", "寒泉冷結花紋細，玉椀香收雪點乾。"]'),
('02c007ea-5826-416b-bb0d-da60a8e35f31','秋日登中山懷道人','舒亶','宋','宋诗','song-poetry','','[]','不見風流李謫仙，彩箋誰繼碧雲篇。',32,'全唐诗/poet.song.50000.json','["不見風流李謫仙，彩箋誰繼碧雲篇。", "黄花零落芙蓉老，惟有青山似去年。"]'),
('d382678e-0b94-4873-9bcc-ba93a4d100f8','題雲湖慶安院','舒亶','宋','宋诗','song-poetry','','[]','門前屏障繞潺湲，付與林僧夜定還。',64,'全唐诗/poet.song.50000.json','["門前屏障繞潺湲，付與林僧夜定還。", "松蓋作雲連十里，竹龍行雨出千山。", "白公香火蓮紅後，謝氏池塘草碧間。", "我亦鳳凰臺上客，圖閒卻笑未能閒。"]'),
('57a2f41e-0c9c-4eae-9bd5-80e938895a79','詠蔗','舒亶','宋','宋诗','song-poetry','','[]','瑤池宴罷王母還，九芝飛入三仙山。',184,'全唐诗/poet.song.50000.json','["瑤池宴罷王母還，九芝飛入三仙山。", "空餘絳節留人間，雲封露洗無時閒。", "節旄落盡何斕斑，野翁提攜出茅菅。", "吳刀戛戛鳴雙環，截斷寒冰何潺潺。", "相如賦就空上林，倦遊渴病長相侵。", "劉伶愛酒真荒淫，狂來欲倒滄溟深。", "此時一嚼輕千金，壚邊何用文君琴。", "五斗一石安足斟，坐想毛髪生清陰。", "蕭瑟甘滋欲誰讓，柤梨橘柚紛殊狀。", "冷氣相射杯盤上，顧郎不見休惆悵。", "佳境到頭還不妄，詩成雖愧陽春唱，全勝乞與將軍杖。"]'),
('b104757d-956f-48bd-af25-592b7d4ac5ec','寶嚴寺','舒亶','宋','宋诗','song-poetry','','[]','四山煙雨收，雙沼漾晴碧。',24,'全唐诗/poet.song.50000.json','["四山煙雨收，雙沼漾晴碧。", "白鳥忽飛來，點破檐前色。"]'),
('34d05471-3744-4ed2-8155-4fde71cd0924','詠雪','舒亶','宋','宋诗','song-poetry','','[]','茅君失卻三神鶴，王母應添五色麟。',32,'全唐诗/poet.song.50000.json','["茅君失卻三神鶴，王母應添五色麟。", "草木未春花事動，乾坤不夜月華新。"]'),
('b908e1bc-cdfe-472b-acca-85fca90970d7','和石尉早梅二首  其一','舒亶','宋','宋诗','song-poetry','','[]','霜林盡處碧溪傍，小露檀心媚夕陽。',64,'全唐诗/poet.song.50000.json','["霜林盡處碧溪傍，小露檀心媚夕陽。", "天下三春無正色，人閒一味有真香。", "相思誰向風前寄，趁早先從雪後芳。", "朝夕催人頭欲白，故園正在水雲鄉。"]'),
('9a08bdda-3854-4fa7-a583-5e70da7e3693','和石尉早梅二首  其二','舒亶','宋','宋诗','song-poetry','','[]','依然想見故傍，半倚垣陰半向陽。',63,'全唐诗/poet.song.50000.json','["依然想見故傍，半倚垣陰半向陽。", "短笛樓頭三弄夜，前村雪裏一枝香。", "可能明月來同色，不待東風已自芳。", "幸免杜郎傷歲暮，莫辭吟對釣漁鄉。"]'),
('1f752663-e5f4-4af7-a50e-040b7e5cbd11','夢入天台','舒亶','宋','宋诗','song-poetry','','[]','天風吹散赤城霞，染出連雲萬樹花。',32,'全唐诗/poet.song.50000.json','["天風吹散赤城霞，染出連雲萬樹花。", "誤入醉鄉迷去路，旁人應笑卻還家。"]'),
('13581fc9-517e-4348-bbda-ce6808f29e64','題明覺寺在在堂十二首  其一','舒亶','宋','宋诗','song-poetry','','[]','不管霜毛不貸人，一年舊了一年新。',32,'全唐诗/poet.song.50000.json','["不管霜毛不貸人，一年舊了一年新。", "山窗未曉聞山樂，可是梅花漏世春。"]'),
('73edeb30-c8a2-4bc1-b7d7-a6411ba1921b','題明覺寺在在堂十二首  其二','舒亶','宋','宋诗','song-poetry','','[]','風吹雨腳細於絲，泠暖渾如寒食時。',32,'全唐诗/poet.song.50000.json','["風吹雨腳細於絲，泠暖渾如寒食時。", "不待千山消盡雪，小紅已到杏花枝。"]'),
('0071f39d-09e6-4718-a1b8-5fc3329bc72e','題明覺寺在在堂十二首  其三','舒亶','宋','宋诗','song-poetry','','[]','沙溪過雨半清渾，徑石高低带雪痕。',32,'全唐诗/poet.song.50000.json','["沙溪過雨半清渾，徑石高低带雪痕。", "又見山農話春事，腰鎌兩兩喚兒孫。"]'),
('ac9109fe-2c3c-48a4-bbdf-0c469520bfcc','題明覺寺在在堂十二首  其四','舒亶','宋','宋诗','song-poetry','','[]','斷橋高下路橫斜，隔水人煙四五家。',32,'全唐诗/poet.song.50000.json','["斷橋高下路橫斜，隔水人煙四五家。", "雨後一枝紅带雪，風流不道有巖花。"]'),
('bde3b0f2-7780-4248-b77c-808c47e9e258','題明覺寺在在堂十二首  其五','舒亶','宋','宋诗','song-poetry','','[]','一溪高自撲巖來，寺在巖腰水抱回。',32,'全唐诗/poet.song.50000.json','["一溪高自撲巖來，寺在巖腰水抱回。", "林下老僧相顧笑，柴門今始爲君開。"]'),
('9d8b724f-8f3c-4d35-8d5d-806c01c7df52','題明覺寺在在堂十二首  其六','舒亶','宋','宋诗','song-poetry','','[]','高低深淺逐陰晴，一簇林巒畫不成。',32,'全唐诗/poet.song.50000.json','["高低深淺逐陰晴，一簇林巒畫不成。", "誰道青山怕雲點，白雲點處轉分明。"]'),
('88c5de04-7eaa-405e-a0c8-3127f5f4bb26','題明覺寺在在堂十二首  其七','舒亶','宋','宋诗','song-poetry','','[]','四山面面玉成圍，只許閒雲去又歸。',32,'全唐诗/poet.song.50000.json','["四山面面玉成圍，只許閒雲去又歸。", "更有小軒人不到，落花狼籍點苔衣。"]'),
('c1d76b75-8ad0-465a-8d30-78aa7e155f8a','題明覺寺在在堂十二首  其八','舒亶','宋','宋诗','song-poetry','','[]','只見青山無水聲，到頭耳目未全清。',32,'全唐诗/poet.song.50000.json','["只見青山無水聲，到頭耳目未全清。", "年來賞遍江東寺，纔入今宵睡未成。"]'),
('f009cc4e-6998-4367-9fc1-910cbdfff65c','題明覺寺在在堂十二首  其九','舒亶','宋','宋诗','song-poetry','','[]','六國干戈擅霸圖，先生談笑有工夫。',32,'全唐诗/poet.song.50000.json','["六國干戈擅霸圖，先生談笑有工夫。", "不知當日縱橫夢，曾識水聲山色無。"]'),
('f07b3ace-a367-4f6c-b360-ad62c0da7e60','題明覺寺在在堂十二首  其一○','舒亶','宋','宋诗','song-poetry','','[]','榛棘叢中舊草堂，千年誰復辨興亡。',32,'全唐诗/poet.song.50000.json','["榛棘叢中舊草堂，千年誰復辨興亡。", "纍纍付與張儀印，珍重空中一炷香。"]'),
('8c0a0f86-4a21-469a-8382-456a3a2f5f7c','題明覺寺在在堂十二首  其一一','舒亶','宋','宋诗','song-poetry','','[]','枉將風月惱肝脾，懶復雕鐫出小詩。',32,'全唐诗/poet.song.50000.json','["枉將風月惱肝脾，懶復雕鐫出小詩。", "晝日焚香面山坐，捲簾時與夜僧棋。"]'),
('0883aede-9cdb-4c16-bfe7-157416c68645','題明覺寺在在堂十二首  其一二','舒亶','宋','宋诗','song-poetry','','[]','小白山前大白山，兩山強坐屬僧閒。',32,'全唐诗/poet.song.50000.json','["小白山前大白山，兩山強坐屬僧閒。", "何時卜筑三椽地，黄帽青鞋日往還。"]'),
('fd31f5c0-b9c1-4c32-81a0-293ec7744d89','上雪竇山奉慈禪院','舒亶','宋','宋诗','song-poetry','','[]','白雲堆裏笑呵呵，上接天衢不較多。',32,'全唐诗/poet.song.50000.json','["白雲堆裏笑呵呵，上接天衢不較多。", "翠鎖亭臺山月冷，香風吹裓盡莎羅。"]'),
('8b3ff373-aae9-4ff1-b907-ec9fa1408f51','題崇福禪院二首  其一','舒亶','宋','宋诗','song-poetry','','[]','一峰傍倚兩山朝，雲裏龍孫響佩瑤。',32,'全唐诗/poet.song.50000.json','["一峰傍倚兩山朝，雲裏龍孫響佩瑤。", "長與幽人發高興，不辭雨雪過溪橋。"]'),
('5371d345-f420-4818-ad2c-cd70a72be800','題崇福禪院二首  其二','舒亶','宋','宋诗','song-poetry','','[]','龕燈隱隱夜初分，落果猿啼枕上聞。',32,'全唐诗/poet.song.50000.json','["龕燈隱隱夜初分，落果猿啼枕上聞。", "客夢欲成成不得，一窗殘月半床雲。"]'),
('5b7be7dd-85d0-4c8a-ae30-01014d87cb06','瑞巖寺','舒亶','宋','宋诗','song-poetry','','[]','十二峰頭月未央，天風吹下紫芝香。',32,'全唐诗/poet.song.50000.json','["十二峰頭月未央，天風吹下紫芝香。", "我來分得僧清致，布衲蒲團一草堂。"]'),
('771befd7-3590-4dde-a458-cd9aff8eba5a','凈居寺','舒亶','宋','宋诗','song-poetry','','[]','老厭冠蓋場，萬事不掛耳。',48,'全唐诗/poet.song.50000.json','["老厭冠蓋場，萬事不掛耳。", "時與林閒人，靜話無生理。", "卻聞錢長官，只飲凈居水。", "使我夜不眠，燈花亦歡喜。"]'),
('b6c518fc-4729-4960-9b60-bf9dcea4fabe','登五磊山','舒亶','宋','宋诗','song-poetry','','[]','五磊峰高筆插天，長松合抱幾千年。',64,'全唐诗/poet.song.50000.json','["五磊峰高筆插天，長松合抱幾千年。", "塵氛灑落非人世，風露清明近月邊。", "枕上數聲敲夜磬，山前百畝起春田。", "我來欲步蒼苔色，不著籃輿兩兩肩。"]'),
('10abc462-f636-4100-94ff-dc88235d3326','和西湖即席三首','舒亶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四明太守愛西湖，想像桃源舊日圖。',64,'全唐诗/poet.song.50000.json','["四明太守愛西湖，想像桃源舊日圖。", "不放塵埃生水面，爲傳風月到皇都。", "花開別嶼千機錦，稻熟僯田萬斛珠。", "聞說兒童騎竹馬，至今昂首望通衢。"]'),
('e1150c9e-3ee7-4d8a-8358-e8ac91f5c6fb','蘆山寺  其一','舒亶','宋','宋诗','song-poetry','','[]','雲山流水水中山，盡日青藜共往還。',32,'全唐诗/poet.song.50000.json','["雲山流水水中山，盡日青藜共往還。", "更向僧房看圖畫，不知身在畫圖間。"]'),
('fb25e15c-3861-41d5-8d14-cfce09073dce','蘆山寺  其二','舒亶','宋','宋诗','song-poetry','','[]','別開小徑入松關，半在雲間半雨間。',32,'全唐诗/poet.song.50000.json','["別開小徑入松關，半在雲間半雨間。", "紅葉滿庭人倚檻，一池寒水動秋山。"]'),
('02c3eb79-22b5-4ed5-a46d-fb5e4403d671','蘆山寺  其三','舒亶','宋','宋诗','song-poetry','','[]','昨日南山今北山，山南山北幾時還。',32,'全唐诗/poet.song.50000.json','["昨日南山今北山，山南山北幾時還。", "世人只道僧閒好，未必僧閒似我閒。"]'),
('e4bb1701-6945-4240-bec9-ac5448d5f5d3','蘆山寺  其四','舒亶','宋','宋诗','song-poetry','','[]','老來漫有愛山心，酒少茶多卻不禁。',32,'全唐诗/poet.song.50000.json','["老來漫有愛山心，酒少茶多卻不禁。", "一夜上方欹客枕，隔窗自伴冷猿吟。"]'),
('aee659b2-ad34-4190-af49-57cfbc5011f7','蘆山寺  其五','舒亶','宋','宋诗','song-poetry','','[]','山水連村不見村，冥冥細雨濕黄昏。',32,'全唐诗/poet.song.50000.json','["山水連村不見村，冥冥細雨濕黄昏。", "秋山咫尺無人到，須信閒人不用門。"]'),
('91b9fe80-93e4-417f-8285-2c62d0446198','蘆山寺  其六','舒亶','宋','宋诗','song-poetry','','[]','山空水落見遙村，取次人家只隔雲。',32,'全唐诗/poet.song.50000.json','["山空水落見遙村，取次人家只隔雲。", "一陣西風雨中過，溪頭笑語隴頭聞。"]'),
('7d476e9a-902f-4b35-bc98-23589999dd5d','含珠林','舒亶','宋','宋诗','song-poetry','','[]','何代神僧機匠深，手栽珠樹作珠林。',64,'全唐诗/poet.song.50000.json','["何代神僧機匠深，手栽珠樹作珠林。", "獰龍離穴頷初鑿，老蚌出泥光易尋。", "海近鮫人工迸泣，山深木客費愁吟。", "開窗夜半不成寐，明月時時照我心。"]'),
('be111ec1-097c-4892-ba7a-4d69089acf1c','蘆山寺  其一','舒亶','宋','宋诗','song-poetry','','[]','江雲扶雨暖溶溶，來往東西只信風。',32,'全唐诗/poet.song.50000.json','["江雲扶雨暖溶溶，來往東西只信風。", "早晚晴陰渾不定，青山半在有無中。"]'),
('a4c26218-2827-4e71-a3d8-052f47f44aee','蘆山寺  其二','舒亶','宋','宋诗','song-poetry','','[]','鵝鴨相呼初出田，昏昏雲日澹平川。',32,'全唐诗/poet.song.50000.json','["鵝鴨相呼初出田，昏昏雲日澹平川。", "寒雲數簇山南北，不見人家空見煙。"]'),
('dd10f76c-a577-4836-802d-f8b502958c95','題桃源書院','舒亶','宋','宋诗','song-poetry','','[]','三月桃源路，先生安在哉。',48,'全唐诗/poet.song.50000.json','["三月桃源路，先生安在哉。", "青衫尚顔色，蜂蝶已塵埃。", "白鶴山雲暗，金雞洞鎖開。", "神遊追不返，巒嶽自崔嵬。"]'),
('e5d84cf9-c482-4b5c-8c83-f6b7b32dd135','赤隴山','舒亶','宋','宋诗','song-poetry','','[]','野草如排戟，山花似列屏。',24,'全唐诗/poet.song.50000.json','["野草如排戟，山花似列屏。", "維舟一登覽，誤入小蓬瀛。"]'),
('1620def1-adfd-4609-8162-f759c90166a1','句  其一','舒亶','宋','宋诗','song-poetry','','[]','空外水光風動月，暗中花氣雪藏梅。',16,'全唐诗/poet.song.50000.json','["空外水光風動月，暗中花氣雪藏梅。"]'),
('1b171a31-f3a3-4c64-a5af-58f0ac12edf4','句  其二','舒亶','宋','宋诗','song-poetry','','[]','宿雨閣雲千嶂碧，野花弄日一村香。',16,'全唐诗/poet.song.50000.json','["宿雨閣雲千嶂碧，野花弄日一村香。"]'),
('2e319ff9-f2ef-4869-ad55-419ad60d9361','句  其三','舒亶','宋','宋诗','song-poetry','','[]','萬壑水澄知月白，千林霜重見松高。',16,'全唐诗/poet.song.50000.json','["萬壑水澄知月白，千林霜重見松高。"]'),
('bd95da8c-ee62-4353-8e92-db3a239bbc7d','句  其四','舒亶','宋','宋诗','song-poetry','','[]','春禽得意千般語，澗草無名百種香。',16,'全唐诗/poet.song.50000.json','["春禽得意千般語，澗草無名百種香。"]'),
('00bed6d6-c61c-4855-b073-a94a07495dd1','句  其五','舒亶','宋','宋诗','song-poetry','','[]','忍看夜影分殘月，別送秋聲入晚風。',16,'全唐诗/poet.song.50000.json','["忍看夜影分殘月，別送秋聲入晚風。"]'),
('9a528ef6-92f9-41ab-b240-3c62a6f7b915','句  其六','舒亶','宋','宋诗','song-poetry','','[]','沙岸金籠樹，燈汀玉湧濤。',12,'全唐诗/poet.song.50000.json','["沙岸金籠樹，燈汀玉湧濤。"]'),
('405d88a6-bcca-4c30-b5ef-63356334ed9d','句  其七','舒亶','宋','宋诗','song-poetry','','[]','纖塵不動天如水，一色無垠月共霜。',16,'全唐诗/poet.song.50000.json','["纖塵不動天如水，一色無垠月共霜。"]'),
('0361cfc2-fed2-4c50-be25-8496a74edbcf','句  其八','舒亶','宋','宋诗','song-poetry','','[]','塵埃滿匣空鳴劍，風雨歸舟只載書。',16,'全唐诗/poet.song.50000.json','["塵埃滿匣空鳴劍，風雨歸舟只載書。"]'),
('59ffcee9-95a7-47fc-80bb-6ff30edb2aed','句  其九','舒亶','宋','宋诗','song-poetry','','[]','一鋒不斷奸凶首，千古焉知將相才。',16,'全唐诗/poet.song.50000.json','["一鋒不斷奸凶首，千古焉知將相才。"]'),
('4f36abac-c30e-4a02-8d65-3e0aa70c0d2a','句  其一○','舒亶','宋','宋诗','song-poetry','','[]','氣味賢中好。',6,'全唐诗/poet.song.50000.json','["氣味賢中好。"]'),
('df31d6b7-f896-42fb-bc9b-5f02a3fc44df','句  其一一','舒亶','宋','宋诗','song-poetry','','[]','雲隨落日移。',6,'全唐诗/poet.song.50000.json','["雲隨落日移。"]'),
('7ff9dab6-9f34-42fa-a354-a62c28b6ba77','句  其一二','舒亶','宋','宋诗','song-poetry','','[]','風煙野外嘉。',6,'全唐诗/poet.song.50000.json','["風煙野外嘉。"]'),
('b2f5c12b-7111-4940-b511-40974cf2cc66','存目  其一','舒亶','宋','宋诗','song-poetry','','[]','詩題：明月堂首句：引月貯虛堂。',15,'全唐诗/poet.song.50000.json','["詩題：明月堂首句：引月貯虛堂。"]'),
('cbb62f99-3115-45f3-b428-6e1f4c416d10','存目  其二','舒亶','宋','宋诗','song-poetry','','[]','詩題：香山首句：抖擻軒裳一鬨塵。',16,'全唐诗/poet.song.50000.json','["詩題：香山首句：抖擻軒裳一鬨塵。"]'),
('ebf1d069-a91c-4f0b-aef8-83747d1d69f3','檢書','劉奉世','宋','宋诗','song-poetry','','[]','朗日照疏櫺，臨風事幽討。',48,'全唐诗/poet.song.50000.json','["朗日照疏櫺，臨風事幽討。", "藥欄紅欲翻，苔砌綠初掃。", "誰令墨王仙，肯使魚子老。", "悠然天祿閣，世世以爲寶。"]'),
('a3af1872-af31-4548-9761-b6d4f65e1c58','入直','劉奉世','宋','宋诗','song-poetry','','[]','玉燭含輝望處遐，禁鐘動後起雌鴉。',64,'全唐诗/poet.song.50000.json','["玉燭含輝望處遐，禁鐘動後起雌鴉。", "天高秘省雲偏重，地迥瓊林月半斜。", "三古文章留大史，百年事業照東華。", "時揮子墨隨班馬，芝檢初分宰相麻。"]'),
('b45a11e1-7506-4b7c-b896-bca14e0a7d1a','蔡州道中','劉奉世','宋','宋诗','song-poetry','','[]','黄河西渡出平沙，汝潁東流千里遐。',32,'全唐诗/poet.song.50000.json','["黄河西渡出平沙，汝潁東流千里遐。", "給餉當年秦令史，封侯不種青門瓜。"]'),
('3d7e7b60-461f-4a45-aec7-551f65178483','過都','劉奉世','宋','宋诗','song-poetry','','[]','嵩高麗中華，岳色連瑤島。',108,'全唐诗/poet.song.50000.json','["嵩高麗中華，岳色連瑤島。", "上清神仙宮，莊嚴絕雕巧。", "浮雲蕩繁陰，變幻入冥眇。", "飄搖逾巖岑，淫翳混鴻灝。", "縱有景慶合，闇然蔽昏曉。", "況復濃霧生，一氣成有昊。", "茫茫世宙間，落落耿孤抱。", "天意不可知，煩心惄焉擣。", "安得噓大風，八方凈如掃。"]'),
('9a6fa833-38ae-4bab-9cdf-d01709f94320','郴州','劉奉世','宋','宋诗','song-poetry','','[]','當年賈傅去長沙，弔屈無靈賦楚些。',64,'全唐诗/poet.song.50000.json','["當年賈傅去長沙，弔屈無靈賦楚些。", "萬里不忘宣室夜，未舒三策不成家。", "西去瀟湘南岳麓，名城疊疊紆盤谷。", "岣嶁不厭百回讀，依然稱是劉光祿。"]'),
('e41f6c30-1148-43a0-aee2-01b0ad7c19ee','楊白花','劉奉世','宋','宋诗','song-poetry','','[]','春風吹百花，楊花飛惱人。',68,'全唐诗/poet.song.50000.json','["春風吹百花，楊花飛惱人。", "誰家芍藥殿春後，花飛楊柳空暮春。", "春來復春去，春去又春來。", "陽阿歌白雪，落絮欲成灰。", "花若有情風引去，拂郎征衣點歸路。"]'),
('cee07711-c159-4a4c-bc9c-004d48244819','鄆州','劉奉世','宋','宋诗','song-poetry','','[]','暮舂朝城粟，曉採觀城葑。',24,'全唐诗/poet.song.50000.json','["暮舂朝城粟，曉採觀城葑。", "一入高魚境，已是武陽東。"]'),
('96c8cec6-ee0c-41cf-8f3b-5597c31aa53e','九河嘆','劉奉世','宋','宋诗','song-poetry','','[]','冀東皆禹蹟，漸海觀朝宗。',60,'全唐诗/poet.song.50000.json','["冀東皆禹蹟，漸海觀朝宗。", "河陰漸淪沒，平沙蕩無蹤。", "漢武築宣房，作歌稱成功。", "今塞商胡口，清流不時通。", "何當灑二渠，載跨碣石東。"]'),
('ebc70a37-9f3c-4de6-9993-dedea16ee9eb','自兖放還','劉奉世','宋','宋诗','song-poetry','','[]','年來策蹇勝乘舟，楚塞齊邊春復秋。',32,'全唐诗/poet.song.50000.json','["年來策蹇勝乘舟，楚塞齊邊春復秋。", "不教微生同腐草，青山依舊水西流。"]'),
('64dc1e74-af2f-472b-a918-3a35ba7151d3','還秩','劉奉世','宋','宋诗','song-poetry','','[]','微臣多忝竊，草莽愧榮褒。',48,'全唐诗/poet.song.50000.json','["微臣多忝竊，草莽愧榮褒。", "覽鏡憐衰白，啣環刷羽毛。", "賈生餘舊策，漢室尚東勞。", "俯伏聞綸綍，柴門日月高。"]'),
('e8d82881-249e-43cf-b1d0-8b2d34190446','自述','劉奉世','宋','宋诗','song-poetry','','[]','楚國中分後，東南世澤長。',156,'全唐诗/poet.song.50000.json','["楚國中分後，東南世澤長。", "發祥曾王父，磨勘成典章。", "王父聲益振，主客尚書郎。", "考廟緒丕顯，直鯁在巖廊。", "歷歷一精白，敬事持人綱。", "顧維予小子，念釋茲勿忘。", "晴空麗皎日，清秋凜嚴霜。", "金石磨不磷，松柏寒逾芳。", "旦評猶足信，清議詎虛張。", "夢寐滋洗滌，俯仰隨否臧。", "所值匪所思，盈虧理有常。", "亨途無詭遇，偃蹇嘶驪黄。", "誰能餌大藥，百年身平康。"]'),
('5c5f8f4d-c03a-4c96-85df-6778518ccf85','送程給事知越州','劉奉世','宋','宋诗','song-poetry','','[]','使君遺愛遍南州，五馬新歸瘴海頭。',64,'全唐诗/poet.song.50000.json','["使君遺愛遍南州，五馬新歸瘴海頭。", "持橐未厭青瑣直，懷章還作鑑湖遊。", "姚餘人物傳吳遠，越絕山川向剡幽。", "應有清詩資臥理，會吟他日記風流。"]'),
('997d7013-357e-42bc-b136-c671185027d8','駕幸太學','劉奉世','宋','宋诗','song-poetry','','[]','聖典垂精及表章，曠儀親舉自宗庠。',64,'全唐诗/poet.song.50000.json','["聖典垂精及表章，曠儀親舉自宗庠。", "縱觀橋擁浮雲蓋，侍問庭充振鷺行。", "首舉儒風隆上國，光增帝業掩前王。", "太平榮遇慚多幸，重見歌虞起廟堂。"]'),
('62d587c5-c33c-44ff-bc1f-a47fff6fcab3','句','劉奉世','宋','宋诗','song-poetry','','[]','鸚鵡有客弔芳草，黄鶴無人吹落梅。',16,'全唐诗/poet.song.50000.json','["鸚鵡有客弔芳草，黄鶴無人吹落梅。"]'),
('af79ae5b-a79c-499e-8c15-bff884d27909','謝太守答詩莱州','鄭俠','宋','宋诗','song-poetry','','[]','閑齋掩晝扉，疏竹間風韻。',288,'全唐诗/poet.song.50000.json','["閑齋掩晝扉，疏竹間風韻。", "兀坐無所爲，仰高方苦峻。", "闗闗兩喜鵲，如以？来獻。", "疑其喜過常，精爽抑何頓。", "謂當有嘉賓，結駟問原憲。", "不然親交書，萬里来問訊。", "何意二千石，新書爛盈卷。", "使者入衡門，紅光十餘仭。", "衣冠出蓬室，再拜望城閫。", "開緘列宿動，芒角相輝焕。", "捧讀未終篇，欽降已三嘆。", "譬如涉春波，渺不知涯岸。", "又若驚雷霆，但覺目眩轉。", "誰言匹夫窮，陋巷一簞飯。", "箧有無價珍，貴於青玉案。", "昨者鄙俚辭，惟求指瑕舋。", "敢期明月珠，傾瀉殊不悋。", "重重借褒譽，許與良過分。", "酷愛愚且直，還憐貧且困。", "惟人最難知，聖哲其猶恨。", "自非明如日，安得物無遁。", "程孔昔中塗，邂逅適所願。", "傾盖畢所懐，日西不知倦。", "聖賢欣道合，萬古直一瞬。"]'),
('d9fcf448-4c3a-4f5a-bf2f-2f282aa2ca0a','謝曹公','鄭俠','宋','宋诗','song-poetry','','[]','螻蟻有統治，羽鱗知所宗。',288,'全唐诗/poet.song.50000.json','["螻蟻有統治，羽鱗知所宗。", "是知君臣初，直與太極同。", "子之於其父，成性天所鍾。", "因其親愛心，以飬日益恭。", "平居竭勤瘁，患難忘厥躬。", "不擇艱與易，那知通與窮。", "至於事其君，是乃孝之中。", "未聞君父間，誠敬有卑崇。", "孔子故有言，移孝斯爲忠。", "穀黍不離草，蠶魚其類蟲。", "皆能衣食人，生世曾不空。", "矧乃備萬物，陰陽資粹冲。", "學問必唐虞，儕軰皆朱熊。", "於世乃無補，將何辨蟊螽。", "五帝道尊極，三王化醇醲。", "皆由諸大臣，汲引相追蹤。", "惜哉物僞熾，慧巧爲心蓬。", "讒邪醜正直，黨與交譏攻。", "上者以翕訿，下焉滋鞠訩。", "鸞鳳遠遁伏，鷹隼摩蒼穹。", "人神共愁嘆，寒暑迷秋冬。", "一人念忠直，百志懐兵戎。", "利口鋭戈矛，危機峻臨衝。", "賢正欲自保，孤羊豢狼叢。"]'),
('3a5764ae-7f86-4b55-90a3-116ab1f21c79','觀孔義甫與謝致仕詩有感','鄭俠','宋','宋诗','song-poetry','','[]','人生足清閑，天下第一福。',288,'全唐诗/poet.song.50000.json','["人生足清閑，天下第一福。", "惜哉聲與利，舉世方逐逐。", "君子耀軒裳，小人腴口腹。", "霜雪滿頤頷，馳競心更速。", "誰如東山後，清風千載續。", "仁孝實天成，聰明乃幾燭。", "弱冠揖高科，聲華光煜煜。", "騏驥駕夷途，千里在舉足。", "歲未再周天，官先上應宿。", "皇華屢更指，間請分符竹。", "端介奉高明，慈仁撫煢獨。", "施設妙通神，歡謳道相屬。", "一旦遽上章，幡然謝羈束。", "古人涖官政，五十曰艾服。", "公年未五十，懇請竟從欲。", "緬彼伋與軻，進退遺佳躅。", "三揖就恩榮，一辭託巖谷。", "由公仕以觀，其庶無愧恧。", "東臯我田園，負郭予室屋。", "兒姪幾百人，圖史逾千軸。", "親舊既周旋，閨門更雍穆。", "賓来酒一樽，興来棋一局。", "吟嘯動煙雲，詩書到僮僕。", "寧知地有仙，但見人如玉。"]'),
('64db08a2-3ea3-4baf-a8f9-522b3e817640','送陳守仁入太學','鄭俠','宋','宋诗','song-poetry','','[]','父子本天性，至恩無比倫。',288,'全唐诗/poet.song.50000.json','["父子本天性，至恩無比倫。", "矧公之尊府，子舍公一身。", "料從少小来，迨兹壯有室。", "未甞越旬月，遠去慈親膝。", "借問今何之，千里具行裝。", "荅言爲道藝，憤悱趨上庠。", "有客前獻言，惟道若大路。", "駕子天神明，賢聖在舉步。", "幽堂列墳典，周孔以爲師。", "學成名亦遂，且不離庭闈。", "荅云子言善，在予非不知。", "父母生我身，劬勞靡不爲。", "垂髫俾之學，外不與毫絲。", "乃今有室家，兒女髪已束。", "分寸無所立，何以酬顧復。", "如彼甲與乙，名高髦俊科。", "又若丙與丁，禄位今嵳峨。", "是皆予親友，予獨無所就。", "是以不寧居，忙於賈求售。", "昔者三千徒，負笈洙泗濵。", "孟軻遠遊學，母老仍家貧。", "尚違晨昏侍，以就德業新。", "盖以慈愛心，惟期已成達。", "男子四方志，安能戀房闥。"]'),
('47bb0af2-45a4-4bbb-88ee-8ac3b5a5f50a','臘月十八日呈子京','鄭俠','宋','宋诗','song-poetry','','[]','歲去如奔馬，殘日十有三。',156,'全唐诗/poet.song.50000.json','["歲去如奔馬，殘日十有三。", "姪爲當嫁女，甥是未婚男。", "叢然猥俗併，殊非力所堪。", "嗟予本支離，塵事素不參。", "東床書一架，西榻經一凾。", "如是歲月深，吻舌如縢緘。", "惟有陶淵明，常欲共清談。", "床頭酒盈壺，亦欲同醺酣。", "二十一二間，煩事如掃芟。", "期使堂下空，宴笑同所耽。", "清尊酌宜深，古語交嶄岩。", "夜久燈熒熒，金波忽東南。", "歲宴獨優游，庶幾爲不凡。"]'),
('c86f124a-1dc4-4248-9d2d-316aae4734c3','示潮州吳宅三甥','鄭俠','宋','宋诗','song-poetry','','[]','大郎性純淑，至寶受磨琢。',168,'全唐诗/poet.song.50000.json','["大郎性純淑，至寶受磨琢。", "二郎姿秀美，白璧光閃爍。", "三郎神照藏，宛若雛在殻。", "五彩翔鳳翰，參差見斑駮。", "三人吾令甥，亦嘗從吾學。", "昊穹有顯通，報應無舛錯。", "未有祖慶厚，而招子孫薄。", "二親又善教，曾不閑飲啄。", "甥雖多似舅，三子自超卓。", "爲文要根理，覽古務詳愽。", "不惟子三人，萬世同矩彠。", "慎勿學舅癡，直指世奸惡。", "心雖在規益，世誰受忠諤。", "立身既不危，青雲在挐攫。"]'),
('9316aeb7-9b35-4617-b983-ed009b43d6da','示女子','鄭俠','宋','宋诗','song-poetry','','[]','吾生鮮兒女，汝次今居首。',288,'全唐诗/poet.song.50000.json','["吾生鮮兒女，汝次今居首。", "柔惠少語言，天性非矯揉。", "女生必有適，二親非終守。", "既嫁又他州，安能長相就。", "幸然汝夫賢，純淑真汝偶。", "出門天其夫，禮律其来久。", "汝姑吾之妹，姑夫爲汝舅。", "事舅如事父，事姑如事母。", "三者無所闕，汝則無大咎。", "門內有尊親，門外有親友。", "歲時或餽助，祭祀合奔走。", "一一無間言，乃可逃父醜。", "治家在勤儉，臨財戒多取。", "誦經味其理，聖心良可究。", "即事念慈和，無但勞吻咮。", "善看育與蟾，二子吾珠錇。", "汝嫁既違鄉，吾遷又遠趣。", "東去十八程，西来二十九。", "三四千里間，吾視堂猶牖。", "人生否與泰，正若夜隨晝。", "但當道無虧，不媿載與覆。", "憶昨汝初生，時吾心有負。", "以爲臣事君，即是子事父。", "閨門有危難，誰不在惸疚。"]'),
('2bb6ab39-1600-41aa-a411-bfa3050bab0b','六鐶助潮士鍾平仲納官輙辭贈以詩','鄭俠','宋','宋诗','song-poetry','','[]','掲陽繁富州，鍾子閈城閈。',288,'全唐诗/poet.song.50000.json','["掲陽繁富州，鍾子閈城閈。", "怡然保清操，不與世俗換。", "豪家富廪庾，鼠雀嫌陳爛。", "鍾子無田園，斗糴供晡旦。", "甲第闢公門，奴僮立如雁。", "鍾子無使令，其子供靧盥。", "無妻備組紃，無婢奉炊爨。", "市屋十數椽，廛商是隣畔。", "暝陰滋蠧蝕，飛屑落几案。", "炎蒸鬰不通，揮扇尚流汗。", "絃誦不輟音，學海窮瀰漫。", "文章有星斗，胸臆藏璀璨。", "何殊盛衣冠，而坐於塗炭。", "下藥百十包，蟲腐皆逾半。", "經年無人顧，蛛網潜滋蔓。", "苦李十數株，採摘亦素幹。", "此外乃一無，兒女不蔽骭。", "固非人所堪，隨分亦侃侃。", "何意官物租，添輸告踰貫。", "太守爲學校，芹茆思樂泮。", "買田垂萬年，供給期無岸。", "誰人不樂輸，我獨無計辦。", "此時私愁憂，幾至方寸亂。", "我身困長途，脫身自投竄。"]'),
('138bb4d9-05ce-4ead-bee7-3850fa07f211','再到吳子野歲寒堂','鄭俠','宋','宋诗','song-poetry','','[]','再到歲寒堂，仍登歲寒閣。',252,'全唐诗/poet.song.50000.json','["再到歲寒堂，仍登歲寒閣。", "閣上與堂前，物物皆如昨。", "鉄幹偃虬龍，雲峰自巖壑。", "文章有神力，璧笥光彩錯。", "主人歲寒翁，古意何淡薄。", "山肴具樽酒，忻喜爲我酌。", "高論冩胞懐，千弩射鯨鱷。", "速悟有寶龜，靈通非火灼。", "辯議恣酬荅，亦以資笑謔。", "想翁賓去後，前扄徐徐鑰。", "萬卷羅目前，舒卷良自若。", "盛暑一榻風，祁寒一爐藥。", "翛然去與来，一個無住着。", "我亦淡泊人，世味聊咀嚼。", "無種不取嘗，畢竟何美惡。", "但聞歲寒風，便覺世齷齪。", "今兹翁如龍，看彼皆尺蠖。", "今兹翁如鴻，視彼皆籠縛。", "故願歲寒翁，高收歲寒脚。", "踞坐百千年，看春華秋落。", "無令木石心，長笑人脆弱。"]'),
('50002600-bc55-405b-9801-caf646560b18','和孔義甫送謝丈致仕','鄭俠','宋','宋诗','song-poetry','','[]','公本神仙人，眸子如點漆。',216,'全唐诗/poet.song.50000.json','["公本神仙人，眸子如點漆。", "少年富詞學，胸府羅星日。", "千鄰告饑糴，靡不售所乞。", "清時登膴仕，直以名駕實。", "非若勢利徒，志意隨纓紱。", "舜立臯益来，文興閎泰出。", "遼遼天地間，千載兹會一。", "神皇真聖神，羣策期盡屈。", "何意羣慮卑，惟思進身疾。", "然否差毫厘，愁寃騰萬室。", "天聰竟下聽，罪已逾帝乙。", "公時如巨龍，盤泊蝦蠏窟。", "孰不念澤施，天人共欣懌。", "寧知未艾服，懇懇乞骸骨。", "不免使衆疑，爲高至遺物。", "應思世役役，耽狥窮終没。", "寕殊雞與鶩，一飽歸罝罻。", "囗囗聞風清，是甘守圭蓽。"]'),
('f83fa96a-8236-4623-a809-c78742b1601c','古交行','鄭俠','宋','宋诗','song-poetry','','[]','大海有時竭，此心瀝不乾。',96,'全唐诗/poet.song.50000.json','["大海有時竭，此心瀝不乾。", "厚地有時坼，此心無裂文。", "持此以相照，百鍊青銅昏。", "用此以相惠，貝璧黄金盤。", "覿面有餘歡，背面無間言。", "德義以相高，慶譽以相先。", "千古似一日，萬里如同筵。", "此爲金石交，誰與知者論。"]'),
('37768ef1-60fc-4b6a-8ee2-4ca5f00fbcb3','教子孫讀書','鄭俠','宋','宋诗','song-poetry','','[]','水在盤盂中，可以鑑毛髪。',168,'全唐诗/poet.song.50000.json','["水在盤盂中，可以鑑毛髪。", "盤盂若動揺，星日亦不察。", "鏡在臺架上，可以照顔面。", "臺架若動揺，眉目不可辨。", "精神在人身，水鏡爲擬倫。", "身定則神凝，明於烏兎輪。", "是以學道者，要先安其身。", "坐欲安如山，行若畏動塵。", "目不妄動視，口不妄談論。", "儼然望而畏，暴慢不得親。", "淡然虗而一，志慮則不分。", "眼見口即誦，耳識潜自聞。", "神焉黙省記，如口味甘珍。", "一遍勝十遍，不令人艱辛。"]'),
('f3253434-a600-4df9-9456-98c5a7aa93e5','次韻种道行衙賞蓮花','鄭俠','宋','宋诗','song-poetry','','[]','城中勢利如聚蛙，聒聒鼓閙窮兩衙。',176,'全唐诗/poet.song.50000.json','["城中勢利如聚蛙，聒聒鼓閙窮兩衙。", "忽聞携樽命真賞，如見地涌金蓮花。", "况兹危亭跨高爽，極目四顧窮天涯。", "紅蕖繚遶幾數畝，盛粧翠蓋相撐拏。", "輿肩不換足已到，咫尺異彼窮幽遐。", "居之自可換凡骨，不必飲露餐朝霞。", "堂堂露衢不户牖，非此非彼無追賒。", "幸時有酒共酩酊，不爾一啜先春茶。", "楸枰小小較勝負，往往笑語成讙譁。", "歸来清風恐飄帽，月影已向西樓斜。", "長舒兩脚就枕簟，一覺已聽清晨笳。"]'),
('6081130c-6b41-4ed2-81d5-81f599494615','賦公悅席上事送周如京','鄭俠','宋','宋诗','song-poetry','','[]','逢世路分歸洛陽，有客邂逅樵溪曲。',256,'全唐诗/poet.song.50000.json','["逢世路分歸洛陽，有客邂逅樵溪曲。", "高談傾蓋萬珠璣，相對崇朝惟不足。", "武陽太守山簡徒，喜賢樂事天下無。", "爲客留公駐斯須，精庖饌玉歌貫珠。", "坐中賓客皆豪傑，凛凛清風生頬舌。", "性情浩浩談云云，不待酒味既凛冽。", "逡巡行幕如風翻，二姝新出屏幃間。", "一人捧心餘故態，對客悄悄眉峰攅。", "一人襜裾半雲霧，仙袂應曲飄飄舉。", "解作陽闗意外聲，舊人只把花卿數。", "此宵嘉會世所稀，席上更覽周侯詩。", "彫金有格但聞說，不覽新集那得知。", "侠於周侯非甚舊，朋友十輩識公九。", "此公惜别事如何，反覆清篇還執手。", "龍韜虎略何處藏，却向吟筆呈鋒鋩。", "堪作太平祥瑞録，將軍白首弄篇章。"]'),
('35adf01d-24f8-4d57-9b70-4b151985748c','贈雲門居士','鄭俠','宋','宋诗','song-poetry','','[]','雲門山口雲徘徊，居士道與山崔嵬。',96,'全唐诗/poet.song.50000.json','["雲門山口雲徘徊，居士道與山崔嵬。", "清時肥遁古亦有，驚猿怨鶴今誰偕。", "居士高卧白雲堆，山門時爲猿鶴開。", "溪花野屮自春色，雲芝石笋寧須栽。", "軟蒸抱石傾新醅，麋鹿慣我還無猜。", "寧知玉署思賢切，御手調羮待客来。"]'),
('be205785-12bf-41f5-af71-f24bf62afde1','送聲父','鄭俠','宋','宋诗','song-poetry','','[]','羅浮主人袁公發，偉才逸氣千人傑。',112,'全唐诗/poet.song.50000.json','["羅浮主人袁公發，偉才逸氣千人傑。", "二子軒昻有父風，妙年趣向天然别。", "邑之子弟亦好儒，遠来迎子求師模。", "子非往教求即應，龜筮有决前光孚。", "春風正好偕行樂，子如健翮摩天鶚。", "秋闈從此卜亨途，回謝卑汙翥寥廓。", "爲我殷勤問袁君，奪人所好非前聞。"]'),
('02d6bb80-46de-4562-9dd5-812ac387472b','謝太守惠酒','鄭俠','宋','宋诗','song-poetry','','[]','重陰未肯避陽明，飄風驟雨加震凌。',400,'全唐诗/poet.song.50000.json','["重陰未肯避陽明，飄風驟雨加震凌。", "正月已缺二月近，滴水成凍威稜稜。", "帝雖乘震利發生，令猶行冬重嚴凝。", "鸎皆遷喬忽入谷，魚已弄煖翻藏冰。", "此時草木亦成愁，祗恐不得違其萌。", "吁嗟羈窮影弔形，安得恝然如無情。", "明良會合千載遇，乃以罪棄投荒荆。", "單親萬里頭應雪，不得朝晚奉甘馨。", "閩嶺之南方弄兵，殺氣殊與生成爭。", "既不能輔助聖時使咸若，又不能慷慨帝前效昔人之請纓。", "詩書滿腹浪自飽，一句不得推而行。", "身雖兀坐心惕驚，愁緒忽起填胸膺。", "但聽曠野深林調調刁刁，如有神號鬼泣聲。", "真江太守真慈明，惠施每每先單煢。", "眼前突兀雙玉瓶，滿貯玉液清冷冷。", "拜公之賜未敢傾，不覺失笑三閭生。", "不學憔悴思獨醒，哺糟啜醨隨其朋。", "往往一飲一石、五斗解酲，被人呼作生劉伶。", "雖然遇酒而酩酊，心不汝醉神亦寧。", "開樽又飲太守德，和氣坐覺生簷楹。", "不知凝冽自何去，至於愁思皆自澄。", "乃知春功亦不遠，緘封祗在瓶與罌。", "安得遽爾披重雲，劃見白日臨青冥。", "和氣習習扇九壤，枯枝朽質爭敷榮。"]'),
('7d87e82f-c34c-4fc1-884d-1f190c3cfbec','上曹大夫','鄭俠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','客從南英到掲陽，十有五年困長道。',328,'全唐诗/poet.song.50000.json','["客從南英到掲陽，十有五年困長道。", "囊資空竭奴僕愁，氣象塵埃顔貎老。", "天矜窮悴幸有緣，太守曹公看客好。", "孤舟薄艤即趨門，一笑相迎見懐抱。", "道途險易人佚勞，俄頃咨詢無不到。", "旌軒雍容屈臨顧，袖出緘封相燕勞。", "舍舟東溪宅西湖，西湖風光畫不如。", "是日佳筵在連理，賓從翕集何舒徐。", "大斗所酌真醍醐，珍肴異果瓊瑶鋪。", "巨觴？灔巡數勸，惟恐不醉非賓娛。", "别有芙蕖對芳席，五幹十花圖在壁。", "萬龍齊幹玉森森，回看華軒籠翠碧。", "熙熙臺上柳青青，衆樂亭前松植植。", "爾乃盤桓四十日，尊罍時展情無斁。", "不知海內爲主人，幾人似公真好客。", "觀公政治誠有倫，合居廊廟居海濵。", "子厚在桺南蠻欣，文翁在蜀西鄙馴。", "天心帝意誠念遠，故爲遠俗迂良臣。", "願公不日居陶鈞，大開東閣羅冠紳。", "烹庖鼉龍脯麒麟，布被底下卧平津，天涯地角盡陽春。"]'),
('77db8f07-d1ff-41e7-a5c3-7f6983dc700f','醉翁行贈黎師醇','鄭俠','宋','宋诗','song-poetry','','[]','金峰醉翁七十九，行步龍鍾面黧垢。',324,'全唐诗/poet.song.50000.json','["金峰醉翁七十九，行步龍鍾面黧垢。", "惟有滿腹奇文章，日月爭新無老醜。", "頬舌鏘洋言不苟，咳唾成珠須信有。", "兩眼如星照耀人，見客偏明儼如舊。", "問翁壯年愛棊酒，邇日還如昔時否。", "曰予不戰猶好看，日飲常能傾一斗。", "因持棊酒前就翁，明日壺漿復予就。", "朱君貧苦亦好奇，接續携持窮清晝。", "城中遑遑競趨走，覿面草草忘親友。", "幾人尊爼暫從容，笑傲松篁弄花柳。", "寧知北郭予三人，繼日相從辰到酉。", "龎眉皓髪常温然，相見妙齡眉目秀。", "惜哉才高命蹇成遺滯，四十餘年州縣吏。", "棄之林野混漁樵，徒使知音動嗟喟。", "愚聞天道高遠不容人測度，無奈人能樂其樂。", "故有鼓琴重圍，行歌遺穟。", "浩然充塞，不以世俗瑣屑累寥廓。", "愚觀翁之子孫詵詵繩繩，此其後慶爲不薄。", "世俗母以翁老生輕心，須知此翁頭白面黮而英心義氣，天地不得而銷鑠。"]'),
('81cf3694-44a7-41f8-93f8-ede148846fbb','江亭與程瞿二君邂逅小飲太守送酒因成','鄭俠','宋','宋诗','song-poetry','','[]','蒼翠擎天江上山，淙琤瀉玉亭前水。',242,'全唐诗/poet.song.50000.json','["蒼翠擎天江上山，淙琤瀉玉亭前水。", "邂逅相逢坐上人，傾蓋論心何俊偉。", "凉風颯颯来几筵，似與清談相表裏。", "程瞿軒軒古遺義，憫我羈窮見辭氣。", "以爲此時無一杯，直恐江山解相鄙。", "旋呼奴僮滌鐺勺，豆肉盤蔬隨所峙。", "三盃五盃復七盃，清興悠悠殊未已。", "復向行舟尋果餌，鱻薧擬欲求諸市。", "豐殽佳饌来使庖，臣囗長鱐間珍脆。", "逡巡長呵下雲際，傳以報謁迂千騎。", "薄聞江滸清飲歡，歸去瓊漿遽来賜。", "大哉何公古循吏，易俗移風有深致。", "人之所背公所趨，正以敦薄醇醨爲已事。", "連英二城接疆理，舊績新庸滿人耳。", "道塗賡載盡歡謡，冠佩清言有餘美。"]'),
('2b0671cf-3451-4379-b60f-a5af1a51e2c8','送杜靖國知連州','鄭俠','宋','宋诗','song-poetry','','[]','杜氏世德光無前，聲華行實相輝鮮。',384,'全唐诗/poet.song.50000.json','["杜氏世德光無前，聲華行實相輝鮮。", "蕢之職也在刀匕，親舉罰爵平公筵。", "預之聞見合左氏，春秋大法因粲然。", "詩爲郡守稱杜母，南陽之人今尚傳。", "如晦作相猶民天，忠誠蹇蹇終始全。", "能令大君思不已，輟瓜奠祭情拳拳。", "子美大雅三千篇，昭昭勸戒日月懸。", "其人骨朽邈千祀，至今聞望猶當年。", "我宋龍興撫嘉運，杜家孫子隨飛奮。", "坤馬承乾禁掖清，傅霖蘇旱華夷潤。", "邇来文武百羣中，詵詵杜姓多翹俊。", "靖國少年即奇絕，雄文常倍千人傑。", "投書天府一不意，却掃雁蕩不復出。", "懐材抱道良自珍，售以連城爲折閲。", "中年不忍自棄置，以蔭調官南海尉。", "手提頑馘授州將，海盗爲之潜喪氣。", "塵埃從此免低顔，倏忽十年今擁旆。", "憶昨建康臨市征，公於吾父爲交承。", "兒童不敢求見面，卓犖但聽馳英聲。", "爾後馳驅逾半紀，投荒乃得親君子。", "孤舟抵岸即登門，見我有悲兼有喜。", "所悲竄逐萬里来，豺狼得路忠信埋。", "長？爲我意愴惻，吾未振汝良悠哉。", "所喜謂我一門吏，一年三黜剛愈鋭。"]'),
('3955960b-0fa8-4147-b5a0-9741a016be39','紀連守植道傍木','鄭俠','宋','宋诗','song-poetry','','[]','道傍木，夹道參參如合屋。',204,'全唐诗/poet.song.50000.json','["道傍木，夹道參參如合屋。", "種之毫末成合抱，太守慈仁輔生育。", "古来善政盖有數，道路開通亦其目。", "芟除翳穢平險阻，堅固橋梁便艫舳。", "何爲萬柯隨曲直，化此長龍被崖谷。", "由吾太守愛民深，孜孜利民惟不足。", "以爲烈日長道難，加兹嶺外炎暑酷。", "黄茅欎蒸之烈氣，重嵐固結之濃毒。", "不得清陰縈且紆，何處憇息而躑躅。", "令如源泉下斯行，長原太山秀可掬。", "桐榕楓果隨所遇，惟其茂密佳蔭速。", "何公之心父母心，後人當如子孫續。", "勿剪勿拜勿抝斸，蠧朽便可添新緑。"]'),
('448e8713-3fd0-4a91-ad10-9f38cbad59bd','示廬山寺老勝師','鄭俠','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','離鄉十九年，日有如年久。',217,'全唐诗/poet.song.50000.json','["離鄉十九年，日有如年久。", "歸来山水亦依然，人物存亡半非舊。", "廬阜之前我舅宅，此寺如我東西家。", "每来舅家必到此，粤自齒稚今疏牙。", "庾嶺閩山四千里，青衫謫逐自我始。", "築臺東望幾悽凉，親故滿前爭不喜。", "林下相逢真實人，非戚非疏非故新。", "執手之言行處親，是以還家一百二十日，五回松下問禪因。", "此身非我身，有君有父，有神有民。", "俯仰回環知有待，古之人居不黔突，行不已輪。", "師住無住，我動非動。", "来不須迎，去不須送。", "聚散會離，百年一夢。", "大千沙界等閒言，尋常只把毫端弄。"]'),
('f83643ed-6e29-4925-a94a-c599778ef5c7','次韻子發勸酒','鄭俠','宋','宋诗','song-poetry','','[]','子真依前家谷口，無地栽禾只栽柳。',184,'全唐诗/poet.song.50000.json','["子真依前家谷口，無地栽禾只栽柳。", "否亨千態古難常，與物浮沉兒女詬。", "鵾鵬海伏而天飛，鷦鷯林棲惟一枝。", "迂談濶論偶相識，千世一遇非爲遲。", "君看大旱希雲霓，又看朝隮雷雨隨。", "天之神力豈不大，若豐若約無定姿。", "况夫人物在宇宙，無異蠅蟻停盃巵。", "生亡尚非已主宰，滋味得不隨醇醨。", "是以衆人察察日不足，我獨悶悶頑無知。", "方吾醺酣以盂杯爲小，正見滄海如池沼。", "子又作詩勸我醉如泥，得非亦以惽惽爲勝曉。"]'),
('49e68524-a879-466a-bb78-1f69400265ad','贈余純臣通判','鄭俠','宋','宋诗','song-poetry','','[]','清人如玉如蘭荃，元是水晶宫裏仙。',272,'全唐诗/poet.song.50000.json','["清人如玉如蘭荃，元是水晶宫裏仙。", "貳車海陽未期月，士庶一口咸稱賢。", "請言清人所以賢，清人貎莊神凛然。", "中扄恬夷已自得，志意高潔凌雲天。", "犀珠焜煌照天地，清人不爲迂其視。", "金鐘球磬雜管絃，清人不以勞其耳。", "惟視與聽尚不爲，豈肯爲彼回其意。", "是焉神照無不通，豈特視明而聽聰。", "是非毁譽不立已，輕重黙與權衡同。", "上誾誾兮下侃侃，和以不同惠而斷。", "自然民物被休賜，芬馥不馳而自遠。", "閩山下士狂且恫，二十八年如萍蓬。", "遇公於兹心膽空，教誨怜念皆深衷。", "大論時聞鍧霹靂，健句每驚爭化工。", "聽言觀事潜欣悦，不見累旬如歲月。", "作歌笥中時一閲，如對岩岩冰蘖節。", "願公保此清人躬，古来大任求明哲。"]'),
('834ed013-ce75-4983-88cb-f7d6cac4610a','和李天與秀才','鄭俠','宋','宋诗','song-poetry','','[]','西塘老人唤回翁，愚惷無他生所鍾。',272,'全唐诗/poet.song.50000.json','["西塘老人唤回翁，愚惷無他生所鍾。", "簧鼓不聞非耳聾，形器不涉非無蹤。", "盡傷萬類物所蒙，圭璋貝璧矜昻顒。", "瑣屑之私背大公，塵埃蔀明荆塞胸。", "宜厚而薄歉爲豐，奚以經濟躋和冲。", "王功曰勲民曰庸，勲誰烈烈庸誰同。", "掊夷劓奪祈爵封，若人無所用其忠。", "扣天惟兹冀祖宗，願一更改由大通。", "雪霜巖巖有高松，羅網密密皆去鴻。", "此身萬死非災凶，生隨螻蟻氣蜺虹。", "共追太古還醇醲，不忍生置爐鼎中。", "聖德如天非世逢，迨兹白髪猶顓侗。", "圭刀爲活羣賈傭，何乃紫木臨身宫。", "地不愛寶人来共，威儀黨黨君子風。", "袖中球琳来相從，手搜明珠心益恭。", "偉哉斯人空不空，其中宏深外雍雍。", "淡交庶幾寧鄙衷，箇中自古無蛇龍。"]'),
('89f4fc7d-63b6-4ad7-84d9-314f2205521c','上知郡承議','鄭俠','宋','宋诗','song-poetry','','[]','至樂之性長自餘，世物莫得而榛蕪。',192,'全唐诗/poet.song.50000.json','["至樂之性長自餘，世物莫得而榛蕪。", "陰陽變化在舒慘，千里豈足勞建除。", "憶昔僣侈擅一隅，瓊宫貝闕粧金珠。", "窮奢極靡相傾奪，所不可道矧可書。", "天清地寧聖神出，蕩蕩一化渾太虗。", "頽基故址盡荒草，往往狐兎来爭居。", "魚書虎符若郵傳，幾人到此圖安舒。", "譚公賢明大國後，寶璞豈肯彫璠璵。", "拂除荒穢出夷曠，茨茅墩瓦從古初。", "璧書齊丘儉化論，譬如論海先河渠。", "千古興亡一端夢，逍遥巾氅日裕如。", "有客登亭見施設，笑殺瑣瑣誇瀛壺。"]'),
('eff276d2-7a48-4b8f-8592-a38bdc61ef7e','連州斛嶺寨井','鄭俠','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','斛嶺寨，行雲際，下視長江入地底。',234,'全唐诗/poet.song.50000.json','["斛嶺寨，行雲際，下視長江入地底。", "汲江登嶺行三里，躋扳峻險爲艱爾。", "將率居民幾半千，度歲終年苦無水。", "爰自慶歴達元符，循舊安常誰擬議。", "元符太守何公賢，愛民慮事誠而至，以爲山頂流泉鮮其事。", "吾觀古人行師動萬億，所至豈必皆平地。", "軍必有井井未達，將渇不敢聞衆耳。", "陰陽者流，以水照星。", "星之所聚，泉所委行。", "行浚鑿三日，遇泉井成矣。", "乃今三井如鼎趾，豈特當年負瓶操綆，僕僕往還之人爲慰喜。", "吾欲後之人，知井所以起，敬守前功無委圯。", "必使甃砌長如今日之清泚，萬萬斯年施何已，故作此歌勒諸斛嶺之市。"]'),
('c8a7b96f-fc61-4cf4-b914-7b3bf0434450','苞苴行','鄭俠','宋','宋诗','song-poetry','','[]','苞苴来，苞苴去，封書裹信不得住。',45,'全唐诗/poet.song.50000.json','["苞苴来，苞苴去，封書裹信不得住。", "君不見箕山之下有仁人，室無杯器，以手捧水，不願風瓢掛高樹。"]'),
('c787256d-5fcc-48d0-bb22-08844d1c08c9','陳元叟清軒','鄭俠','宋','宋诗','song-poetry','','[]','塵坌中軒户，誰標似水名。',48,'全唐诗/poet.song.50000.json','["塵坌中軒户，誰標似水名。", "物訛空自汩，人性本来清。", "天上雲藏月，人間石裹英。", "雲開與石裂，精瑩自分明。"]'),
('688ae5be-0ca6-49eb-93e9-74c415da5d5f','季冬桃花','鄭俠','宋','宋诗','song-poetry','','[]','真宰終無妄，元和豈有偏。',48,'全唐诗/poet.song.50000.json','["真宰終無妄，元和豈有偏。", "如何洞天蕋，開向雪花前。", "遊騎雖然閴，紅芳亦自鮮。", "惟應祝融氏，偷竊翫餘年。"]'),
('19c0cef7-4407-43b7-9330-5a62438e4dd7','次韻嚴巨孟  其一','鄭俠','宋','宋诗','song-poetry','','[]','侠也生来拙，論才寸不通。',48,'全唐诗/poet.song.50000.json','["侠也生来拙，論才寸不通。", "趨時慚寡術，守古又無功。", "永日書千卷，閑宵月數峰。", "惟期賢者達，邃閤見開通。"]'),
('5ce91374-6d40-42db-a5bb-d05b36251e7e','次韻嚴巨孟  其二','鄭俠','宋','宋诗','song-poetry','','[]','侠也荒唐學，文章愧古風。',48,'全唐诗/poet.song.50000.json','["侠也荒唐學，文章愧古風。", "誰將覆醯醢，子謂近蜺虹。", "去聖雖云遠，微言信可宗。", "期君振頽敝，謨典嗣前功。"]'),
('06a42fe7-3453-4f6f-9b56-6de563458f01','次韻嚴巨孟  其三','鄭俠','宋','宋诗','song-poetry','','[]','侠也愚而已，奚稱忠與剛。',48,'全唐诗/poet.song.50000.json','["侠也愚而已，奚稱忠與剛。", "未能安社稷，自合竄炎荒。", "國以民爲本，仁當生不傷。", "君其明辨此，萬里在飛翔。"]'),
('88453485-10c1-42fd-831a-f5adf68f5813','和孟堅二月晦同出城  其一','鄭俠','宋','宋诗','song-poetry','','[]','花柳接重闉，三分破二春。',48,'全唐诗/poet.song.50000.json','["花柳接重闉，三分破二春。", "江梅初弄雪，壟麥旋收新。", "纓紼嗟塵事，農桑羨野民。", "暫陪遊樂乘，此日是何辰。"]'),
('96b43432-3184-4fa7-8873-afa06da21e68','和孟堅二月晦同出城  其二','鄭俠','宋','宋诗','song-poetry','','[]','城中未必悶，出郭喜還生。',48,'全唐诗/poet.song.50000.json','["城中未必悶，出郭喜還生。", "濃淡山原氣，高低溪澗聲。", "鳴棊振幽谷，把酒聽流鶯。", "疏曠還隨分，何須學步兵。"]'),
('19719927-21c6-41b6-bfd5-2259fb6bb951','瑞像閣同楊驥雪夜飲酒','鄭俠','宋','宋诗','song-poetry','','[]','濃雪暴寒齋，寒齋豈怕哉。',48,'全唐诗/poet.song.50000.json','["濃雪暴寒齋，寒齋豈怕哉。", "書隨更漏盡，春遂酒瓶開。", "一酌留孔孟，再酌招賜回。", "酌酌入詩句，同上玉樓臺。"]'),
('ad99f0cf-69e2-4edd-97aa-f7a6264662a6','和荆公何處難忘酒詩','鄭俠','宋','宋诗','song-poetry','','[]','何處難緘口，熙寧政失中。',48,'全唐诗/poet.song.50000.json','["何處難緘口，熙寧政失中。", "四方三面戰，十室九家空。", "見佞眸如水，聞忠耳似聾。", "君門深萬里，安得此言通。"]'),
('f1e2b398-2810-4a26-baf4-a986c98afdd6','和叔粲滄浪亭','鄭俠','宋','宋诗','song-poetry','','[]','高亭殖殖水冷冷，笑指鷗鳬坐晚汀。',64,'全唐诗/poet.song.50000.json','["高亭殖殖水冷冷，笑指鷗鳬坐晚汀。", "遠不聞聲千櫓去，矯如爭秀數峰青。", "煙雲窗牖紛紛雨，露月蒹葭點點星。", "最好歸輿擁雙璧，笙歌燈火照仙屏。"]'),
('74461803-6e04-4fc5-8182-bf8165d4474a','題仁王横山閣','鄭俠','宋','宋诗','song-poetry','','[]','案俯横山跨海来，拂雲高閣爲誰開。',64,'全唐诗/poet.song.50000.json','["案俯横山跨海来，拂雲高閣爲誰開。", "荒溪古木閒猿洞，明月白沙空釣臺。", "曉日東風龍夭矯，秋風西峡鳳徘徊。", "居然靜卧江南岸，天塹波濤亦壯哉。"]'),
('644001e5-4b29-4704-943b-2ebda932eaa1','次張子京遊天王湖作','鄭俠','宋','宋诗','song-poetry','','[]','湖上遲遲不忍還，談玄清徹幾重闗。',64,'全唐诗/poet.song.50000.json','["湖上遲遲不忍還，談玄清徹幾重闗。", "旋嵐野馬皆歸靜，逝鳥潜魚各自閒。", "墜果露巢秋後樹，淡煙斜日晚来山。", "吟情到此何終極，注目紅雲紫霧間。"]'),
('5e6f7c54-2934-4ac3-9797-bb7d50f0ccbd','同子忠上西樓','鄭俠','宋','宋诗','song-poetry','','[]','偶因送客上西樓，共愛佳城枕海陬。',64,'全唐诗/poet.song.50000.json','["偶因送客上西樓，共愛佳城枕海陬。", "雁翅人家千巷陌，犬牙商舶數汀洲。", "風吹細雨兼秋凈，雲漏疏星带水流。", "獨有單親頭早白，迢迢東望不勝愁。"]'),
('7f64260c-a938-46d9-846e-379d963da96a','次韻陳秀才告别之作','鄭俠','宋','宋诗','song-poetry','','[]','行槖蕭蕭又出門，豈應踪跡溷東園。',64,'全唐诗/poet.song.50000.json','["行槖蕭蕭又出門，豈應踪跡溷東園。", "詩書無地人間世，山野有亭江上村。", "幾許春秋由白髪，誰能枝葉事閒言。", "行矣吾衰今已矣，獨將清夢到乾坤。"]'),
('1e4c836d-d8b6-499c-9691-1ab097372d3a','示廬山寺勝老','鄭俠','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','寶鼎當年未結丹，幽棲曾此掩柴闗。',64,'全唐诗/poet.song.50000.json','["寶鼎當年未結丹，幽棲曾此掩柴闗。", "羽軿欲化乘風馭，梵錫應留解虎環。", "僧卧碧雲皆壽考，鶴迷華表幾時還。", "好應月白長廊下，澗水無聲人自閒。"]'),
('f22fd0c6-0c19-413a-abf2-a642c7eea05d','次韻子京早春雨中','鄭俠','宋','宋诗','song-poetry','','[]','花草迎春意已嬌，霡如膏雨復連朝。',64,'全唐诗/poet.song.50000.json','["花草迎春意已嬌，霡如膏雨復連朝。", "昏雲暗霧饒慵困，疏李殘梅共寂寥。", "賴有河陽遊約近，能令圃澤睡魔消。", "看看陌上千紅紫，只好公孫日觧貂。"]'),
('81f4d0d3-2025-46ac-8619-653b848007f1','贈陳通其致仕頣壽軒','鄭俠','宋','宋诗','song-poetry','','[]','七十退休人所共，一生清苦獨推賢。',64,'全唐诗/poet.song.50000.json','["七十退休人所共，一生清苦獨推賢。", "枝棲腹飲知安分，骨聳神清合永年。", "靜引兒孫黄卷下，閒馴龜鶴小池邉。", "恬夷益得冲和力，無病無憂一地仙。"]'),
('3368f2b3-ecc5-4705-8cc0-018986adb4a9','送林六秀才之廣勸其早歸','鄭俠','宋','宋诗','song-poetry','','[]','無情烏兔兩相追，歲月蹉跎一箭飛。',64,'全唐诗/poet.song.50000.json','["無情烏兔兩相追，歲月蹉跎一箭飛。", "觧報劬勞能幾日，可堪容易曠慈闈。", "須知楚國千鍾粟，不直莱庭一綵衣。", "我念松楸心獨苦，故知吾子不如歸。"]'),
('e1615b92-7cdf-4c82-9503-587cedc04456','次孟堅初冬晴和見梨桃二花作','鄭俠','宋','宋诗','song-poetry','','[]','十月南天尚暑襟，幽花何怪動清吟。',64,'全唐诗/poet.song.50000.json','["十月南天尚暑襟，幽花何怪動清吟。", "半扉素蕋呈修徑，幾朶夭紅出茂林。", "地借小春回暖氣，日勻疏影轉輊陰。", "惟應幕府多才俊，不負行臺醉賞心。"]'),
('f78df0b1-baac-42c9-87c4-ed7eac45e1a9','次張君舉秀才','鄭俠','宋','宋诗','song-poetry','','[]','長風清洒翳天塵，捧出重光耀世輪。',64,'全唐诗/poet.song.50000.json','["長風清洒翳天塵，捧出重光耀世輪。", "龍衮未温當扆坐，鳳書先軫向隅人。", "一緘符命来差緩，四尺先墳夢已頻。", "衰老將何報明主，雪霜柯幹艸莱身。"]'),
('9a790958-337c-4542-836f-15e891eb84f3','題頤軒','鄭俠','宋','宋诗','song-poetry','','[]','達人取次總佳宜，瀟洒清軒聊自頤。',64,'全唐诗/poet.song.50000.json','["達人取次總佳宜，瀟洒清軒聊自頤。", "垣果砌花堪笑語，牖風庭月共希夷。", "滿堂虗白琴三弄，竟日醺酣酒一巵。", "别有工夫留客住，時時談笑出新詩。"]'),
('4316a311-490a-43c8-b9b9-4d1ff94ac2f2','次韻環翠亭','鄭俠','宋','宋诗','song-poetry','','[]','天圍湖海凈團圞，水色山光四座寒。',64,'全唐诗/poet.song.50000.json','["天圍湖海凈團圞，水色山光四座寒。", "暗結濃陰森萬木，靜鋪遥碧擁千巒。", "共斟緑醑看浮蟻，遥見孤舟下遠湍。", "是處煙雲有佳隠，﨑嶇長道太無端。"]'),
('1d733e18-fe66-4288-967f-9e27c7376c8f','仲常龍圖自廣中移師閩','鄭俠','宋','宋诗','song-poetry','','[]','節鉞依前向釣臺，祥煙喜氣兩崔嵬。',64,'全唐诗/poet.song.50000.json','["節鉞依前向釣臺，祥煙喜氣兩崔嵬。", "民思父母無窮已，天借星辰有去回。", "千里袴襦還衆煖，三山樓閣爲誰開。", "須知道路先騰說，又見清凉古佛来。"]'),
('cad7f261-3717-4b4e-99f7-9d1a94a0b61f','次張漢公言懐','鄭俠','宋','宋诗','song-poetry','','[]','人間滚滚竟何營，只爲蠅頭利與名。',64,'全唐诗/poet.song.50000.json','["人間滚滚竟何營，只爲蠅頭利與名。", "千里瘴鄉吾逐客，一簞窮巷子書生。", "文章相誤終須别，寵辱無闗自不驚。", "贏得白頭閑處坐，一竿風月有誰爭。"]'),
('7ba29792-0348-4d5e-b285-4e5d0b88ede5','次韻太守仁智堂','鄭俠','宋','宋诗','song-poetry','','[]','堂下玻瓈看碧瀾，天邉圖畵指層巒。',64,'全唐诗/poet.song.50000.json','["堂下玻瓈看碧瀾，天邉圖畵指層巒。", "崔嵬切漢星辰近，清泚照人毛骨寒。", "已嘆神明傳政化，仍觀慈惠展盃盤。", "尊前不爲扶衰病，敢惜酡顔勝渥丹。"]'),
('9c6d37e5-a1e7-4472-b822-3417f05d7ea8','次韻春登樓','鄭俠','宋','宋诗','song-poetry','','[]','公餘閒步古城巔，遲日和風暇豫天。',64,'全唐诗/poet.song.50000.json','["公餘閒步古城巔，遲日和風暇豫天。", "花引嫩芳迎曉露，柳垂輕絮拂晴煙。", "一尊椒桂除三品，千室謳歌在五絃。", "紅紫正争春又半，斷崖荒塹草芊芊。"]'),
('5ab5f781-c11c-429e-af41-1f00411f2d48','幽居','鄭俠','宋','宋诗','song-poetry','','[]','蕭條深巷寄門墻，城郭村居事異常。',64,'全唐诗/poet.song.50000.json','["蕭條深巷寄門墻，城郭村居事異常。", "石展地衣三藥徑，錦圍天柱十花檣。", "幽禽隔樹鈎膠語，異草揺風合和香。", "不覺冬歸與春到，但知無事日偏長。"]'),
('eb22637d-e40b-4b1c-ab8a-81797d9338f5','次韻李天與張温夫','鄭俠','宋','宋诗','song-poetry','','[]','年来年去一衰翁，幾不能言但守中。',64,'全唐诗/poet.song.50000.json','["年来年去一衰翁，幾不能言但守中。", "每嘆善交如管鮑，那知所得並軻雄。", "直教顔巷人難處，秪願融尊酒不空。", "自古英賢有窮達，誰能朋友謝磨礱。"]'),
('12977654-b8d4-4bdd-aa9c-569d7b0391e2','辭謝諸相知見招','鄭俠','宋','宋诗','song-poetry','','[]','蓋倚嬴肩汗滿鞲，晨饔夕燕未曾休。',64,'全唐诗/poet.song.50000.json','["蓋倚嬴肩汗滿鞲，晨饔夕燕未曾休。", "盃盤狼藉君雖厚，僕馬疲勞我亦羞。", "淡淡交知猶可久，區區口腹不須謀。", "還能收取筵中費，遍使饑窮飽暖不。"]'),
('d3c25795-68e0-42e1-93b4-18aee5fa74c7','上蘇端明  其一','鄭俠','宋','宋诗','song-poetry','','[]','聞說天南受賜深，傳方施藥每揮金。',64,'全唐诗/poet.song.50000.json','["聞說天南受賜深，傳方施藥每揮金。", "看天風格樽前態，妙國胸懐枕上心。", "草木亦蒙銓品力，山川難載頌歌音。", "如今收拾知何用，衣被華夷有傅霖。"]'),
('4f9fca77-6c37-42a5-ae76-195a46eb6ecd','上蘇端明  其二','鄭俠','宋','宋诗','song-poetry','','[]','昔向東坡覽古文，長嗟簡策鎻風雲。',64,'全唐诗/poet.song.50000.json','["昔向東坡覽古文，長嗟簡策鎻風雲。", "那知日月歸元首，立見夔龍遇放勛。", "夷夏生靈真久困，聖賢膏澤有前聞。", "帡幪天地期功業，妙畵奇書請暫焚。"]'),
('470369c8-abbc-4861-a1b0-bac806c4f751','辭方公悦','鄭俠','宋','宋诗','song-poetry','','[]','又承尊酒細論文，日日樽前得未聞。',64,'全唐诗/poet.song.50000.json','["又承尊酒細論文，日日樽前得未聞。", "憐舊直忘趨走賤，有疑俱向笑談分。", "心緣明德懐高屏，日爲偏親斷遠雲。", "明日迢迢東郭路，未行離思已紛紛。"]'),
('3ac3312f-0591-434d-a4c5-a1d36edcdcc9','次韻清溪樊主簿','鄭俠','宋','宋诗','song-poetry','','[]','欲致皇恩浃羽鱗，天涯地角盡如春。',64,'全唐诗/poet.song.50000.json','["欲致皇恩浃羽鱗，天涯地角盡如春。", "當年欵欵曾忘死，今日區區肯患貧。", "正以庭闈安梓里，誰知魂夢達楓宸。", "海邦一見如疇昔，心膂相知亦宿因。"]'),
('6726f97e-c08d-4606-97fb-47725ef93490','次韻余純臣通判球瑯軒','鄭俠','宋','宋诗','song-poetry','','[]','聳翠凌空不少盤，回環使宅對千巒。',64,'全唐诗/poet.song.50000.json','["聳翠凌空不少盤，回環使宅對千巒。", "高華誰爲球瑯闢，勁節相憐霜雪寒。", "引得鳳来緣有實，化爲龍去始堪看。", "桐廬寂寞烟雲暝，惆悵無人近釣竿。"]'),
('9cab010b-ff05-4b50-b164-8616cfe51113','次韻余倅籠碧軒','鄭俠','宋','宋诗','song-poetry','','[]','萬龍齊幹擁高牙，占盡幽奇只一家。',64,'全唐诗/poet.song.50000.json','["萬龍齊幹擁高牙，占盡幽奇只一家。", "分破密陰開細路，罩將餘碧入江沙。", "靜籠簮玉朝雲合，暮到盃金夜月斜。", "賢守二車真可畏，尊前詩筆太豪華。"]'),
('b4864684-d01e-4d6c-8ff1-7ce70bc33bf1','次韻廣州梁有爲秀才','鄭俠','宋','宋诗','song-poetry','','[]','孤直惟知不愧天，飄零無復記流年。',64,'全唐诗/poet.song.50000.json','["孤直惟知不愧天，飄零無復記流年。", "學從鄒魯已如此，貧甚顔原亦浩然。", "乞食偶隨持鉢老，入城因訪跨羊仙。", "真人到了扶真道，手付瑶臺刻玉篇。"]'),
('f7e86b7d-7d36-4136-b781-48d663313d78','煙雨樓  其一','鄭俠','宋','宋诗','song-poetry','','[]','層梯叠構倚穹蒼，煙雨江山見渺茫。',64,'全唐诗/poet.song.50000.json','["層梯叠構倚穹蒼，煙雨江山見渺茫。", "人是神仙来鎮守，物隨時節亦循良。", "靜鋪紫翠資吟興，時作霏微助歲穰。", "豈比啼猩兼嘯鬼，浪將愁恨向瀟湘。"]'),
('20f7a511-605a-4998-8990-0f907b1c9d58','煙雨樓  其二','鄭俠','宋','宋诗','song-poetry','','[]','仙人居處即鰲宫，更作層樓峭倚空。',64,'全唐诗/poet.song.50000.json','["仙人居處即鰲宫，更作層樓峭倚空。", "羣岫西来煙漠漠，大江南去雨濛濛。", "花鑣柳策熙怡裏，耘笠漁簑笑語中。", "别有夜楹千里月，凭欄清興與誰同。"]'),
('e4a2f3c9-804b-480c-9a38-d89396591ccc','示潮州妹子','鄭俠','宋','宋诗','song-poetry','','[]','八人兄弟三人在，獨立他州信汝賢。',64,'全唐诗/poet.song.50000.json','["八人兄弟三人在，獨立他州信汝賢。", "直使無情如槁木，忍看垂淚念南遷。", "從今依舊歌泉水，何物偏宜寄謫仙。", "美酒年年須百甕，好從南海便乘船。"]'),
('40d03c9c-7306-4434-9a57-13fc0422dd19','次韻子京下元雨過對月','鄭俠','宋','宋诗','song-poetry','','[]','年雖小歉俗安蘇，小雨時時濟旱枯。',64,'全唐诗/poet.song.50000.json','["年雖小歉俗安蘇，小雨時時濟旱枯。", "天爲下民成晚霽，月將三五上東隅。", "星如青女臨銀鏡，人似寒冰在玉壺。", "想是庭前吟望久，豈殊雲外一輪孤。"]'),
('fe1009f3-6a77-4764-88b1-4279aa132d4f','元符放還謝英守何智翁','鄭俠','宋','宋诗','song-poetry','','[]','僦屋平山至典衣，来時便作十年期。',64,'全唐诗/poet.song.50000.json','["僦屋平山至典衣，来時便作十年期。", "豈知未報歸餘閠，早有潜吟送别詩。", "聖主恩仁天地力，明公憐念父兄慈。", "征鞍擬待春和煖，催促行裝願少遲。"]'),
('6f8e09ab-5732-47ab-a9c4-c36a4a4ab2c0','和子京霜字見寄','鄭俠','宋','宋诗','song-poetry','','[]','秋深園圃雖無雨，晚歲頭鬚自有霜。',64,'全唐诗/poet.song.50000.json','["秋深園圃雖無雨，晚歲頭鬚自有霜。", "身事無功且人事，酒囊餘地乃書嚢。", "寒雅嘯侣鳴喬木，粉蝶成圍過矮墻。", "對此每思良友伴，幸時来訪浣愁膓。"]'),
('32032317-08fb-4641-a610-e1f222c7bfdf','次韻趙資道秋夜聞角','鄭俠','宋','宋诗','song-poetry','','[]','蕭索秋城五鼓前，月臨殘夢正團圎。',64,'全唐诗/poet.song.50000.json','["蕭索秋城五鼓前，月臨殘夢正團圎。", "彤樓一曲梅花落，玉枕誰家繡带連。", "歌酒梁園人散後，弓刀秦戍雁南天。", "一般凄咽西風下，轉展空床夜不眠。"]'),
('1e692d25-577e-45fa-a1b5-18ae3b0fabc7','次韻知郡登高言懐','鄭俠','宋','宋诗','song-poetry','','[]','莫向天涯說故鄉，人身不似雁隨陽。',64,'全唐诗/poet.song.50000.json','["莫向天涯說故鄉，人身不似雁隨陽。", "黄花滿手空佳節，千里有懐如寸腸。", "爲許功名酬聖代，不須愁緒付瑤觴。", "男兒不是閨中物，生則桑弧射四方。"]'),
('25cce06f-1294-40c6-9032-c52a347c8383','次韻杜幕春日','鄭俠','宋','宋诗','song-poetry','','[]','平明驅馬出城東，馬上知君興莫窮。',64,'全唐诗/poet.song.50000.json','["平明驅馬出城東，馬上知君興莫窮。", "淮曲山川三月路，春光桃李萬家風。", "酒腸寛處須吞海，詩思狂来幾擊鐘。", "何事青□正雙鬂，擬將漁釣約溪翁。"]'),
('b240f27d-48fe-4999-bf3d-627423ff52d7','次韻張伯時以再任爲賀','鄭俠','宋','宋诗','song-poetry','','[]','再官庠序爲寧親，立道惟憂歉泗濵。',64,'全唐诗/poet.song.50000.json','["再官庠序爲寧親，立道惟憂歉泗濵。", "若使佞諛求利達，便居廊廟亦沉淪。", "環惟書史何如樂，得是英髦信不貧。", "如子才豪猶未第，每思冥晦避通津。"]'),
('5104cd88-cee3-457c-9cfe-8c715e364fca','次韻子京述懐','鄭俠','宋','宋诗','song-poetry','','[]','桑海有涯殊浩蕩，蕙風無動任飄颻。',64,'全唐诗/poet.song.50000.json','["桑海有涯殊浩蕩，蕙風無動任飄颻。", "莫窮興廢千年事，但看盈虗兩信潮。", "方聽民間歌道化，何爲天際想歸橈。", "當知得意無南北，隨向生成似玉杓。"]'),
('cd7ed651-4d0d-4aef-a2dd-fcc6750f4e66','和英州太守何智翁次韻馮仲禮麻江橋  其一','鄭俠','宋','宋诗','song-poetry','','[]','疊石梁空太守賢，一年功力倍千年。',64,'全唐诗/poet.song.50000.json','["疊石梁空太守賢，一年功力倍千年。", "惠從今日流終古，智是當時决九川。", "有競輪蹄何雜沓，無情風月亦流連。", "紅燈焰焰三更市，從此吳江不直錢。"]'),
('192f5848-5f67-48c9-b85b-a133a6bb2728','和英州太守何智翁次韻馮仲禮麻江橋  其二','鄭俠','宋','宋诗','song-poetry','','[]','一带危橋接市廛，春成冬壞幾多年。',64,'全唐诗/poet.song.50000.json','["一带危橋接市廛，春成冬壞幾多年。", "誰驅巨石如填海，化作長虹下飲川。", "白水曉寒孤洞杳，紅燈夜午萬珠連。", "清風明月如堪買，且問如今直幾錢。"]'),
('bce89d15-ca9a-445f-b067-434ae0e1440a','次韻張老見贈','鄭俠','宋','宋诗','song-poetry','','[]','烏鴉螻蟻有君臣，此義如何易世塵。',64,'全唐诗/poet.song.50000.json','["烏鴉螻蟻有君臣，此義如何易世塵。", "欲爲無窮宗社計，肯憂如幻死生身。", "八千江上奔馳路，十二天南黯淡春。", "歸到親闈捧杯酒，始知終是福唐人。"]'),
('68f7dc0f-9af0-4df4-af63-a623627f4659','觀棋','鄭俠','宋','宋诗','song-poetry','','[]','三百六十路，通精此有門。',120,'全唐诗/poet.song.50000.json','["三百六十路，通精此有門。", "數奇藏日月，機發動乾坤。", "對面知爲敵，渾輸却有翻。", "詐貪常易喪，仁守乃長存。", "隻子如輕用，全功更莫論。", "就令投險勝，寧抵被圍奔。", "縱得四方盡，寧同一腹尊。", "傍觀饒好着，當局奈嗔言。", "慚愧中孚信，幾危大壯藩。", "坐觀成敗者，安得不驚魂。"]'),
('01599e51-c724-4de9-b20a-4f443adbf822','謝工部徘徊堂','鄭俠','宋','宋诗','song-poetry','','[]','高堂增構廣幽齋，鑿破青青遍地苔。',96,'全唐诗/poet.song.50000.json','["高堂增構廣幽齋，鑿破青青遍地苔。", "雲入洞房疑有氣，月當疏牖若爲開。", "路無荆棘皆新闢，砌得芝蘭是舊栽。", "流水聲中迎送屐，緑筠叢下獻酬杯。", "達生不爲休塵慮，齊物元由悟本来。", "終見東山報重起，未登囗乘且徘徊。"]'),
('6c574ca6-21df-442f-ba44-e57b0e568be5','集鷗渚','鄭俠','宋','宋诗','song-poetry','','[]','主人無機心，兕虎皆可入。',24,'全唐诗/poet.song.50000.json','["主人無機心，兕虎皆可入。", "君看小渚中，豈特羣鷗集。"]'),
('820b75cc-b610-4735-8f4e-ed8df40dcbae','忘機亭','鄭俠','宋','宋诗','song-poetry','','[]','鳬鷗近隼旟，亭陰戲魴鱒。',24,'全唐诗/poet.song.50000.json','["鳬鷗近隼旟，亭陰戲魴鱒。", "我自無機心，忘機成戲論。"]'),
('457fec40-6179-48a7-89be-05c7339af146','孤嶼亭','鄭俠','宋','宋诗','song-poetry','','[]','峰巒何迤邐，天際相依倚。',24,'全唐诗/poet.song.50000.json','["峰巒何迤邐，天際相依倚。", "如何是孤嶼，獨立澄明裏。"]'),
('13f903e0-6969-496b-8dad-63c95c947478','芳沚亭','鄭俠','宋','宋诗','song-poetry','','[]','澄流良湜湜，幽藻還漪漪。',24,'全唐诗/poet.song.50000.json','["澄流良湜湜，幽藻還漪漪。", "不是采蘩手，芬芳長自持。"]'),
('c4dceb9e-ef24-4be8-8113-820ee6d1ab9d','讀史','鄭俠','宋','宋诗','song-poetry','','[]','亂亡由佞舌，覽古每嗟吁。',24,'全唐诗/poet.song.50000.json','["亂亡由佞舌，覽古每嗟吁。", "擬刻姦諛像，申明兩觀誅。"]'),
('8693e1b1-107c-4c6b-99ab-c7196e031221','論誠','鄭俠','宋','宋诗','song-poetry','','[]','萬事以誠立，不誠心不專。',24,'全唐诗/poet.song.50000.json','["萬事以誠立，不誠心不專。", "誠心非鐵石，鐵石被誠穿。"]'),
('308c8d9b-5322-48c1-9771-9a28c05bca4f','和蔡公上巳','鄭俠','宋','宋诗','song-poetry','','[]','愷悌侯藩修禊事，風流草木薦天香。',32,'全唐诗/poet.song.50000.json','["愷悌侯藩修禊事，風流草木薦天香。", "使君喜爲民行樂，擬築春光作舞塲。"]'),
('0434c195-b442-4d16-ad8f-0de407c57461','閉戸','鄭俠','宋','宋诗','song-poetry','','[]','居然訟息愧王通，反閉柴門亦古風。',32,'全唐诗/poet.song.50000.json','["居然訟息愧王通，反閉柴門亦古風。", "幽鳥一聲庭日永，軒窗從此近盧仝。"]'),
('699f6639-c5da-4d35-ba4d-6ecb12697a9f','漁家','鄭俠','宋','宋诗','song-poetry','','[]','月滿平湖夜漸深，浩波千頃蕩黄金。',32,'全唐诗/poet.song.50000.json','["月滿平湖夜漸深，浩波千頃蕩黄金。", "不知世有榮華事，何至中藏喜懼心。"]'),
('fbc457f5-8fd3-4478-ae03-b5d089ec737a','見遠亭','鄭俠','宋','宋诗','song-poetry','','[]','天邊毫末見千峰，景物都窮見不窮。',32,'全唐诗/poet.song.50000.json','["天邊毫末見千峰，景物都窮見不窮。", "因念當時小天下，亦如亭上老仙翁。"]'),
('4f55ccd7-4ee1-452e-9b4a-3d316a87a310','大水除廳前小屋','鄭俠','宋','宋诗','song-poetry','','[]','庭下新来不掩門，洒然無復舊時喧。',32,'全唐诗/poet.song.50000.json','["庭下新来不掩門，洒然無復舊時喧。", "小鋤輕瓮從兹起，無補清時合灌園。"]'),
('a83a1b92-408b-4ae2-a9cc-4b1b89272f9d','宴十五約重陽飲患無登高處','鄭俠','宋','宋诗','song-poetry','','[]','道義相歡勝飲醪，况添流雪見承糟。',32,'全唐诗/poet.song.50000.json','["道義相歡勝飲醪，况添流雪見承糟。", "卧籬一醉陶家宅，不是龍山趣也高。"]'),
('73f4a974-6518-4a16-b468-73a163a4b807','出御史臺','鄭俠','宋','宋诗','song-poetry','','[]','萬險千艱六出身，如今也得避囂塵。',32,'全唐诗/poet.song.50000.json','["萬險千艱六出身，如今也得避囂塵。", "須知從此寒原上，有個行歌拾穗人。"]'),
('d64ccdba-2654-4788-9f18-5067b2e2a09a','道中見以索牽五六十人監理錢者','鄭俠','宋','宋诗','song-poetry','','[]','可憐平地不生錢，稚老累累被索連。',32,'全唐诗/poet.song.50000.json','["可憐平地不生錢，稚老累累被索連。", "困苦新圗誰畵此，祗愁中禁又無眠。"]'),
('688503bc-dbd8-4ee9-9b69-5d6590d62882','題靈峰平步亭','鄭俠','宋','宋诗','song-poetry','','[]','天險嘗聞不可升，人間危塹更難名。',32,'全唐诗/poet.song.50000.json','["天險嘗聞不可升，人間危塹更難名。", "欲知平步亭中意，平得心来處處平。"]'),
('4a5f3918-a7cc-4e0c-802c-f43b6b521fad','謾成','鄭俠','宋','宋诗','song-poetry','','[]','琴雖古意元無取，詩近虗名亦懶吟。',32,'全唐诗/poet.song.50000.json','["琴雖古意元無取，詩近虗名亦懶吟。", "不是將心就無事，都緣無事可關心。"]'),
('8161ebf8-2bff-4100-bb50-70d97b0522b0','送呂景山赴虔州理掾','鄭俠','宋','宋诗','song-poetry','','[]','江西古浩穰，昭信雄江濱。',48,'全唐诗/poet.song.50000.json','["江西古浩穰，昭信雄江濱。", "州獄千里平，舒慘繫誾囂。", "景山之胸中，曉然烏兔輪。", "敢爲虔人賀，何以致龍麟。"]'),
('7069f1a4-4dbb-4496-a5a0-98cd129ba808','漫成','鄭俠','宋','宋诗','song-poetry','','[]','衲帽麻衣君勿輕，有如華衮貴難名。',64,'全唐诗/poet.song.50000.json','["衲帽麻衣君勿輕，有如華衮貴難名。", "人須自力方能立，事若無誠斷不成。", "倚物蔓條終嫩脆，冒霜寒柏始堅貞。", "男兒一副黄金骨，莫學伊阿浪死生。"]'),
('0b73572c-c453-4b00-9aeb-60d472882b25','權府黄叔粲朝奉雙門落成之會有感而作','鄭俠','宋','宋诗','song-poetry','','[]','鳳管鸞絲徹太清，雙門今日落功成。',64,'全唐诗/poet.song.50000.json','["鳳管鸞絲徹太清，雙門今日落功成。", "一州壯觀新樓好，千里欣歡太守名。", "已見聲華逾綵絢，更期中外倚端平。", "詳風瑞雨年年事，海角天涯似此城。"]'),
('b7ece8ea-30fe-4e9b-9e6b-f1bf7fe2edc4','漫成','鄭俠','宋','宋诗','song-poetry','','[]','風送微涼來小戶，月回清影向疏窗。',32,'全唐诗/poet.song.50000.json','["風送微涼來小戶，月回清影向疏窗。", "不知人世何珍麗，可與詩書氣味雙。"]'),
('33d54f11-38b0-4bed-91ea-99537ae0753b','仲常龍圖自廣中移帥閩  其一','鄭俠','宋','宋诗','song-poetry','','[]','去年牙戟海邊城，空望門闌涕泗橫。',64,'全唐诗/poet.song.50000.json','["去年牙戟海邊城，空望門闌涕泗橫。", "今日去旄東嚮夢，那知高纛此中迎。", "豈非丈席諧瞻對，亦似雲衢有否亨。", "十有餘年想諄誨，更期朱玉似河傾。"]'),
('93de3b99-8769-4249-9613-75b8566f71aa','仲常龍圖自廣中移帥閩  其二','鄭俠','宋','宋诗','song-poetry','','[]','惠茲政化及民功，內外聲稱有古風。',64,'全唐诗/poet.song.50000.json','["惠茲政化及民功，內外聲稱有古風。", "五嶺山川情正黮，七閩桃李意先通。", "大明繼照天衢闢，重德還朝衆願同。", "早晚皇穹順輿議，老人星在玉堂中。"]'),
('0d06d7d2-bcc7-4afd-85ea-7ad2ee4c3d1e','臨終作','鄭俠','宋','宋诗','song-poetry','','[]','似此平生只藉天，還如過鳥在雲邊。',32,'全唐诗/poet.song.50000.json','["似此平生只藉天，還如過鳥在雲邊。", "如今身畔渾無物，贏得虛堂一枕眠。"]'),
('103edc06-4380-4b67-b6d8-fdff9342d8fa','句','鄭俠','宋','宋诗','song-poetry','','[]','未言路上舟車費，尚欠城中酒藥錢。',16,'全唐诗/poet.song.50000.json','["未言路上舟車費，尚欠城中酒藥錢。"]'),
('f041e982-531c-4f06-99d8-a9dd2090e402','麻姑山','朱京','宋','宋诗','song-poetry','','[]','仙都朝百靈，奇絕衆峰冠。',180,'全唐诗/poet.song.50000.json','["仙都朝百靈，奇絕衆峰冠。", "朝初五馬遊，萬里卷雲幔。", "春陽散地脈，指顧群陰泮。", "刻玉露巉巖，嚴嚴色足憚。", "怪木走獰虬，老藤連朽貫。", "峰勢忽騫騰，天馬脫脩絆。", "飛流三百尺，餘沫拂霄漢。", "空谷隱晴雷，聒耳笑語亂。", "所願化日長，誰憂斧柯爛。", "況復值此時，桃竹分相半。", "乘興事幽尋，頓覺神還觀。", "信步忘險易，履襪遭污漫。", "恣觀融結巧，疑費陰陽炭。", "暝色生四垂，孤煙起樵爨。", "千騎去如飛，夕陽人影散。"]'),
('6a73702f-fe12-4c56-8b20-af59fa3812c9','祥光寺','朱京','宋','宋诗','song-poetry','','[]','山寺藏遺刻，塵埃字半昏。',48,'全唐诗/poet.song.50000.json','["山寺藏遺刻，塵埃字半昏。", "空揮峴首淚，誰起謝公門。", "白石千年像，蒼頭五世孫。", "他年想陳迹，卜築向雲根。"]'),
('9e178a40-0589-4d2a-9281-531cfd27e002','題清芬閣','朱京','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我愛君家似洞庭，却疑身在小蓬灜。',64,'全唐诗/poet.song.50000.json','["我愛君家似洞庭，却疑身在小蓬灜。", "白波潭上魚龍舞，紅葉村中雞犬聲。", "大雅篇章無弟子，高門事業有公卿。", "後來若要知優劣，千古何人繼盛名。"]'),
('92ac7fba-0e47-473f-a08d-9746fe9b3a8d','句','朱京','宋','宋诗','song-poetry','','[]','削成雙峰玉骨清。',8,'全唐诗/poet.song.50000.json','["削成雙峰玉骨清。"]'),
('e8de969f-9b4f-422b-bb32-a465258c1ede','題清芬閣','令狐俅','宋','宋诗','song-poetry','','[]','元英去世二百年，其迹雖久騷雅傳。',128,'全唐诗/poet.song.50000.json','["元英去世二百年，其迹雖久騷雅傳。", "田廬不廢子孫賢，慶門簪組方蟬聯。", "我來源中訪高隱，囗人邀客雲山前。", "朱門綠閣照溪水，長松茂竹囗寒煙。", "灘聲蕭蕭到几席，魂清骨冷忘睡眠。", "伊子出處不自判，塵纓俗網常縈纏。", "兒孫漸多食囗衆，高翔遠引嗟無緣。", "他年家事苟有付，杖藜囗此同悠然。"]'),
('5a11cb17-8dd1-4fb9-9620-73461ef50c51','曾公巖','劉宗傑','宋','宋诗','song-poetry','','[]','謝公高興在東山，尋得仙巖郡邑邊。',64,'全唐诗/poet.song.50000.json','["謝公高興在東山，尋得仙巖郡邑邊。", "萬朵連峰凝碧乳，一溪鳴玉逗寒泉。", "由來物外無塵景，須信壺中有洞天。", "嶺服已安褒詔近，莫將歸夢更留連。"]'),
('013cc072-3060-4209-a280-3e6f17491110','制勝樓','王延禧','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','夔子城新築，長江便作壕。',144,'全唐诗/poet.song.50000.json','["夔子城新築，長江便作壕。", "欲兼諸面敵，故起北樓高。", "即舊基仍峻，因時力不勞。", "青天纔咫尺，翠壁似週遭。", "近照東西瀼，遙分上下牢。", "百蠻歸指掌，三峽見秋毫。", "帝道方無外，皇威到不毛。", "三鉤閑夜鎖，八陣縱春邀。", "守土慚非稱，提兵亦繆叨。", "經營皆使指，備豫本戎韜。", "功乏爲山助，名加制勝褒。", "登臨欲吟咤，深愧杜陵豪。"]'),
('b201008d-05da-4468-ae59-602c83f16280','過龜山','朴寅亮','宋','宋诗','song-poetry','','[]','巖巖峻石疊成山，下著珠蠙一水環。',64,'全唐诗/poet.song.50000.json','["巖巖峻石疊成山，下著珠蠙一水環。", "塔影倒垂淮浪底，鐘聲搖落碧雲間。", "門前客棹洪濤急，竹下僧棋白日閑。", "一奉勝遊堪惜景，故留詩句約重還。"]'),
('89023650-28d5-43df-8665-2a6634bcee16','句','朴寅亮','宋','宋诗','song-poetry','','[]','萬疊危岑天倚杵，一竿斜日水浮金。',16,'全唐诗/poet.song.50000.json','["萬疊危岑天倚杵，一竿斜日水浮金。"]'),
('64d5fcff-9220-4507-91c7-ece5d68d92ff','句','張介','宋','宋诗','song-poetry','','[]','應是子規啼不到，致令我父未歸家。',16,'全唐诗/poet.song.50000.json','["應是子規啼不到，致令我父未歸家。"]'),
('78401b3f-206d-438a-8647-a23b0232eeea','句  其一','能長老','宋','宋诗','song-poetry','','[]','僧家祗合在深山。',8,'全唐诗/poet.song.50000.json','["僧家祗合在深山。"]'),
('0ed40655-1528-4f28-b384-4db3c4eaae25','句  其二','能長老','宋','宋诗','song-poetry','','[]','待到黄龍鱗甲備。',8,'全唐诗/poet.song.50000.json','["待到黄龍鱗甲備。"]'),
('a52703cb-974d-49fa-aaaf-f544cdb3149a','虎溪二首  其一','林仲嘉','宋','宋诗','song-poetry','','[]','山闊青連海，溪長綠繞城。',24,'全唐诗/poet.song.50000.json','["山闊青連海，溪長綠繞城。", "規模唐故郡，弦誦魯諸生。"]'),
('6d444b6a-f3fc-4050-8159-5f0510c1c3ee','虎溪二首  其二','林仲嘉','宋','宋诗','song-poetry','','[]','白日經檐短，風霜路客衣。',24,'全唐诗/poet.song.50000.json','["白日經檐短，風霜路客衣。", "梅梢驚歲晚，沙際看春歸。"]'),
('3faf88e6-0a1e-44cf-ab70-a9b63faf265e','寄父','王氏','宋','宋诗','song-poetry','','[]','西風不入小窗紗，秋氣應憐我憶家。',32,'全唐诗/poet.song.50000.json','["西風不入小窗紗，秋氣應憐我憶家。", "極目江南千里恨，依然和淚看黄花。"]'),
('edfbce0e-1a90-4984-8431-efbc9ce0e10e','戲咏白羅繫髻','王氏','宋','宋诗','song-poetry','','[]','香羅如雪縷新裁，惹在烏雲不放回。',32,'全唐诗/poet.song.50000.json','["香羅如雪縷新裁，惹在烏雲不放回。", "還似遠山秋水際，夜來吹散一枝梅。"]'),
('05aec2f8-36ba-44e8-9e4f-d559cd11d26c','拋毬曲三首  其一','李慎言','宋','宋诗','song-poetry','','[]','侍宴黄昏未肯休，玉階夜色月如流。',32,'全唐诗/poet.song.50000.json','["侍宴黄昏未肯休，玉階夜色月如流。", "朝來自覺承恩最，笑倩傍人認繡毬。"]'),
('dae0bf00-173d-46b3-ab6e-2fc728ee3844','拋毬曲三首  其二','李慎言','宋','宋诗','song-poetry','','[]','隋家宮殿鎖清秋，曾晚嬋娟颺繡毬。',32,'全唐诗/poet.song.50000.json','["隋家宮殿鎖清秋，曾晚嬋娟颺繡毬。", "金钥玉簫俱寂寂，一天明月照高樓。"]'),
('282a8ed4-e84f-4271-99f1-da170a309f99','拋毬曲三首  其三','李慎言','宋','宋诗','song-poetry','','[]','堪恨隋家幾帝王，舞腰緩盡繡鴛鴦。',32,'全唐诗/poet.song.50000.json','["堪恨隋家幾帝王，舞腰緩盡繡鴛鴦。", "如今重到拋毬處，不見熏爐舊日香。"]'),
('da473aae-d184-450b-8381-e761fdc935c9','忠孝圖','彭汝礪','宋','宋诗','song-poetry','','[]','君親等乾坤，恩義俱罔極。',240,'全唐诗/poet.song.50000.json','["君親等乾坤，恩義俱罔極。", "浮生一毫髮，盡出覆載力。", "我思古之人，節義有遺則。", "以身託萬事，糜殞終無嗇。", "名教落編簡，不與日月蝕。", "世薄道亦微，綱常墮荆棘。", "想像不可追，徘徊意悽惻。", "燕卿真士雄，繪素見顔色。", "謀惟引深思，摩揣窮多識。", "金朱寵純懿，斧鉞誅姦慝。", "欲將春秋法，轉徙示九域。", "肥陵泮宮庭，收拾在四壁。", "千年土中身，精神回翰墨。", "崢嶸列星辰，奴隸生歎息。", "已死疑可求，欲語嗟復默。", "清風颯冰霜，直氣森劍戟。", "富貴喜圖畫，蓄聚窮千億。", "丹青彼雖工，龜鑑吾自得。", "願言同此心，論世師盛德。", "當使忠孝風，自家刑邦國。"]'),
('9ae3d17e-2d34-4b3f-a3ec-47266d396d1e','宿萬孝子家','彭汝礪','宋','宋诗','song-poetry','','[]','昔人迴車勝母里，今我枉步孝子家。',96,'全唐诗/poet.song.50000.json','["昔人迴車勝母里，今我枉步孝子家。", "天寒日暮林谷暗，回旋道路甘泥沙。", "高臺隆隆起門戶，松檜夾逕清陰斜。", "縣官把燭讀碑字，夜闌相視生咨嗟。", "今我爲詩語萬氏，萬事成難敗之易。", "爾家承承今幾年，勉旃無爲先世累。"]'),
('bcbc8d6d-4f88-4d76-b747-d7c447520e51','七門堰','彭汝礪','宋','宋诗','song-poetry','','[]','古人材大心亦公，憂樂每與天下同。',176,'全唐诗/poet.song.50000.json','["古人材大心亦公，憂樂每與天下同。", "謀功慮事不草草，欲與天地爲無窮。", "我來舒城道三堰，行看利入東南徧。", "漁樵處處樂太平，稻粱歲歲收餘羨。", "江淮旱澇相綴聯，舒城獨自爲豐年。", "人知今日樂其土，不知古人爲爾天。", "二劉未必真奇偉，謀慮及民乃如此。", "俗儒文多實已亡，洋洋大論言羲皇。", "心欲爲功害輒勝，醫庸未足平膏肓。", "紛紛予亦何爲者，愛古傷今空涕灑。", "題詩倚立寄西風，不知材力非騷雅。"]'),
('14ded8f3-93aa-4fe6-80bd-a2131d738771','金星硯行','彭汝礪','宋','宋诗','song-poetry','','[]','星出雲之端，石在溪之潯。',177,'全唐诗/poet.song.50000.json','["星出雲之端，石在溪之潯。", "天上地下相絕幾百千萬里，硯中安得有星點點明如金。", "既非瑕掩瑜，又似徽在琴。", "我疑星之飛流運動或不居，精采誤落黟流深。", "不然神靈憫惻學士久濡滯，故借光景資清吟。", "或有感此理，杳默難推尋。", "君不見虢山之石團團有桂在中象圓月，又不見廬江之石扶疏有木相樛爲寒林。", "無重言，但置寒窗筆札往古研于今。", "大剛無睢睢，至明無陰陰。", "君也能如此，是真金星硯之知音。"]'),
('4dfcbe12-8a15-4796-9f46-3d79db88543f','選仙圖','彭汝礪','宋','宋诗','song-poetry','','[]','自昔黄老言無爲，謬說汗漫爲神仙。',128,'全唐诗/poet.song.50000.json','["自昔黄老言無爲，謬說汗漫爲神仙。", "古人力探源未塞，今世復用根尤堅。", "仙經自是物外來，畫圖誰向人間傳。", "碧油堂印始等差，洞天福地分後先。", "勢窮或滯酆都幽，採勝即上崑崙巔。", "得失無端見掌握，勝負有勢生迴旋。", "終朝相視何爲哉，萬事不齊俱偶然。", "物雖無庸意甚遠，爲子探取題詩篇。"]'),
('b4db7013-d5fd-486d-8a44-5f25a9a1cfd7','李卿惠太平州學詩','彭汝礪','宋','宋诗','song-poetry','','[]','李侯昔也治當塗，作學以遺當塗民。',160,'全唐诗/poet.song.50000.json','["李侯昔也治當塗，作學以遺當塗民。", "謠言散落在樵牧，事迹收拾歸瑶珉。", "高文大字比珠玉，長與後世爲奇珍。", "我因李侯念往初，黨庠遂序明人倫。", "井田變更萬事廢，士林泣血悲孤秦。", "今人思慮到本原，願見風俗終還醇。", "嘗聞君子天下志，一視萬物無疏親。", "侯來我邦嗣其兄，愛惜不後當塗人。", "即視學宮動風采，復尊師席尸陶鈞。", "道路尚思前召父，閭閻敢忘小馮君。"]'),
('5c117958-d9d7-481d-87d3-3665ae1ca4a2','瓦鼓','彭汝礪','宋','宋诗','song-poetry','','[]','客游南昌歸，歸我四瓦鼓。',120,'全唐诗/poet.song.50000.json','["客游南昌歸，歸我四瓦鼓。", "渾完自甄冶，質樸排罌甒。", "觸之散遺聲，往往中商羽。", "聲來殆天得，不用詢有瞽。", "野心愛不徹，取之置林宇。", "竹梢奏清風，似喜佳物伍。", "岸巾策筇杖，共爾蠲毒暑。", "世浮見此拙，坐覺幽興聚。", "丹楹惜異時，蕢桴想淳古。", "君年比予少，能亦珍此否。"]'),
('8fae2012-a77e-4e09-b3f6-793bda644589','寄佛印禪師','彭汝礪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','遣奴持書問雲居，我今持節行匡廬。',112,'全唐诗/poet.song.50000.json','["遣奴持書問雲居，我今持節行匡廬。", "請服磨衲大牛車，來飯香積及雕胡。", "舍施琥珀及珊瑚，滄海徑寸之明珠。", "師應問吾今何如，謂方據案治文書。", "較量貴賤調盈虛，擒取猾吏如捕狐。", "夜凉飲酒一百壺，醉視萬物渾錙銖。", "雲居若言太粗疏，謂我寄聲謝云吁。"]'),
('07af5a8b-10e3-490f-b8ce-733b00815618','去年行建昌作詩招雲居元禪師近過南康不見用前韵馳寄','彭汝礪','宋','宋诗','song-poetry','','[]','雕金閒璧雲中居，臥龍更有文公廬。',112,'全唐诗/poet.song.50000.json','["雕金閒璧雲中居，臥龍更有文公廬。", "門前不設羊牛車，誰捋虎鬚跋狼胡。", "寶林環繞千珊瑚，中間一點摩尼珠。", "游戲樂說心如如，諸方傳錄爲奇書。", "愛師談實非空虛，生决定信無疑狐。", "表裏洞徹如冰壺，輕重已自分錙銖。", "咫尺祇恨相逢疏，各自有口能無吁。"]'),
('d5865c01-520c-40b5-a280-28be087f4d48','答趙溫甫見謝茶甌韵','彭汝礪','宋','宋诗','song-poetry','','[]','我昔曾涉昌江濱，故人指我觀陶鈞。',160,'全唐诗/poet.song.51000.json','["我昔曾涉昌江濱，故人指我觀陶鈞。", "龐眉老匠矜捷手，爲我百轉雕輿輪。", "鎸刓刻畫走風雨，須臾萬態增鮮新。", "盤龍飛鳳滿日月，細花密葉生瑶珉。", "輕浮兒女愛奇崛，舟浮輦運傾金銀。", "我盂不野亦不文，渾然美璞含天真。", "光沉未入世人愛，德潔誠爲天下珍。", "朅來東江欲學古，喜聽英傑參吾倫。", "謹持清白與子共，敢因泥土邀仁恩。", "空言見復非所欲，再拜謝子之殷勤。"]'),
('11c88c01-962a-43c7-8980-77f5ec0cc8b9','雪夜飲分題得雪字','彭汝礪','宋','宋诗','song-poetry','','[]','顛風夜號花木折，平明階前三尺雪。',131,'全唐诗/poet.song.51000.json','["顛風夜號花木折，平明階前三尺雪。", "誰家羌笛落早梅，中夜南樓對明月。", "苦寒侵人毛髮縮，厭厭夜飲腸內熱。", "公才奔放欲萬里，應恨低徊受羈紲。", "一巢安穩身自在，生涯却羨鳲鳩拙。", "人生所值俱所樂，萬事悠悠無可說。", "偶有名酒須盡醉，醉輒題詩如靖節。", "君不見萬卒征南凱未旋，戎衣雖厚冷如鐵。"]'),
('afb0a8f6-f4b0-4d75-9678-8a4716d5d26c','和深之飲字','彭汝礪','宋','宋诗','song-poetry','','[]','窮陰方欲歸，故故作凝凜。',120,'全唐诗/poet.song.51000.json','["窮陰方欲歸，故故作凝凜。", "乾坤幾日雪，晝作宵還甚。", "寒威鎮氛沴，和氣生豐稔。", "君子有酒食，健啖亦豪飲。", "虀鹽本吾味，笑此已多品。", "芬芳臭如蘭，爛熳文似錦。", "夜闌燭花低，更轉鳥聲噤。", "私飲樂已湛，情話言尤審。", "駑才負荷重，終夕無安寢。", "樓頭鐘幾聲，展轉屢欹枕。"]'),
('17a1722f-fa3c-4037-a7bc-9b9389d05af7','和亶甫夜字','彭汝礪','宋','宋诗','song-poetry','','[]','雪輕不自持，風急更相借。',156,'全唐诗/poet.song.51000.json','["雪輕不自持，風急更相借。", "仙人集蓬島，鴻鵠雲中下。", "飛騰障空虛，細碎穿隙罅。", "光明入幽室，晃耀不知夜。", "苦寒爲公飲，酒盡解貂貰。", "盤蔬起鄉思，披綿問鵝鮓。", "浮生夙何緣，今昔同官舍。", "才調稍迫促，每羨公優暇。", "草玄入幽微，曾不解嘲駡。", "文衡委輕重，事亦宗伯亞。", "我愚實未稱，得友還自詫。", "兩驂萬里心，雙璧連城價。", "塵土難淹留，雲霄看高跨。"]'),
('b2ffd399-bf22-4e3b-919b-764abed52fec','和執中游山四詩 谷隠寺 其一','彭汝礪','宋','宋诗','song-poetry','','[]','谷隠多牡丹，一花百千葉。',48,'全唐诗/poet.song.51000.json','["谷隠多牡丹，一花百千葉。", "一根出一切，一切一根攝。", "愛君看花處，立悟恒沙劫。", "其誰知此意，祇有花間蝶。"]'),
('cf1850a3-4f52-44a1-b8a3-a63bb7c21b12','和執中游山四詩 谷隠寺 其二','彭汝礪','宋','宋诗','song-poetry','','[]','樓閣倚天外，鐘梵落人間。',48,'全唐诗/poet.song.51000.json','["樓閣倚天外，鐘梵落人間。", "俗客有時去，野僧長日閑。", "白雲何所往，飛鳥未能還。", "一望輒一歎，令人唯厚顔。"]'),
('48a677e6-2707-4aae-a234-1f1025e2c8d4','和執中游山四詩 峴山','彭汝礪','宋','宋诗','song-poetry','','[]','甘棠如衆木，峴首如衆山。',60,'全唐诗/poet.song.51000.json','["甘棠如衆木，峴首如衆山。", "燕人愛召公，公去不忍攀。", "襄陽思叔子，墮淚濕孱顔。", "至今山外溪，日夜波瀾翻。", "如公章貢祠，亦在山水間。"]'),
('42e68cff-42c9-4ae8-b35d-c40cb6fa5055','和執中游山四詩 高陽池','彭汝礪','宋','宋诗','song-poetry','','[]','三年南雍居，十至高陽池。',48,'全唐诗/poet.song.51000.json','["三年南雍居，十至高陽池。", "魚鳥如故人，相忘不相疑。", "但持青蓮葉，不倒白接䍦。", "我與之子游，何似山公時。"]'),
('5579ec20-c415-4952-8a95-fdc6eeeb48ca','內鄉山中  其一','彭汝礪','宋','宋诗','song-poetry','','[]','野人住山中，不見山色好。',48,'全唐诗/poet.song.51000.json','["野人住山中，不見山色好。", "我行久塵土，窺覽慰懷抱。", "禹稷不乏人，翻焉憶商皓。", "使我有以食，甘於此山老。"]'),
('1cf5ba38-b9cc-4b75-a577-097e2424daaf','內鄉山中  其二','彭汝礪','宋','宋诗','song-poetry','','[]','靜喧豈殊途，能靜理亦好。',48,'全唐诗/poet.song.51000.json','["靜喧豈殊途，能靜理亦好。", "所以見山色，愛之置懷抱。", "攬鏡照鬚髮，已如霜雪皓。", "吾方與神遊，未肯塵土老。"]'),
('00499088-e1ee-4281-b845-73d8c1b90b08','寄葉法曹','彭汝礪','宋','宋诗','song-poetry','','[]','參軍琢玉爲天性，靈臺一點秋江靜。',128,'全唐诗/poet.song.51000.json','["參軍琢玉爲天性，靈臺一點秋江靜。", "少年勤苦取富貴，不知勤苦今爲病。", "世人喜邪疾中正，愛君與物終無競。", "圍棋坐爭百局勝，雕弓力挽六鈞勁。", "棋子勞神弓力硬，此圖養疾俱非令。", "作詩勸君今勿更，詩書自足資游泳。", "奧室重簾鎖幽徑，我不見君心怲怲。", "疾病勿憂有天命，愷悌君子神所慶。"]'),
('c05de4ad-d4b3-4dc7-97f5-7e203cea162f','送皇甫法曹','彭汝礪','宋','宋诗','song-poetry','','[]','始余來肥陵，問士得皇甫。',72,'全唐诗/poet.song.51000.json','["始余來肥陵，問士得皇甫。", "經年在閭巷，不肯出公府。", "樽俎獻酬間，爲之賦翹楚。", "今上襄陽官，拙詩愧兼取。", "襄陽真名區，碑碣字多古。", "能因東南風，取以寄予否。"]'),
('cc374a5a-4016-4990-899e-f7204c6cd8c9','寄友人','彭汝礪','宋','宋诗','song-poetry','','[]','漢上近多雨，江頭應好風。',84,'全唐诗/poet.song.51000.json','["漢上近多雨，江頭應好風。", "想君當此際，掛席隨孤鴻。", "翔龍壓大浪，畫鷁凌長空。", "男子四方志，生時射桑蓬。", "爾來何遲遲，吾憂祇忡忡。", "安得百頃田，稍鄰五老峰。", "早賦歸去來，同爲採芝翁。"]'),
('bdf85648-4584-40de-ba85-3e93ed5c5525','和君時弟見貽一首','彭汝礪','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鳬短非不足，鶴長非有餘。',96,'全唐诗/poet.song.51000.json','["鳬短非不足，鶴長非有餘。", "泰山逮毫芒，其理固一如。", "君才乃驊騮，行矣無踟躕。", "萬里不加鞭，日力復有舒。", "豈如老鈍馬，寸進徒渠渠。", "低頭戀棧豆，時復仰天噓。", "徊徨槽櫪間，不用論智愚。", "惟中可以休，吾與子歸歟。"]'),
('535d677b-45d8-48f0-b258-cf9f9cf6acd0','送范侍郎歸許昌一首','彭汝礪','宋','宋诗','song-poetry','','[]','鳳鳥蹌蹌，其羽儀儀。',170,'全唐诗/poet.song.51000.json','["鳳鳥蹌蹌，其羽儀儀。", "其集伊何，梧桐之枝。", "鴻飛冥冥，其翼差差。", "其止伊何，清泠之池。", "朝廷於公，夫豈不知。", "國有大疑，爰度爰咨。", "公雖家居，如在廟堂。", "國之大經，論討靡忘。", "徐徐公車，在汴之郊。", "薄言追之，以永今朝。", "汎汎公舟，在河之陰。", "薄言維之，以慰我心。", "公賜我言，我斯藏之。", "何以報之，羔羊素絲，秉德不遺。", "公飲我酒，我斯酬之。", "何以祝之，秀髮龐眉，受福無期。"]'),
('314f03a3-e2ca-431f-8047-7437fa569b23','讀史','彭汝礪','宋','宋诗','song-poetry','','[]','婁敬脫輓輅，獨建金城安。',60,'全唐诗/poet.song.51000.json','["婁敬脫輓輅，獨建金城安。", "韓信出羈旅，遽上將軍壇。", "謀出萬乘驚，名飛百夫歎。", "丈夫松桂姿，直氣虹霓蟠。", "得時樹功業，未謝婁與韓。"]'),
('0e855cfc-8532-4847-af01-2eec6b84c254','管仲有老母','彭汝礪','宋','宋诗','song-poetry','','[]','王陽爲孝子，王尊未能非。',48,'全唐诗/poet.song.51000.json','["王陽爲孝子，王尊未能非。", "管仲有老母，鮑叔獨能知。", "同途不同行，亦各有所思。", "今或有斯人，執鞭吾不辭。"]'),
('4c6ae88a-dd4f-4b0b-8302-649c02336bb1','暴雨','彭汝礪','宋','宋诗','song-poetry','','[]','雲如驚瀾如潑墨，萬竅怒號四山黑。',384,'全唐诗/poet.song.51000.json','["雲如驚瀾如潑墨，萬竅怒號四山黑。", "電母摇睛嚇風伯，疾雷怒張坤軸側。", "雨如河傾如雨石，上山下山泉動脈。", "石漂木拔崖裂坼，高原立脚成大澤。", "古寺顛前後岡逼，瓦腐椽折破無壁。", "泥佛露頭水浸臆，苔錢藤蔓生金碧。", "背堂衆流如箭激，挾氣急欲投閒隙。", "衣掣脚芒看溝淢，有惻烝徒老荆棘。", "荷戈與殳甲不釋，中夕愁居晝艱食。", "我今乃敢求安席，閭閻人家水沒極。", "壯夫浮泅老者溺，高占鳥巢據猨杙。", "可憐欲走無羽翮，我起熟視惟歎息。", "斷蘗棲苴在簷額，雞飛犬跳上屋脊。", "蛟黿睥睨迷所宅，乾坤欲晴但頃刻。", "廣庭泥深猶數尺，大浪如銀沸阡陌。", "萬馬相踶轂相擊，窮民欲炊無釜鬲。", "蚯蚓在堂魚在閾，兒童捕魚不知戚。", "溪南不能過溪北，跬步如越與胡隔。", "溺者漫不見蹤跡，東村西村哭聲塞。", "手援不能淚沾臆，掩胔雖欲終何益。", "天理吁嗟杳難測，惸獨無辜不愛惜。", "葬填溪魚瘞砂礫，乃能屈折容盜賊。", "鑿險開深聽藏匿，不以血膋膏鋒鏑。", "皇天無情禍福直，昔也昭昭今也惑。"]'),
('d2ec8af7-2212-47a4-8699-203907f26ca3','和執中游山','彭汝礪','宋','宋诗','song-poetry','','[]','峨峨楚山前，屹屹樊堞後。',288,'全唐诗/poet.song.51000.json','["峨峨楚山前，屹屹樊堞後。", "汗漫清漢左，蜿蜒大堤右。", "雷霆沸波瀾，龍虎臥岡阜。", "春風無偏陂，潤澤到藜莠。", "日月有底急，匆匆似奔走。", "樂哉城南游，矧復得智叟。", "橫踰路東頭，縱踏山北口。", "逶迤陟嶔崟，莽蒼度林藪。", "巍亭立青冥，隠几見十部。", "崖石險欲落，參差露妍醜。", "沉深開殿閣，闕穴得圈臼。", "尚或埋泥塗，誰能斬薪槱。", "法海惟我汎，禪關與君叩。", "清泉給醍醐，一飲失塵垢。", "丹鳳杳不來，瞻想更搔首。", "潭潭谷中寺，花木照堂坳。", "樓閣守岧嶢，敧危貼星斗。", "白雲雜香霧，終日在戶牖。", "有沼旱不枯，金蓮豈凡偶。", "不見白馬至，似聞蒼龍吼。", "一雨作豐年，歡愉逮雞狗。", "稅車高陽池，遺事問黄耉。", "歎息當世士，所懷自非苟。", "方醉白接䍦，寧貴朱組綬。"]'),
('c57e4673-c8d0-44c7-88bf-cd13d1d275ba','次韵堯民同年','彭汝礪','宋','宋诗','song-poetry','','[]','飛雪鱠長鯨，浮蛆醱新酒。',144,'全唐诗/poet.song.51000.json','["飛雪鱠長鯨，浮蛆醱新酒。", "故人不我過，絕壁頻回首。", "北岡無斷絕，參錯紛燕豆。", "觸目事斬新，愴懷治平舊。", "龍飛第一牓，四百如蘭友。", "勁氣沮金石，高文爛星斗。", "我衰也久矣，彫落幾無有。", "未去真厚顔，欲歸猶掣肘。", "盤根發餘刃，想見敏捷手。", "江河被郛郭，雲霧生戶牖。", "顧瞻良集易，歎息幽期後。", "興到詩輒成，吾窮久箝口。"]'),
('aaf141ba-ed4e-4d75-8caa-7dde4080b2da','答同舍游凝祥池','彭汝礪','宋','宋诗','song-poetry','','[]','仙宮神靈之所宅，樓閣倚天一千尺。',160,'全唐诗/poet.song.51000.json','["仙宮神靈之所宅，樓閣倚天一千尺。", "先生好游猶挾冊，藜莧不慚吾鼎食。", "凝祥池頭三月春，腰金騎狨多貴人。", "天邊五岳烟霞闊，海上三山雨露新。", "蛺蝶能飛燕能舞，鳳凰在雲鴻在渚。", "仙人驂鸞入雲霧，寂寂不聞青鳥語。", "洞天落日晚沉沉，漁舟縹緲桃源深。", "紅玉坐看花著子，青雲行見葉成陰。", "疾雷怒飛風雨急，瘦馬不行歸旆濕。", "投閒一日須一來，歲時變化猶呼吸。"]'),
('c928d7b6-349f-40eb-a44b-42fda7b11601','栽竹','彭汝礪','宋','宋诗','song-poetry','','[]','一生正能著幾屐，曠達人稱阮遙集。',64,'全唐诗/poet.song.51000.json','["一生正能著幾屐，曠達人稱阮遙集。", "何可一日無此君，風流我愛王參軍。", "夏葛冬裘吾便足，由來世間無可欲。", "但栽翠竹滿東林，我日對之歌且吟。"]'),
('6a5255c4-8af6-489a-8ff9-f66d03ada155','送君宜之臨城簿二首  其一','彭汝礪','宋','宋诗','song-poetry','','[]','人之與萬物，異名而同體。',120,'全唐诗/poet.song.51000.json','["人之與萬物，異名而同體。", "貴賤何以殊，知與不知爾。", "知之莫如學，學莫如修己。", "汝學自有得，願言惟不已。", "不已須自到，不到由中止。", "請觀爲田者，日夜服耒耜。", "久之田自熟，其入須倍蓰。", "至于耕耘廢，稂莠敗穈芑。", "常時不用力，畬穫終無幾。", "予與爾知田，肆言聊及此。"]'),
('92af7e44-2b15-4b33-9d8e-a85778341088','送君宜之臨城簿二首  其二','彭汝礪','宋','宋诗','song-poetry','','[]','事賢如事親，敬長如敬兄。',96,'全唐诗/poet.song.51000.json','["事賢如事親，敬長如敬兄。", "讀書如喫飯，近欲如近兵。", "百事總欲是，一言不可輕。", "汝能慎於初，更欲觀厥成。", "仲兮舍予南，汝今復北去。", "南北牽我夢，終夕無定處。", "但寄兩眼淚，爲君衣上露。", "會知老者心，從爾無早暮。"]'),
('452aab64-d232-45ce-93f7-85dc68736bf1','送范侍郎帥慶州得以字','彭汝礪','宋','宋诗','song-poetry','','[]','池水日夜流，日行無停軌。',120,'全唐诗/poet.song.51000.json','["池水日夜流，日行無停軌。", "人生長道路，擾擾還如此。", "莫辭飲我酒，酒盡君且起。", "贈君雙寶劍，有言慚近俚。", "聖人之於物，愛視猶赤子。", "顧復愁不至，不知分此爾。", "誰歟較尋尺，竟未知所以。", "夷外當反內，刮毛須及裏。", "邊陲今無事，自可緩带理。", "願君宏遠業，赫赫光祖禰。"]'),
('bcf4524c-3e4e-492a-b537-98841bfffcda','送穎叔帥臨洮','彭汝礪','宋','宋诗','song-poetry','','[]','風如疾雷雹如芋，積雪如丘壅道路，蔣侯車馳挽不住。',160,'全唐诗/poet.song.51000.json','["風如疾雷雹如芋，積雪如丘壅道路，蔣侯車馳挽不住。", "見說西人復嘯聚，目視陰山欲飛去。", "蔣侯文如江海注，一决萬里無盡處。", "筆落在紙成雲霧，氣吞雲夢八九數。", "力轉丘山縛螭虎，終日笑言公不怒。", "三軍號令成樽俎，羌戎膽落汗流跗，邊人乃至歌五袴。", "昔誇禁中得頗牧，今見南陽稱召杜。", "前席宣室疑已暮，勒功燕然無可慕。", "歸來遍作人間雨，杕杜吾當爲君賦。"]'),
('66822660-992b-4f42-ac2f-e6eeeb33da61','舟中大熱夜半起坐因作是詩寄諸友','彭汝礪','宋','宋诗','song-poetry','','[]','星辰與天旋，河漢入地流。',96,'全唐诗/poet.song.51000.json','["星辰與天旋，河漢入地流。", "其行雖不同，晝夜不自休。", "彼能致其誠，豈不至誠猶。", "如何爾爲士，乃不彊厥脩。", "功不償其食，不如馬與牛。", "金朱豈不寵，顧視祇可羞。", "誰謂古之人，乃無一可憂。", "何以圖厥終，尚惟友之求。"]'),
('30f6b25d-e15a-484d-aae2-f2d5bd083338','彥衡約飲湖亭行不及赴','彭汝礪','宋','宋诗','song-poetry','','[]','主人欲留客，其意良已厚。',108,'全唐诗/poet.song.51000.json','["主人欲留客，其意良已厚。", "行人念行役，奔命惟恐後。", "張帆半夜起，撇若驚蓬走。", "盈盈水中蓮，鬰鬰堤上柳。", "相別不相見，已行更迴首。", "人生如朝露，理固無可久。", "可爲惟爲德，萬一或不朽。", "行也死後已，庶猶無大咎。", "君恩不勝報，聊一報我友。"]'),
('fe2f8359-c470-4214-97d9-36888fa7a0dc','宋履中示月桂佳篇并聖俞詩因賦四韵','彭汝礪','宋','宋诗','song-poetry','','[]','古人種花昔已老，後人種花今更好。',64,'全唐诗/poet.song.51000.json','["古人種花昔已老，後人種花今更好。", "聽詩令人饑頓飽，歎息古人不可到。", "庭中花落君勿掃，醉飲全勝藉幽草。", "白髮不嫌花壓帽，寄聲我友車先膏。"]'),
('035a8438-2e44-44c0-a8d9-b393242a7f52','再用前韵書呈諸友學士','彭汝礪','宋','宋诗','song-poetry','','[]','凡花朝開暮即老，仙桂春花秋更好。',64,'全唐诗/poet.song.51000.json','["凡花朝開暮即老，仙桂春花秋更好。", "幽砌終年看不飽，洞門無日春不到。", "玉樽一挹把筆掃，跂脚詩成不立草。", "醉倒淋漓應落帽，衣襟沾溼雲如膏。"]'),
('27e4be18-9954-4d93-9af4-95b4b2b2eb56','察院學士灸焫連日戲作鄙句','彭汝礪','宋','宋诗','song-poetry','','[]','截艾作炷大如椽，三日徹夜燒丹田。',192,'全唐诗/poet.song.51000.json','["截艾作炷大如椽，三日徹夜燒丹田。", "心腹生火口生烟，皮毛潤澤骨骼堅。", "舍杖趨走脚輕儇，赫如渥丹顔色鮮。", "五十六歲如少年，顧我一生百迍邅。", "病多未老先華顛，欲灸自量無罪愆。", "一切久矣付諸緣，三月人家花欲燃。", "陽春水色碧於天，更欲載公青翰船。", "喚取佳人舞繡筵，一飲一斗醉不眠。", "不怕世人笑逃禪，火中自會生金蓮。", "作詩問公奚若旃，肌肉忍自投戈鋋。", "亶顧厥後勤著鞭，萬事悉置心超然。", "服食不須求汞鉛，公名已自列諸仙。"]'),
('600327ad-3037-4b82-87ee-6c7f5e2f29b7','再用前韵呈察院學士','彭汝礪','宋','宋诗','song-poetry','','[]','真人養真如養源，道士耕道如耕田。',192,'全唐诗/poet.song.51000.json','["真人養真如養源，道士耕道如耕田。", "吐納日月踏雲烟，牢如金石齒牙堅。", "捷如猨猱身體儇，沐浴露霧甚榮鮮。", "受命一萬有千年，既安且樂無迴邅。", "後人好惡紛倒顛，湎淫蠱惑作罪愆。", "墮落世網縛塵緣，愛河流轉業火燃。", "猗公淡泊其得天，泛泛乘世如虛船。", "精神采色照四筵，老鶴飲露夜不眠。", "戲笑中有第三禪，凈不著水花如蓮。", "酬酢不停奚敏旃，賦詩馬上橫殳鋋。", "不放祖生先着鞭，北方灸焫自古然。", "其力十百倍凡鉛，功成不數飲中仙。"]'),
('fc9c9716-6f8b-4f24-89e1-2b9ae4a13e38','是非寄君時','彭汝礪','宋','宋诗','song-poetry','','[]','一或以爲是，一或以爲非。',36,'全唐诗/poet.song.51000.json','["一或以爲是，一或以爲非。", "是非如環中，畢竟無窮時。", "汝唱我其從，嗟吾亦何爲。"]'),
('da16279b-031b-41be-9bc5-690c260d1027','自然','彭汝礪','宋','宋诗','song-poetry','','[]','皇天典下民，實亦付自然。',60,'全唐诗/poet.song.51000.json','["皇天典下民，實亦付自然。", "禍福與是非，日夜相推遷。", "譬猶泥在鈞，隨分有醜妍。", "醜非其所惡，妍非其所憐。", "彼憐吾不知，方知樂其天。"]'),
('ed931592-c4a4-4b19-b459-c6f85eb6e87c','行西城','彭汝礪','宋','宋诗','song-poetry','','[]','我將行西城，曲指計日月。',84,'全唐诗/poet.song.51000.json','["我將行西城，曲指計日月。", "汝來今幾時，已卜錢塘別。", "吾衰况多病，冉冉鬢已雪。", "安能久去汝，漫自投羈紲。", "田園苟可飯，聲利非吾屑。", "與汝歸去來，相看至耆耋。", "蒼茫尚無涘，空復愁如結。"]'),
('70f5fab4-950c-401b-820e-bed47066f0f7','漢上謁劉執中','彭汝礪','宋','宋诗','song-poetry','','[]','塵土能污人，有如衣匪澣。',60,'全唐诗/poet.song.51000.json','["塵土能污人，有如衣匪澣。", "驅車出闉闍，縱目盡江漢。", "漁舟泛青雲，瀟灑雁爲伴。", "蘆花如飛雪，時逐風散漫。", "可憐獨清人，憔悴行澤畔。"]'),
('fb0db279-a249-49ac-9259-7cd59a702508','答君時用前韵','彭汝礪','宋','宋诗','song-poetry','','[]','振衣近滄浪，聊以垢膩澣。',60,'全唐诗/poet.song.51000.json','["振衣近滄浪，聊以垢膩澣。", "仰首冥冥雁，肅肅在雲漢。", "吾今寡所合，爾獨爲吾伴。", "蕩舟泛江海，四顧畏汗漫。", "君看水中坻，不是無邊畔。"]'),
('b255aa17-630a-4378-86e2-c052c60e8105','口占和君時','彭汝礪','宋','宋诗','song-poetry','','[]','吾生有窮通，吾志不可衰。',120,'全唐诗/poet.song.51000.json','["吾生有窮通，吾志不可衰。", "飄飄如浮雲，富貴我何爲。", "我今樂不淺，我歌爾其隨。", "譬猶富者家，畜聚不可訾。", "怡怡任天真，何害爲偲偲。", "人惟學不學，高下成雲泥。", "是非惟所求，萬物豈我私。", "君看鑑中明，不隠嫫母媸。", "君病本自無，吾藥奚所施。", "惟作日新銘，與汝同爲規。"]'),
('1fcd0900-0e00-4efb-a325-b5c3ef17955d','菊苗  其一','彭汝礪','宋','宋诗','song-poetry','','[]','重陽黄菊花，零落殆無有。',48,'全唐诗/poet.song.51000.json','["重陽黄菊花，零落殆無有。", "微陽動淵泉，嫩葉出枯朽。", "青青好顔色，寂寥霜雪後。", "物理如轉環，開花豈其久。"]'),
('c3d41bdb-9387-4a76-87e1-7338ed078aa5','菊苗  其二','彭汝礪','宋','宋诗','song-poetry','','[]','物理如轉環，昔亡乃今有。',48,'全唐诗/poet.song.51000.json','["物理如轉環，昔亡乃今有。", "眷言籬邊菊，根葉未終朽。", "盛衰各一時，何足競先後。", "彼花似無情，能並天地久。"]'),
('020cd77c-c48e-4673-8c87-1eecadc900dc','採葵','彭汝礪','宋','宋诗','song-poetry','','[]','古人採薇蕨，我亦愛斯葵。',48,'全唐诗/poet.song.51000.json','["古人採薇蕨，我亦愛斯葵。", "能隨朝陽傾，不爲秋露萎。", "烹調戒中厨，聊以燕母慈。", "拔根取廉名，未愧魯公儀。"]'),
('aa131254-e8c7-406e-b7cb-8a065c7ce033','薺','彭汝礪','宋','宋诗','song-poetry','','[]','陰風號暮景，零落悲晚秋。',48,'全唐诗/poet.song.51000.json','["陰風號暮景，零落悲晚秋。", "紛紛彼芳薺，鬰鬰此中丘。", "作甘豈不珍，冒寒不爲柔。", "薄言擷以歸，呼奴具晨羞。"]'),
('9e564e68-b6a1-44d1-895f-44db661dae42','途中和君時  其一','彭汝礪','宋','宋诗','song-poetry','','[]','相望不相見，一步一回頭。',48,'全唐诗/poet.song.51000.json','["相望不相見，一步一回頭。", "况汝將有適，前路正悠悠。", "土壤去宛葉，星躔近斗牛。", "不知明之日，何以解吾憂。"]'),
('d5accdb3-8208-47fe-b034-338d055f0df6','途中和君時  其二','彭汝礪','宋','宋诗','song-poetry','','[]','聞君欲脂車，輾轉睡不安。',48,'全唐诗/poet.song.51000.json','["聞君欲脂車，輾轉睡不安。", "憂心頑如石，百計不可寬。", "鳲鳩祇在桑，歸雁乃雲端。", "一瞻百歎息，强飲終無歡。"]'),
('5a50f5b1-967f-4fd4-8eba-b7f2809ac08c','行役','彭汝礪','宋','宋诗','song-poetry','','[]','行行重行行，吾役幾時休。',48,'全唐诗/poet.song.51000.json','["行行重行行，吾役幾時休。", "春風不相饒，塵土滿敝裘。", "人生能幾何，乃有千歲憂。", "須知一罇酒，可勝萬戶侯。"]'),
('76124c4f-781c-4487-9d94-e95ff24bfa65','南陽','彭汝礪','宋','宋诗','song-poetry','','[]','復爾行南陽，興言涉清漢。',48,'全唐诗/poet.song.51000.json','["復爾行南陽，興言涉清漢。", "日晴川谷明，風靡花竹亂。", "遙瞻萬山麓，近眺樊城岸。", "南北有仳離，令人感鴻雁。"]'),
('51d9e5d9-e598-49bb-b45a-c3ab622e8ad4','途中','彭汝礪','宋','宋诗','song-poetry','','[]','一日復一日，悠悠竟何之。',48,'全唐诗/poet.song.51000.json','["一日復一日，悠悠竟何之。", "萬物但此理，百年能幾時。", "墨翟悲已誤，賈生哭奚爲。", "可憐日月輪，日夜爭東西。"]'),
('0290fdc1-7012-4608-8eaa-35102cb90c50','早起','彭汝礪','宋','宋诗','song-poetry','','[]','客心不能休，未曉輒欲起。',48,'全唐诗/poet.song.51000.json','["客心不能休，未曉輒欲起。", "耳凍南山風，衣冰北溪水。", "捨我一息勞，先行十餘里。", "因知人之學，患不勉旃爾。"]'),
('6f50059b-a1a0-4e46-86c6-a690540efac6','昨日餞趙教授行會飲秀楚堂晚徙櫻桃花下夜月上正夫設燭于花上光明焜燿昔所未見正夫因約賦詩','彭汝礪','宋','宋诗','song-poetry','','[]','夜凉月色清如水，天靜無風塵不起。',128,'全唐诗/poet.song.51000.json','["夜凉月色清如水，天靜無風塵不起。", "移酒近花坐明月，畫燭橫斜插花裏。", "月寒燭艷花淡薄，意思相疑不相似。", "一下一高總能見，半白半紅渾可喜。", "時有幽香闇着人，更分疏影低臨水。", "密如雲霧即成陰，團作珠璣看結子。", "異時尚擬與君醉，景物更作今日比。", "富貴功名是底物，人生百年行樂耳。"]'),
('be05c5f2-333b-4360-9bbc-3b8856cd1476','再用前韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','朝日薰酣晨露洗，中林入夜幽香起。',128,'全唐诗/poet.song.51000.json','["朝日薰酣晨露洗，中林入夜幽香起。", "燭與花明月影中，月和燭照花陰裏。", "光華混雜不可認，刻畫雖工難比似。", "燭偏月下花亦別，疏影橫從俱可喜。", "使君白頭衰久矣，空惜流年去如水。", "作詩與花雪羞恥，多材自屬佳公子。", "青春九十今能幾，不當祇作常時比。", "莫令俗事一關心，可厭浩歌頻到耳。"]'),
('d5163e8a-b5a7-4ac1-82e5-a6b164bd0b5f','再用前韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','夜色清如水新洗，月上燭明栖鳥起。',128,'全唐诗/poet.song.51000.json','["夜色清如水新洗，月上燭明栖鳥起。", "灼灼其華散成綺，仙翁岸幘光明裏。", "公明如月非如燭，文華亦非花得似。", "安危自以天下任，故與衆人同笑喜。", "手折芳枝嚼紅蕊，臨池想濯滄浪水。", "芳菲肯付游人醉，知公愛民一如子。", "月盈易虧花落易，直須催促公排比。", "公看光陰去無止，欻如白駒過隙耳。"]'),
('600fab08-90aa-4074-b549-713023668920','次正夫登沛中歌風臺','彭汝礪','宋','宋诗','song-poetry','','[]','屹屹泗上城，隆隆沛中臺。',108,'全唐诗/poet.song.51000.json','["屹屹泗上城，隆隆沛中臺。", "登臺不見人，祇見山崔嵬。", "高祖湯武資，神明天所開。", "潜龍已飛躍，乘馬寧邅迴。", "倒戈與天旋，萬國俱子來。", "西楚殪封兕，東齊蕩纖埃。", "任使雖故人，蕭曹亦賢哉。", "功成思猛士，樂極自成哀。", "如何古之人，懿德乃所懷。"]'),
('26218444-483d-42b2-83d6-e50fc4ec4a34','次正夫相寄佳句','彭汝礪','宋','宋诗','song-poetry','','[]','朱橘大可圍，白魚闊盈尺。',120,'全唐诗/poet.song.51000.json','["朱橘大可圍，白魚闊盈尺。", "掀林擷甘芳，艤岸披的皪。", "我酒清且旨，于焉餞佳客。", "鴻飛不知遠，日暮寒雲碧。", "回瀾祇如昨，不見舟行跡。", "寄詩何遒麗，若見好顔色。", "遙想翰墨揮，波濤瀉胸臆。", "維纚遠林外，坐看晨風翼。", "萬物歸一致，知公無不適。", "人之與天地，同是爲形役。"]'),
('5f96e6fb-60de-4953-ae7c-946952bc881b','次正夫宿留侯廟韵','彭汝礪','宋','宋诗','song-poetry','','[]','龍飛景雲從，林茂衆鳥息。',120,'全唐诗/poet.song.51000.json','["龍飛景雲從，林茂衆鳥息。", "真人翔灞上，多士生王國。", "留侯豪傑士，乃獨爲所得。", "韓亡竟不去，漢興愈厲策。", "不見馬上功，奚多幕中畫。", "眇焉視嬰布，若數百與億。", "鴻鵠已高飛，翩然斂歸翼。", "堂堂高皇業，屹立如磐石。", "始卒如公者，是不慚廟食。", "載瞻水邊祠，老檜寒更碧。"]'),
('b22f4bd2-5a91-453e-8212-4b6df4a9aa64','次正夫途中懷親韵','彭汝礪','宋','宋诗','song-poetry','','[]','動靜非兩途，久勞逸更好。',108,'全唐诗/poet.song.51000.json','["動靜非兩途，久勞逸更好。", "開門看白雲，婉婉出山嶠。", "身閑亦已樂，言念親及耄。", "豈無青精飯，每食終不飽。", "鏡中髮如漆，一夜成素葆。", "言歸采其蘭，堂北種萱草。", "日以五鼎食，不如綵衣老。", "我今無此樂，感泣形已槁。", "日夜思故鄉，欹眠夢郊堡。"]'),
('370afca5-7e0e-4b7e-a4dd-b3942cf27021','次正夫途中蔬食韵','彭汝礪','宋','宋诗','song-poetry','','[]','昔未與公游，同志不同居。',144,'全唐诗/poet.song.51000.json','["昔未與公游，同志不同居。", "我寵居鳳掖，公名專石渠。", "醪醴賜上尊，膏羶給天厨。", "彭城作逐客，事事秦越殊。", "尚慚素餐詩，苦畏城旦書。", "豈能萬錢食，謬駕雙輪車。", "時時置盃盤，登眺隨所如。", "公行適在野，乃至歌無魚。", "人生一世間，百年實斯須。", "無所不可安，何獨貴紆朱。", "飲河惟滿腹，奚欠亦奚餘。", "作詩促公歸，去直承明廬。"]'),
('f32ddf9e-cc8a-4ffe-ac9b-96e58cd1a01a','正夫臥疾予往訪之正夫置酒因作是詩','彭汝礪','宋','宋诗','song-poetry','','[]','來問清漳病，煩置東武酒。',96,'全唐诗/poet.song.51000.json','["來問清漳病，煩置東武酒。", "敬窺石窌君，愛始士衡母。", "大論窺道奧，禪關恣深叩。", "是非棄糠粃，直與造化友。", "人游于一世，萬事俱非偶。", "養疾先息念，息念他何有。", "此言乃良藥，不在砭石後。", "長日從公游，徑醉須五斗。"]'),
('d0f713f0-da33-4e35-8d61-89637836675c','再用前韵','彭汝礪','宋','宋诗','song-poetry','','[]','從公飲輒醉，醉德非醉酒。',96,'全唐诗/poet.song.51000.json','["從公飲輒醉，醉德非醉酒。", "噬肯易子教，義應容拜母。", "歌聲清以長，發若金石叩。", "予非多聞者，或似直諒友。", "身世飄流並，神形條達偶。", "萬事實一夢，奚亡亦奚有。", "是非可姑置，試俟千載後。", "但願酒不空，何庸印如斗。"]'),
('5e57b6cd-c0e1-42d1-be87-d67545cdc18d','和君時十章章四句  其一','彭汝礪','宋','宋诗','song-poetry','','[]','猗彼君子，篤志乎道。',20,'全唐诗/poet.song.51000.json','["猗彼君子，篤志乎道。", "道之云遠，於焉慥慥。"]'),
('5f1a2585-6924-43b1-a0bf-286b94a377cd','和君時十章章四句  其二','彭汝礪','宋','宋诗','song-poetry','','[]','猗彼君子，克誠其身。',20,'全唐诗/poet.song.51000.json','["猗彼君子，克誠其身。", "匪祿是榮，日以養親。"]'),
('54b3c844-8210-4906-8de8-e3b2e702321d','和君時十章章四句  其三','彭汝礪','宋','宋诗','song-poetry','','[]','孰違孰從，曰吾從義。',20,'全唐诗/poet.song.51000.json','["孰違孰從，曰吾從義。", "孰去孰與，曰吾由禮。"]'),
('4129bc58-a702-4aef-95c6-22f3c82d5871','和君時十章章四句  其四','彭汝礪','宋','宋诗','song-poetry','','[]','溫凊匪偕，云如之何。',20,'全唐诗/poet.song.51000.json','["溫凊匪偕，云如之何。", "得彼失茲，得失孰多。"]'),
('90150ab4-ada3-4036-ba9c-fc2766ce0bc8','和君時十章章四句  其五','彭汝礪','宋','宋诗','song-poetry','','[]','吾斯未信，吾顔之厚。',20,'全唐诗/poet.song.51000.json','["吾斯未信，吾顔之厚。", "重輕惟法，于爾何有。"]'),
('b949ecae-0332-4d9d-bf67-4c45c7577ada','和君時十章章四句  其六','彭汝礪','宋','宋诗','song-poetry','','[]','爾旋爾車，不知其期。',20,'全唐诗/poet.song.51000.json','["爾旋爾車，不知其期。", "我陟其岡，祇益我思。"]'),
('4e4ebdf2-c297-46b2-91ee-88c6a49c096c','和君時十章章四句  其七','彭汝礪','宋','宋诗','song-poetry','','[]','凡人逐物，其力則倍。',20,'全唐诗/poet.song.51000.json','["凡人逐物，其力則倍。", "苟知其養，是用無悔。"]'),
('e13d5847-1e69-47ec-881e-2dd17a911c23','和君時十章章四句  其八','彭汝礪','宋','宋诗','song-poetry','','[]','無悔無尤，是則養親。',20,'全唐诗/poet.song.51000.json','["無悔無尤，是則養親。", "爾慎旃哉，以慰母心。"]'),
('d2f7b205-08c9-4640-b036-148368b2735f','和君時十章章四句  其九','彭汝礪','宋','宋诗','song-poetry','','[]','爲山一簣，懼乎或止。',20,'全唐诗/poet.song.51000.json','["爲山一簣，懼乎或止。", "道之云遠，曷云其已。"]'),
('7641d6d2-df37-41a5-aa47-64c741e1bdd6','和君時十章章四句  其一○','彭汝礪','宋','宋诗','song-poetry','','[]','我田我田，以遲爾歸。',20,'全唐诗/poet.song.51000.json','["我田我田，以遲爾歸。", "何速于行，姑樂我私。"]'),
('81cb75cc-56cd-4132-9ef4-e5a216211591','寄君時四章章四句','彭汝礪','宋','宋诗','song-poetry','','[]','我脂我車，陟彼高岡。',84,'全唐诗/poet.song.51000.json','["我脂我車，陟彼高岡。", "母也吾懷，匪居或忘。", "我帆我舟，汎彼大江。", "母也吾憂，匪食或皇。", "我池有魚，亦可以羹。", "何必鮪及魴，叔兮其歸哉。", "我田有菽，苟可以食。", "何必稻與粱，叔兮其歸哉。"]'),
('989f7615-f322-48e4-8ca9-9be2d773ec61','寄君時四章章四句  其一','彭汝礪','宋','宋诗','song-poetry','','[]','我脂我車，陟彼高岡。',20,'全唐诗/poet.song.51000.json','["我脂我車，陟彼高岡。", "母也吾懷，匪居或忘。"]'),
('d547fb28-07dc-437b-9aa6-19bc0d6ed07e','寄君時四章章四句  其二','彭汝礪','宋','宋诗','song-poetry','','[]','我帆我舟，汎彼大江。',20,'全唐诗/poet.song.51000.json','["我帆我舟，汎彼大江。", "母也吾憂，匪食或皇。"]'),
('37e26577-68ab-4d86-92df-367b18f4d6a0','寄君時四章章四句  其三','彭汝礪','宋','宋诗','song-poetry','','[]','我池有魚，亦可以羹。',22,'全唐诗/poet.song.51000.json','["我池有魚，亦可以羹。", "何必鮪及魴，叔兮其歸哉。"]'),
('f71297c0-87de-4573-b695-ad50b4793384','寄君時四章章四句  其四','彭汝礪','宋','宋诗','song-poetry','','[]','我田有菽，苟可以食。',22,'全唐诗/poet.song.51000.json','["我田有菽，苟可以食。", "何必稻與粱，叔兮其歸哉。"]'),
('9f8c7bd6-de9a-48b6-a8ea-0eef6d0a1ebd','寄君時六章章四句  其一','彭汝礪','宋','宋诗','song-poetry','','[]','我思古人，克誠其心。',20,'全唐诗/poet.song.51000.json','["我思古人，克誠其心。", "如陟于高，如臨于深。"]'),
('d9ef004c-3aa0-4ca0-9a94-cbdb7f6a2282','寄君時六章章四句  其二','彭汝礪','宋','宋诗','song-poetry','','[]','我處于中，而舍其偏。',20,'全唐诗/poet.song.51000.json','["我處于中，而舍其偏。", "我棄其零，而取其全。"]'),
('05ba23ac-0089-42f3-aa99-65fb70ac26ab','寄君時六章章四句  其三','彭汝礪','宋','宋诗','song-poetry','','[]','勿謂道遠，我至之難。',20,'全唐诗/poet.song.51000.json','["勿謂道遠，我至之難。", "我勇以前，人孰我先。"]'),
('f666f758-cadf-4970-99d9-1ac58c2f66fc','寄君時六章章四句  其四','彭汝礪','宋','宋诗','song-poetry','','[]','勿謂過小，我姑爲之。',20,'全唐诗/poet.song.51000.json','["勿謂過小，我姑爲之。", "千里之差，始于毫釐。"]'),
('feaf76af-4480-40e9-a5f0-d4417fab5030','寄君時六章章四句  其五','彭汝礪','宋','宋诗','song-poetry','','[]','勇兮勇兮，子我所器。',20,'全唐诗/poet.song.51000.json','["勇兮勇兮，子我所器。", "子誠不已，我今所畏。"]'),
('11ae45d3-c55b-4105-b4b8-02229628a8c1','寄君時六章章四句  其六','彭汝礪','宋','宋诗','song-poetry','','[]','子能吾取，吾誰之匿。',20,'全唐诗/poet.song.51000.json','["子能吾取，吾誰之匿。", "子銘于盤，以視朝夕。"]'),
('4be029c0-0209-460a-9dd1-dbc82489d6c5','寄君時四章章四句  其一','彭汝礪','宋','宋诗','song-poetry','','[]','我灌我園，有采之心。',20,'全唐诗/poet.song.51000.json','["我灌我園，有采之心。", "于以擷之，既有且多。"]'),
('0dcb9db0-0bd6-4378-96dd-b3c44145418b','寄君時四章章四句  其二','彭汝礪','宋','宋诗','song-poetry','','[]','我游我庭，有菊之苗。',20,'全唐诗/poet.song.51000.json','["我游我庭，有菊之苗。", "于以芼之，既旨且時。"]'),
('176c6ee0-f478-497a-a32b-8bb31515f299','寄君時四章章四句  其三','彭汝礪','宋','宋诗','song-poetry','','[]','我思昔人，亦採其薇。',20,'全唐诗/poet.song.51000.json','["我思昔人，亦採其薇。", "我樂所安，奚慍其微。"]'),
('17b49b19-8aeb-4b3d-ad06-f65ff08a5402','寄君時四章章四句  其四','彭汝礪','宋','宋诗','song-poetry','','[]','仲兮仲兮，曷日汝偕。',20,'全唐诗/poet.song.51000.json','["仲兮仲兮，曷日汝偕。", "以事以游，以慰予懷。"]'),
('d2a581bf-1f39-4652-b5e6-c70324722142','元祐元年十二月庚子雪夏首蓴湖結冰鶺鴒群集于上者至不可數感而作是詩也  其一','彭汝礪','宋','宋诗','song-poetry','','[]','宛彼鶺鴒，其樂孔群。',22,'全唐诗/poet.song.51000.json','["宛彼鶺鴒，其樂孔群。", "彼類維何，而有若于仁兮。"]'),
('39b0d57d-e6b3-4023-bf34-29c2c29ac1ac','元祐元年十二月庚子雪夏首蓴湖結冰鶺鴒群集于上者至不可數感而作是詩也  其二','彭汝礪','宋','宋诗','song-poetry','','[]','宛彼鶺鴒，爰集于冰。',22,'全唐诗/poet.song.51000.json','["宛彼鶺鴒，爰集于冰。", "彼至維何，而有冽其清兮。"]'),
('ffe744f2-1457-4d60-911e-13364cca022f','元祐元年十二月庚子雪夏首蓴湖結冰鶺鴒群集于上者至不可數感而作是詩也  其三','彭汝礪','宋','宋诗','song-poetry','','[]','宛彼鶺鴒，既飛且鳴。',22,'全唐诗/poet.song.51000.json','["宛彼鶺鴒，既飛且鳴。", "彼行維何，而有篤其誠兮。"]'),
('457796a0-d08f-4922-abe8-da626063d880','寄甯和仲二章章四句  其一','彭汝礪','宋','宋诗','song-poetry','','[]','鳳山之泉，孔潔且長。',21,'全唐诗/poet.song.51000.json','["鳳山之泉，孔潔且長。", "止而不流，是不如汙潢。"]'),
('ab603a3c-f489-46af-89a1-cded230d05cc','寄甯和仲二章章四句  其二','彭汝礪','宋','宋诗','song-poetry','','[]','鳳山之木，可棟大厦。',24,'全唐诗/poet.song.51000.json','["鳳山之木，可棟大厦。", "舍而殘之，是將與荆棘而並化。"]'),
('ee640177-b648-475c-8fd2-9a6c78df72f9','送張子固','彭汝礪','宋','宋诗','song-poetry','','[]','吾少飲酒不知數，有如長虹吞百川。',64,'全唐诗/poet.song.51000.json','["吾少飲酒不知數，有如長虹吞百川。", "老來畏酒飲輒醉，百事一無如少年。", "瘦脚踉蹌走病鶴，吟腸悲壯啼寒蟬。", "夫君尚勇不宜怯，急上青雲須着鞭。"]'),
('84a1ef4d-8865-4ede-a7f9-635c9d95a9f8','吳園雜詠十九首 吳園','彭汝礪','宋','宋诗','song-poetry','','[]','布夷韓彭誅，國奪名亦隕。',36,'全唐诗/poet.song.51000.json','["布夷韓彭誅，國奪名亦隕。", "芮王獨以正，百世榮如近。", "至今園中草，欲踐猶不忍。"]'),
('7d0461e9-7a8f-46ad-8114-db5a6328007b','吳園雜詠十九首 燕閣','彭汝礪','宋','宋诗','song-poetry','','[]','高閣高入雲，俛焉視岡阜。',36,'全唐诗/poet.song.51000.json','["高閣高入雲，俛焉視岡阜。", "老來更無事，賓至但飲酒。", "陰功在其鄉，更足燕爾後。"]'),
('c85d4812-0933-4bc2-98ca-ef1589711125','吳園雜詠十九首 書堂','彭汝礪','宋','宋诗','song-poetry','','[]','藐視一籝金，獨藏五車書。',36,'全唐诗/poet.song.51000.json','["藐視一籝金，獨藏五車書。", "高堂見古今，其樂亦只且。", "以此燕子孫，吾誰數陶朱。"]'),
('5f663a42-4216-4c50-9d55-00f118f87d1e','吳園雜詠十九首 集虛堂','彭汝礪','宋','宋诗','song-poetry','','[]','室虛即生白，惟道在集虛。',36,'全唐诗/poet.song.51000.json','["室虛即生白，惟道在集虛。", "詩書掃塵跡，仁義外蘧廬。", "形忘心亦忘，萬物同一如。"]'),
('8dbb8f58-43a3-4798-b103-d69d13b9ddf0','吳園雜詠十九首 覺軒','彭汝礪','宋','宋诗','song-poetry','','[]','本覺不見覺，大夢非是夢。',36,'全唐诗/poet.song.51000.json','["本覺不見覺，大夢非是夢。", "覺夢夢非覺，其歸理則共。", "兔魚亦既得，筌蹄自無用。"]'),
('de853c00-2a61-44d1-811a-910141bb3b5c','吳園雜詠十九首 山亭','彭汝礪','宋','宋诗','song-poetry','','[]','飛簷截山出，碧瓦貼雲齊。',36,'全唐诗/poet.song.51000.json','["飛簷截山出，碧瓦貼雲齊。", "水靜見魚樂，竹深聞鳥啼。", "春風花落處，誤認武陵溪。"]'),
('0d2cd37a-2e1c-47a9-ba76-57a2b198d9d7','吳園雜詠十九首 觀德亭','彭汝礪','宋','宋诗','song-poetry','','[]','男兒厥生時，弧矢射四方。',36,'全唐诗/poet.song.51000.json','["男兒厥生時，弧矢射四方。", "茲禮古所重，嘆嗟今已亡。", "典章可披尋，君試行一鄉。"]'),
('7a3d07a9-4f93-41cf-a3b3-f9d8b33c605e','吳園雜詠十九首 思賢亭','彭汝礪','宋','宋诗','song-poetry','','[]','大風無邪聲，積雪不改色。',36,'全唐诗/poet.song.51000.json','["大風無邪聲，積雪不改色。", "根方爲龍去，實擬待鳳食。", "一日有不見，恍如歲三易。"]'),
('a839b0d7-eb10-44d1-8464-03e645172108','吳園雜詠十九首 紫筠亭','彭汝礪','宋','宋诗','song-poetry','','[]','青竹老出藍，紫竹嫩施粉。',36,'全唐诗/poet.song.51000.json','["青竹老出藍，紫竹嫩施粉。", "樂彼奇節並，歲寒不彫隕。", "言如拾芥者，設意毋乃近。"]'),
('846669ce-47ec-4bfa-bec2-e42b97abffa9','吳園雜詠十九首 澡雪亭','彭汝礪','宋','宋诗','song-poetry','','[]','塵土能汙人，譬如衣匪澣。',36,'全唐诗/poet.song.51000.json','["塵土能汙人，譬如衣匪澣。", "窺臨得清曠，其去已大半。", "不必濯滄浪，神明自還觀。"]'),
('e8194849-77b3-4264-87e1-d7ab835b86c3','吳園雜詠十九首 四并臺','彭汝礪','宋','宋诗','song-poetry','','[]','時將景共好，物與心相投。',36,'全唐诗/poet.song.51000.json','["時將景共好，物與心相投。", "曠覽盡萬物，分明一浮漚。", "此臺無不并，樂只臺上游。"]'),
('25dd48b0-7e00-4fff-a442-eed892286787','吳園雜詠十九首 四曲池','彭汝礪','宋','宋诗','song-poetry','','[]','大池方如矩，小池曲如鈎。',36,'全唐诗/poet.song.51000.json','["大池方如矩，小池曲如鈎。", "方奚避汙辱，曲不趨公侯。", "時傍白蓮葉，獨行青翰舟。"]'),
('7bb1e66d-0881-4581-ab38-bdf6421eca61','吳園雜詠十九首 眉壽堂','彭汝礪','宋','宋诗','song-poetry','','[]','枝幹上參天，長松不枯槁。',36,'全唐诗/poet.song.51000.json','["枝幹上參天，長松不枯槁。", "朱頂雪衣裳，仙鶴顔色好。", "主人一千歲，似此松鶴老。"]'),
('48142b59-4429-4f29-9a75-4618baa59149','吳園雜詠十九首 忘憂亭','彭汝礪','宋','宋诗','song-poetry','','[]','徙竹種前林，栽松滿幽島。',36,'全唐诗/poet.song.51000.json','["徙竹種前林，栽松滿幽島。", "主人無所憂，不用植萱草。", "吐納奚所事，忘憂自難老。"]'),
('dc45f102-0720-41b8-a5cc-a6f90ee0137f','吳園雜詠十九首 秋月樓','彭汝礪','宋','宋诗','song-poetry','','[]','秋月如秋水，瑩澈萬里流。',36,'全唐诗/poet.song.51000.json','["秋月如秋水，瑩澈萬里流。", "我欲挹其清，登彼百尺樓。", "隨時有佳趣，不但是中秋。"]'),
('81aba85b-3e0d-4d62-abd5-5e3bcffa1407','吳園雜詠十九首 觀稼亭','彭汝礪','宋','宋诗','song-poetry','','[]','多稼爲豐年，觀言亦云樂。',36,'全唐诗/poet.song.51000.json','["多稼爲豐年，觀言亦云樂。", "秋雲滿原隰，漫不知厚薄。", "帝力彼焉知，陶然飽耕穫。"]'),
('1bc8b9f5-1bfd-42a5-a690-268681de7b54','吳園雜詠十九首 戒得菴','彭汝礪','宋','宋诗','song-poetry','','[]','衆人貪狥財，種利不種德。',36,'全唐诗/poet.song.51000.json','["衆人貪狥財，種利不種德。", "誰如之人心，白首能戒得。", "以此風里閭，貪競當自息。"]'),
('cf122eec-2998-4098-ab44-66aec03f035d','吳園雜詠十九首 秋香亭','彭汝礪','宋','宋诗','song-poetry','','[]','豈不有春華，不如秋後香。',36,'全唐诗/poet.song.51000.json','["豈不有春華，不如秋後香。", "紅紫不禁風，黄花耐雪霜。", "幾時登其亭，采采泛彼觴。"]'),
('75632e81-d927-4525-90dc-23fac17f2a69','吳園雜詠十九首 薰風閣','彭汝礪','宋','宋诗','song-poetry','','[]','衆山走蜿蜒，高閣立崔嵬。',36,'全唐诗/poet.song.51000.json','["衆山走蜿蜒，高閣立崔嵬。", "流水橫其前，時有薰風來。", "聊可解吾慍，敢言阜民財。"]'),
('a0605d2e-6e21-4dad-bc94-3f160af8acc6','晨起祠先農道中','彭汝礪','宋','宋诗','song-poetry','','[]','更闌燭花低，呼童起視夜。',240,'全唐诗/poet.song.51000.json','["更闌燭花低，呼童起視夜。", "問夜如何其，露落月未謝。", "皇帝共神明，朝燕或爲罷。", "多儀禮有敬，少怠刑無赦。", "今茲先農饗，上意在耕稼。", "駕言投明起，不敢私安暇。", "馬蹄踏冰雪，霧露溼鞍馬。", "寒林月中影，十里開圖畫。", "燈火望壇場，冠裳出次舍。", "鏘洋響金石，馨香紛彝斝。", "百年禮樂中，萬事無雜霸。", "昏冥久塵土，今日聞韶夏。", "心知至誠通，自可膏澤下。", "清風吹菽麥，綠陰密桑柘。", "人家實倉廩，得以時婚嫁。", "四夷共安富，兵偃祭類禡。", "山川百神寧，天子樂無假。", "敢後秋冬報，還見擊鼓御。", "顧予真缺然，何以補漏罅。", "尚堪逐農樵，擊壤歌聖化。"]'),
('e8b32aa7-d717-4f45-b5f7-e38364c9dce7','自吉泛舟入贛','彭汝礪','宋','宋诗','song-poetry','','[]','我行欲從車，好風苦相招。',120,'全唐诗/poet.song.51000.json','["我行欲從車，好風苦相招。", "謂言困行役，厭此道路遙。", "駸駸四駱馬，終日在岧嶢。", "簿書更追隨，精耗髮欲焦。", "乃復汎柏舟，錦幔蘭爲橈。", "是時春始和，暖風秀蘭苕。", "彼柳已青青，彼桃已夭夭。", "王事敢不修，我行歌且謠。", "彼不知之者，謂我士也驕。", "不知非所知，我茲以逍遙。"]'),
('3d4e572c-e7e6-4bba-903d-a089af3ffd2b','胡雛','彭汝礪','宋','宋诗','song-poetry','','[]','禿鬢胡雛色如玉，頰拳突起深其目。',98,'全唐诗/poet.song.51000.json','["禿鬢胡雛色如玉，頰拳突起深其目。", "鼻頭穹隆脚心曲，被裘騎馬追鴻鵠。", "出入林莽乘山谷，凌空絕險如平陸。", "臂鷹緤犬紛馳逐，雕弓羽箭黄金鏃。", "爭血雉兔羞麋鹿，詭遇得禽非我欲。", "莫怪小兒敏捷强，老宿胡人以此爲風俗。"]'),
('efbfe562-91b4-42af-b029-124ece13ca0b','六月自西城歸','彭汝礪','宋','宋诗','song-poetry','','[]','駕言將西征，呼僕問行李。',288,'全唐诗/poet.song.51000.json','["駕言將西征，呼僕問行李。", "吾行無所苟，雖遠親則喜。", "癡兒不知事，飲血淚如水。", "憶昨唐許邊，逋逃聚蜂蟻。", "巔崖寄巢穴，絕險不可邇。", "撲滅無先幾，捕督誤詔旨。", "是時寡妻病，吾計或可止。", "君曰無妾私，促裝勉行矣。", "妾病雖云危，姑慈有足恃。", "是身如浮雲，永訣或此始。", "一馬纔登途，渠魁頭掛市。", "猶虞未寧歸，走訃忽在耳。", "羈栖二十年，粱肉飽有幾。", "單車行四方，歲月幾萬里。", "私居乃如寄，方此還之彼。", "愛君能知分，嗜苦同甘旨。", "誓欲相厥成，完百無一毀。", "中流即我棄，我恨無涯涘。", "家貧未能去，顧惜尚壯齒。", "含愁復于行，嗜祿祇自鄙。", "悠悠涉清漢，欲往轅更柅。", "滄浪照顔面，不與舊相似。", "蓬鬢生雪霜，龜胸點泥滓。", "驕陽恰中伏，旱魃方哆侈。"]'),
('9709e8a3-a727-4a1c-ac6a-60d52148f28f','寄君時','彭汝礪','宋','宋诗','song-poetry','','[]','豈不有性靈，稍可學操縵。',144,'全唐诗/poet.song.51000.json','["豈不有性靈，稍可學操縵。", "公私足憂責，耗蠹幾大半。", "馳驅寢食廢，真自殘軀幹。", "叔兮識至理，真僞不可亂。", "讀書老不輟，夜坐頻達旦。", "特立無倚著，剛嚴實予憚。", "歲時有多少，每復愁分散。", "顧瞻鶺鴒飛，俛仰發浩歎。", "安得桑麻田，穀粟粗可飯。", "晨昏侍萱堂，綵服何粲粲。", "箴切庶寡尤，詩書恣娛玩。", "相從不相離，如彼鴻與雁。"]'),
('eaea253a-b586-4758-ba80-d9e586dbe850','觀畫','彭汝礪','宋','宋诗','song-poetry','','[]','少時馳驅走四方，馬足遍踏無邊疆。',384,'全唐诗/poet.song.51000.json','["少時馳驅走四方，馬足遍踏無邊疆。", "北踰崦嵫薄扶桑，遠陟羊腸上太行。", "歷參涉昴捫亢房，蕩舟溟渤浮河潢。", "五湖彭蠡窺沅湘，蛟龍出沒鱗鬣蒼。", "大浪震疊鐘鼓撞，怒蜃結搆珠瑶光。", "游魚鰷鱨鱣鮪魴，鸂鶒沉浮旅鴐鶬。", "大鵬一飛凌鷫鸘，中林荃蕙雜蘭菖。", "妖紅曼綠艷靚粧，回溪曲覆秀篔簹。", "老松怪柏號風霜，桂丹楓赤橘柚黄。", "閬風仙人醉瓊漿，前旆虹蜺騎鳳皇。", "雲臺曲璧絡奇璜，縹緲天樂非宮商。", "我欲從之匪暇遑，昨朝圖畫紛開張。", "睥睨舊游心惚慌，南嶺赤日西玄霜。", "愁雲不開雨雪雱，變化倏忽無經常。", "隆樓傑閣鬰相望，遠峰截嵲插雕梁。", "商人騎馬兒牧羊，牛車魚艇浮纖芒。", "蒼鵝無聲浴滄浪，熟視却顧疑騰驤。", "驊騮奚爲棄路傍，骨骼雖老終軒昂。", "重陽籬菊開煌煌，怪見桃杏爭芬芳。", "梅花一枝忽自折，半籬彷彿聞幽香。", "文陛網戶綠綺窗，中有美人豈媖媓。", "流珠蛺蝶金鴛鴦，一盼少年猶斷腸。", "蓬萊宮中日月長，世界凡閱幾炎凉。", "悠悠彼樂未遽央，棋局未知誰子强。"]'),
('498935d2-d73f-4f2e-bc5a-38c1e49f6e46','答蜀公謝寄酒','彭汝礪','宋','宋诗','song-poetry','','[]','彼酒孰爲之，湛然若天成。',168,'全唐诗/poet.song.51000.json','["彼酒孰爲之，湛然若天成。", "爲之非草草，纖悉中度程。", "其香匹幽蘭，色不減瓊英。", "采采白菊花，亦酌潭水清。", "潭水取之源，擇菊廢枝莖。", "我將饗明神，乃獨以其精。", "千里馳寄公，非將解公酲。", "祝公百年壽，多益不爲盈。", "想公初飲時，瑩徹顔微赬。", "幽吟倚巖石，緩步睨層城。", "爰聞在陰鶴，載嘆出谷鶑。", "我聞至人心，萬物莫足攖。", "存亡漫憂喜，泛然若無情。", "此理公得之，奚藉醪醴并。"]'),
('d84c79fd-7e29-4244-854f-330b8c947b6c','方城與君時相別遇雨因寄是詩','彭汝礪','宋','宋诗','song-poetry','','[]','五更赤晴平旦雨，愁雲不開風勁怒。',176,'全唐诗/poet.song.51000.json','["五更赤晴平旦雨，愁雲不開風勁怒。", "霰雹夜落大如芋，日月不出愁烏兔。", "兄曰嗟予季行役，道阻且修日云暮。", "泥深一尺水交注，僕肩不任馬蹄駐。", "一車十牛不能御，晨征忽忽立乘遽。", "恐汝悲啼不還顧，昔知爲快今知誤。", "恨不赭陽一月住，人生百年惟所遇。", "曲折萬變皆歸數，乾坤與人同寄寓。", "擾擾眼前皆細故，慎勿動心悲景露。", "九阪王陽猶叱馭，平明天晴卷雲霧。", "驊騮安穩行道路，一日千里如跬步。"]'),
('9eff2e1d-c905-4733-8915-be5e1e7a496a','我行','彭汝礪','宋','宋诗','song-poetry','','[]','我行日不休，行亦讀吾書。',48,'全唐诗/poet.song.51000.json','["我行日不休，行亦讀吾書。", "朝爲忘機鷗，夜作不瞑魚。", "日月雙跳丸，乾坤一蘧廬。", "而吾于其間，擾擾亦自如。"]'),
('8529e739-6a61-4d2f-aef7-5e822b131c7d','離家','彭汝礪','宋','宋诗','song-poetry','','[]','離家一千里，十日不得書。',48,'全唐诗/poet.song.51000.json','["離家一千里，十日不得書。", "不怨天上鴻，祇恨水中魚。", "我行穀伯國，明日武侯廬。", "慈親髮雪白，安否比何如。"]'),
('58e4bf68-4d27-4178-ac9b-6cac295758f2','游峴首','彭汝礪','宋','宋诗','song-poetry','','[]','去年冬少雪，二月春始晴。',48,'全唐诗/poet.song.51000.json','["去年冬少雪，二月春始晴。", "南游峴首山，東下石頭城。", "揉藍染江水，爛錦貼園英。", "幽亭一杯酒，不用千載名。"]'),
('c6855dff-f4bd-4354-9a7d-0d32aa5c2f59','叔子祠堂','彭汝礪','宋','宋诗','song-poetry','','[]','不折亭下柏，不採山頭石。',48,'全唐诗/poet.song.51000.json','["不折亭下柏，不採山頭石。", "羊公昔茲游，千載人愛惜。", "焚香薦巵酒，一拜三嘆息。", "却汎峴水波，汪洋感餘澤。"]'),
('ab775d98-c92d-45a1-97b1-7d5a6b3d193d','恒河','彭汝礪','宋','宋诗','song-poetry','','[]','恒河世界浮漚上，漭漭衆生久流浪。',64,'全唐诗/poet.song.51000.json','["恒河世界浮漚上，漭漭衆生久流浪。", "老蠶作繭自糾纏，枯木生蟲不相放。", "止止靈泉風震蕩，昭昭惠日雲遮障。", "却語諸人莫惆悵，煩惱菩提同一相。"]'),
('03966a0b-c0b4-4b8a-9e11-a15a9eeb5b8a','舟行','彭汝礪','宋','宋诗','song-poetry','','[]','莫打槳，打槳驚鴻雁，鴻雁不慕魚蝦賤。',60,'全唐诗/poet.song.51000.json','["莫打槳，打槳驚鴻雁，鴻雁不慕魚蝦賤。", "暮宿江湖晝雲漢，我不見之其心亂。", "莫鳴桹，鳴桹鴻雁飛。", "鴻雁不是鷄鶩兒，我不見之心孔悲。"]'),
('3b9634d7-bf00-4273-9e28-f179e21fed6f','送君時','彭汝礪','宋','宋诗','song-poetry','','[]','思親一日如三歲，去家十舍如萬里。',80,'全唐诗/poet.song.51000.json','["思親一日如三歲，去家十舍如萬里。", "投明叔也欲別我，枕上聞鷄淚如洗。", "丈夫蓋棺事則已，君雖白髮猶壯齒。", "奚慚折腰五斗米，三釜及親胡不喜。", "弧桑蓬矢射四方，男子生來志如此。"]'),
('0883f484-b447-49cf-8dd8-af25db73b79d','高陽池','彭汝礪','宋','宋诗','song-poetry','','[]','駕言之石城，爰至高陽池。',48,'全唐诗/poet.song.51000.json','["駕言之石城，爰至高陽池。", "是時春始和，池水生渺瀰。", "徒能躊躇顧，不及酩酊歸。", "令人憶山翁，倒著白接䍦。"]'),
('d67bdb1d-030e-4583-8562-884c80d49094','谷隠寺','彭汝礪','宋','宋诗','song-poetry','','[]','樓臺寄山巔，屹屹與雲齊。',48,'全唐诗/poet.song.51000.json','["樓臺寄山巔，屹屹與雲齊。", "登臨覽昭曠，感慨發悲悽。", "西顧隆中廬，北睨漢陰畦。", "願言脫樊籠，超然此幽棲。"]'),
('55d30365-e6b3-46f0-9bca-4da66b0b1f1e','白馬寺','彭汝礪','宋','宋诗','song-poetry','','[]','老龍挾神機，變化無拘攣。',48,'全唐诗/poet.song.51000.json','["老龍挾神機，變化無拘攣。", "大作四海水，斂爲一泓泉。", "白露泛素液，黄金折嘉蓮。", "樂哉襄陽人，歲歲無凶年。"]'),
('c310fc4e-8035-4394-bc68-49db118f1722','春風破窮陰','彭汝礪','宋','宋诗','song-poetry','','[]','春風破窮陰，草木爭秀發。',48,'全唐诗/poet.song.51000.json','["春風破窮陰，草木爭秀發。", "紛敷作錦繡，晃耀映霜雪。", "我行縱披賞，欲戴羞白髮。", "相看一杯酒，聊以酬佳節。"]'),
('7d1fd21f-ef75-4e0a-94b6-f37e97079d3d','寄十二十四弟','彭汝礪','宋','宋诗','song-poetry','','[]','有弟有弟各一隅，萬里不見徒嗟吁。',64,'全唐诗/poet.song.51000.json','["有弟有弟各一隅，萬里不見徒嗟吁。", "江湖春色又歸矣，庭檻花枝還有無。", "欲寄我聲無鯉魚，欲寫我恨無酒壺。", "開編一見鶺鴒詩，潸然淚落如真珠。"]'),
('14b8ed24-d362-4351-9d1e-038b9dd0a39e','秋風','彭汝礪','宋','宋诗','song-poetry','','[]','晚來雨霽秋風顛，驚我枕上清晝眠。',64,'全唐诗/poet.song.51000.json','["晚來雨霽秋風顛，驚我枕上清晝眠。", "四林荒凉好景氣，萬里晻靄皆雲烟。", "乳鳩深藏叫苦竹，蒼鶻欻起摩青天。", "花枝柳葉便凋隕，山上松筠徑儼然。"]'),
('6a9ecce0-1568-49d3-b37f-0902323f4aef','武岡路中','彭汝礪','宋','宋诗','song-poetry','','[]','朝行黄茅岡，暮宿黄茅驛。',48,'全唐诗/poet.song.51000.json','["朝行黄茅岡，暮宿黄茅驛。", "一岡復一岡，岡岡如絡繹。", "一驛復一驛，思親頭易白。", "何時自此還，行李兼晨夕。"]'),
('f9fff9df-f3d0-4f9e-8b97-9bdef64e9532','城東行事去李簡夫甚邇可以卜見而俱有往返之禁因戲爲歌馳寄','彭汝礪','宋','宋诗','song-poetry','','[]','故人咫尺水東頭，我欲見之心悠悠。',232,'全唐诗/poet.song.51000.json','["故人咫尺水東頭，我欲見之心悠悠。", "有足欲往不自由，形骸靜對鶑花留。", "我思肥陵昔之游，雲霧密鎖城上樓。", "把酒待月生海陬，月到行午醉未休。", "濡須南池水中洲，脫帽散髮尋漁舟。", "夕陽扶欄持釣鈎，白蘋風起寒颼飀。", "別來紛紛幾春秋，彼此待盡棲林丘。", "滴淚落水東爭流，肺肝雖大不容憂。", "殘息乃復如懸疣，得官相望真如囚。", "李夫子，借使復得把酒與子飲，其樂還如昔時不。", "我今鬢髮已絲志已偷，力不能前鈍如牛。", "泡浪亦悟吾生浮，尚壯欲以華簪投。", "日月逐逐同傳郵，何用自與身爲矛。", "我歌草草子須酬，欲讀子歌銷我愁。"]'),
('72812fb3-345b-4457-9a8a-b38c7b96a645','舟過當塗','彭汝礪','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','悠悠章江柁，復自姑孰北。',96,'全唐诗/poet.song.51000.json','["悠悠章江柁，復自姑孰北。", "此身與此水，日夜俱無息。", "關關林中鳥，軟語如相識。", "楊柳枝葉長，青青祇如昔。", "惟予鬢間髮，種種添新白。", "開尊泛溪水，宛轉隨山色。", "四方本予志，夷險非我惻。", "掛帆出長江，萬里追鵬翼。"]'),
('5f3a0d1d-4772-42ae-81c1-ecb142e2f91c','阻風飲酒','彭汝礪','宋','宋诗','song-poetry','','[]','繫舟不能前，酌酒聊自慰。',72,'全唐诗/poet.song.51000.json','["繫舟不能前，酌酒聊自慰。", "異鄉少親友，市遠無兼味。", "惟茲佳山水，渾渾含正氣。", "旁皇無賓主，恣取不爲費。", "王事不爲緩，簡書實吾畏。", "夜晴如何其，呼吏看星緯。"]'),
('439c9364-ef2e-4187-bbfa-0efa42308243','癸未季秋偕子仲都官文淵節推子堅先輩同游東湖分題得東字','彭汝礪','宋','宋诗','song-poetry','','[]','高山據西南，湖水自南東。',48,'全唐诗/poet.song.51000.json','["高山據西南，湖水自南東。", "中有避漢人，如彼雲中鴻。", "一日克諸己，百世聞其風。", "樂哉今日游，况有賢者同。"]'),
('32554fcc-504b-417f-8bae-fc5bdd47c6c6','和廣漢見和東字  其一','彭汝礪','宋','宋诗','song-poetry','','[]','駕言欲何之，于彼湖水東。',48,'全唐诗/poet.song.51000.json','["駕言欲何之，于彼湖水東。", "茫洋衆游魚，凌厲一歸鴻。", "嚼蕊挹飛泉，解带臨清風。", "寄聲詩中伯，暇日倘來同。"]'),
('7b2c331b-0a0f-49c1-842b-de575f614fba','和廣漢見和東字  其二','彭汝礪','宋','宋诗','song-poetry','','[]','出處勢不齊，譬若西與東。',48,'全唐诗/poet.song.51000.json','["出處勢不齊，譬若西與東。", "在陰有鳴鶴，漸陸見飛鴻。", "禹稷顔回道，下惠伯夷風。", "故彼孺子者，亦庶與古同。"]'),
('a6edc946-9cc7-4ed1-b321-7a52692fa139','與甯節推游聘君亭邂逅廣漢同游分題得聘字','彭汝礪','宋','宋诗','song-poetry','','[]','漢衰至桓靈，王室既不競。',120,'全唐诗/poet.song.51000.json','["漢衰至桓靈，王室既不競。", "豪杰死黨錮，奸嬖偷權柄。", "娟娟彼孺子，德譽南州盛。", "耕稼以自食，羞詣安車聘。", "彼非硜硜者，而欲爲奇行。", "未能比禹稷，夫豈慙蘧甯。", "我登斯亭上，悠悠發幽興。", "高山知仰止，池水不可泳。", "魚戲芙蓉花，鳬雜參差荇。", "嗟嘆之不足，俛仰成諷詠。"]'),
('57c2e76f-e582-4c60-84eb-aa36ab3a366e','送甯秀才過溪口占','彭汝礪','宋','宋诗','song-poetry','','[]','邂逅吾所樂，爰復惜分携。',120,'全唐诗/poet.song.51000.json','["邂逅吾所樂，爰復惜分携。", "繫帆且少留，聊慰吾所思。", "嗟我行老矣，志意非昔時。", "鬢毛黑如漆，種種今如絲。", "譬如七年牛，力乏氣亦衰。", "囁嚅食青芻，欲往脚自遲。", "愛子齒未壯，骨骼超等夷。", "軒昂宇宙間，萬里惟所之。", "舉足我即到，寧復論華夷。", "行矣尚勉旃，卒慰吾所期。"]'),
('05ce7e73-d7e6-48a8-a8d5-e347ea5bc24b','沐浴有感','彭汝礪','宋','宋诗','song-poetry','','[]','去垢如去邪，不欲留毫分。',48,'全唐诗/poet.song.51000.json','["去垢如去邪，不欲留毫分。", "髮不止一沐，身不止三薰。", "如何迷本原，浴德不自勤。", "區區養樲棘，俯仰愧前聞。"]'),
('112116c1-016a-436f-8423-18ae1965c95a','答張天覺學士','彭汝礪','宋','宋诗','song-poetry','','[]','龐藴襄陽老精怪，辛勤欲挾山超海。',64,'全唐诗/poet.song.51000.json','["龐藴襄陽老精怪，辛勤欲挾山超海。", "破除枉被馬師瞞，扶起頼存靈照在。", "最上一機終不傳，喃喃謾自費羅干。", "晚年遭值張居士，冷火寒灰更熾然。"]'),
('eddc2ee6-0482-4d23-93fc-2aabf7182ea3','內鄉先春','彭汝礪','宋','宋诗','song-poetry','','[]','古寺前無廊，空林中有亭。',96,'全唐诗/poet.song.51000.json','["古寺前無廊，空林中有亭。", "淅水爲襟带，蕭山作畫屏。", "仰高聽流水，志體得所寧。", "不能念羈旅，天地俱浮萍。", "舉首望飛泉，日暮未肯歸。", "夜凉多好風，明月有清輝。", "一舉隨所之，不如鴻鵠飛。", "思親淚如雨，有露亦在衣。"]'),
('a65a118c-dee3-4330-8211-aa0d6387d5a8','久雨','彭汝礪','宋','宋诗','song-poetry','','[]','十日七日雨，十步九步水。',48,'全唐诗/poet.song.51000.json','["十日七日雨，十步九步水。", "師徒宿蓁莽，宴坐吾亦恥。", "其誰護封穴，未忍鳥鼠死。", "天意若有謂，無人可言此。"]'),
('c0052268-ad9d-4615-9d69-097ff20fc093','寄定州許資政','彭汝礪','宋','宋诗','song-poetry','','[]','中行耀師寵，北顧寬上憂。',108,'全唐诗/poet.song.51000.json','["中行耀師寵，北顧寬上憂。", "惠澤蘇民瘵，威名聞鬼陬。", "鹽梅合調羹，帷幄聊運籌。", "中山想可見，更登城上樓。", "清患在未形，患形其計難。", "父老不言兵，朝廷今久安。", "貴侯弄絲竹，騎士矜綺紈。", "念念須預防，壯士心爲寒。", "非公能知微，何敢矢此言。"]'),
('1d0fd0fb-4b65-4e6e-b84e-0d8b43e6e045','月夜示子文','彭汝礪','宋','宋诗','song-poetry','','[]','喜見明月到池東，我時獨與孤轉同。',64,'全唐诗/poet.song.51000.json','["喜見明月到池東，我時獨與孤轉同。", "山光水色飲不盡，更煩佳木來清風。", "浩歌一聲志萬里，飛飛欲到蟾蜍宮。", "君家玉琴試借我，爲君寫盡絲弦中。"]'),
('a413ba25-cc8b-42b8-993a-afca6087fcdf','招趙溫甫飲','彭汝礪','宋','宋诗','song-poetry','','[]','典衫買酒送春歸，與春惜別無歡怡。',48,'全唐诗/poet.song.51000.json','["典衫買酒送春歸，與春惜別無歡怡。", "窮村荒凉物色薄，肥雞綠笋皆出雌。", "却思清談醉我腹，願君促駕無遲遲。"]'),
('e4f4a67d-614a-43e0-bd51-a70f469d0e9a','和蔣深甫雷亭韵','彭汝礪','宋','宋诗','song-poetry','','[]','巉巖巨石藏蛟龍，石破龍歸舊迹空。',64,'全唐诗/poet.song.51000.json','["巉巖巨石藏蛟龍，石破龍歸舊迹空。", "風生江面激驚浪，雨歇天涯橫斷虹。", "高吟獨據一老木，遠望喜見雙飛鴻。", "蹤步忽逢溪上叟，忘言疑是渭濱翁。"]'),
('9102006e-f3fa-41e7-b0ad-0a5cd0c7adb8','賦朱令水渠','彭汝礪','宋','宋诗','song-poetry','','[]','宣城貌古心亦老，自誇渠成非草草。',64,'全唐诗/poet.song.51000.json','["宣城貌古心亦老，自誇渠成非草草。", "始挈孤忠犯衆仇，此身棄絕甘夷島。", "異言塞盡流始通，大功成就民斯保。", "天子虛心問民利，利如此渠亦須寶。"]'),
('94c9951f-5865-4941-859c-44ebb091a0c0','諒闇聞笛','彭汝礪','宋','宋诗','song-poetry','','[]','夜聞孤笛城頭上，少年側聽成惆悵。',64,'全唐诗/poet.song.51000.json','["夜聞孤笛城頭上，少年側聽成惆悵。", "明月紛紛送憂咽，清風點點來悽愴。", "鼎湖夢短飛不到，蒼梧望斷目幾耗。", "此身犬馬賤徒勞，君德岳山崇未報。"]'),
('be0de4c7-6193-480e-8311-a1139af44aeb','積德','彭汝礪','宋','宋诗','song-poetry','','[]','積德由絲毫，揚名滿天地。',60,'全唐诗/poet.song.51000.json','["積德由絲毫，揚名滿天地。", "古人成之難，今人敗之易。", "不知責己重，而獨于人備。", "天下此說用，無亦殘風誼。", "觀物竊有得，作詩聊自誌。"]'),
('d68b689b-6209-425e-9f99-a44c75707cb2','有感','彭汝礪','宋','宋诗','song-poetry','','[]','吾身本山林，艱難知備嘗。',108,'全唐诗/poet.song.51000.json','["吾身本山林，艱難知備嘗。", "天寒負書橐，萬里冒雪霜。", "山川風借力，道路泥爲漿。", "瘦馬鞭不前，悲歌自慨慷。", "今也偶得祿，雖勞庸何傷。", "念爾草野夫，百輩勤送將。", "不惟風雪勤，無乃田疇妨。", "素餐煩爾徒，心顔兩愧惶。", "作詩書諸紳，庶幾久無忘。"]'),
('5443666c-c75b-462d-9465-84be184e9680','夜登竹亭','彭汝礪','宋','宋诗','song-poetry','','[]','碧玉多朝風，蕭灑不及夜。',60,'全唐诗/poet.song.51000.json','["碧玉多朝風，蕭灑不及夜。", "滄溟月飛出，碎影如刻畫。", "愛君有素節，霜雪不凋謝。", "無言靜相對，似欲聞情話。", "城上已三更，欲歸猶未罷。"]'),
('88e42f0f-e795-4224-a7a6-edc6e02e689f','輕舟','彭汝礪','宋','宋诗','song-poetry','','[]','輕舟入深川，鈍駒陟高山。',48,'全唐诗/poet.song.51000.json','["輕舟入深川，鈍駒陟高山。", "胡爲棄安樂，輕去趨險艱。", "一身事業荒，雙親鬢髮斑。", "思之不遠慮，覽照胡爲顔。"]'),
('79238e64-ae7d-4b4a-8057-cfa48b9c0d24','鄰雞','彭汝礪','宋','宋诗','song-poetry','','[]','鄰雞號清晨，客子起長道。',48,'全唐诗/poet.song.51000.json','["鄰雞號清晨，客子起長道。", "二儀久風雨，百里生泥潦。", "高山險難登，鈍馬行欲倒。", "僕勞請休息，西北日尚杲。"]'),
('8f6df7e1-2227-4f46-b602-8185bdccf171','寒食','彭汝礪','宋','宋诗','song-poetry','','[]','山川路崎嶇，于此遇寒食。',48,'全唐诗/poet.song.51000.json','["山川路崎嶇，于此遇寒食。", "冒雨雖甚苦，驅車不遑息。", "敵愁酒無功，悅目花少色。", "誰當逆旅思，獨任清吟力。"]'),
('016b218d-d6ef-45d4-b100-112acf7cb7d5','游子','彭汝礪','宋','宋诗','song-poetry','','[]','游子何所之，上下山水中。',48,'全唐诗/poet.song.51000.json','["游子何所之，上下山水中。", "泛濫不繫舟，飄颻孤飛鴻。", "楊朱泣路歧，阮籍悲途窮。", "我志非此流，高吟屬春風。"]'),
('b799295a-9d07-491f-a849-42f3996198bd','陟山登澗','彭汝礪','宋','宋诗','song-poetry','','[]','此身何時休，終日鎮衮衮。',48,'全唐诗/poet.song.51000.json','["此身何時休，終日鎮衮衮。", "纔登澗之濱，又陟山之阪。", "僕駑怯負重，馬困憂途遠。", "道路亦常態，勉旃强餐飯。"]'),
('69777b3d-6067-4dec-9112-a9edc5b8d316','偶題','彭汝礪','宋','宋诗','song-poetry','','[]','雝然鳳之雛，傑然龍之駒。',40,'全唐诗/poet.song.51000.json','["雝然鳳之雛，傑然龍之駒。", "九天無亂雲，萬里多坦途。", "霜蹄風翮一朝舉，疲駑燕雀安能俱。"]'),
('2809752d-e7a6-48fb-8111-10bb402ae727','贈君俞茶盂','彭汝礪','宋','宋诗','song-poetry','','[]','人心一何巧，得泥自山隅。',60,'全唐诗/poet.song.51000.json','["人心一何巧，得泥自山隅。", "運泥置盤中，百轉成雙盂。", "粹質淹雪霜，清輝奪璠璵。", "精明絕隠匿，潔白無瑕污。", "殷勤持贈君，意似生束芻。"]'),
('2beba300-f042-460c-8481-5cf8b0398fc0','賦劉令公署雙頭芍藥','彭汝礪','宋','宋诗','song-poetry','','[]','花容人所憐，花意我獨知。',60,'全唐诗/poet.song.51000.json','["花容人所憐，花意我獨知。", "雨露三月春，齊榮一纖枝。", "並立無妒心，相逢况芳時。", "長同白日照，不爲顛風離。", "世情正暌乖，因賦芍藥詩。"]'),
('48e29efa-7ead-4ed2-9a13-dae8906e9343','自誡','彭汝礪','宋','宋诗','song-poetry','','[]','居方貴由禮，待物當竭誠。',48,'全唐诗/poet.song.51000.json','["居方貴由禮，待物當竭誠。", "誠亡鄙慮見，禮去驕心萌。", "曾參日三省，楊子嗟四輕。", "勉旃踐此誠，蠻貊猶可行。"]'),
('3f84164a-b693-46fa-a4ba-3fcc0c84c4fb','寄春卿','彭汝礪','宋','宋诗','song-poetry','','[]','相約童稚間，遂成歲寒圖。',72,'全唐诗/poet.song.51000.json','["相約童稚間，遂成歲寒圖。", "奈何離別多，各自東西隅。", "我心明月輪，子志青松株。", "明月千里光，豈爲吳越殊。", "青松四時心，豈爲風霜枯。", "相思不相見，作詩報區區。"]'),
('a4f216ec-dfe3-4bef-a994-c5bd8524284e','自謝','彭汝礪','宋','宋诗','song-poetry','','[]','瘠田歷水旱，畎畝多荒蕪。',288,'全唐诗/poet.song.51000.json','["瘠田歷水旱，畎畝多荒蕪。", "良農爲鋤耰，不歲成膏腴。", "瘦木僵風雪，枝幹皆蟠迂。", "良工試刻斲，不日成盤盂。", "在人雖不肖，蒙教當自殊。", "重念賤子庸，僅同流俗愚。", "學不達本原，行行無廉隅。", "九思失孔戒，三省忘曾模。", "背道而妄行，輕言以招辜。", "一身旅焚巢，衆目睽張弧。", "奔馳今逝矣，玷圭可磨乎。", "晝寢過甚微，聖門斥弗誅。", "于今底荒唐，較彼尤昏逾。", "尚頼君子仁，爲包小人蒙。", "未即遠方屏，止于鳴鼓攻。", "過愆苟不滌，憂慮環無窮。", "歸來訟醜跡，自欲鞭微躬。", "父母遣汝來，期爾才德豐。", "親友壯爾行，思爾事業充。", "不沿仁義流，反扇偷惰風。", "固宜衆人歸，詎可多雷同。", "猶願追已往，從此圖令終。", "庶幾謝顔子，自誓規繆公。", "敢期白日光，重照幽谷中。"]'),
('3de19371-08b0-4061-b20a-44829355f962','衢州道中','彭汝礪','宋','宋诗','song-poetry','','[]','登山復降山，僕膝良已酸。',60,'全唐诗/poet.song.51000.json','["登山復降山，僕膝良已酸。", "出溪復入溪，僕衣未嘗乾。", "嗟余久羈旅，囊橐亦已殫。", "無食充爾饑，無衣覆爾寒。", "買酒聊一醉，行行莫長嘆。"]'),
('0ff51da6-7b42-4b86-889c-44234b2ce2b0','冬日道中作','彭汝礪','宋','宋诗','song-poetry','','[]','夜臥衾裯單，不敢嗟體寒。',48,'全唐诗/poet.song.51000.json','["夜臥衾裯單，不敢嗟體寒。", "晨餐蔬食微，不敢嘆腹饑。", "重念饑寒民，亦有甚我身。", "我心若嗟吁，彼俗當何如。"]'),
('e151692a-40a5-4d95-ae65-093948583872','寄甯子文','彭汝礪','宋','宋诗','song-poetry','','[]','相逢一笑東風前，相別一醉昌江邊。',64,'全唐诗/poet.song.51000.json','["相逢一笑東風前，相別一醉昌江邊。", "我來西山春正妍，未見君子心欲燃。", "紫泥詔命鼎來矣，黄卷文章宜勉旃。", "題柱相如知有志，著鞭無使祖生先。"]'),
('eb9c2875-1e3b-4608-a8bc-5b5d447bf1f6','送蔣司勳赴河北漕使','彭汝礪','宋','宋诗','song-poetry','','[]','於皇時宋，治定百年。',263,'全唐诗/poet.song.51000.json','["於皇時宋，治定百年。", "朝廷肅雍，以有多賢。", "蔣侯孔碩，克明其德。", "其立嶷嶷，其嚴翼翼。", "英考是擢，以司邦直。", "彼富貴不仁，人則憚之，侯曰吾治之。", "彼孤有幼，人則侮之，侯曰吾綏之。", "竄逐流落，江湖東南。", "侯曰行哉，義豈吾慚。", "皇帝思之，擢使于閩。", "于淮于江，治績升聞。", "皇帝曰咨，朕寵爾勤。", "俾相爾攸宜，莫如河朔。", "往都漕事，以謀以度。", "侯拜稽首，受命不敢居。", "言秣其馬，言脂其車。", "其馬騑騑，雖疾而儀。", "其車軒軒，既博且閑。", "蔣侯歸止，覲于天子。", "天子是喜，曰朕有賢卿士。", "明明蔣侯，政事文章。", "以明以將，當至廟堂，奚止河一方。", "汝礪作詩，式贈其行。", "俾人詠歌，以永厥聲。"]'),
('8bb1451b-da58-40a5-9cbe-d2f4d1bad815','送上官察院歸閩中','彭汝礪','宋','宋诗','song-poetry','','[]','南山幽幽，非可陵之丘。',75,'全唐诗/poet.song.51000.json','["南山幽幽，非可陵之丘。", "淵淵其淵，非潢汙之泉。", "我徒以趨，君假我以車。", "我泳而遊，君載我以舟。", "君行未至，我心非樂。", "君去不遲，如之何勿思。", "是用作歌，以告吾懷。"]'),
('d45c0cf9-1998-41b0-81ca-6e1e74b1a5d0','某偷惰不强日陷罪惡元忠哀憐惷愚未忍誅絕賜詩爲戒佩服弗忘韵險且長賡和未逮聊作短句以代負荆','彭汝礪','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','小人無遠慮，苟志懷與安。',168,'全唐诗/poet.song.51000.json','["小人無遠慮，苟志懷與安。", "富貴本浮雲，百計圖一完。", "辰乎來之遲，玩弄如等閑。", "其不爲禽狄，不能分寸間。", "故人哀憐之，投以藥石言。", "伏讀夜達旦，顔汗肌骨寒。", "顧惟壯盛時，氣大力亦敦。", "泰山陟其顛，不見宇宙寬。", "蕩舟絕溟渤，獨自觀其瀾。", "老大不自强，喑嘿甘素餐。", "更欲盜恩榮，歸取妻子歡。", "自非仁人心，孰肯救此患。", "過惡苟容改，勿憚提耳煩。", "將大書諸紳，佩服永弗諼。"]'),
('5bfa936a-0d08-402f-9a9c-bd1fbf265035','蔣穎叔以廣陵詩見贈次其韵','彭汝礪','宋','宋诗','song-poetry','','[]','久病乘秋足寒熱，欲巢高木藏營窟。',192,'全唐诗/poet.song.51000.json','["久病乘秋足寒熱，欲巢高木藏營窟。", "衰遲不是富貴人，便合買田投印紱。", "荆溪大士簡我詩，坐覺闇室陰雲披。", "垢盡清明入兩目，憂忘喜樂生中脾。", "緘縢扃鐍欲自私，不知半夜揚清輝。", "兒童怪駭私問我，謂予藴玉藏珠顆。", "輶車近說足遐觀，烟霞日夜生毫端。", "樓臺縹緲雲中寺，衆馬不前君獨至。", "却躋雙林跋提水，更登百丈大雄山。", "游淮已擅中秋夜，落帽須分九日天。", "茱萸準擬樓頭會，終朝把酒千峰對。", "杖藜徙倚望八荒，孤鴻飛出青雲外。"]'),
('8b453298-5059-4bdc-aa3a-815980135180','擬田園樂  其一','彭汝礪','宋','宋诗','song-poetry','','[]','買田何須近郭，作屋却要依山。',28,'全唐诗/poet.song.51000.json','["買田何須近郭，作屋却要依山。", "青松共我終始，白鳥隨人往還。"]'),
('2c1567ba-b380-42a1-ba0f-a84d18884284','擬田園樂  其二','彭汝礪','宋','宋诗','song-poetry','','[]','春酒家家初熟，春花處處光輝。',28,'全唐诗/poet.song.51000.json','["春酒家家初熟，春花處處光輝。", "看花更携酒去，酒醉却插花歸。"]'),
('b9ae301f-65f5-4db3-bc5a-4eb72a104758','擬田園樂  其三','彭汝礪','宋','宋诗','song-poetry','','[]','步月溪頭置酒，野草不妨醉眠。',28,'全唐诗/poet.song.51000.json','["步月溪頭置酒，野草不妨醉眠。", "百歲獨多暇日，萬家共樂豐年。"]'),
('8f5119f3-489b-4af4-9490-0768f849a65c','擬田園樂  其四','彭汝礪','宋','宋诗','song-poetry','','[]','山色依雲闇淡，溪聲潄玉玲瓏。',28,'全唐诗/poet.song.51000.json','["山色依雲闇淡，溪聲潄玉玲瓏。", "孤笛醉吹明月，扁舟臥釣秋風。"]'),
('59395b08-16a6-489a-8405-fb1ae7194d9a','擬田園樂  其五','彭汝礪','宋','宋诗','song-poetry','','[]','霜寒禾黍初熟，日落牛羊自歸。',28,'全唐诗/poet.song.51000.json','["霜寒禾黍初熟，日落牛羊自歸。", "樂事須還田舍，浮名不入柴扉。"]'),
('91943370-7362-448c-acbe-5c66bce4eac8','擬田園樂  其六','彭汝礪','宋','宋诗','song-poetry','','[]','稚子騎牛橫笛，老翁置酒高歌。',28,'全唐诗/poet.song.51000.json','["稚子騎牛橫笛，老翁置酒高歌。", "算來人生有幾，莫問世事如何。"]'),
('5b82f73a-d75c-4ddd-9872-274f6a511767','送許屯田','彭汝礪','宋','宋诗','song-poetry','','[]','君嘗治浮梁，德愛均父母。',228,'全唐诗/poet.song.51000.json','["君嘗治浮梁，德愛均父母。", "黎明令一出，百里無敢侮。", "黠吏竄狐鼠，惠愛沾農畝。", "浮梁巧燒瓷，顔色比瓊玖。", "因官射利疾，衆喜君獨不。", "父老爭嘆息，此事古未有。", "君嘗速我飲，漓薄祇村酒。", "君舉長滿觴，我畏不濡口。", "京師晚相值，相笑俱老醜。", "我欲提君名，四方爲奔走。", "君立掉頭去，自謝吾無取。", "移舟去都門，待水三月久。", "不一詣權貴，掛席隨南斗。", "廬陵據艱險，獄訟成淵藪。", "君以一目視，無惡亦無苟。", "三年最課上，坐冠江西部。", "我來君及瓜，欲薦嗟掣肘。", "有才使如君，未見終不售。", "即聽宣室詔，莫愛潮陽守。"]'),
('11400fbb-bc4a-4258-bdb9-f6ef254f6bab','馬粹老謁黄龍祖心云得趣向處除煩惱矣因以偈謁之','彭汝礪','宋','宋诗','song-poetry','','[]','門門趙州門，路路曹溪路。',48,'全唐诗/poet.song.51000.json','["門門趙州門，路路曹溪路。", "此間無向背，云何說向趣。", "佛遊五濁世，不說無煩惱。", "此心即是佛，云何說除埽。"]'),
('65880df0-1056-4804-941f-6e92282731e3','大暑道中','彭汝礪','宋','宋诗','song-poetry','','[]','高堂臥清風，顧我豈不欲。',48,'全唐诗/poet.song.51000.json','["高堂臥清風，顧我豈不欲。", "王事不可緩，驅車冒炎酷。", "赤日暴形骸，毛髮幾焦禿。", "義命有固然，勤勞不爲辱。"]'),
('7aa84b26-b8ed-42fa-9a5a-ed91e3482b39','小舟過陂口','彭汝礪','宋','宋诗','song-poetry','','[]','輕舟落陂漘，脫去如一葉。',60,'全唐诗/poet.song.51000.json','["輕舟落陂漘，脫去如一葉。", "篙工習欹險，振呼矜巧捷。", "急水生凉風，盛暑熨汗浹。", "涉遠雖力壯，臨危固心怯。", "不如山居安，魂夢亦妥帖。"]'),
('c649dcc6-9a27-4d73-8da5-6bb7f658702a','大暑息林下','彭汝礪','宋','宋诗','song-poetry','','[]','溪流轉東西，日色不可障。',48,'全唐诗/poet.song.51000.json','["溪流轉東西，日色不可障。", "水風鼓炎熱，如坐蒸炊上。", "幽林隤山谷，弛楫沒清曠。", "行矣難少留，白雲在吾望。"]'),
('419c10be-5b73-46fa-aaac-c3715c13b343','老母德安縣君生辰頌時湖南奉使途中作','彭汝礪','宋','宋诗','song-poetry','','[]','有節維冬，有載維春。',90,'全唐诗/poet.song.51000.json','["有節維冬，有載維春。", "維時斯成，惟誕斯辰。", "婦妾祇祇，兒女詵詵。", "是笑是言，是祝是虔。", "其德維何，維厚之坤。", "其福維何，維北之山。", "嗟爾小子，不克駿奔。", "靡不肅雍，維我母賢。", "無有申之，有永其年。"]'),
('79f5bb3f-2ad5-485d-815b-efa2ec41c06c','自勉呈尊叔','彭汝礪','宋','宋诗','song-poetry','','[]','欲成九層臺，不敢寧厥居。',48,'全唐诗/poet.song.51000.json','["欲成九層臺，不敢寧厥居。", "昨朝雨暴至，圮敗祇須臾。", "百年養不足，一日毀有餘。", "非叔有至言，吾終小人徒。"]'),
('5b4a05e7-0a71-4150-b042-af5061376970','和君時城上樂字韵','彭汝礪','宋','宋诗','song-poetry','','[]','吾衰寡所欣，惟子足與樂。',84,'全唐诗/poet.song.51000.json','["吾衰寡所欣，惟子足與樂。", "愛君凌雲氣，更老更充擴。", "危城縱登眺，萬里見澄廓。", "中林韵秋風，往往中宮角。", "瓊液白玉漿，十分許君酌。", "是非等毫髮，未足煩商搉。", "貪狥終不還，彼哉世人錯。"]'),
('7563079e-00be-4062-8868-5af221b8cfff','長蘆阻風','彭汝礪','宋','宋诗','song-poetry','','[]','縱目江南路，繫船淮上村。',144,'全唐诗/poet.song.51000.json','["縱目江南路，繫船淮上村。", "長蘆雲作陣，高柳石爲根。", "浪逐江風急，潮連海水渾。", "雪霜千騎散，鉦鼓萬兵屯。", "蒲藻魚游處，泥沙鳥篆痕。", "參差鄰畫舫，咫尺想空門。", "貝葉有秘語，韋編無近言。", "漫瞻雙去翼，空飾兩朱轓。", "好在彌天釋，何如炙輠髠。", "濁清羅酒斝，南北看風幡。", "敬信無非事，精微詎可論。", "孤忠天未棄，尚合辱垂恩。"]'),
('4394849a-f26e-4dd1-afdf-f998ba766fc8','路人有棄其子者因作是詩予時奉使湖外','彭汝礪','宋','宋诗','song-poetry','','[]','彼呱呱者，其孰棄之。',90,'全唐诗/poet.song.51000.json','["彼呱呱者，其孰棄之。", "彼嬛嬛者，其孰收之。", "彼禽何知，能字其雛。", "飛前則顧，饑啄則呼。", "孰謂斯人，禽之不如。", "彼雛之微，皆得所依。", "婉娩其音，婆娑其衣。", "孰謂斯人，乃獨無歸。", "我號斯言，以告採詩。"]'),
('10e847f7-af62-4281-b3d1-3f7c0286c11e','和君時弟韵','彭汝礪','宋','宋诗','song-poetry','','[]','流火退縮金盛强，郊原日夜生寒凉。',112,'全唐诗/poet.song.51000.json','["流火退縮金盛强，郊原日夜生寒凉。", "梨垂栗皺橙柚香，田家笑語炊黄粱。", "山水秀徹摇秋光，重岩細菊斑斑黄。", "萬象呈露無遯藏，時和歲豐辰亦良。", "脂車與子游上方，吐論縱橫氣軒昂。", "書帙羅列圖畫張，睥睨孔孟窺虞唐。", "偃息道奧緣禪床，苒苒定看移星霜。"]'),
('dfa7c506-2773-4eb9-9cd7-48f2c5032d91','不寐','彭汝礪','宋','宋诗','song-poetry','','[]','吾行不能休，中夜或不寐。',48,'全唐诗/poet.song.51000.json','["吾行不能休，中夜或不寐。", "悠悠此時心，往返徧萬類。", "鰥魚固不瞑，夢蝶亦無事。", "紛紛爾何爲，百慮終一致。"]'),
('f0e2f734-f832-4fa7-88cd-c3ef8d9477cf','和叔宜弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','悠悠白雲飛，戚戚感我情。',180,'全唐诗/poet.song.51000.json','["悠悠白雲飛，戚戚感我情。", "白雲行四方，顧我豈憚行。", "投袂起番水，荷擔指宜城。", "所懷再踰秋，計以頃刻成。", "遠裝有書帙，貧囊無金籯。", "馬羸半徒步，僕瘦復兼程。", "天寒雪頻飛，山阻路少平。", "林端虎豹跡，驛後豺狼聲。", "我行有所懷，雖壯如孩嬰。", "入門旅愁破，侍席春風生。", "丁寧道懷感，惻怛一坐傾。", "我今授汝記，汝當以孝名。", "孝能事其親，榮亦及乃兄。", "乃兄久衰矣，山川倦遐征。", "歸與治爾田，我歸耦而耕。"]'),
('c0e12c5a-f597-4f84-8b15-f7390f0ed369','和叔宜弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','淚痕如雨欲垂垂，知汝心誠繫綵衣。',32,'全唐诗/poet.song.51000.json','["淚痕如雨欲垂垂，知汝心誠繫綵衣。", "江外若逢鴻雁過，時將音問寄庭幃。"]'),
('6e8b52b0-8601-4166-8369-812bd5ca8f6c','答張知常  其一','彭汝礪','宋','宋诗','song-poetry','','[]','曰歸去上鳳凰臺，已見雲中鳴雁來。',64,'全唐诗/poet.song.51000.json','["曰歸去上鳳凰臺，已見雲中鳴雁來。", "携酒幾時窺北海，采蘭三月去南陔。", "山間鼠竊不爲盜，屋上鸛巢無妄災。", "但喜朝廷容正直，更須郡守擇賢才。"]'),
('2efc2f70-7ade-4e15-9f73-58eaaeb29bdb','答張知常  其二','彭汝礪','宋','宋诗','song-poetry','','[]','兩鬢蕭條今更衰，茱萸祇似去年時。',64,'全唐诗/poet.song.51000.json','["兩鬢蕭條今更衰，茱萸祇似去年時。", "甘從彭澤淵明醉，未肯牛山丘據悲。", "泛菊想公多樂事，及瓜如我有歸期。", "須穿略彴行松徑，尚見芙蓉出槿籬。"]'),
('7a576280-7aa4-4419-9c19-e9d31da8f377','遊西山','彭汝礪','宋','宋诗','song-poetry','','[]','我少及長從公游，我今老矣公白頭。',160,'全唐诗/poet.song.51000.json','["我少及長從公游，我今老矣公白頭。", "淵明彭澤不歸去，太史周南方滯留。", "愛山興與精神聚，形骸自笑縻珪組。", "欲騎馬去陟彼砠，空羨鴻飛在于渚。", "西山第一列洞天，別有日月無歲年。", "洪崖已成丹竈藥，瑶池每賦白雲篇。", "嘒嘒蟬噪竹枝露，斑斑豹宿顛崖霧。", "伯兮伯兮歸勿遽，人間旱歲須霖雨。", "秋雨辛勤開菊花，春風取次生蘭芽。", "我雖調公不敢易，龍駒會去超胡沙。"]'),
('fa86f724-1cff-49f3-bb6d-2b617fc63f25','愛山樓歌','彭汝礪','宋','宋诗','song-poetry','','[]','山隆然兮爲屏，樓縹緲兮浮空。',95,'全唐诗/poet.song.51000.json','["山隆然兮爲屏，樓縹緲兮浮空。", "朝陽起兮輝輝，白雲宿兮溶溶。", "喬木兮陰陰，泉飛兮瓏瓏。", "花香兮春雨，鶴唳兮秋風。", "企望焉兮徜徉，橫四海兮無窮。", "氣飄浮兮欲仙，嗟勢利兮樊籠。", "歸去來兮何爲，從公游兮山之中。"]'),
('f83826c9-1306-4ca7-a9fa-8dd67b9333ff','和彥衡直講  其一','彭汝礪','宋','宋诗','song-poetry','','[]','日隠天北角，月飛海東頭。',36,'全唐诗/poet.song.51000.json','["日隠天北角，月飛海東頭。", "清暉到堂除，轉覺夜氣幽。", "睥睨天地間，無物奚爲憂。"]'),
('8ac44bdb-16dd-42e2-ae8e-6a86fd8ea8cb','和彥衡直講  其二','彭汝礪','宋','宋诗','song-poetry','','[]','是身如芭蕉，况復身外名。',24,'全唐诗/poet.song.51000.json','["是身如芭蕉，况復身外名。", "至人本無心，肯爲寵辱驚。"]'),
('df024031-45f5-4516-8318-ce13f49146c0','和彥衡直講  其三','彭汝礪','宋','宋诗','song-poetry','','[]','風隨月明來，終夜共清白。',48,'全唐诗/poet.song.51000.json','["風隨月明來，終夜共清白。", "先生靜無語，獨看庭前柏。", "冠带褫客衣，詩書倦塵跡。", "好風此時來，應與君相識。"]'),
('d5791cd0-c87a-4c22-9d80-b0348af534f2','和彥衡直講  其四','彭汝礪','宋','宋诗','song-poetry','','[]','照月槐影碎，吹風柏聲繁。',24,'全唐诗/poet.song.51000.json','["照月槐影碎，吹風柏聲繁。", "悠悠此時心，可樂不可言。"]'),
('b1a057ea-503f-4089-82a3-7c65f8a3883e','使虜有懷','彭汝礪','宋','宋诗','song-poetry','','[]','長年日戲老萊衣，不忍此身終日違。',64,'全唐诗/poet.song.51000.json','["長年日戲老萊衣，不忍此身終日違。", "今日馬頭燕北去，不堪頻望白雲飛。", "白雲汝飛去何許，悠悠會到江南路。", "朔風吹洒淚大河，直與波瀾競東注。"]'),
('121bc57b-1a26-47ff-bc98-f107d61d90be','蘆花','彭汝礪','宋','宋诗','song-poetry','','[]','風起蘆花散雪，紛紛故着枯槎。',28,'全唐诗/poet.song.51000.json','["風起蘆花散雪，紛紛故着枯槎。", "曉日曚曨照處，十分認作梅花。"]'),
('12bcf98a-9dc5-4c36-9a54-8585130cb271','沙柳','彭汝礪','宋','宋诗','song-poetry','','[]','沙陀祇見塵土，柳色如逢故人。',28,'全唐诗/poet.song.51000.json','["沙陀祇見塵土，柳色如逢故人。", "憶着千條萬葉，金明馳道青春。"]'),
('86f922c3-491d-40eb-90b2-4a81015d0709','韓氏周宣王時爲侯嘗入覲而歸顯父餞之尹吉甫作誦今司空康國公既老元祐丁卯朝京師戊辰春還許天子賜燕某賦是詩','彭汝礪','宋','宋诗','song-poetry','','[]','在昔韓侯，受命有周。',195,'全唐诗/poet.song.51000.json','["在昔韓侯，受命有周。", "紹嗣禹功，以續祖考。", "韓侯入覲，玄衮介圭，有淑其旆。", "韓侯歸止，顯父是餞。", "籩豆有踐，奏鼓衎衎。", "韓侯燕喜，既多受祉。", "施于子孫，爲宋柄臣。", "有子且賢，長則上公。", "亦似前人，有赫厥庸。", "公老許田，載見式時。", "朝有大疑，公爲蓍龜。", "公去不留，天子是思。", "薄言維之，旟旐有輝。", "都人咸喜，祝之千歲。", "國有元老，邦家是頼。", "康公之德，寅亮孔碩。", "利澤在民，功在社稷。", "孰能詩之，以繼韓奕。", "誕發其聲，施于罔極。"]'),
('26c80d85-4323-435f-95ba-ad7474333714','舟中偶言','彭汝礪','宋','宋诗','song-poetry','','[]','水聚即爲漚，漚散還爲水。',24,'全唐诗/poet.song.51000.json','["水聚即爲漚，漚散還爲水。", "祇這聚散中，便是真如理。"]'),
('e84f7194-e78e-4427-890a-11e9a06ccaf4','和瑛師','彭汝礪','宋','宋诗','song-poetry','','[]','去來的的然，莫道無來去。',48,'全唐诗/poet.song.51000.json','["去來的的然，莫道無來去。", "烟蘿寶峰境，風月清源路。", "雨漲沒滄洲，雲歸出孤嶼。", "風便水亦便，非訟亦非訴。"]'),
('9a171c49-bd5a-4f8c-932e-9822ccf7df82','題本覺庵','彭汝礪','宋','宋诗','song-poetry','','[]','本覺非今覺，今覺如本覺。',24,'全唐诗/poet.song.51000.json','["本覺非今覺，今覺如本覺。", "悟得本覺時，非覺非非覺。"]'),
('6e8f6a16-7a94-4041-addf-d7d03ef0748f','皇帝郊祀禮畢詣景靈恭謝次履中學士韵','彭汝礪','宋','宋诗','song-poetry','','[]','黎明駕出告熙成，朝野人呼萬歲聲。',64,'全唐诗/poet.song.51000.json','["黎明駕出告熙成，朝野人呼萬歲聲。", "日上天門春意近，雪殘宮瓦曉寒生。", "六龍寵護隨天仗，三爵恩容醉御觥。", "德似丘山纖未報，白頭知愧不知榮。"]'),
('7d10ef58-8dbe-4fe0-959e-5d02d1e27028','皇帝郊丘從駕次履中學士','彭汝礪','宋','宋诗','song-poetry','','[]','今歲郊丘上始躬，宿齋初出未央宮。',64,'全唐诗/poet.song.51000.json','["今歲郊丘上始躬，宿齋初出未央宮。", "百年禮樂星辰爛，萬國衣冠錦繡中。", "精意與天相應接，人心如水自流通。", "聖時好作休成記，今日誰爲太史公。"]'),
('802f85a8-cbea-4c53-b7a1-7dcc38348735','次韵履中學士宴集英殿','彭汝礪','宋','宋诗','song-poetry','','[]','衮衣玉色殿中央，簪佩參差萬翼張。',64,'全唐诗/poet.song.51000.json','["衮衣玉色殿中央，簪佩參差萬翼張。", "和氣每窺天一笑，晬容時見日重光。", "九成樂奏蓬山近，百和香焚黼座傍。", "魚躍鳥飛應自喜，君仁三倍勝岐昌。"]'),
('4034484c-6e76-4b53-abb3-41029aebdd57','次履中學士正月十一日迎駕大慶殿','彭汝礪','宋','宋诗','song-poetry','','[]','瑞霧蒼茫杳靄間，遲明催立大庭班。',64,'全唐诗/poet.song.51000.json','["瑞霧蒼茫杳靄間，遲明催立大庭班。", "禁林草木青春近，秘閣文書白日閑。", "華蓋熒煌天帝座，蓬萊縹緲道家山。", "金輿玉乘歸何晚，樂奏鈞天夢未還。"]'),
('c4c884d0-3c1c-41d9-858a-84f0815d42b9','考試閣下次子由韵','彭汝礪','宋','宋诗','song-poetry','','[]','省曹祇有西曹要，官府無如憲府嚴。',64,'全唐诗/poet.song.51000.json','["省曹祇有西曹要，官府無如憲府嚴。", "國論于今須汲直，人才自昔畏由兼。", "斧斤準擬棟梁得，塵土吁嗟圭璧淹。", "萬事調和歸適可，諸公聞望在梅鹽。"]'),
('d21c97f6-358e-4561-82aa-413b6d429761','贈去華學士','彭汝礪','宋','宋诗','song-poetry','','[]','射策熙寧第二人，十年青綬困京塵。',64,'全唐诗/poet.song.51000.json','["射策熙寧第二人，十年青綬困京塵。", "聲名未誤如椽筆，寵辱何疑是夢身。", "壯志自能探虎穴，危言更看逆龍鱗。", "美才何但膺門客，觀國今時正利賓。"]'),
('3f6ff175-2ac5-4c71-b4d9-f514e434731c','巖夫庭佐欲歸出長安以詩邀游後圃','彭汝礪','宋','宋诗','song-poetry','','[]','馬蹄容易去吾東，行李紛紛計已怱。',64,'全唐诗/poet.song.51000.json','["馬蹄容易去吾東，行李紛紛計已怱。", "還使寸腸隨夜月，不知一淚落春風。", "雙飛露草看原鶺，獨宿雲溪念塞鴻。", "更約藏舟今日飲，百壺清笑慰飄蓬。"]'),
('298a05c1-36ba-45eb-86bd-f31216a13326','奉答諸兄弟詩韵','彭汝礪','宋','宋诗','song-poetry','','[]','饑渴相期侍板輿，途中千萬數脂車。',64,'全唐诗/poet.song.51000.json','["饑渴相期侍板輿，途中千萬數脂車。", "浮生本自雲無定，白髮新來雪不如。", "原上脊令知望汝，洲前鸚鵡看題書。", "愁腸日有平安信，祇問江頭雙鯉魚。"]'),
('55e51345-4ce2-4e2f-bec2-e526e8a77091','得至郢州寄知郡朝議','彭汝礪','宋','宋诗','song-poetry','','[]','襄陽曾賦贈行詩，邂逅扁舟得所期。',64,'全唐诗/poet.song.51000.json','["襄陽曾賦贈行詩，邂逅扁舟得所期。", "勝迹好尋梅福宅，真游稍記習家池。", "郢中白雪今誰和，漢上仙槎恰是時。", "冰酒直須多準備，寄聲先報主人知。"]'),
('e22e6393-363f-49c0-be11-b20b893615a3','寄和仲','彭汝礪','宋','宋诗','song-poetry','','[]','日月其除如擲梭，老來衰疾轉添多。',64,'全唐诗/poet.song.51000.json','["日月其除如擲梭，老來衰疾轉添多。", "苦心不祇荼毒似，短髮無如霜雪何。", "畢竟行藏渾有定，尋常聚散亦非它。", "欲知日暮相思意，牛首山前湖水波。"]'),
('f51b24ab-4803-40b4-8ec7-3fec3574e3d5','奉懷深父學士友兄  其一','彭汝礪','宋','宋诗','song-poetry','','[]','泛泛公舟何所之，江湖不似月相隨。',64,'全唐诗/poet.song.51000.json','["泛泛公舟何所之，江湖不似月相隨。", "關西夫子吾所畏，河上丈人今所思。", "蓬髮白如相別日，菊花黄似去年時。", "看花欲飲竟無味，不是貧家缺酒巵。"]'),
('2dd4b9b4-ef5e-4543-94a6-21925715f2e8','奉懷深父學士友兄  其二','彭汝礪','宋','宋诗','song-poetry','','[]','看山更飽更無厭，野色雖寒亦不嫌。',64,'全唐诗/poet.song.51000.json','["看山更飽更無厭，野色雖寒亦不嫌。", "風作浪頭高突兀，雲埋雨脚細廉纖。", "一雙遠岸釣魚艇，三尺近村沽酒帘。", "海上浮舟憶彭蠡，門前栽柳舊陶潜。"]'),
('72495636-4009-45fa-832f-37a95b515d25','奉和施禽魚食復賡一章','彭汝礪','宋','宋诗','song-poetry','','[]','南方有國號清凉，人好禽魚性亦良。',64,'全唐诗/poet.song.51000.json','["南方有國號清凉，人好禽魚性亦良。", "在藻日分香積飯，銜花時繞浄明床。", "濠梁孰謂安知樂，大澤吾能不亂行。", "但得養魚如養己，相濡仍不似相忘。"]'),
('1b0ba60c-1e38-4166-99f8-501c8534aecc','江上寄廣漢屯田丈','彭汝礪','宋','宋诗','song-poetry','','[]','白首扁舟西復東，滄江時對百花叢。',64,'全唐诗/poet.song.51000.json','["白首扁舟西復東，滄江時對百花叢。", "山光縹緲雲霄外，水氣溟濛烟靄中。", "似酒鵝兒隨暮雨，于飛燕子語春風。", "一杯欲飲終無緒，想望鄰家鶴髮翁。"]'),
('7423ea3b-8668-4adc-a919-8230d1b343fc','和瑛師','彭汝礪','宋','宋诗','song-poetry','','[]','江湖日夜著東流，水上乾坤一點浮。',64,'全唐诗/poet.song.51000.json','["江湖日夜著東流，水上乾坤一點浮。", "隔浦雲山隨客步，近村花竹慰人愁。", "同舟自有林宗在，結社還須惠遠游。", "酒興正酣歸更懶，坐看凉月上滄洲。"]'),
('5e231cbd-7cb7-43d8-9a3f-df4cd3bf181e','兵部敏叔頒示佳句謹依原韵','彭汝礪','宋','宋诗','song-poetry','','[]','遍瀰川澤壓岡巒，萬室清明更可觀。',64,'全唐诗/poet.song.51000.json','["遍瀰川澤壓岡巒，萬室清明更可觀。", "麥上早春誰漏洩，梅邊窮臘自凋殘。", "陰陽順適天時好，高下均平地澤寬。", "歲歲豐登今以始，都人切勿怨祁寒。"]'),
('b2e1da69-33ae-4261-863c-4ca89bdf2ff1','次去華學士韵','彭汝礪','宋','宋诗','song-poetry','','[]','九衢塵土暴秋陽，宮殿深沉早自凉。',64,'全唐诗/poet.song.51000.json','["九衢塵土暴秋陽，宮殿深沉早自凉。", "庭柏染霜千丈碧，籬花著雨一番黄。", "天邊河漢波瀾闊，海上蓬萊日月光。", "文物豈惟淹漢魏，太平久矣四三皇。"]'),
('f4b124a5-e6a0-4597-a5ba-2b0c8de101f3','寄君時弟','彭汝礪','宋','宋诗','song-poetry','','[]','日夜風前聽好音，書來一讀一傷心。',64,'全唐诗/poet.song.51000.json','["日夜風前聽好音，書來一讀一傷心。", "淚摇眼尾催花發，愁結眉頭見雪侵。", "秋徑自栽彭澤菊，夜堂時奏武城琴。", "事多不廢看書否，白首知君惜寸陰。"]'),
('d407fb59-03e1-4793-8fec-4d4ab04dc195','送祖道朝奉','彭汝礪','宋','宋诗','song-poetry','','[]','二月同舟出宋都，轉頭即是十年餘。',64,'全唐诗/poet.song.51000.json','["二月同舟出宋都，轉頭即是十年餘。", "可憐老大猶爲客，莫怪尋常不作書。", "蠟屐阮孚人不會，鱸魚張翰子何如。", "寄聲莫汙清風地，留與先生作隠居。"]'),
('4d34a6d8-d6f8-48e5-a12f-d37fc1138ccd','送吳縣丞','彭汝礪','宋','宋诗','song-poetry','','[]','四十青衫似老翁，作官不似作詩工。',64,'全唐诗/poet.song.51000.json','["四十青衫似老翁，作官不似作詩工。", "身追鴻鵠雲霄外，手縛鯨鯢波浪中。", "俊敏今非無李白，沉深古自有揚雄。", "和聲直可奏宗廟，嘆息無人知爨桐。"]'),
('694a38cc-36f3-47fa-b06e-155b0e763ee8','送葉亨仲','彭汝礪','宋','宋诗','song-poetry','','[]','太學聲名二十年，詞場少以一當千。',64,'全唐诗/poet.song.51000.json','["太學聲名二十年，詞場少以一當千。", "王良僅可使執轡，祖逖豈容爭着鞭。", "文字莫愁蒙醤瓿，功名欲看勒燕然。", "故人相見如相問，爲說蕭條雪滿顛。"]'),
('77ebc411-ffd0-4780-ac8b-0ed47dc995d3','四月七日出城西見河中資政侍郎遇中叔聯騎入池南門行東北隅以歸各賦一首','彭汝礪','宋','宋诗','song-poetry','','[]','一過西城首一迴，經年欲往限塵埃。',64,'全唐诗/poet.song.51000.json','["一過西城首一迴，經年欲往限塵埃。", "薔薇露溼春猶在，楊柳烟深曉未開。", "雨後波光浮渤澥，雲中山色隠蓬萊。", "與君馳馬競東北，也道曾來池上來。"]'),
('d7cdb0da-7cd2-4c6b-a14e-e8c060601500','和美叔學士','彭汝礪','宋','宋诗','song-poetry','','[]','早日清明氣鬰葱，翠輿朝出建章宮。',64,'全唐诗/poet.song.51000.json','["早日清明氣鬰葱，翠輿朝出建章宮。", "光回鷺羽雲霄外，翠滴荷衣雨露中。", "苦愛平心似崔郾，預愁啟事愧山公。", "酬詩自笑才慳澀，不似清微長養風。"]'),
('cc415649-12a6-4ec0-8c5c-d23b7e90b70e','和彥常侍郎','彭汝礪','宋','宋诗','song-poetry','','[]','濯濯威靈赫赫光，天顔咫尺在岩廊。',64,'全唐诗/poet.song.51000.json','["濯濯威靈赫赫光，天顔咫尺在岩廊。", "圖功未肯兄三古，較藝何嫌弟寸長。", "鼓舞雷風馳漢詔，昭回雲漢見堯章。", "酒樽更有論文樂，一笑令人萬事忘。"]'),
('62c500bb-7cb5-4733-aa32-d445e97d698b','再和彥常侍郎','彭汝礪','宋','宋诗','song-poetry','','[]','天上九重開禁闥，雲間千步見修廊。',64,'全唐诗/poet.song.51000.json','["天上九重開禁闥，雲間千步見修廊。", "仙源水近漂花急，化國人閑愛日長。", "較藝過旬窺錦繡，賦詩終日聽韶章。", "時沾好賜終何報，自許餘忠老未忘。"]'),
('c0c5ccab-63b4-4fad-a27e-a24ba7be002b','送池須文長官','彭汝礪','宋','宋诗','song-poetry','','[]','龍淵虎穴少窮探，老大生涯一劍鐔。',64,'全唐诗/poet.song.51000.json','["龍淵虎穴少窮探，老大生涯一劍鐔。", "曲沼鴛鴦多白髮，雕籠鸚鵡久青衫。", "能知令尹三無慍，正似嵇康七不堪。", "見說明朝好天色，鵬程從此穩圖南。"]'),
('85fe0092-485d-4928-9993-ed9a32fdeebc','劉生適中初業儒稍能文詞氣勇而不暴甚得鄉士人心連蹇不得志以醫游四方元祐七年來京師予與喬給事公權豐侍郎相之薦于朝入翰林爲醫官孫待制傳師帥渭辟以從予哀生之志未得而喜其得賢主人以歸也作是詩以送之','彭汝礪','宋','宋诗','song-poetry','','[]','短衣瘦馬去從軍，辛苦知君祇爲貧。',64,'全唐诗/poet.song.51000.json','["短衣瘦馬去從軍，辛苦知君祇爲貧。", "絲綬戲拈五兩去，桂華志取一枝春。", "持書關內大丞相，寄語渭濱賢主人。", "種種別時雙鬢髮，蕭條今日總如銀。"]'),
('e407eb5c-dd7a-4b0c-938d-9f857d377353','送蔣和父赴代州教授','彭汝礪','宋','宋诗','song-poetry','','[]','十年場屋飽聲名，落筆從容一坐傾。',64,'全唐诗/poet.song.51000.json','["十年場屋飽聲名，落筆從容一坐傾。", "餘澤未能沾萬物，緒言聊復啟諸生。", "青衫簿領當時態，白首詩書足義榮。", "得失已知君不恤，春風談笑入邊城。"]'),
('e99ff771-5cea-4aa0-8b08-e290a547cf2f','豐湖  其一','彭汝礪','宋','宋诗','song-poetry','','[]','漫漫平湖十里賒，南州今作畫圖誇。',64,'全唐诗/poet.song.51000.json','["漫漫平湖十里賒，南州今作畫圖誇。", "波瀾雨過魚兒出，草木春歸荔子花。", "山近冷光摇几席，地平餘潤入桑麻。", "使君恩德還如水，長滿羅浮十萬家。"]'),
('bc39c6f0-77f5-4dfc-886a-4d28e0ee266d','豐湖  其二','彭汝礪','宋','宋诗','song-poetry','','[]','仙閣玲瓏高出雲，畫橋縹緲浄無塵。',64,'全唐诗/poet.song.51000.json','["仙閣玲瓏高出雲，畫橋縹緲浄無塵。", "滿分江海千年潤，平占蓬瀛十里春。", "照浦蠙珠應自復，隨舟鷗鳥會相親。", "使君愛物能如此，閭巷當時合借恂。"]'),
('b3411bac-c6e6-47d2-b35f-0b1b6346d4d7','和深父學士','彭汝礪','宋','宋诗','song-poetry','','[]','故人氣分比松筠，凌雨霜風轉更新。',64,'全唐诗/poet.song.51000.json','["故人氣分比松筠，凌雨霜風轉更新。", "暇日莫辭三斗酒，浮雲便是百年身。", "今來古往祇如此，弟唱兄酬莫厭頻。", "雪霽擁爐須酩酊，月明分手更逡巡。"]'),
('75944bb4-6a9e-4fda-9167-30806f8db247','和侯利建運使朝請','彭汝礪','宋','宋诗','song-poetry','','[]','當年置酒峴山亭，公作新詩我載賡。',64,'全唐诗/poet.song.51000.json','["當年置酒峴山亭，公作新詩我載賡。", "疾病尚憐憂似醉，文章還看美如英。", "傷哉無復老萊戲，久矣不聞韶樂聲。", "饑鵠欲飛嗟已老，謬煩江漢借修程。"]'),
('2d97baba-ae54-45cb-986b-20e5e777a3bd','和通判朝奉宋丈  其一','彭汝礪','宋','宋诗','song-poetry','','[]','塵事如毛日日生，故園久擬問歸程。',64,'全唐诗/poet.song.51000.json','["塵事如毛日日生，故園久擬問歸程。", "飛鵬怒薄扶摇上，病驥饑尋巀嵲行。", "綠野盡頭迷漢水，白雲深處是樊城。", "私懷借問何其似，祇看摇摇車上旌。"]'),
('410181e1-eae4-44a4-a41a-98e1e735a2ae','和通判朝奉宋丈  其二','彭汝礪','宋','宋诗','song-poetry','','[]','未忍田間老此生，衰遲已覺怯修程。',64,'全唐诗/poet.song.51000.json','["未忍田間老此生，衰遲已覺怯修程。", "頻頻彼似鸒斯黨，踽踽吾非杕杜行。", "雲影晝迷芝嶺路，水聲夜到鳳林城。", "僕夫不見人憂思，未曉匆匆已抗旌。"]'),
('c0fe73fd-46b1-4526-b3f8-a747847dad07','再呈通判承議  其一','彭汝礪','宋','宋诗','song-poetry','','[]','山邊置酒水邊行，魚鳥于人各有情。',64,'全唐诗/poet.song.51000.json','["山邊置酒水邊行，魚鳥于人各有情。", "終世果能著幾屐，此時聊可濯吾纓。", "啟期拍手誇三樂，漁父張頤笑獨清。", "四海一舟歸未得，低徊長恐負平生。"]'),
('c33d5e13-678a-4d6b-867e-11258eb0fc05','再呈通判承議  其二','彭汝礪','宋','宋诗','song-poetry','','[]','南頭如送北頭迎，祇有溪山不世情。',64,'全唐诗/poet.song.51000.json','["南頭如送北頭迎，祇有溪山不世情。", "少日激昂投耒耜，老年辛苦畏簪纓。", "長松根脚龍蛇蟄，老鶴精神玉雪清。", "會得無生渾自足，還容款曲問長生。"]'),
('9e130ed8-8a71-42bd-bc8c-93800964a492','呈通判朝奉宋丈  其一','彭汝礪','宋','宋诗','song-poetry','','[]','昨日南陽今淅川，馳驅不敢恨華顛。',64,'全唐诗/poet.song.51000.json','["昨日南陽今淅川，馳驅不敢恨華顛。", "久披褐布是居士，時着斑衣猶少年。", "係屧記尋幽徑竹，泛舟憶近碧池蓮。", "笑君與我渾相似，目病鰥鰥夜不眠。"]'),
('4d35d3f1-0818-4280-ad9c-955f480b4bb1','呈通判朝奉宋丈  其二','彭汝礪','宋','宋诗','song-poetry','','[]','經時山川浪跋履，半夜衣裳時倒顛。',64,'全唐诗/poet.song.51000.json','["經時山川浪跋履，半夜衣裳時倒顛。", "塵土最能催白首，風波祇會送流年。", "寂寥彭澤門栽柳，萧洒東林社結蓮。", "語及故鄉歸未得，看雲步月欲忘眠。"]'),
('9bcac1eb-3632-4088-8d4c-0d3c76552a62','持正率和中丞諸公喜雨  其一','彭汝礪','宋','宋诗','song-poetry','','[]','昊天旋日照宸憂，靈雨崇朝遍舜州。',64,'全唐诗/poet.song.51000.json','["昊天旋日照宸憂，靈雨崇朝遍舜州。", "雲起山川初一點，水傾河漢欲交流。", "歡愉散入輿人誦，潤澤渾供萬物求。", "遙想玉山禾粒熟，來儀還見鳳凰秋。"]'),
('4f623e06-dc93-4c07-98f4-b74a7efbe826','持正率和中丞諸公喜雨  其二','彭汝礪','宋','宋诗','song-poetry','','[]','盛德無煩百姓憂，分明靈貺厚齊州。',64,'全唐诗/poet.song.51000.json','["盛德無煩百姓憂，分明靈貺厚齊州。", "精神散接諸天遠，潤澤橫隨四海流。", "玉色晬溫知有喜，淵衷澄寂本無求。", "史官屢得豐年事，還記熙寧第十秋。"]'),
('28e521d3-2ae8-4f72-96eb-c5c6f271e7f9','奉寄深之學士子開侍郎','彭汝礪','宋','宋诗','song-poetry','','[]','萬國承平道更尊，君王取士夙臨軒。',64,'全唐诗/poet.song.51000.json','["萬國承平道更尊，君王取士夙臨軒。", "雕蟲立廢賈馬賦，發策跂聞晁董言。", "蘭艾同榮春靄靄，魚龍欲化海渾渾。", "風流想見東華路，夾道傳呼看狀元。"]'),
('d324be76-7ff0-459c-9c83-1df1eea08259','時在集英幕中呈諸公學士','彭汝礪','宋','宋诗','song-poetry','','[]','衰病從來飯亦慵，不堪鎖宿似南宮。',64,'全唐诗/poet.song.51000.json','["衰病從來飯亦慵，不堪鎖宿似南宮。", "夜凉月滿重簾外，春雨花開一夢中。", "軒陛直言尊董氏，朝廷故事問胡公。", "文章久怪無新語，議論初欣有古風。"]'),
('2341ed97-93df-4e62-9658-7b6537065b18','和范學士韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','大府池臺能近郭，鄰家花木巧當顔。',64,'全唐诗/poet.song.51000.json','["大府池臺能近郭，鄰家花木巧當顔。", "叢篁著雨初成徑，巨石浮烟恰是山。", "御氣即能馳碧落，戰文誰敢敵黄間。", "樂天自得三無慍，易地何殊五不還。"]'),
('87d3b3dc-32e5-4a71-bed9-5db24958e59c','和范學士韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','先生亡子衆推賢，號慕今猶似慟顔。',64,'全唐诗/poet.song.51000.json','["先生亡子衆推賢，號慕今猶似慟顔。", "西竺嘗言空是色，南華亦笑澤藏山。", "由來世事無窮處，畢竟人生在幾間。", "看著江流長泛泛，可言逝水不知還。"]'),
('4a0a97a2-657d-4e54-8437-36bec1f0d737','和范學士韵  其三','彭汝礪','宋','宋诗','song-poetry','','[]','日華苒苒在波瀾，水色依依照面顔。',64,'全唐诗/poet.song.51000.json','["日華苒苒在波瀾，水色依依照面顔。", "漢上仙槎浮八月，海中金闕隠三山。", "芙蓉開席成陰處，楊柳維舟倒影間。", "景物向人情不淺，頻將風月送公還。"]'),
('5f4537ff-6561-4869-8f9d-86d47087e802','和范學士韵  其四','彭汝礪','宋','宋诗','song-poetry','','[]','清香一炷意超然，萬事無緣更動顔。',64,'全唐诗/poet.song.51000.json','["清香一炷意超然，萬事無緣更動顔。", "野鳥銜花來丈室，烟蘿招月出遙山。", "居方不礙游方內，住世還如出世間。", "却笑晚年貪著事，野邊湖外夜忘還。"]'),
('d1a6e619-455c-43de-b450-49d8071cdf54','和范學士韵  其五','彭汝礪','宋','宋诗','song-poetry','','[]','南陽五月飽偷安，報政無聞祇汗顔。',64,'全唐诗/poet.song.51000.json','["南陽五月飽偷安，報政無聞祇汗顔。", "平日髠鉗盈狴犴，豐年盜賊出丘山。", "簿書細碎晨昏事，弦誦寂寥庠序間。", "但見潁川多鳳集，仍知合浦有珠還。"]'),
('eb4fabe4-992e-44b1-92a9-1b4ad7ed4b03','和范學士韵  其六','彭汝礪','宋','宋诗','song-poetry','','[]','豈有微功答謬恩，尚思榮祿慰慈顔。',64,'全唐诗/poet.song.51000.json','["豈有微功答謬恩，尚思榮祿慰慈顔。", "心誠似水知宗海，事責如蚊欲負山。", "資性僅同中以下，行能未及二之間。", "木桃每屈言爲贈，祇恐瓊瑶未足還。"]'),
('36c7e9a9-703a-4718-8864-2ed09e23df1c','和范學士韵  其七','彭汝礪','宋','宋诗','song-poetry','','[]','南陽雖好遠江干，襄沔歸來失病顔。',64,'全唐诗/poet.song.51000.json','["南陽雖好遠江干，襄沔歸來失病顔。", "雨霽遠浮清漢水，雲歸深見上方山。", "傷心蜀主君臣際，回首龐公父子間。", "薄暮樓頭待明月，笛聲時見釣舟還。"]'),
('93d10912-5066-4253-95f9-5f0fcf0d9cb2','和范學士韵  其八','彭汝礪','宋','宋诗','song-poetry','','[]','起照青銅已鬢斑，早衰不似舊容顔。',64,'全唐诗/poet.song.51000.json','["起照青銅已鬢斑，早衰不似舊容顔。", "塵埃苒苒行其野，霜雪紛紛陟彼山。", "稍憶輟耕棲壠上，不堪待罪久行間。", "陽臺自笑雲無定，華表應疑鶴未還。"]'),
('4fb8ab3f-def4-44f3-ae9d-e86c0f5f075a','和范學士韵  其九','彭汝礪','宋','宋诗','song-poetry','','[]','風雨先催十月寒，顧瞻言邁祇悲顔。',64,'全唐诗/poet.song.51000.json','["風雨先催十月寒，顧瞻言邁祇悲顔。", "二天舊澤流淮水，五色新文照楚山。", "我病欲歸虜使重，君行合在侍臣間。", "潁川莫厭次公去，宣室方思賈誼還。"]'),
('66a97f99-d05a-4b3e-a935-9b8beae5d65f','和劉舍人','彭汝礪','宋','宋诗','song-poetry','','[]','剪綵微茫比絲髮，雕金焜晃映蟬貂。',64,'全唐诗/poet.song.51000.json','["剪綵微茫比絲髮，雕金焜晃映蟬貂。", "鵷鸞破曉趨丹禁，雨露迎春下九霄。", "花映上尊非索寞，雪侵餘鬢自蕭條。", "讀書終日不知味，恰似在齊聞舜韶。"]'),
('cdb5aeb8-ce00-47fc-a2d5-8f19c4cdf38d','和執中寄師厚同年  其一','彭汝礪','宋','宋诗','song-poetry','','[]','千載風雲慶一逢，枯榮相望百年中。',64,'全唐诗/poet.song.51000.json','["千載風雲慶一逢，枯榮相望百年中。", "雪霜松檜材先老，泥土驊騮路未通。", "顔子奚慚一簞食，阮生不是哭途窮。", "春游取次吟花藥，枉負燈窗翰墨功。"]'),
('c31e2157-f2ff-4adb-8dff-753b00001377','和執中寄師厚同年  其二','彭汝礪','宋','宋诗','song-poetry','','[]','日暮相忘城上亭，雲深祇見數峰青。',64,'全唐诗/poet.song.51000.json','["日暮相忘城上亭，雲深祇見數峰青。", "傅岩可獨爲霖雨，荀里還歸聚德星。", "漢水溯風增浩蕩，蘭花着雨長芳馨。", "嘯吟久不過諸葛，丰度今誰似九齡。"]'),
('118cb885-a41e-4b1f-b082-2669ba6e7bf2','招執中看酴醾','彭汝礪','宋','宋诗','song-poetry','','[]','恰是酴醾初盛時，清香終日在塵衣。',64,'全唐诗/poet.song.51000.json','["恰是酴醾初盛時，清香終日在塵衣。", "參差正對金沙拆，散漫更爲蝴蝶飛。", "日暖綠雲長闇淡，春深白雪更霏微。", "急來相就花前醉，看盡此花春欲歸。"]'),
('045e500e-3ff7-4fc4-b4e2-1f8b10b4b2ce','寄正夫判官','彭汝礪','宋','宋诗','song-poetry','','[]','數竿嚴瀨釣魚綸，一幅淵明漉酒巾。',64,'全唐诗/poet.song.51000.json','["數竿嚴瀨釣魚綸，一幅淵明漉酒巾。", "天上舊傳公子貴，漢陰今見丈人真。", "登山臨水能胥宇，問舍求田待卜鄰。", "欲作獨清無已甚，時將數字寄埃塵。"]'),
('45b17cac-73d5-426a-9c71-47f7cbb19903','送宗文先輩','彭汝礪','宋','宋诗','song-poetry','','[]','夫子聲名二十年，塵埃歎息欲華顛。',64,'全唐诗/poet.song.51000.json','["夫子聲名二十年，塵埃歎息欲華顛。", "相如舊有凌雲賦，靖節今無種秫田。", "南國寂寥歸見雁，北風悲壯屢聞蟬。", "思量世事真如幻，合置窮愁頓酒邊。"]'),
('5ac2e1e4-421c-4492-9317-419741bff817','和子仲都官徐孺亭','彭汝礪','宋','宋诗','song-poetry','','[]','已矣斯人不可從，風流今見一亭中。',64,'全唐诗/poet.song.51000.json','["已矣斯人不可從，風流今見一亭中。", "雲藏洲渚秋長碧，日在波瀾晚更紅。", "旱歲會爲岩際雨，貪夫亦畏海瀕風。", "于今未見如公比，嘆息陳蕃榻亦空。"]'),
('ab8a6121-2c57-439c-93bc-7ec0c446cbdc','和穎叔寄佛印  其一','彭汝礪','宋','宋诗','song-poetry','','[]','有客寄詩南雍州，清新全占峴山秋。',64,'全唐诗/poet.song.51000.json','["有客寄詩南雍州，清新全占峴山秋。", "官名便據非常寵，文學元居第一流。", "雲近蛟龍朝丈室，夜寒星月宿重樓。", "知公有勇斷鼇足，到彼不須騎虎頭。"]'),
('b6532583-7aeb-466c-9113-d0dcb619ecd2','和穎叔寄佛印  其二','彭汝礪','宋','宋诗','song-poetry','','[]','憶留鐵甕城經夏，却泛金山寺看秋。',64,'全唐诗/poet.song.51000.json','["憶留鐵甕城經夏，却泛金山寺看秋。", "鐘梵去隨滄海遠，樓臺低湧大江流。", "波瀾隠約開龍國，烟霧分明見蜃樓。", "他日上方容聽法，不應疑我皺眉頭。"]'),
('942a73b3-25dc-45b7-8f3a-fc08f537926f','又寄佛印','彭汝礪','宋','宋诗','song-poetry','','[]','神仙苒苒在蓬壺，更得詩來慰索居。',64,'全唐诗/poet.song.51000.json','["神仙苒苒在蓬壺，更得詩來慰索居。", "天上樓臺開佛國，日邊香火讀天書。", "籃輿獨往公今爾，蠟屐他時我亦如。", "彼是此非無足問，悠悠同是一空虛。"]'),
('1ef8883e-c149-46b7-82da-18e72cb24bf7','途中久雨','彭汝礪','宋','宋诗','song-poetry','','[]','我征徂西今復東，分明身世如飄蓬。',64,'全唐诗/poet.song.51000.json','["我征徂西今復東，分明身世如飄蓬。", "歲華便是百年半，日氣恰當三伏中。", "山谷無情頻送雨，園林何事急招風。", "浮生所遇皆知分，未用紛紛論色空。"]'),
('74281be6-74dd-4b77-b183-ab09e2b73f76','灘上','彭汝礪','宋','宋诗','song-poetry','','[]','片帆逆水過溪山，吾賤能諳世路難。',64,'全唐诗/poet.song.51000.json','["片帆逆水過溪山，吾賤能諳世路難。", "小雨作雲迷澗谷，急風吹雪上波瀾。", "草根已定春來意，梅蕊猶含臘後寒。", "漸老豈能支道路，扁舟欲去老漁竿。"]'),
('189762d2-03dc-402b-8a38-cfdb5ccc11f8','送正孺','彭汝礪','宋','宋诗','song-poetry','','[]','離筵冰凍樽中酒，行路雪沾身上衣。',64,'全唐诗/poet.song.51000.json','["離筵冰凍樽中酒，行路雪沾身上衣。", "游子思鄉夢先到，老人惜別涕交揮。", "昔年終軍棄繻去，今日買臣懷綬歸。", "晝繡奚爲公不樂，祇應愁見白雲飛。"]'),
('ea088a4b-0325-4f6d-a342-71a774060324','答執中見和','彭汝礪','宋','宋诗','song-poetry','','[]','枉費山公席上珍，看書轉憶笑言親。',64,'全唐诗/poet.song.51000.json','["枉費山公席上珍，看書轉憶笑言親。", "舊時香積厨中飯，新得金蓮社裏人。", "傳語簿書聊借日，寄聲風雨莫催春。", "須容飽飫先生饌，可便閑防異姓賓。"]'),
('d945aba7-c84e-4899-ac96-b938bfa5c119','和伯鈞節推','彭汝礪','宋','宋诗','song-poetry','','[]','昔年相見蜀山隈，落落知君匪衆材。',64,'全唐诗/poet.song.51000.json','["昔年相見蜀山隈，落落知君匪衆材。", "白髮今時俱老大，青山何日盍歸來。", "烟塵草草馳軍檄，風雨匆匆把酒盃。", "萬事欲言終不盡，詩成悽愴有餘哀。"]'),
('42baa835-6c5e-4e6f-9f29-dfe0d1132461','東流寄天保弟','彭汝礪','宋','宋诗','song-poetry','','[]','湖山高下綠參差，目斷東流此一時。',64,'全唐诗/poet.song.51000.json','["湖山高下綠參差，目斷東流此一時。", "日久不聞鴻雁信，春來初見棠棣詩。", "草根二月蔞蒿熟，沙外數家楊柳垂。", "恰是去年相送處，酒樽還憶數追隨。"]'),
('be1a8bb7-8ca5-4289-90fc-6b0305c8e1eb','寄君時弟','彭汝礪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','正直多疑勢易孤，官情時態近何如。',64,'全唐诗/poet.song.51000.json','["正直多疑勢易孤，官情時態近何如。", "應知秋後無窮事，未得冬來第一書。", "憶汝愁聞洞庭雁，作詩欲寄武昌魚。", "江湖此別何其久，日月居諸又歲除。"]'),
('1e6cf28f-cb0f-4f8f-aac2-e6f126a395db','使遼','彭汝礪','宋','宋诗','song-poetry','','[]','北行未始過陳橋，仗節今朝使大遼。',64,'全唐诗/poet.song.51000.json','["北行未始過陳橋，仗節今朝使大遼。", "寒日擁雲初漠漠，急風招雪晚蕭蕭。", "江湖夢寐時之楚，象魏精誠日望堯。", "孤驛夜深誰可語，青燈黄卷慰無聊。"]'),
('79051482-ea9c-45f6-a5e9-b77c04d9d73c','古北口楊太尉廟','彭汝礪','宋','宋诗','song-poetry','','[]','將軍百戰死嶔岑，祠廟巖巖古到今。',64,'全唐诗/poet.song.51000.json','["將軍百戰死嶔岑，祠廟巖巖古到今。", "萬里胡人猶破膽，百年壯士獨傷心。", "遺靈半夜雨如雹，餘恨長時日爲陰。", "驛舍愴懷心欲碎，不須更聽鼓鼙音。"]'),
('47ac3922-5841-4fd6-8eab-03fd8678dde4','過虎北口始聞雞','彭汝礪','宋','宋诗','song-poetry','','[]','雪餘天色更清明，野店忽聞鷄一聲。',64,'全唐诗/poet.song.51000.json','["雪餘天色更清明，野店忽聞鷄一聲。", "地里山川從禹畫，人情風俗近燕京。", "漁陽父老尚垂涕，燕頷將軍誰請纓。", "容覆不分南與北，方知聖德與天平。"]'),
('fc483193-1d2a-4c76-b018-e079e154e586','塞外冬至','彭汝礪','宋','宋诗','song-poetry','','[]','今年至日是今朝，日影方長路更遙。',64,'全唐诗/poet.song.51000.json','["今年至日是今朝，日影方長路更遙。", "霜雪辛勤白榆塞，鵷鴻悵望紫宸朝。", "陰冥丘壑雲長暗，陽觸淵泉凍欲銷。", "欲問春來消息近，幾多垂柳在溪橋。"]'),
('06760cd7-9aab-4fe8-aae1-da46d70c80c8','聞駕幸太學','彭汝礪','宋','宋诗','song-poetry','','[]','四海承平正右文，君王昨日幸成均。',64,'全唐诗/poet.song.51000.json','["四海承平正右文，君王昨日幸成均。", "三千縫掖星辰拱，十二旗常日月新。", "萬里去持山國節，六龍阻望屬車塵。", "上心直欲窺堯禹，咫尺誰能席上珍。"]'),
('687b4ffa-93ad-4901-bbcb-f6426094482d','寄君時宿直','彭汝礪','宋','宋诗','song-poetry','','[]','天寒不歸汝安否，日暮有懷如此何。',64,'全唐诗/poet.song.51000.json','["天寒不歸汝安否，日暮有懷如此何。", "丈室全如在林壑，重雲漫不見星河。", "高風側聽雝雝雁，濡露長悲蓼蓼莪。", "不是不知詩廢事，相思不寐自成歌。"]'),
('2320947a-ccf4-4ed3-8489-0651e296832e','雁池','彭汝礪','宋','宋诗','song-poetry','','[]','池水人言是雁池，池邊兀坐久忘歸。',64,'全唐诗/poet.song.51000.json','["池水人言是雁池，池邊兀坐久忘歸。", "蓬瀛仙子紅蓮出，湖海幽人白鷺飛。", "楊柳垂陰留客佩，滄浪潑翠點人衣。", "故園一別頭今白，目斷江邊舊釣磯。"]'),
('558eeafa-aa0f-4aa7-b612-648ee07d1c53','萬安道中','彭汝礪','宋','宋诗','song-poetry','','[]','上下雞籠牛口灘，灘頭濯濯雨聲寒。',64,'全唐诗/poet.song.51000.json','["上下雞籠牛口灘，灘頭濯濯雨聲寒。", "氣蒸曉日雲無間，波漾春風雪未乾。", "落絮並花浮遠水，飛鷗隨鷺落驚湍。", "扁舟穩泛滄浪遠，珍重嚴陵一釣竿。"]'),
('dbfebe5d-61a8-4784-b72e-d460e8efafe9','和佛印','彭汝礪','宋','宋诗','song-poetry','','[]','供佛堂中香積飯，度人門外白牛車。',64,'全唐诗/poet.song.51000.json','["供佛堂中香積飯，度人門外白牛車。", "參禪長老或雪涕，說法虛空時雨花。", "靈鷲御風朝海瀆，飛翬撒水抗烟霞。", "老師住處即安樂，祇恐臥龍生嘆嗟。"]'),
('9b2e618a-3c95-4c45-ab72-0b2f011a278a','執中學士以蔬菜見貺戲寄小詩','彭汝礪','宋','宋诗','song-poetry','','[]','貸粟監河公自貧，蔬菹投我覺情親。',64,'全唐诗/poet.song.51000.json','["貸粟監河公自貧，蔬菹投我覺情親。", "不須乞飯去香積，誰會獻芹如野人。", "維笋及蒲全似古，式歌且舞恰當春。", "投閑即擬同公醉，莫道無魚可及賓。"]'),
('5e3edf0c-5d9c-48c7-a8b8-dfde794eefae','與文淵游聘君亭分題和文淵亭字韵','彭汝礪','宋','宋诗','song-poetry','','[]','東湖九日水如冰，畫舫還尋孺子亭。',64,'全唐诗/poet.song.51000.json','["東湖九日水如冰，畫舫還尋孺子亭。", "雨後斷雲歸冉冉，天寒孤雁去冥冥。", "蘭苕散漫池塘遠，松竹參差島嶼青。", "貪惜上恩歸未得，自憐雙鬢欲垂星。"]'),
('b33bdd6f-149f-4871-978b-07b2d0a6dd63','內鄉','彭汝礪','宋','宋诗','song-poetry','','[]','山谷生雲作風雨，樓臺映日貼烟霞。',64,'全唐诗/poet.song.51000.json','["山谷生雲作風雨，樓臺映日貼烟霞。", "危峰熊耳倍千丈，廢堞虎遙今數家。", "野外小橋丹作水，潭邊仙菊雪開花。", "隆寒大熱三經涉，世事催人早鬢華。"]'),
('54dafc99-a708-4c30-8b39-7bd3ded4b443','送子開侍郎出守徐州','彭汝礪','宋','宋诗','song-poetry','','[]','彭城事事似南都，頃歲曾分刺史符。',64,'全唐诗/poet.song.51000.json','["彭城事事似南都，頃歲曾分刺史符。", "吏治甚慚前有召，民謠更愧昔無襦。", "最思鳳沼鳳凰集，還見雁池鴻雁孤。", "萬事我今無一樂，扁舟歸夢滿江湖。"]'),
('50346e50-8c2a-4379-85e3-1a8014aeb687','致政侍郎知郡學士賡和詩凡數篇謹用元韵寄呈知郡學士','彭汝礪','宋','宋诗','song-poetry','','[]','玉色諸兒馥若蘭，綵衣想見日承顔。',64,'全唐诗/poet.song.51000.json','["玉色諸兒馥若蘭，綵衣想見日承顔。", "塵纓遠濯滄浪水，燕几深居畏壘山。", "俗眼漫譏身察察，人情方喜知閒閒。", "夕陽歸興隨飛鳥，真意無人語此還。"]'),
('4c7ac3a8-2d12-4127-aea3-72b5f9b7bc51','和蜀公家居','彭汝礪','宋','宋诗','song-poetry','','[]','平湖三月水猶寒，霜鑑冰壺照玉顔。',64,'全唐诗/poet.song.51000.json','["平湖三月水猶寒，霜鑑冰壺照玉顔。", "柳暗何如江上路，雲深不礙海中山。", "春風鳬雁窺青瑣，晚日波濤在白間。", "景物會招山簡醉，時時倒着接䍦還。"]'),
('877b89b5-ec00-4fa2-93fb-46859456d0e7','西湖','彭汝礪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','篇章蕪漫不中看，誤得先生一解顔。',64,'全唐诗/poet.song.51000.json','["篇章蕪漫不中看，誤得先生一解顔。", "明月何爲投暗室，陽春不意在窮山。", "平時借以齒牙論，今日見之眉睫間。", "自笑鳲鳩爲計拙，誰知鴻雁及時還。"]'),
('3a871754-1ad6-4088-b50c-39e4e1115952','答蜀公奉酬  其一','彭汝礪','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','疊石栽花作小園，庭柯顧盼足怡顔。',64,'全唐诗/poet.song.51000.json','["疊石栽花作小園，庭柯顧盼足怡顔。", "盡捐勢利隨流水，多占聲名似泰山。", "細雨鳬雛浮水際，微風燕子語梁間。", "竹冠筇杖籃輿好，認得公從湖上還。"]'),
('a9b6ac42-e8f2-40ba-b901-491e9d89f308','答蜀公奉酬  其二','彭汝礪','宋','宋诗','song-poetry','','[]','逍遙今是地行仙，無事全勝藥駐顔。',64,'全唐诗/poet.song.51000.json','["逍遙今是地行仙，無事全勝藥駐顔。", "早歲風流都翰苑，他時文字出名山。", "修竿養竹千餘畝，小屋誅茅八九間。", "潁水可憐歸未得，不如雲鶴會飛還。"]'),
('8551842a-7e66-4b04-8c62-b12961f77480','答蜀公奉酬  其三','彭汝礪','宋','宋诗','song-poetry','','[]','叢條潤澤無瞋膽，芳杜將迎失厚顔。',64,'全唐诗/poet.song.51000.json','["叢條潤澤無瞋膽，芳杜將迎失厚顔。", "陶令葛巾曾漉酒，謝公蠟屐慣尋山。", "觀魚恰似濠梁上，結宇渾如岡曲間。", "楚醴滿觴知意愜，胡香細炷覺神還。"]'),
('a04d669c-c5be-43e9-9867-582ae3ec23fe','途中奉寄','彭汝礪','宋','宋诗','song-poetry','','[]','水涉山行歧路長，思親一夜鬢毛霜。',64,'全唐诗/poet.song.51000.json','["水涉山行歧路長，思親一夜鬢毛霜。", "紛紛枝上慈烏宿，肅肅雲中鴻雁行。", "活計一行隨夢幻，生涯好去老耕桑。", "知君合續南陔賦，萬里因風數寄將。"]'),
('f36fcedb-8bdc-4263-b769-3243a31b6a2c','武岡路中','彭汝礪','宋','宋诗','song-poetry','','[]','複嶺重岡烟靄深，晚年多病覺難任。',64,'全唐诗/poet.song.51000.json','["複嶺重岡烟靄深，晚年多病覺難任。", "他鄉一日如三歲，遠路家書抵萬金。", "流水可憐君未息，白雲誰似爾無心。", "天寒日暮雙飛鳥，寂寂歸棲只舊林。"]'),
('fea95ded-b6f5-4a2f-a7f0-e5100211ce0a','答張大夫友兄','彭汝礪','宋','宋诗','song-poetry','','[]','塵土無人慰病懷，篇章一見覺心開。',64,'全唐诗/poet.song.51000.json','["塵土無人慰病懷，篇章一見覺心開。", "風高昨夜冥鴻去，水澀何時畫鷁來。", "天上舊傳公子貴，江東還見步兵才。", "老成合有言爲贈，倚馬相望故鳳臺。"]'),
('82f275d7-7bf5-488a-b5ef-928ce1c55238','送周朝議赴郢  其一','彭汝礪','宋','宋诗','song-poetry','','[]','岩石滄洲一水涯，畫船幾夜宿蘆花。',64,'全唐诗/poet.song.51000.json','["岩石滄洲一水涯，畫船幾夜宿蘆花。", "芭蕉山谷靈峰寺，龜鶴池塘梅福家。", "今日豈應無白雪，當時亦未見皇華。", "兵厨且善爲冰酒，當爲公浮八月槎。"]'),
('1c1534af-991f-4c45-b987-438d4df91765','送周朝議赴郢  其二','彭汝礪','宋','宋诗','song-poetry','','[]','驅馬悠悠何所之，峴山南去習家池。',64,'全唐诗/poet.song.51000.json','["驅馬悠悠何所之，峴山南去習家池。", "蓮花可愛肌如雪，鷗鳥何爲鬢亦絲。", "一葉林頭秋到處，片雲溪上雨來時。", "公方紫綬金章貴，可要山公白接䍦。"]'),
('83649070-8463-44cb-9219-01a273abc5b2','城上','彭汝礪','宋','宋诗','song-poetry','','[]','孤城縱目盡南東，山轉溪回翠且重。',64,'全唐诗/poet.song.51000.json','["孤城縱目盡南東，山轉溪回翠且重。", "雲際靜浮濱漢水，林端清送上方鐘。", "今時漢北無雛鳳，當日襄南有臥龍。", "萬事廢興無足問，登臨吾樂正從容。"]'),
('fc76559c-d6d6-46ec-a551-d369379a2fb4','代人答周朝議生辰贈章','彭汝礪','宋','宋诗','song-poetry','','[]','我辰邂逅得朱明，一離陰邪一點生。',64,'全唐诗/poet.song.51000.json','["我辰邂逅得朱明，一離陰邪一點生。", "蓬矢尚存隨薄宦，龍駒已老怯修程。", "鬢毛久似安仁白，神氣初慚衛玠清。", "南郭丈人慈愛並，遠分珠玉助光榮。"]'),
('30a9dd5a-c58b-4bbe-a733-943d53ec9229','穀城溪亭','彭汝礪','宋','宋诗','song-poetry','','[]','穀國有亭溪水邊，稅車安寢不無緣。',64,'全唐诗/poet.song.51000.json','["穀國有亭溪水邊，稅車安寢不無緣。", "芰荷苒苒雙飛鳥，蘆葦深深一釣船。", "故國寄聲無去雁，他鄉催淚有啼蟬。", "江山亦爲行人動，六月寒風正凜然。"]'),
('0fb1019d-9023-4d5d-8490-764df2a335fc','答孫荆州頏','彭汝礪','宋','宋诗','song-poetry','','[]','鳳林清淑鬰扶輿，五馬當年數駐車。',64,'全唐诗/poet.song.51000.json','["鳳林清淑鬰扶輿，五馬當年數駐車。", "故老作歌今未已，大賢爲政法何如。", "二碑峴首窺餘烈，一紙荆州得近書。", "縮項槎頭知未羨，龍州聞說更多魚。"]'),
('cfb28384-38e5-4167-b779-8090a4640004','病中寄君時','彭汝礪','宋','宋诗','song-poetry','','[]','可憐平生不堪處，未有一朝無病時。',64,'全唐诗/poet.song.51000.json','["可憐平生不堪處，未有一朝無病時。", "患難尋常心欲折，塵埃四十髮如絲。", "倦游司馬多聞友，現病維摩大導師。", "筋力尚堪游樂在，不應空廢百花期。"]'),
('bf70116f-f824-4df6-b667-925dbfa57b69','寄孫元忠','彭汝礪','宋','宋诗','song-poetry','','[]','離羣已是四年秋，昔是少年今白頭。',64,'全唐诗/poet.song.51000.json','["離羣已是四年秋，昔是少年今白頭。", "舊日雁池應好在，多情睢水會東流。", "更貧尚有簞瓢在，已見誰能度數求。", "三徑淵明多種菊，五湖范蠡有歸舟。"]'),
('30503545-37f4-4936-b3b0-b7aabb0cb672','戲呈葉提舉','彭汝礪','宋','宋诗','song-poetry','','[]','自笑肩輿鈍似椎，不如馬足快如鵻。',64,'全唐诗/poet.song.51000.json','["自笑肩輿鈍似椎，不如馬足快如鵻。", "驅馳祇似江西日，懶病全非年少時。", "熟睡疑空浄石室，沈思若下董生帷。", "道途不獨輸公敏，凡事相方總較遲。"]'),
('cd3f6f8e-e902-47b8-9451-6dfb9a8f9e29','和馬太守五首 寒林','彭汝礪','宋','宋诗','song-poetry','','[]','平林十里看深秋，疏影橫斜翠欲流。',64,'全唐诗/poet.song.51000.json','["平林十里看深秋，疏影橫斜翠欲流。", "日晚小舟維別浦，天寒飛鳥浴滄洲。", "傍山畦徑村村遠，近水軒楹事事幽。", "欲賦祇慚非太白，酒巵獨覬一朝酬。"]'),
('794aa6c0-2035-4d9f-950b-f073d33750cc','和馬太守五首 翠玉','彭汝礪','宋','宋诗','song-poetry','','[]','平湖如鑑見寒林，誰作高亭據靜深。',64,'全唐诗/poet.song.51000.json','["平湖如鑑見寒林，誰作高亭據靜深。", "到海水源終有本，從龍雲影自無心。", "芰荷一片隨幽賞，鸂鶒雙飛近醉吟。", "顧我倦游歸欲早，寒門獨覬數窺臨。"]'),
('19e2f81a-47fa-4e98-956f-fde2d6c1faf7','和馬太守五首 水雲','彭汝礪','宋','宋诗','song-poetry','','[]','萬竹娟娟一徑開，禪師當日爲誰栽。',64,'全唐诗/poet.song.51000.json','["萬竹娟娟一徑開，禪師當日爲誰栽。", "本支間出爲龍去，秀實長留待鳳來。", "揮袂好風能應接，杖藜棲鳥誤驚猜。", "公游豈得如嵇阮，禁省方歸治劇材。"]'),
('df5fbb04-a2b8-4032-9abd-69ccc818557b','和馬太守五首 五老峰','彭汝礪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不到匡廬今幾年，幽亭縱目意茫然。',64,'全唐诗/poet.song.51000.json','["不到匡廬今幾年，幽亭縱目意茫然。", "蒼顔想像重湖外，翠色參差落照前。", "潤澤爲霖功及物，堅高作柱勢參天。", "使君筆墨真能賦，不必須憑繪畫傳。"]'),
('249e6c47-9554-4ec5-8dd4-3276ccba144a','和馬太守五首 澄心亭','彭汝礪','宋','宋诗','song-poetry','','[]','逸老初開池上亭，使君鐘鼓樂新成。',64,'全唐诗/poet.song.51000.json','["逸老初開池上亭，使君鐘鼓樂新成。", "寶林自有湖山助，定水何曾風浪生。", "雨過淡雲迷島嶼，日長幽鳥下簷楹。", "扁舟遠泛滄浪碧，可避時人笑獨清。"]'),
('cf3c596b-d8fa-4b67-8289-a328fc1ffc71','和念一弟','彭汝礪','宋','宋诗','song-poetry','','[]','岡陵盤泊土湖深，蛟蜃伏藏山鳥吟。',64,'全唐诗/poet.song.51000.json','["岡陵盤泊土湖深，蛟蜃伏藏山鳥吟。", "大雪埋雲冬寂寞，喬松夾竹晝陰森。", "百年身逐無涯智，萬斛愁中方寸心。", "昨日汝詩催淚落，暴添溪水兩三尋。"]'),
('fecaf495-f33c-4466-a15c-1e1b6ac24863','臨江道中人家多植竹','彭汝礪','宋','宋诗','song-poetry','','[]','遠遠平山淺淺溪，人家栽竹當藩籬。',64,'全唐诗/poet.song.51000.json','["遠遠平山淺淺溪，人家栽竹當藩籬。", "雪霜盡臘青如昨，風月乘春綠更滋。", "淡薄冷光浮莽蒼，招摇清影落漣漪。", "故園所富今幾頃，會有歸來築隠時。"]'),
('578acf20-5a55-4705-8293-fc993cccd9d8','和毛正仲','彭汝礪','宋','宋诗','song-poetry','','[]','風雨登危奚壯哉，見書三賦彼崔嵬。',64,'全唐诗/poet.song.51000.json','["風雨登危奚壯哉，見書三賦彼崔嵬。", "細緣狗脊僕肩病，曲轉羊腸車轍摧。", "晨鵲卜知書信到，夜星占見使華來。", "愛君最識思親意，取次枯腸夜九回。"]'),
('e5f56828-a8ce-4ec1-9a01-e8f4cf226de3','寄提舉朝議丈','彭汝礪','宋','宋诗','song-poetry','','[]','安穩青雲喜得輿，寂寥窮巷憶回車。',64,'全唐诗/poet.song.51000.json','["安穩青雲喜得輿，寂寥窮巷憶回車。", "灌畦搰搰知同病，遊刃恢恢想自如。", "暇日會馳千里駕，好風時寄一行書。", "愛公有似能鳴雁，顧我還同喣溼魚。"]'),
('344efee8-3323-42dd-8a0a-3e11bd84dbd7','河東橋亭以久廢置不用欲移菜畦以爲老之游息之地因以詩就公權乞之','彭汝礪','宋','宋诗','song-poetry','','[]','全家歸住白雲中，舊地新成半畝宮。',64,'全唐诗/poet.song.51000.json','["全家歸住白雲中，舊地新成半畝宮。", "簇簇要添垂柏翠，紛紛已出小花紅。", "自知北海恩懷厚，况是東鄰路逕通。", "到得落成應不負，携壺先約醉春風。"]'),
('0997fb60-4270-4c4e-8995-ce6446e324e4','雜詠一首','彭汝礪','宋','宋诗','song-poetry','','[]','小林幽徑自春華，不似城頭望處佳。',64,'全唐诗/poet.song.51000.json','["小林幽徑自春華，不似城頭望處佳。", "山色倚雲千萬里，蓬門穿水兩三家。", "聲聞翠篠紛紛葉，香落寒梅細細花。", "更上幽亭望南北，欲隨幽鳥到天涯。"]'),
('071b1b95-1a22-42fb-b184-a559531964a9','病告詩上侍讀','彭汝礪','宋','宋诗','song-poetry','','[]','詩句親題慰下僚，清心洗盡渴心焦。',64,'全唐诗/poet.song.51000.json','["詩句親題慰下僚，清心洗盡渴心焦。", "雲移星月來幽隠，風轉英莖下寂寥。", "肝膽塵生知幾日，齒牙病久起今朝。", "篇章盡出樵蘇鄙，不識鼇宮路徑遙。"]'),
('2b78b905-0e42-411a-bea5-86a09cf1dfc7','寄史司理','彭汝礪','宋','宋诗','song-poetry','','[]','日就妻孥問藥囊，鏡中自笑鬢毛蒼。',64,'全唐诗/poet.song.51000.json','["日就妻孥問藥囊，鏡中自笑鬢毛蒼。", "詩編欲乞閑方記，茶面親題病未嘗。", "飲量無涯傾北海，風情不薄念東陽。", "終篇未盡相望意，洗耳風前遲報章。"]'),
('9e37b477-da8d-444c-a950-094cb4780d98','睦仲乞詩用其韵謝之','彭汝礪','宋','宋诗','song-poetry','','[]','鬰鬰胸懷百未伸，道途容易學參辰。',64,'全唐诗/poet.song.51000.json','["鬰鬰胸懷百未伸，道途容易學參辰。", "桂科今日須吾子，鼎食當時况所親。", "景物依依吟曉色，謳謠細細問途人。", "春風寫寄南淮地，蕭灑文章自細陳。"]'),
('2572d52c-0295-4432-8b29-efd20135a8f7','和濟叔兄書齋言志  其一','彭汝礪','宋','宋诗','song-poetry','','[]','子夏今爲河上居，諸生從此望夷涂。',64,'全唐诗/poet.song.51000.json','["子夏今爲河上居，諸生從此望夷涂。", "聖賢事業長難合，仁義生涯未至迂。", "盛德固能蘇弊俗，明時安忍作潜夫。", "鞭駑欲副新詩念，爭奈曾參性質愚。"]'),
('29cd71dd-48bb-4842-a5a3-82b65355a0fe','和濟叔兄書齋言志  其二','彭汝礪','宋','宋诗','song-poetry','','[]','常因多病泣途窮，性命于今亦少通。',64,'全唐诗/poet.song.51000.json','["常因多病泣途窮，性命于今亦少通。", "貴賤固宜常厥德，死生豈足動吾中。", "游心自有詩書學，扶病須憑藥石功。", "否剝亦留歸泰復，天時安得久屯蒙。"]'),
('c0553866-71d2-4c02-95d2-39a2b9a22a00','和濟叔兄書齋言志  其三','彭汝礪','宋','宋诗','song-poetry','','[]','旅人汲汲赴前程，奔走川途不暫停。',64,'全唐诗/poet.song.51000.json','["旅人汲汲赴前程，奔走川途不暫停。", "蹤跡無如今困蹇，才謀不似舊精靈。", "雍容可羨雲中雁，浩蕩來隨水面萍。", "富貴功名皆外物，艱難險阻亦須經。"]'),
('7a8e693b-922f-4e8c-9839-0b688622b263','和濟叔兄書齋言志  其四','彭汝礪','宋','宋诗','song-poetry','','[]','未得臨流一醉觀，江山應是怨無端。',64,'全唐诗/poet.song.51000.json','["未得臨流一醉觀，江山應是怨無端。", "苦吟夜月橫詩筆，爛醉秋風把釣竿。", "溪瀨最宜霜後聽，峰巒曾向雨中看。", "輸君瞬息窮千里，苒苒羈懷幾萬般。"]'),
('3fa65875-d5ac-47b7-8e75-87fa0f215b7e','寓學芝山','彭汝礪','宋','宋诗','song-poetry','','[]','鯨鵬未得遂南飛，翻學鷦鷯寄一枝。',64,'全唐诗/poet.song.51000.json','["鯨鵬未得遂南飛，翻學鷦鷯寄一枝。", "翠石碧泉無盡處，冷蛩鳴雁不勝悲。", "驅除窮困知何計，收拾功名竟幾時。", "穹昊不言難遽問，性情無奈祇吟詩。"]'),
('d900864b-13f4-4dde-8a54-08817cd74ce7','初秋曉起','彭汝礪','宋','宋诗','song-poetry','','[]','雲影冥蒙雨細飄，風傳秋意又經宵。',64,'全唐诗/poet.song.51000.json','["雲影冥蒙雨細飄，風傳秋意又經宵。", "蒼溪岸側千峰翠，高樹枝頭一葉凋。", "病久亦傷光景速，起來尤愛暑威銷。", "徐徐步向亭中立，逸興飄浮酒氣驕。"]'),
('bfbb8d0a-7662-4283-9a51-16230803b04e','舟中作','彭汝礪','宋','宋诗','song-poetry','','[]','曉日新晴三月天，征途令我一悽然。',64,'全唐诗/poet.song.51000.json','["曉日新晴三月天，征途令我一悽然。", "謀身獨愧聲名淺，得地安辭道里千。", "匹馬荒山嗟困矣，扁舟濁水喜安然。", "桐廬雖遠今伊邇，魂夢先歸絳帳前。"]'),
('c5d21c20-fef5-4b0f-913a-8deb0fcd2f08','寄張子直  其一','彭汝礪','宋','宋诗','song-poetry','','[]','常願從君授古書，血誠瀝盡更無餘。',64,'全唐诗/poet.song.51000.json','["常願從君授古書，血誠瀝盡更無餘。", "漂流豈意來深野，繫滯無由後從車。", "蹤跡浸違南郡帳，夢魂長繞武侯廬。", "仁人有意收庸賤，時寄聲音一起予。"]'),
('3b148cd8-6d4d-4970-9023-59d7689b3f11','寄張子直  其二','彭汝礪','宋','宋诗','song-poetry','','[]','性質迂迴趣向卑，此身敢望聖門歸。',64,'全唐诗/poet.song.51000.json','["性質迂迴趣向卑，此身敢望聖門歸。", "趨時已愧雕蟲陋，學古還憂畫虎非。", "材近蓬蒿難自立，目無松柏竟誰依。", "重嗟蹤跡匏瓜繫，翻羨蒼蠅附尾飛。"]'),
('eeec3404-be2f-4a22-a9d6-e6b45dd99f34','子直見和前韵因復之  其一','彭汝礪','宋','宋诗','song-poetry','','[]','平時祇畏才無敵，今日方知器有餘。',64,'全唐诗/poet.song.51000.json','["平時祇畏才無敵，今日方知器有餘。", "一第已多新宦况，潜思猶入舊田廬。", "鳳凰固合栖阿閣，騏驥誰令駕鼓車。", "千里青雲今至矣，願傾深畫盡傳予。"]'),
('918ecc6d-7e39-4586-a051-b07878258cfe','子直見和前韵因復之  其二','彭汝礪','宋','宋诗','song-poetry','','[]','淹延未得共山居，愁積胸腸萬斛餘。',64,'全唐诗/poet.song.51000.json','["淹延未得共山居，愁積胸腸萬斛餘。", "致遠自傷無巨翮，臨危誰肯借安車。", "油幢金印男兒事，碧水青山隠者廬。", "窮達計謀今已决，故人天際亦思予。"]'),
('487f0146-0284-4444-8759-2d4a4423adc6','戲呈子直','彭汝礪','宋','宋诗','song-poetry','','[]','步入松筠水石間，回眸方覺世途難。',64,'全唐诗/poet.song.51000.json','["步入松筠水石間，回眸方覺世途難。", "蒙茸草色縈行徑，淩亂花陰覆釣灣。", "暇日還能邀我醉，清時未肯縱君閑。", "烹鮮酌酒且行樂，北圃春容今又殘。"]'),
('ea1ca651-b781-48cb-b7a8-9bed0f10c7f0','寄獻教授友兄','彭汝礪','宋','宋诗','song-poetry','','[]','焦心猶覬就功名，痛惜長爲疢疾嬰。',64,'全唐诗/poet.song.51000.json','["焦心猶覬就功名，痛惜長爲疢疾嬰。", "欲起病軀思扁鵲，未知窮命問君平。", "道途遼邈何由及，田壤蕭條不復耕。", "好學豈能幾亞聖，受經從此愧丘明。"]'),
('bd7ae8af-7d22-4463-b6be-9140b08ac1be','千乘先生有草堂之吟而人或譏之因次其韵','彭汝礪','宋','宋诗','song-poetry','','[]','世俗無輕好遁譏，先生豈是愛山扉。',64,'全唐诗/poet.song.51000.json','["世俗無輕好遁譏，先生豈是愛山扉。", "聖人固重潜龍誡，君子安爲即鹿非。", "白水會來朝草徑，紅塵不敢傍麻衣。", "金輿應有商岩夢，即聽東南一詔飛。"]'),
('b9cff9f5-2956-483d-9d66-ca7d6395b030','次道濟韵','彭汝礪','宋','宋诗','song-poetry','','[]','吾材未及明時用，來傍師門靜養蒙。',64,'全唐诗/poet.song.51000.json','["吾材未及明時用，來傍師門靜養蒙。", "多病因知妨力學，潜思猶是覬成功。", "松心並老凝寒後，玉色相看烈火中。", "天意欲令更患難，詩辭何必議窮通。"]'),
('7b563d6e-e806-4e3b-88fd-e90105584edc','病居婺女','彭汝礪','宋','宋诗','song-poetry','','[]','蕩漾扁舟冒曉征，此身何日得安停。',80,'全唐诗/poet.song.51000.json','["蕩漾扁舟冒曉征，此身何日得安停。", "窮途敢恨身無託，多病惟思藥有靈。", "氣誼腹心雙古劍，江湖蹤跡一浮萍。", "塵埃易使羈容黑，仁義難邀俗眼青。", "鄉思浪憑歌笑解，微辭不是楚騷經。"]'),
('5f000167-59e5-4f1f-a798-784ed3efcb14','寄子直友兄秘書','彭汝礪','宋','宋诗','song-poetry','','[]','碧水青山一萬尋，不量無力强登臨。',64,'全唐诗/poet.song.51000.json','["碧水青山一萬尋，不量無力强登臨。", "辛勤亦覬功名就，痛惜長爲疾患侵。", "憔悴已成今日態，英豪不復舊時心。", "歸期未遂家千里，空對秋風淚滿襟。"]'),
('23ad51f7-b715-433f-acde-68ae943fa27c','元夕與莘老俱宿齋因寄莘老','彭汝礪','宋','宋诗','song-poetry','','[]','零雨其濛春始和，明星有爛夜如何。',64,'全唐诗/poet.song.51000.json','["零雨其濛春始和，明星有爛夜如何。", "笙篁故與風聲遠，燈火疑添月色多。", "漸老自能忘世味，欲明更起看天河。", "定留太一青藜照，願寄荆人白雪歌。"]'),
('46288b0b-bdfc-44d8-9b47-04a0d8d0ad48','知常三十一致其政遷通直郎遇郊恩以親之封封其祖父母以妻之封封其父母其外舅知府龍圖安中以詩美之提刑大夫信叔和之俾某屬和','彭汝礪','宋','宋诗','song-poetry','','[]','立節秉心誠與俱，至誠少日慕顔徒。',64,'全唐诗/poet.song.51000.json','["立節秉心誠與俱，至誠少日慕顔徒。", "榮名及祖親仍與，盛事超今古亦無。", "番國山川元潤澤，吳園魚鳥亦驩虞。", "冰翁星使詩酬唱，在昔嘗聞德不孤。"]'),
('c855b3a3-19be-42c7-8400-8d074092d3a7','承臬山毅夫提點學士有游會庾樓因用元韵','彭汝礪','宋','宋诗','song-poetry','','[]','擁旜昔過趙州關，剖竹今鄰四祖山。',64,'全唐诗/poet.song.51000.json','["擁旜昔過趙州關，剖竹今鄰四祖山。", "問法幾生成密記，焚香曷月禮慈顔。", "知天稍似三無慍，易地何如五不還。", "邂逅晦堂聊寄意，而今事事祇如閑。"]'),
('55385e01-1143-47e3-b9b9-0c61239ba24f','按澇','彭汝礪','宋','宋诗','song-poetry','','[]','瘦馬扁舟迹已勤，三鄉行盡獨傷神。',64,'全唐诗/poet.song.51000.json','["瘦馬扁舟迹已勤，三鄉行盡獨傷神。", "湖邊圍漲魚龍富，野外田乾燕雀貧。", "豈有異能裨此理，試留餘澤遺斯民。", "東南步武豐凶別，却笑天心似未均。"]'),
('8976f3f6-9e50-4bd4-8add-f74cf8fd6469','寄錢穆父','彭汝礪','宋','宋诗','song-poetry','','[]','忠義文章見一門，風流竊喜得諸孫。',64,'全唐诗/poet.song.51000.json','["忠義文章見一門，風流竊喜得諸孫。", "古人事業非無意，天下幾微定有言。", "寒鬭雪霜松老大，高飛霄漢鳳騰軒。", "治功今日俱無補，塵土相看畏素飱。"]'),
('f165b55f-c309-4868-b4e2-29d71cba5d8a','憶程公權','彭汝礪','宋','宋诗','song-poetry','','[]','游從邂逅值王孫，萬事無窮寄一真。',64,'全唐诗/poet.song.51000.json','["游從邂逅值王孫，萬事無窮寄一真。", "傾蓋異時心似舊，望塵今日味如新。", "清風遂別江山曉，潤澤空餘草木春。", "欲寄贈言終少取，獨爲瞻慕共斯民。"]'),
('0d959855-5a1d-4a39-a1af-dafe74fa339f','嘗約誼父同游龍泉奔走失期故作是詩奉和元韵','彭汝礪','宋','宋诗','song-poetry','','[]','野寺幽幽隠翠嵐，山川形勢盡東南。',64,'全唐诗/poet.song.51000.json','["野寺幽幽隠翠嵐，山川形勢盡東南。", "吟隨野竹吾懷愜，醉啜溪泉此意堪。", "樂事難并真可惜，登高能賦亦曾諳。", "游從欲盡林間勝，雨氣渾渾滿古潭。"]'),
('7d16db78-23b4-4efc-b305-3d9b250042f6','古木','彭汝礪','宋','宋诗','song-poetry','','[]','雨溼路岐泥滑滑，風吹江海水茫茫。',64,'全唐诗/poet.song.51000.json','["雨溼路岐泥滑滑，風吹江海水茫茫。", "壯心弦直值吾道，孤宦蓬飛各異鄉。", "詩句好吟江上碧，酒巵已負菊邊香。", "豐年誰及農家樂，老稚驩謳自滌場。"]'),
('06c69aea-2547-4973-876d-348290bd6f7d','得庭佐巖夫二弟二書','彭汝礪','宋','宋诗','song-poetry','','[]','十年翰墨共螢窗，萬里憂勤鬢欲樁。',64,'全唐诗/poet.song.51000.json','["十年翰墨共螢窗，萬里憂勤鬢欲樁。", "薄宦鹿埃寄南國，歸心日夜度重江。", "春風喜詠棠陰秀，夜月愁看雁影雙。", "病眼相望勞不徹，書來聊得此心降。"]'),
('e94a7933-82d2-43ba-b3e0-1bebc2f70366','賀兄長有子','彭汝礪','宋','宋诗','song-poetry','','[]','鳷鵲曾將喜信來，奇祥昨夜出珠胎。',64,'全唐诗/poet.song.51000.json','["鳷鵲曾將喜信來，奇祥昨夜出珠胎。", "一枝始得龍孫貴，萬里看成驥子材。", "道路笑臨詩首首，庭幃歡上酒盃盃。", "風吹消息歸江國，老稚應須眼爲開。"]'),
('f1a942a8-ca0a-476c-9707-eb97f7003aad','欲雨馬上寄兄長','彭汝礪','宋','宋诗','song-poetry','','[]','去馬驚塵犯客襟，喜看雲影聚輕陰。',64,'全唐诗/poet.song.51000.json','["去馬驚塵犯客襟，喜看雲影聚輕陰。", "雁飛淺草風聲疾，蟻鬭枯梨雨意深。", "亭外見山輸獨嘯，林邊上馬强清吟。", "一聲誤認齊蟬晚，叫起肥陵夜夜心。"]'),
('406835a4-f6d3-44aa-895b-b56760a8e724','暑雨','彭汝礪','宋','宋诗','song-poetry','','[]','暑熱炎炎起道途，霆雷一陣出山隅。',64,'全唐诗/poet.song.51000.json','["暑熱炎炎起道途，霆雷一陣出山隅。", "雨吹細點沾鬚鬢，風卷輕寒上髮膚。", "但使田疇終潤澤，敢言車馬久泥塗。", "天時信有豐年意，笑語輕便共野夫。"]'),
('a5e7f2c0-942f-4109-8812-fca54e03d44e','過紫金山','彭汝礪','宋','宋诗','song-poetry','','[]','薄晚遲留問舊山，塵埃敢意紫金丹。',64,'全唐诗/poet.song.51000.json','["薄晚遲留問舊山，塵埃敢意紫金丹。", "雲生石眼千年潤，風出雲稍五月寒。", "下蔡塗泥沾馬足，長淮風浪觸漁竿。", "八公更有威靈在，簿領應須笑賤官。"]'),
('54420fd9-0219-4753-91e5-ac851b97bdc5','擬賞花釣魚詩  其一','彭汝礪','宋','宋诗','song-poetry','','[]','晴雲扶日上昭陽，翠輦鳴鞭下建章。',64,'全唐诗/poet.song.51000.json','["晴雲扶日上昭陽，翠輦鳴鞭下建章。", "化國樓臺天半際，瀛洲殿閣水中央。", "魚游自並龜龍國，花氣渾如薝蔔香。", "擬學華封人作頌，千秋萬歲奉君王。"]'),
('e6f515df-eaa2-443c-ad4b-4c7b09cf707e','擬賞花釣魚詩  其二','彭汝礪','宋','宋诗','song-poetry','','[]','琉璃宮殿雲深處，錦繡池堂雨過時。',64,'全唐诗/poet.song.51000.json','["琉璃宮殿雲深處，錦繡池堂雨過時。", "魚躍定名千歲鯉，花開多是萬年枝。", "恩流河漢波瀾闊，春在蓬瀛日月遲。", "三十餘年無此會，今朝會見柏梁詩。"]'),
('8e70babd-55eb-4eab-bc0c-a3fcf4237f1a','擬賞花釣魚詩  其三','彭汝礪','宋','宋诗','song-poetry','','[]','孔雀橫斜寶扇回，雕龍浮動翠輿來。',64,'全唐诗/poet.song.51000.json','["孔雀橫斜寶扇回，雕龍浮動翠輿來。", "魚知迎日爭先躍，花會留春獨後開。", "法部方將九成樂，侍臣迭送萬年盃。", "太平恰似唐虞際，臣主從容賦起哉。"]'),
('9393ae40-da93-4d94-8a1b-018d2a40bcf8','擬賞花釣魚詩  其四','彭汝礪','宋','宋诗','song-poetry','','[]','翠蹕雕輿下未央，禁林春色秀天芳。',64,'全唐诗/poet.song.51000.json','["翠蹕雕輿下未央，禁林春色秀天芳。", "帝居便是蓬萊勝，花氣渾如薝蔔香。", "五色靈池魚撥剌，九苞阿閣鳳徊翔。", "神仙世界光陰別，比着人間一倍長。"]'),
('99f05f7d-3ec3-498f-9b90-04f83a6bb4b8','擬賞花釣魚詩  其五','彭汝礪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','日暖魚游百子池，雨餘花折萬年枝。',64,'全唐诗/poet.song.51000.json','["日暖魚游百子池，雨餘花折萬年枝。", "微風靜覺絲緡遠，暖日徐看淑景移。", "九奏高張洞庭樂，七言徧賦柏梁詩。", "吁俞不忘幾微戒，恰似唐堯虞舜時。"]'),
('2124af51-29ae-4a05-b6f8-45eac102c8f4','擬賞花釣魚詩  其六','彭汝礪','宋','宋诗','song-poetry','','[]','甘雨祈祈兆歲豐，君王暇豫與人同。',64,'全唐诗/poet.song.51000.json','["甘雨祈祈兆歲豐，君王暇豫與人同。", "晴陽魚躍烟濤外，暖日花開錦繡中。", "更有靈龜千歲綠，仍多陳粟萬倉紅。", "便知豈樂歌頒首，不比飛揚賦大風。"]'),
('fbb62fe5-f23f-4c63-a654-6a24835dfbd1','擬賞花釣魚詩  其七','彭汝礪','宋','宋诗','song-poetry','','[]','百子池塘春復還，五雲樓閣曉猶寒。',64,'全唐诗/poet.song.51000.json','["百子池塘春復還，五雲樓閣曉猶寒。", "蛟龍影上黄金輦，錦繡香浮白玉盤。", "宿蘂萬包開雨露，修鱗五色躍波瀾。", "太平既醉恩無報，白首侵尋畏素餐。"]'),
('8cc446a2-6a4f-4f26-a3f1-526c9232ac49','擬賞花釣魚詩  其八','彭汝礪','宋','宋诗','song-poetry','','[]','檻外幽花暖欲然，池邊弱柳困初眠。',64,'全唐诗/poet.song.51000.json','["檻外幽花暖欲然，池邊弱柳困初眠。", "風晴鶑戲長楊日，水浄魚游太液天。", "玉斝酒深浮湛露，寶爐香聚引長烟。", "雲章光絕無能繼，但頌南山億萬年。"]'),
('93acf4fb-da6e-4451-b417-a17cc858f679','擬賞花釣魚詩  其九','彭汝礪','宋','宋诗','song-poetry','','[]','霽色蒼茫杳藹中，玉輿朝出大明宮。',64,'全唐诗/poet.song.51000.json','["霽色蒼茫杳藹中，玉輿朝出大明宮。", "修鱗戲躍神池日，宿蕊爭開禁籞風。", "韶樂大恩流動植，靈臺餘澤入魚蟲。", "龍光所被何其厚，欲報慚無尺寸功。"]'),
('260b1abb-bb23-4de3-8ba8-5fd8a5181540','擬賞花釣魚詩  其一○','彭汝礪','宋','宋诗','song-poetry','','[]','九重殿閣五雲中，閒暇君臣燕樂同。',64,'全唐诗/poet.song.51000.json','["九重殿閣五雲中，閒暇君臣燕樂同。", "芳卉便成金色界，游鱗如在水晶宮。", "承雲樂見太平象，湛露詩成王者風。", "從幸甘泉能獻賦，愧無人可似揚雄。"]'),
('4fdecae9-3cf1-4369-8e0d-b26ad4174309','題醒心亭','彭汝礪','宋','宋诗','song-poetry','','[]','紅塵萬里困征鞍，喜向幽亭一倚欄。',64,'全唐诗/poet.song.51000.json','["紅塵萬里困征鞍，喜向幽亭一倚欄。", "日夜水聲趨澗曲，西南山色上雲端。", "窗橫古木秋陰老，檻逼蒼崖雨氣寒。", "搜盡肺腸吟不竟，欲君親置畫圖看。"]'),
('046947ab-c484-4c54-b3ff-6a14011d5ad2','謹次知縣奉議','彭汝礪','宋','宋诗','song-poetry','','[]','早日蒼茫杳靄中，繡衣綵旆照花驄。',64,'全唐诗/poet.song.51000.json','["早日蒼茫杳靄中，繡衣綵旆照花驄。", "路從古汴聊分北，家在瑯琊更近東。", "大野曉行千嶂月，長河朝濟一帆風。", "賜環不獨邦人願，名字從來重兩宮。"]'),
('2d5c4c5f-0ca9-43f3-9ee0-ff0f59a319e2','次來韵','彭汝礪','宋','宋诗','song-poetry','','[]','山川不見石泉城，風日摇摇想旆旌。',64,'全唐诗/poet.song.51000.json','["山川不見石泉城，風日摇摇想旆旌。", "鸑鷟老尋丹穴宿，驊騮饑上赤霄行。", "隆冬霜雪傷萍泛，末路埃塵憶蓋傾。", "父老祇知榮衣繡，鄉人未會貴登瀛。"]'),
('cdd6f7f4-4e47-4539-87ee-4d17779dee74','拙句送通判學士正夫','彭汝礪','宋','宋诗','song-poetry','','[]','山谷冥冥多雪霜，人情隨處不悲凉。',64,'全唐诗/poet.song.51000.json','["山谷冥冥多雪霜，人情隨處不悲凉。", "綵衣公獨有老母，喬木我今思故鄉。", "行酒賦詩不忍別，登高臨遠便相望。", "故鄉雖好莫留滯，日月其除行路長。"]'),
('21516181-9b04-42b0-b03f-20c9df090f2e','長沙道中寄君時','彭汝礪','宋','宋诗','song-poetry','','[]','少時惜別惟男女，老大相思味尤苦。',64,'全唐诗/poet.song.51000.json','["少時惜別惟男女，老大相思味尤苦。", "時節愁深聚作雲，道途淚落紛如雨。", "夢魂章水去無時，書信蒲山來有數。", "幾時與汝歸去來，綵服相看老農圃。"]'),
('23020f94-c981-4461-a381-7e7d3b3c3218','和文淵游餘干山寺','彭汝礪','宋','宋诗','song-poetry','','[]','愛山終日在山巔，山徑遲留幾屐穿。',64,'全唐诗/poet.song.51000.json','["愛山終日在山巔，山徑遲留幾屐穿。", "澗水曲流隨步屧，爐香深處作雲烟。", "峨峨健馬橫岩石，漠漠蒼龍宿舊淵。", "爲語琵琶洲上路，幾時容我繫歸船。"]'),
('1dde9624-3e9a-4b56-8d14-d2a62fd01ec6','道中每至山寺輒遲留久之','彭汝礪','宋','宋诗','song-poetry','','[]','杖屨徜徉信所之，偶逢佳致即忘歸。',64,'全唐诗/poet.song.51000.json','["杖屨徜徉信所之，偶逢佳致即忘歸。", "舟帷不繫東西去，雲似無心在處飛。", "歲月漫能催我老，江山可復與人違。", "一廛未足南陔志，靜笑浮生事事非。"]'),
('31bcd07f-9c1b-4030-b2ae-d70a1133ba20','武岡驛','彭汝礪','宋','宋诗','song-poetry','','[]','行路蕭條傷客心，黄雲不動祇陰陰。',64,'全唐诗/poet.song.51000.json','["行路蕭條傷客心，黄雲不動祇陰陰。", "天寒獨鶴飛平澤，日暮慈鴉歸故林。", "鱗翼不將一字至，雪霜莫怪二毛侵。", "擁爐更飲鍾陵酒，抱膝漫爲梁甫吟。"]'),
('8cca756e-a891-4dd7-9594-29061f8e7bca','依韵和蕭推官見貽推官字子方知桂州修撰字子善相及喜論兵嘗見于鄱陽','彭汝礪','宋','宋诗','song-poetry','','[]','晚年相遇更堂堂，祇似當時鄱水陽。',64,'全唐诗/poet.song.51000.json','["晚年相遇更堂堂，祇似當時鄱水陽。", "物論固非低閥閱，家聲元自滿湖湘。", "風回獠俗歸陶冶，囊括蠻州入井疆。", "使指質成非有用，贈言虛自辱圭璋。"]'),
('3c09b4c9-9d5a-4a27-9920-e99e1d22a736','寄佛印','彭汝礪','宋','宋诗','song-poetry','','[]','菩薩化成瑶象車，超騰倏忽到雲居。',64,'全唐诗/poet.song.51000.json','["菩薩化成瑶象車，超騰倏忽到雲居。", "提携滿鉢雕胡飯，供養一簞明月珠。", "稱我姓名日專甲，問師安否近何如。", "即今無病無言說，還有人能致問無。"]'),
('5d9eec6c-f96a-4ed7-8a84-e4b44d036387','清江聞提舉承議先行馳寄小詩','彭汝礪','宋','宋诗','song-poetry','','[]','一水相忘復此時，世情豈故與人違。',64,'全唐诗/poet.song.51000.json','["一水相忘復此時，世情豈故與人違。", "江湖雨漲潜鱗去，霄漢雲深畫鷁飛。", "曉月正思公共載，春風好與我同歸。", "別來道味知何似，丹竈黄芽想更肥。"]'),
('55cb371e-2d6a-4337-91bb-ee73347b3ec0','走筆和蕭推官迎提舉承議  其一','彭汝礪','宋','宋诗','song-poetry','','[]','青山遠遠水回回，初見鍾陵城上臺。',32,'全唐诗/poet.song.51000.json','["青山遠遠水回回，初見鍾陵城上臺。", "將迎不獨兒童喜，楊柳看人亦眼開。"]'),
('1eaaf657-e03f-4a27-8d74-0dbdaebe03e0','走筆和蕭推官迎提舉承議  其二','彭汝礪','宋','宋诗','song-poetry','','[]','畫舫急隨江上鷗，猶嗟不及水先流。',32,'全唐诗/poet.song.51000.json','["畫舫急隨江上鷗，猶嗟不及水先流。", "欲知今日陳雷社，不數當時李郭舟。"]'),
('9df41087-a949-4ebf-ba7b-0e0556f09115','又和治居許昌詩  其一','彭汝礪','宋','宋诗','song-poetry','','[]','事與心違即掛冠，逍遙芝朮長童顔。',64,'全唐诗/poet.song.51000.json','["事與心違即掛冠，逍遙芝朮長童顔。", "黄金晚去雲中闕，員嶠深游海上山。", "平日以身當國論，老年將夢比人間。", "文章氣力終豪健，四韵詩來倚馬還。"]'),
('3875363a-f603-4839-a06b-80f98b9ad21d','又和治居許昌詩  其二','彭汝礪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聞說當年鵷鷺班，諫書無數慰龍顔。',64,'全唐诗/poet.song.51000.json','["聞說當年鵷鷺班，諫書無數慰龍顔。", "水橫潁首歸新第，雲斷峨眉憶舊山。", "漫有新詩名海內，曾聞雅樂獻河間。", "西湖今日春應好，想見扁舟載月還。"]'),
('7942b919-a4d8-4d20-8b56-bc95737af99e','途中寄君時弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','郵亭車馬日紛紛，可遂塵埃老此身。',64,'全唐诗/poet.song.51000.json','["郵亭車馬日紛紛，可遂塵埃老此身。", "燕子恰如曾宿客，雁奴猶是未歸人。", "晚雲明滅初收雨，朝日陰晴擬放春。", "花木一時渾自好，寄聲華髮莫爭新。"]'),
('a7625c93-2cd0-42f3-8257-39a413188db1','途中寄君時弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','天晴日馭去遲遲，恰是春風中半時。',64,'全唐诗/poet.song.51000.json','["天晴日馭去遲遲，恰是春風中半時。", "柳色笑花須似錦，雨聲欺雪故如絲。", "遷喬他日吾求友，發藥明朝汝得師。", "樂事信知人不及，異鄉同有拜親期。"]'),
('910ddfc3-096e-40f4-96b0-9270f21860b8','次君時韵','彭汝礪','宋','宋诗','song-poetry','','[]','牙弦不願世人知，末路論心有子期。',64,'全唐诗/poet.song.51000.json','["牙弦不願世人知，末路論心有子期。", "萬物參差爲我與，三人邂逅得吾師。", "更貧未乏揚雄宅，已會誰悲墨子絲。", "欲說本來時節事，直須會得未來時。"]'),
('9b11d0fe-e8d5-4917-a3e9-4bc1d3c45297','寄檢法奉議','彭汝礪','宋','宋诗','song-poetry','','[]','長春月月與玫瑰，煩近萱堂仔細栽。',32,'全唐诗/poet.song.51000.json','["長春月月與玫瑰，煩近萱堂仔細栽。", "却語花開無造次，老親寒食以前來。"]');
